INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 1, 1, 'Y ACONTECIO después de la muerte de Moisés siervo de Jehová, que Jehová habló á Josué hijo de Nun, ministro de Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 1, 2, 'Mi siervo Moisés es muerto: levántate pues ahora, y pasa este Jordán, tú y todo este pueblo, á la tierra que yo les doy á los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 1, 3, 'Yo os he entregado, como lo había dicho á Moisés, todo lugar que pisare la planta de vuestro pie.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 1, 4, 'Desde el desierto y este Líbano hasta el gran río Eufrates, toda la tierra de los Hetheos hasta la gran mar del poniente del sol, será vuestro término.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 1, 5, 'Nadie te podrá hacer frente en todos los días de tu vida: como yo fuí con Moisés, seré contigo; no te dejaré, ni te desampararé.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 1, 6, 'Esfuérzate y sé valiente: porque tú repartirás á este pueblo por heredad la tierra, de la cual juré á sus padres que la daría á ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 1, 7, 'Solamente te esfuerces, y seas muy valiente, para cuidar de hacer conforme á toda la ley que mi siervo Moisés te mandó: no te apartes de ella ni á diestra ni á siniestra, para que seas prosperado en todas las cosas que emprendieres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 1, 8, 'El libro de aquesta ley nunca se apartará de tu boca: antes de día y de noche meditarás en él, para que guardes y hagas conforme á todo lo que en él está escrito: porque entonces harás prosperar tu camino, y todo te saldrá bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 1, 9, 'Mira que te mando que te esfuerces y seas valiente: no temas ni desmayes, porque Jehová tu Dios será contigo en donde quiera que fueres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 1, 10, 'Y Josué mandó á los oficiales del pueblo, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 1, 11, 'Pasad por medio del campo, y mandad al pueblo, diciendo: Preveníos de comida; porque dentro de tres días pasaréis el Jordán, para que entréis á poseer la tierra que Jehová vuestro Dios os da para que la poseáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 1, 12, 'También habló Josué á los Rubenitas y Gaditas, y á la media tribu de Manasés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 1, 13, 'Acordaos de la palabra que Moisés, siervo de Jehová, os mandó diciendo: Jehová vuestro Dios os ha dado reposo, y os ha dado esta tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 1, 14, 'Vuestras mujeres y vuestros niños y vuestras bestias, quedarán en la tierra que Moisés os ha dado de esta parte del Jordán; mas vosotros, todos los valientes y fuertes, pasaréis armados delante de vuestros hermanos, y les ayudaréis;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 1, 15, 'Hasta tanto que Jehová haya dado reposo á vuestros hermanos como á vosotros, y que ellos también posean la tierra que Jehová vuestro Dios les da: y después volveréis vosotros á la tierra de vuestra herencia, la cual Moisés siervo de Jehová os ha dado, de esta parte del Jordán hacia donde nace el sol; y la poseeréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 1, 16, 'Entonces respondieron á Josué, diciendo: Nosotros haremos todas las cosas que nos has mandado, é iremos adonde quiera que nos mandares.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 1, 17, 'De la manera que obedecimos á Moisés en todas las cosas, así te obedeceremos á ti: solamente Jehová tu Dios sea contigo, como fué con Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 1, 18, 'Cualquiera que fuere rebelde á tu mandamiento, y no obedeciere á tus palabras en todas las cosas que le mandares, que muera; solamente que te esfuerces, y seas valiente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 2, 1, 'Y JOSUÉ, hijo de Nun, envió desde Sittim dos espías secretamente, diciéndoles: Andad, reconoced la tierra, y á Jericó. Los cuales fueron, y entráronse en casa de una mujer ramera que se llamaba Rahab, y posaron allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 2, 2, 'Y fué dado aviso al rey de Jericó, diciendo: He aquí que hombres de los hijos de Israel han venido aquí esta noche á espiar la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 2, 3, 'Entonces el rey de Jericó, envió á decir á Rahab: Saca fuera los hombres que han venido á ti, y han entrado en tu casa; porque han venido á espiar toda la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 2, 4, 'Mas la mujer había tomado los dos hombres, y los había escondido; y dijo: Verdad que hombres vinieron á mí, mas no supe de dónde eran:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 2, 5, 'Y al cerrarse la puerta, siendo ya oscuro, esos hombres se salieron, y no sé á dónde se han ido: seguidlos apriesa, que los alcanzaréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 2, 6, 'Mas ella los había hecho subir al terrado, y habíalos escondido entre tascos de lino que en aquel terrado tenía puestos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 2, 7, 'Y los hombres fueron tras ellos por el camino del Jordán, hasta los vados: y la puerta fué cerrada después que salieron los que tras ellos iban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 2, 8, 'Mas antes que ellos durmiesen, ella subió á ellos al terrado, y díjoles:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 2, 9, 'Sé que Jehová os ha dado esta tierra; porque el temor de vosotros ha caído sobre nosotros, y todos los moradores del país están desmayados por causa de vosotros;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 2, 10, 'Porque hemos oído que Jehová hizo secar las aguas del mar Bermejo delante de vosotros, cuando salisteis de Egipto, y lo que habéis hecho á los dos reyes de los Amorrheos que estaban de la parte allá del Jordán, á Sehón y á Og, á los cuales habéis destruído.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 2, 11, 'Oyendo esto, ha desmayado nuestro corazón; ni ha quedado más espíritu en alguno por causa de vosotros: porque Jehová vuestro Dios es Dios arriba en los cielos y abajo en la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 2, 12, 'Ruégoos pues ahora, me juréis por Jehová, que como he hecho misericordia con vosotros, así la haréis vosotros con la casa de mi padre, de lo cual me daréis una señal cierta;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 2, 13, 'Y que salvaréis la vida á mi padre y á mi madre, y á mis hermanos y hermanas, y á todo lo que es suyo; y que libraréis nuestras vidas de la muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 2, 14, 'Y ellos le respondieron: Nuestra alma por vosotros hasta la muerte, si no denunciareis este nuestro negocio: y cuando Jehová nos hubiere dado la tierra, nosotros haremos contigo misericordia y verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 2, 15, 'Entonces ella los hizo descender con una cuerda por la ventana; porque su casa estaba á la pared del muro, y ella vivía en el muro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 2, 16, 'Y díjoles: Marchaos al monte, porque los que fueron tras vosotros no os encuentren; y estad escondidos allí tres días, hasta que los que os siguen hayan vuelto; y después os iréis vuestro camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 2, 17, 'Y ellos le dijeron: Nosotros seremos desobligados de este juramento con que nos has conjurado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 2, 18, 'He aquí, cuando nosotros entráremos en la tierra, tú atarás este cordón de grana á la ventana por la cual nos descolgaste: y tú juntarás en tu casa tu padre y tu madre, tus hermanos y toda la familia de tu padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 2, 19, 'Cualquiera que saliere fuera de las puertas de tu casa, su sangre será sobre su cabeza, y nosotros sin culpa. Mas cualquiera que se estuviere en casa contigo, su sangre será sobre nuestra cabeza, si mano le tocare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 2, 20, 'Y si tú denunciares este nuestro negocio, nosotros seremos desobligados de este tu juramento con que nos has juramentado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 2, 21, 'Y ella respondió: Sea así como habéis dicho. Luego los despidió, y se fueron: y ella ató el cordón de grana á la ventana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 2, 22, 'Y caminando ellos, llegaron al monte, y estuvieron allí tres días, hasta que los que los seguían se hubiesen vuelto: y los que los siguieron, buscaron por todo el camino, mas no los hallaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 2, 23, 'Y tornándose los dos varones, descendieron del monte, y pasaron, y vinieron á Josué hijo de Nun, y contáronle todas las cosas que les habían acontecido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 2, 24, 'Y dijeron á Josué: Jehová ha entregado toda la tierra en nuestras manos; y también todos los moradores del país están desmayados delante de nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 3, 1, 'Y LEVANTOSE Josué de mañana, y partieron de Sittim, y vinieron hasta el Jordán, él y todos los hijos de Israel, y reposaron allí antes que pasasen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 3, 2, 'Y pasados tres días, los oficiales atravesaron por medio del campo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 3, 3, 'Y mandaron al pueblo, diciendo: Cuando viereis el arca del pacto de Jehová vuestro Dios, y los sacerdotes y Levitas que la llevan, vosotros partiréis de vuestro lugar, y marcharéis en pos de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 3, 4, 'Empero entre vosotros y ella haya distancia como de la medida de dos mil codos: y no os acercaréis á ella, á fin de que sepáis el camino por donde habéis de ir: por cuanto vosotros no habéis pasado antes de ahora por este camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 3, 5, 'Y Josué dijo al pueblo: Santificaos, porque Jehová hará mañana entre vosotros maravillas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 3, 6, 'Y habló Josué á los sacerdotes, diciendo: Tomad el arca del pacto, y pasad delante del pueblo. Y ellos tomaron el arca del pacto, y fueron delante del pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 3, 7, 'Entonces Jehová dijo á Josué: Desde aqueste día comenzaré á hacerte grande delante de los ojos de todo Israel, para que entiendan que como fuí con Moisés, así seré contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 3, 8, 'Tú, pues, mandarás á los sacerdotes que llevan el arca del pacto, diciendo: Cuando hubiereis entrado hasta el borde del agua del Jordán, pararéis en el Jordán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 3, 9, 'Y Josué dijo á los hijos de Israel: Llegaos acá, y escuchad las palabras de Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 3, 10, 'Y añadió Josué: En esto conoceréis que el Dios viviente está en medio de vosotros, y que él echará de delante de vosotros al Cananeo, y al Heteo, y al Heveo, y al Pherezeo, y al Gergeseo, y al Amorrheo, y al Jebuseo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 3, 11, 'He aquí, el arca del pacto del Señoreador de toda la tierra pasa el Jordán delante de vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 3, 12, 'Tomad, pues, ahora doce hombres de las tribus de Israel, de cada tribu uno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 3, 13, 'Y cuando las plantas de los pies de los sacerdotes que llevan el arca de Jehová Señoreador de toda la tierra, fueren asentadas sobre las aguas del Jordán, las aguas del Jordán se partirán: porque las aguas que vienen de arriba se detendrán en un montón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 3, 14, 'Y aconteció, que partiendo el pueblo de sus tiendas para pasar el Jordán, y los sacerdotes delante del pueblo llevando el arca del pacto,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 3, 15, 'Cuando los que llevaban el arca entraron en el Jordán, así como los pies de los sacerdotes que llevaban el arca fueron mojados á la orilla del agua, (porque el Jordán suele reverter sobre todos sus bordes todo el tiempo de la siega,)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 3, 16, 'Las aguas que venían de arriba, se pararon como en un montón bien lejos de la ciudad de Adam, que está al lado de Sarethán; y las que descendían á la mar de los llanos, al mar Salado, se acabaron y fueron partidas; y el pueblo pasó en derecho de Jericó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 3, 17, 'Mas los sacerdotes que llevaban el arca del pacto de Jehová, estuvieron en seco, firmes en medio del Jordán, hasta que todo el pueblo hubo acabado de pasar el Jordán; y todo Israel pasó en seco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 4, 1, 'Y CUANDO toda la gente hubo acabado de pasar el Jordán, Jehová habló á Josué, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 4, 2, 'Tomad del pueblo doce hombres, de cada tribu uno,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 4, 3, 'Y mandadles, diciendo: Tomaos de aquí del medio del Jordán, del lugar donde están firmes los pies de los sacerdotes, doce piedras, las cuales pasaréis con vosotros, y las asentaréis en el alojamiento donde habéis de tener la noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 4, 4, 'Entonces Josué llamó á los doce hombres, los cuales había él ordenado de entre los hijos de Israel, de cada tribu uno;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 4, 5, 'Y díjoles Josué: Pasad delante del arca de Jehová vuestro Dios al medio del Jordán; y cada uno de vosotros tome una piedra sobre su hombro, conforme al número de las tribus de los hijos de Israel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 4, 6, 'Para que esto sea señal entre vosotros; y cuando vuestros hijos preguntaren á sus padres mañana, diciendo: ¿Qué os significan estas piedras?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 4, 7, 'Les responderéis: Que las aguas del Jordán fueron partidas delante del arca del pacto de Jehová; cuando ella pasó el Jordán, las aguas del Jordán se partieron: y estas piedras serán por memoria á los hijos de Israel para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 4, 8, 'Y los hijos de Israel lo hicieron así como Josué les mandó: que levantaron doce piedras del medio del Jordán, como Jehová lo había dicho á Josué, conforme al número de las tribus de los hijos de Israel, y pasáronlas consigo al alojamiento, y las asentaron allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 4, 9, 'Josué también levantó doce piedras en medio del Jordán, en el lugar donde estuvieron los pies de los sacerdotes que llevaban el arca del pacto; y han estado allí hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 4, 10, 'Y los sacerdotes que llevaban el arca se pararon en medio del Jordán, hasta tanto que se acabó todo lo que Jehová había mandado á Josué que hablase al pueblo, conforme á todas las cosas que Moisés había á Josué mandado: y el pueblo se dió priesa y pasó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 4, 11, 'Y cuando todo el pueblo acabó de pasar, pasó también el arca de Jehová, y los sacerdotes, en presencia del pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 4, 12, 'También los hijos de Rubén y los hijos de Gad, y la media tribu de Manasés, pasaron armados delante de los hijos de Israel, según Moisés les había dicho:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 4, 13, 'Como cuarenta mil hombres armados á punto pasaron hacia la campiña de Jericó delante de Jehová á la guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 4, 14, 'En aquel día Jehová engrandeció á Josué en ojos de todo Israel: y temiéronle, como habían temido á Moisés, todos los días de su vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 4, 15, 'Y Jehová habló á Josué, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 4, 16, 'Manda á los sacerdotes que llevan el arca del testimonio, que suban del Jordán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 4, 17, 'Y Josué mandó á los sacerdotes, diciendo: Subid del Jordán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 4, 18, 'Y aconteció que como los sacerdotes que llevaban el arca del pacto de Jehová, subieron del medio del Jordán, y las plantas de los pies de los sacerdotes estuvieron en seco, las aguas del Jordán se volvieron á su lugar, á su lugar, fkbcorriendo como antes sobre todos sus bordes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 4, 19, 'Y el pueblo subió del Jordán el diez del mes primero, y asentaron el campo en Gilgal, al lado oriental de Jericó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 4, 20, 'Y Josué erigió en Gilgal las doce piedras que habían traído del Jordán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 4, 21, 'Y habló á los hijos de Israel, diciendo: Cuando mañana preguntaren vuestros hijos á sus padres, y dijeren: ¿Qué os significan estas piedras?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 4, 22, 'Declararéis á vuestros hijos, diciendo: Israel pasó en seco por este Jordán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 4, 23, 'Porque Jehová vuestro Dios secó las aguas del Jordán delante de vosotros, hasta que habíais pasado, á la manera que Jehová vuestro Dios lo había hecho en el mar Bermejo, al cual secó delante de nosotros hasta que pasamos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 4, 24, 'Para que todos los pueblos de la tierra conozcan la mano de Jehová, que es fuerte; para que temáis á Jehová vuestro Dios todos los días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 5, 1, 'Y CUANDO todos los reyes de los Amorrheos, que estaban de la otra parte del Jordán al occidente, y todos los reyes de los Cananeos, que estaban cerca de la mar, oyeron como Jehová había secado las aguas del Jordán delante de los hijos de Israel hasta que hubieron pasado, desfalleció su corazón, y no hubo más espíritu en ellos delante de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 5, 2, 'En aquel tiempo Jehová dijo á Josué: Hazte cuchillos afilados, y vuelve á circuncidar la segunda vez á los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 5, 3, 'Y Josué se hizo cuchillos afilados, y circuncidó á los hijos de Israel en el monte de los prepucios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 5, 4, 'Esta es la causa por la cual Josué los circuncidó: todo el pueblo que había salido de Egipto, los varones, todos los hombres de guerra, habían muerto en el desierto por el camino, después que salieron de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 5, 5, 'Porque todos los del pueblo que habían salido, estaban circuncidados: mas todo el pueblo que había nacido en el desierto por el camino, después que salieron de Egipto, no estaban circuncidados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 5, 6, 'Porque los hijos de Israel anduvieron por el desierto cuarenta años, hasta que toda la gente de los hombres de guerra que habían salido de Egipto, fué consumida, por cuanto no obedecieron á la voz de Jehová; por lo cual Jehová les juró que no les dejaría ver la tierra, de la cual Jehová había jurado á sus padres que nos la daría, tierra que fluye leche y miel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 5, 7, 'Y los hijos de ellos, que él había hecho suceder en su lugar, Josué los circuncidó; pues eran incircuncisos, porque no habían sido circuncidados por el camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 5, 8, 'Y cuando hubieron acabado de circuncidar toda la gente, quedáronse en el mismo lugar en el campo, hasta que sanaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 5, 9, 'Y Jehová dijo á Josué: Hoy he quitado de vosotros el oprobio de Egipto: por lo cual el nombre de aquel lugar fué llamado Gilgal, hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 5, 10, 'Y los hijos de Israel asentaron el campo en Gilgal, y celebraron la pascua á los catorce días del mes, por la tarde, en los llanos de Jericó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 5, 11, 'Y al otro día de la pascua comieron del fruto de la tierra los panes sin levadura, y en el mismo día espigas nuevas tostadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 5, 12, 'Y el maná cesó el día siguiente, desde que comenzaron á comer del fruto de la tierra: y los hijos de Israel nunca más tuvieron maná, sino que comieron de los frutos de la tierra de Canaán aquel año.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 5, 13, 'Y estando Josué cerca de Jericó, alzó sus ojos, y vió un varón que estaba delante de él, el cual tenía una espada desnuda en su mano. Y Josué yéndose hacia él, le dijo: ¿Eres de los nuestros, ó de nuestros enemigos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 5, 14, 'Y él respondió: No; mas Príncipe del ejército de Jehová, ahora he venido. Entonces Josué postrándose sobre su rostro en tierra le adoró; y díjole: ¿Qué dice mi Señor á su siervo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 5, 15, 'Y el Príncipe del ejército de Jehová repondió á Josué: Quita tus zapatos de tus pies; porque el lugar donde estás es santo. Y Josué lo hizo así.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 6, 1, 'EMPERO Jericó estaba cerrada, bien cerrada, á causa de los hijos de Israel: nadie entraba, ni salía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 6, 2, 'Mas Jehová dijo á Josué: Mira, yo he entregado en tu mano á Jericó y á su rey, con sus varones de guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 6, 3, 'Cercaréis pues la ciudad todos los hombres de guerra, yendo alrededor de la ciudad una vez: y esto haréis seis días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 6, 4, 'Y siete sacerdotes llevarán siete bocinas de cuernos de carneros delante del arca; y al séptimo día daréis siete vueltas á la ciudad, y los sacerdotes tocarán las bocinas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 6, 5, 'Y cuando tocaren prolongadamente el cuerno de carnero, así que oyereis el sonido de la bocina, todo el pueblo gritará á gran voz, y el muro de la ciudad caerá debajo de sí: entonces el pueblo subirá cada uno en derecho de sí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 6, 6, 'Y llamando Josué hijo de Nun á los sacerdotes, les dijo: Llevad el arca del pacto, y siete sacerdotes lleven bocinas de cuernos de carneros delante del arca de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 6, 7, 'Y dijo al pueblo: Pasad, y rodead la ciudad; y los que están armados pasarán delante del arca de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 6, 8, 'Y así que Josué hubo hablado al pueblo, los siete sacerdotes, llevando las siete bocinas de cuernos de carneros, pasaron delante del arca de Jehová, y tocaron las bocinas: y el arca del pacto de Jehová los seguía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 6, 9, 'Y los armados iban delante de los sacerdotes que tocaban las bocinas, y la gente reunida iba detrás del arca, andando y tocando bocinas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 6, 10, 'Y Josué mandó al pueblo, diciendo: Vosotros no daréis grita, ni se oirá vuestra voz, ni saldrá palabra de vuestra boca, hasta el día que yo os diga: Gritad: entonces daréis grita.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 6, 11, 'El arca pues de Jehová dió una vuelta alrededor de la ciudad, y viniéronse al real, en el cual tuvieron la noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 6, 12, 'Y Josué se levantó de mañana, y los sacerdotes tomaron el arca de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 6, 13, 'Y los siete sacerdotes, llevando las siete bocinas de cuernos de carneros, fueron delante del arca de Jehová, andando siempre y tocando las bocinas; y los armados iban delante de ellos, y la gente reunida iba detrás del arca de Jehová, andando y tocando las bocinas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 6, 14, 'Así dieron otra vuelta á la ciudad el segundo día, y volviéronse al real: de esta manera hicieron por seis días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 6, 15, 'Y al séptimo día levantáronse cuando subía el alba, y dieron vuelta á la ciudad de la misma manera siete veces: solamente este día dieron vuelta alrededor de ella siete veces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 6, 16, 'Y como los sacerdotes hubieron tocado las bocinas la séptima vez, Josué dijo al pueblo: Dad grita, porque Jehová os ha entregado la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 6, 17, 'Mas la ciudad será anatema á Jehová, ella con todas las cosas que están en ella: solamente Rahab la ramera vivirá, con todos los que estuvieren en casa con ella, por cuanto escondió los mensajeros que enviamos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 6, 18, 'Empero guardaos vosotros del anatema, que ni toquéis, ni toméis alguna cosa del anatema, porque no hagáis anatema el campo de Israel, y lo turbéis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 6, 19, 'Mas toda la plata, y el oro, y vasos de metal y de hierro, sea consagrado á Jehová, y venga al tesoro de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 6, 20, 'Entonces el pueblo dió grita, y los sacerdotes tocaron las bocinas: y aconteció que como el pueblo hubo oído el sonido de la bocina, dió el pueblo grita con gran vocerío, y el muro cayó á plomo. El pueblo subió luego á la ciudad, cada uno en derecho de sí, y tomáronla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 6, 21, 'Y destruyeron todo lo que en la ciudad había; hombres y mujeres, mozos y viejos, hasta los bueyes, y ovejas, y asnos, á filo de espada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 6, 22, 'Mas Josué dijo á los dos hombres que habían reconocido la tierra: Entrad en casa de la mujer ramera, y haced salir de allá á la mujer, y á todo lo que fuere suyo, como lo jurasteis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 6, 23, 'Y los mancebos espías entraron, y sacaron á Rahab, y á su padre, y á su madre, y á sus hermanos, y todo lo que era suyo; y también sacaron á toda su parentela, y pusiéronlos fuera del campo de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 6, 24, 'Y consumieron con fuego la ciudad, y todo lo que en ella había: solamente pusieron en el tesoro de la casa de Jehová la plata, y el oro, y los vasos de metal y de hierro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 6, 25, 'Mas Josué salvó la vida á Rahab la ramera, y á la casa de su padre, y á todo lo que ella tenía: y habitó ella entre los Israelitas hasta hoy; por cuanto escondió los mensajeros que Josué envió á reconocer á Jericó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 6, 26, 'Y en aquel tiempo Josué les juramentó diciendo: Maldito delante de Jehová el hombre que se levantare y reedificare esta ciudad de Jericó. En su primogénito eche sus cimientos, y en su menor asiente sus puertas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 6, 27, 'Fué pues Jehová con Josué, y su nombre se divulgó por toda la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 7, 1, 'EMPERO los hijos de Israel cometieron prevaricación en el anatema: porque Achân, hijo de Carmi, hijo de Zabdi, hijo de Zera, de la tribu de Judá, tomó del anatema; y la ira de Jehová se encendió contra los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 7, 2, 'Y Josué envió hombres desde Jericó á Hai, que estaba junto á Beth-aven hacia el oriente de Beth-el; y hablóles diciendo: Subid, y reconoced la tierra. Y ellos subieron, y reconocieron á Hai.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 7, 3, 'Y volviendo á Josué, dijéronle: No suba todo el pueblo, mas suban como dos mil ó como tres mil hombre, y tomarán á Hai: no fatigues á todo el pueblo allí, porque son pocos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 7, 4, 'Y subieron allá del pueblo como tres mil hombres, los cuales huyeron delante de los de Hai.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 7, 5, 'Y los de Hai hirieron de ellos como treinta y seis hombre, y siguiéronlos desde la puerta hasta Sebarim, y los rompieron en la bajada: por lo que se disolvió el corazón del pueblo, y vino á ser como agua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 7, 6, 'Entonces Josué rompió sus vestidos, y postróse en tierra sobre su rostro delante del arca de Jehová hasta la tarde, él y los ancianos de Israel; y echaron polvo sobre sus cabezas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 7, 7, 'Y Josué dijo: ¡Ah, Señor Jehová! ¿Por qué hiciste pasar á este pueblo el Jordán, para entregarnos en las manos de los Amorrheos, que nos destruyan? ¡Ojalá nos hubiéramos quedado de la otra parte del Jordán!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 7, 8, '¡Ay Señor! ¿qué diré, ya que Israel ha vuelto las espaldas delante de sus enemigos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 7, 9, 'Porque los Cananeos y todos los moradores de la tierra oirán, y nos cercarán, y raerán nuestro nombre de sobre la tierra: entonces ¿qué harás tú á tu grande nombre?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 7, 10, 'Y Jehová dijo á Josué: Levántate; ¿por qué te postras así sobre tu rostro?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 7, 11, 'Israel ha pecado, y aun han quebrantado mi pacto que yo les había mandado; pues aun han tomado del anatema, y hasta han hurtado, y también han mentido, y aun lo han guardado entre sus enseres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 7, 12, 'Por esto los hijos de Israel no podrán estar delante de sus enemigos, sino que delante de sus enemigos volverán las espaldas; por cuanto han venido á ser anatema: ni seré más con vosotros, si no destruyereis el anatema de en medio de vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 7, 13, 'Levántate, santifica al pueblo, y di: Santificaos para mañana, porque Jehová el Dios de Israel dice así: Anatema hay en medio de ti, Israel; no podrás estar delante de tus enemigos, hasta tanto que hayáis quitado el anatema de en medio de vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 7, 14, 'Os allegaréis, pues, mañana por vuestras tribus; y la tribu que Jehová tomare, se allegará por sus familias; y la familia que Jehová tomare, se allegará por sus casas; y la casa que Jehová tomare, allegaráse por los varones;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 7, 15, 'Y el que fuere cogido en el anatema, será quemado á fuego, él y todo lo que tiene, por cuanto ha quebrantado el pacto de Jehová, y ha cometido maldad en Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 7, 16, 'Josué, pues, levantándose de mañana, hizo allegar á Israel por sus tribus; y fué tomada la tribu de Judá;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 7, 17, 'Y haciendo allegar la tribu de Judá, fué tomada la familia de los de Zera; haciendo luego allegar la familia de los de Zera por los varones, fué tomado Zabdi;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 7, 18, 'E hizo allegar su casa por los varones, y fué tomado Achân, hijo de Carmi, hijo de Zabdi, hijo de Zera, de la tribu de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 7, 19, 'Entonces Josué dijo á Achân: Hijo mío, da gloria ahora á Jehová el Dios de Israel, y dale alabanza, y declárame ahora lo que has hecho; no me lo encubras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 7, 20, 'Y Achân respondió á Josué, diciendo: Verdaderamente yo he pecado contra Jehová el Dios de Israel, y he hecho así y así:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 7, 21, 'Que vi entre los despojos un manto babilónico muy bueno, y doscientos siclos de plata, y un changote de oro de peso de cincuenta siclos; lo cual codicié, y tomé: y he aquí que está escondido debajo de tierra en el medio de mi tienda, y el dinero debajo de ello.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 7, 22, 'Josué entonces envió mensajeros, los cuales fueron corriendo á la tienda; y he aquí estaba escondido en su tienda, y el dinero debajo de ello:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 7, 23, 'Y tomándolo de en medio de la tienda, trajéronlo á Josué y á todos los hijos de Israel, y pusiéronlo delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 7, 24, 'Entonces Josué, y todo Israel con él, tomó á Achân hijo de Zera, y el dinero, y el manto, y el changote de oro, y sus hijos, y sus hijas, y sus bueyes, y sus asnos, y sus ovejas, y su tienda, y todo cuanto tenía, y lleváronlo todo al valle de Achôr;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 7, 25, 'Y dijo Josué: ¿Por qué nos has turbado? Túrbete Jehová en este día. Y todos los Israelitas los apedrearon, y los quemaron á fuego, después de apedrearlos con piedras;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 7, 26, 'Y levantaron sobre él un gran montón de piedras, hasta hoy. Y Jehová se tornó de la ira de su furor. Y por esto fué llamado aquel lugar el Valle de Achôr, hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 1, 'Y JEHOVA dijo á Josué: No temas, ni desmayes; toma contigo toda la gente de guerra, y levántate y sube á Hai. Mira, yo he entregado en tu mano al rey de Hai, y á su pueblo, á su ciudad, y á su tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 2, 'Y harás á Hai y á su rey como hiciste á Jericó y á su rey: sólo que sus despojos y sus bestias tomaréis para vosotros. Pondrás, pues, emboscadas á la ciudad detrás de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 3, 'Y levantóse Josué, y toda la gente de guerra, para subir contra Hai: y escogió Josué treinta mil hombres fuertes, los cuales envió de noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 4, 'Y mandóles, diciendo: Mirad, pondréis emboscada á la ciudad detrás de ella: no os alejaréis mucho de la ciudad, y estaréis todos apercibidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 5, 'Y yo, y todo el pueblo que está conmigo, nos acercaremos á la ciudad; y cuando saldrán ellos contra nosotros, como hicieron antes, huiremos delante de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 6, 'Y ellos saldrán tras nosotros, hasta que los arranquemos de la ciudad; porque ellos dirán: Huyen de nosotros como la primera vez. Huiremos, pues, delante de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 7, 'Entonces vosotros os levantaréis de la emboscada, y os echaréis sobre la ciudad; pues Jehová vuestro Dios la entregará en vuestras manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 8, 'Y cuando la hubiereis tomado, le prenderéis fuego. Haréis conforme á la palabra de Jehová. Mirad que os lo he mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 9, 'Entonces Josué los envió; y ellos se fueron á la emboscada, y pusiéronse entre Beth-el y Hai, al occidente de Hai: y Josué se quedó aquella noche en medio del pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 10, 'Y levantándose Josué muy de mañana, revistó al pueblo, y subió él, con los ancianos de Israel, delante del pueblo contra Hai.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 11, 'Y toda la gente de guerra que con él estaba, subió, y acercóse, y llegaron delante de la ciudad, y asentaron el campo á la parte del norte de Hai: y el valle estaba entre él y Hai.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 12, 'Y tomó como cinco mil hombres, y púsolos en emboscada entre Beth-el y Hai, á la parte occidental de la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 13, 'Y el pueblo, todo el campo que estaba á la parte del norte de la ciudad, colocado ya cerca, y su emboscada al occidente de la ciudad, vínose Josué aquella noche al medio del valle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 14, 'Lo cual como viese el rey de Hai, levantóse prestamente de mañana, y salió con la gente de la ciudad contra Israel, él y todo su pueblo, para combatir por el llano al tiempo señalado, no sabiendo que le estaba puesta emboscada á las espaldas de la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 15, 'Entonces Josué y todo Israel, haciéndose vencidos, huyeron delante de ellos por el camino del desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 16, 'Y todo el pueblo que estaba en Hai se juntó para seguirlos: y siguieron á Josué, siendo así arrancados de la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 17, 'Y no quedó hombre en Hai y Beth-el, que no saliera tras de Israel; y por seguir á Israel dejaron la ciudad abierta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 18, 'Entonces Jehová dijo á Josué: Levanta la lanza que tienes en tu mano hacia Hai, porque yo la entregaré en tu mano. Y Josué levantó hacia la ciudad la lanza que en su mano tenía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 19, 'Y levantándose prestamente de su lugar los que estaban en la emboscada, corrieron luego que él alzó su mano, y vinieron á la ciudad, y la tomaron, y apresuráronse á prenderle fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 20, 'Y como los de la ciudad miraron atrás, observaron, y he aquí el humo de la ciudad que subía al cielo, y no tuvieron arbitrio para huir ni á una parte ni á otra: y el pueblo que iba huyendo hacia el desierto, se volvió contra los que le seguían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 21, 'Josué y todo Israel, viendo que los de la emboscada habían tomado la ciudad, y que el humo de la ciudad subía, tornaron, é hirieron á los de Hai.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 22, 'Y los otros salieron de la ciudad á su encuentro: y así fueron encerrados en medio de Israel, los unos de la una parte, y los otros de la otra. Y los hirieron hasta que no quedó ninguno de ellos que escapase.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 23, 'Y tomaron vivo al rey de Hai, y trajéronle á Josué.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 24, 'Y cuando los Israelitas acabaron de matar á todos los moradores de Hai en el campo, en el desierto, donde ellos los habían perseguido, y que todos habían caído á filo de espada hasta ser consumidos, todos los Israelitas se tornaron á Hai, y también la pusieron á cuchillo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 25, 'Y el número de los que cayeron aquel día, hombres y mujeres, fué doce mil, todos los de Hai.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 26, 'Y Josué no retrajo su mano que había extendido con la lanza, hasta que hubo destruído á todos los moradores de Hai.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 27, 'Empero los Israelitas tomaron para sí las bestias y los despojos de la ciudad, conforme á la palabra de Jehová que él había mandado á Josué.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 28, 'Y Josué quemó á Hai y redújola á un montón perpetuo, asolado hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 29, 'Mas al rey de Hai colgó de un madero hasta la tarde: y como el sol se puso, mandó Josué que quitasen del madero su cuerpo, y lo echasen á la puerta de la ciudad: y levantaron sobre él un gran montón de piedras, hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 30, 'Entonces Josué edificó un altar á Jehová Dios de Israel en el monte de Ebal,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 31, 'Como Moisés, siervo de Jehová, lo había mandado á los hijos de Israel, como está escrito en el libro de la ley de Moisés, un altar de piedras enteras sobre las cuales nadie alzó hierro: y ofrecieron sobre él holocaustos á Jehová, y sacrificaron víctimas pacíficas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 32, 'También escribió allí en piedras la repetición de la ley de Moisés, la cual él había escrito delante de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 33, 'Y todo Israel, y sus ancianos, oficiales, y jueces, estaban de la una y de la otra parte junto al arca, delante de los sacerdotes Levitas que llevan el arca del pacto de Jehová; así extranjeros como naturales, la mitad de ellos estaba hacia el monte de Gerizim, y la otra mitad hacia el monte de Ebal; de la manera que Moisés, siervo de Jehová, lo había mandado antes, para que bendijesen primeramente al pueblo de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 34, 'Después de esto, leyó todas las palabras de la ley, las bendiciones y las maldiciones, conforme á todo lo que está escrito en el libro de la ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 8, 35, 'No hubo palabra alguna de todas las cosas que mandó Moisés, que Josué no hiciese leer delante de toda la congregación de Israel, mujeres y niños, y extranjeros que andaban entre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 9, 1, 'Y ACONTECIO que como oyeron estas cosas todos los reyes que estaban de esta parte del Jordán, así en las montañas como en los llanos, y en toda la costa de la gran mar delante del Líbano, los Hetheos, Amorrheos, Cananeos, Pherezeos, Heveos, y Jebuseos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 9, 2, 'Juntáronse á una, de un acuerdo, para pelear contra Josué é Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 9, 3, 'Mas los moradores de Gabaón, como oyeron lo que Josué había hecho á Jericó y á Hai,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 9, 4, 'Ellos usaron también de astucia; pues fueron y fingiéronse embajadores, y tomaron sacos viejos sobre sus asnos, y cueros viejos de vino, rotos y remendados,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 9, 5, 'Y zapatos viejos y recosidos en sus pies, con vestidos viejos sobre sí; y todo el pan que traían para el camino, seco y mohoso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 9, 6, 'Así vinieron á Josué al campo en Gilgal, y dijéronle á él y á los de Israel: Nosotros venimos de tierra muy lejana: haced pues ahora con nosotros alianza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 9, 7, 'Y los de Israel respondieron á los Heveos: Quizás vosotros habitáis en medio de nosotros: ¿cómo pues podremos nosotros hacer alianza con vosotros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 9, 8, 'Y ellos respondieron á Josué: Nosotros somos tus siervos. Y Josué les dijo: ¿Quién sois vosotros y de dónde venís?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 9, 9, 'Y ellos respondieron: Tus siervos han venido de muy lejanas tierras, por la fama de Jehová tu Dios; porque hemos oído su fama, y todas las cosas que hizo en Egipto,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 9, 10, 'Y todo lo que hizo á los dos reyes de los Amorrheos que estaban de la otra parte del Jordán; á Sehón rey de Hesbón, y á Og rey de Basán, que estaba en Astaroth.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 9, 11, 'Por lo cual nuestros ancianos y todos los moradores de nuestra tierra nos dijeron: Tomad en vuestras manos provisión para el camino, é id al encuentro de ellos, y decidles: Nosotros somos vuestros siervos, y haced ahora con nosotros alianza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 9, 12, 'Este nuestro pan tomamos caliente de nuestras casas para el camino el día que salimos para venir á vosotros; y helo aquí ahora que está seco y mohoso:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 9, 13, 'Estos cueros de vino también los henchimos nuevos; helos aquí ya rotos: también estos nuestros vestidos y nuestros zapatos están ya viejos á causa de lo muy largo del camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 9, 14, 'Y los hombres de Israel tomaron de su provisión del camino, y no preguntaron á la boca de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 9, 15, 'Y Josué hizo paz con ellos, y concertó con ellos que les dejaría la vida: también los príncipes de la congregación les juraron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 9, 16, 'Pasados tres días después que hicieron con ellos el concierto, oyeron como eran sus vecinos, y que habitaban en medio de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 9, 17, 'Y partiéronse los hijos de Israel, y al tercer día llegaron á sus ciudades: y sus ciudades eran Gabaón, Caphira, Beeroth, y Chiriath-jearim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 9, 18, 'Y no los hirieron los hijos de Israel, por cuanto los príncipes de la congregación les habían jurado por Jehová el Dios de Israel. Y toda la congregación murmuraba contra los príncipes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 9, 19, 'Mas todos los príncipes respondieron á toda la congregación: Nosotros les hemos jurado por Jehová Dios de Israel; por tanto, ahora no les podemos tocar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 9, 20, 'Esto haremos con ellos: les dejaremos vivir, porque no venga ira sobre nosotros á causa del juramento que les hemos hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 9, 21, 'Y los príncipes les dijeron: Vivan; mas sean leñadores y aguadores para toda la congregación, como los príncipes les han dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 9, 22, 'Y llamándolos Josué, les habló diciendo: ¿Por qué nos habéis engañado, diciendo, Habitamos muy lejos de vosotros; una vez que moráis en medio de nosotros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 9, 23, 'Vosotros pues ahora sois malditos, y no faltará de vosotros siervo, y quien corte la leña y saque el agua para la casa de mi Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 9, 24, 'Y ellos respondieron á Josué, y dijeron: Como fué dado á entender á tus siervos, que Jehová tu Dios había mandado á Moisés su siervo que os había de dar toda la tierra, y que había de destruir todos los moradores de la tierra delante de vosotros, por esto temimos en gran manera de vosotros por nuestras vidas, é hicimos esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 9, 25, 'Ahora pues, henos aquí en tu mano: lo que te pareciere bueno y recto hacer de nosotros, hazlo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 9, 26, 'Y él lo hizo así; que los libró de la mano de los hijos de Israel, para que no los matasen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 9, 27, 'Y constituyólos Josué aquel día por leñadores y aguadores para la congregación y para el altar de Jehová, en el lugar que él escogiese: lo que son hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 1, 'Y COMO Adonisedec rey de Jerusalem oyó que Josué había tomado á Hai, y que la habían asolado, (como había hecho á Jericó y á su rey, así hizo á Hai y á su rey;) y que los moradores de Gabaón habían hecho paz con los Israelitas, y que estaban entre ellos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 2, 'Tuvieron muy gran temor; porque Gabaón era una gran ciudad, como una de las ciudades reales, y mayor que Hai, y todos sus hombres fuertes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 3, 'Envió pues á decir Adonisedec rey de Jerusalem, á Oham rey de Hebrón, y á Phiream rey de Jerimoth, y á Japhia rey de Lachîs, y á Debir rey de Eglón:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 4, 'Subid á mí, y ayudadme, y combatamos á Gabaón: porque ha hecho paz con Josué y con los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 5, 'Y cinco reyes de los Amorrheos, el rey de Jerusalem, el rey de Hebrón, el rey de Jerimoth, el rey de Lachîs, el rey de Eglón, se juntaron y subieron, ellos con todos sus ejércitos, y asentaron campo sobre Gabaón, y pelearon contra ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 6, 'Y los moradores de Gabaón enviaron á decir á Josué al campo en Gilgal: No encojas tus manos de tus siervos; sube prestamente á nosotros para guardarnos y ayudarnos: porque todos los reyes de los Amorrheos que habitan en las montañas, se han juntado contra nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 7, 'Y subió Josué de Gilgal, él y todo el pueblo de guerra con él, y todos los hombres valientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 8, 'Y Jehová dijo á Josué: No tengas temor de ellos: porque yo los he entregado en tu mano, y ninguno de ellos parará delante de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 9, 'Y Josué vino á ellos de repente, toda la noche subió desde Gilgal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 10, 'Y Jehová los turbó delante de Israel, é hiriólos con gran mortandad en Gabaón: y siguiólos por el camino que sube á Beth-oron, é hiriólos hasta Azeca y Maceda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 11, 'Y como iban huyendo de los Israelitas, á la bajada de Beth-oron, Jehová echó sobre ellos del cielo grandes piedras hasta Azeca, y murieron: muchos más murieron de las piedras del granizo, que los que los hijos de Israel habían muerto á cuchillo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 12, 'Entonces Josué habló á Jehová el día que Jehová entregó al Amorrheo delante de los hijos de Israel, y dijo en presencia de los Israelitas: Sol, detente en Gabaón; Y tú, Luna, en el valle de Ajalón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 13, 'Y el sol se detuvo y la luna se paró, Hasta tanto que la gente se hubo vengado de sus enemigos. ¿No está aquesto escrito en el libro de Jasher? Y el sol se paró en medio del cielo, y no se apresuró á ponerse casi un día entero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 14, 'Y nunca fué tal día antes ni después de aquél, habiendo atendido Jehová á la voz de un hombre: porque Jehová peleaba por Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 15, 'Y Josué, y todo Israel con él, volvíase al campo en Gilgal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 16, 'Pero los cinco reyes huyeron, y se escondieron en una cueva en Maceda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 17, 'Y fué dicho á Josué que los cinco reyes habían sido hallados en una cueva en Maceda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 18, 'Entonces Josué dijo: Rodad grandes piedras á la boca de la cueva, y poned hombres junto á ella que los guarden;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 19, 'Y vosotros no os paréis, sino seguid á vuestros enemigos, y heridles la retaguardia, sin dejarles entrar en sus ciudades; porque Jehová vuestro Dios los ha entregado en vuestra mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 20, 'Y aconteció que como Josué y los hijos de Israel hubieron acabado de herirlos con mortandad muy grande, hasta destruirlos, los que quedaron de ellos se metieron en las ciudades fuertes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 21, 'Y todo el pueblo se volvió salvo al campo á Josué en Maceda; que no hubo quien moviese su lengua contra los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 22, 'Entonces dijo Josué: Abrid la boca de la cueva, y sacadme de ella á estos cinco reyes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 23, 'E hiciéronlo así, y sacáronle de la cueva aquellos cinco reyes: al rey de Jerusalem, al rey de Hebrón, al rey de Jerimoth, al rey de Lachîs, al rey de Eglón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 24, 'Y cuando hubieron sacado estos reyes á Josué, llamó Josué á todos los varones de Israel, y dijo á los principales de la gente de guerra que habían venido con él: Llegad y poned vuestros pies sobre los pescuezos de aquestos reyes. Y ellos se llegaron, y pusieron sus pies sobre los pescuezos de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 25, 'Y Josué les dijo: No temáis, ni os atemoricéis; sed fuertes y valientes: porque así hará Jehová á todos vuestros enemigos contra los cuales peleáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 26, 'Y después de esto Josué los hirió y los mató, é hízolos colgar en cinco maderos: y quedaron colgados en los maderos hasta la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 27, 'Y cuando el sol se iba á poner, mandó Josué que los quitasen de los maderos, y los echasen en la cueva donde se habían escondido: y pusieron grandes piedras á la boca de la cueva, hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 28, 'En aquel mismo día tomó Josué á Maceda, y la puso á cuchillo, y mató á su rey; á ellos y á todo lo que en ella tenía vida, sin quedar nada: mas al rey de Maceda hizo como había hecho al rey de Jericó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 29, 'Y de Maceda pasó Josué, y todo Israel con él, á Libna; y peleó contra Libna:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 30, 'Y Jehová la entregó también á ella, y á su rey, en manos de Israel; y metióla á filo de espada, con todo lo que en ella había vivo, sin quedar nada: mas á su rey hizo de la manera que había hecho al rey de Jericó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 31, 'Y Josué, y todo Israel con él, pasó de Libna á Lachîs, y puso campo contra ella, y combatióla:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 32, 'Y Jehová entregó á Lachîs en mano de Israel, y tomóla al día siguiente, y metióla á cuchillo, con todo lo que en ella había vivo, como había hecho en Libna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 33, 'Entonces Horam, rey de Gezer, subió en ayuda de Lachîs; mas á él y á su pueblo hirió Josué, hasta no quedar ninguno de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 34, 'De Lachîs pasó Josué, y todo Israel con él, á Eglón: y pusieron campo contra ella, y combatiéronla:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 35, 'Y la tomaron el mismo día, y metiéronla á cuchillo; y aquel día mató á todo lo que en ella había vivo, como había hecho en Lachîs.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 36, 'Subió luego Josué, y todo Israel con él, de Eglón á Hebrón, y combatiéronla;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 37, 'Y tomándola, la metieron á cuchillo, á su rey y á todas su ciudades, con todo lo que en ella había vivo, sin quedar nada: como habían hecho á Eglón, así la destruyeron con todo lo que en ella había vivo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 38, 'Y volviéndose Josué, y todo Israel con él, sobre Debir, combatióla;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 39, 'Y tomóla, y á su rey, y á todas sus villas; y metiéronlos á cuchillo, y destruyeron todo lo que allí dentro había vivo, sin quedar nada; como había hecho á Hebrón, así hizo á Debir y á su rey; y como había hecho á Libna y á su rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 40, 'Hirió pues Josué toda la región de las montañas, y del mediodía, y de los llanos, y de las cuestas, y á todos sus reyes, sin quedar nada; todo lo que tenía vida mató, al modo que Jehová Dios de Israel lo había mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 41, 'E hiriólos Josué desde Cades-barnea hasta Gaza, y toda la tierra de Gosén hasta Gabaón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 42, 'Todos estos reyes y sus tierras tomó Josué de una vez; porque Jehová el Dios de Israel peleaba por Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 10, 43, 'Y tornóse Josué, y todo Israel con él, al campo en Gilgal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 11, 1, 'OYENDO esto Jabín rey de Hasor, envió mensaje á Jobab rey de Madón, y al rey de Simrom, y al rey de Achsaph,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 11, 2, 'Y á los reyes que estaban á la parte del norte en las montañas, y en el llano al mediodía de Cinneroth, y en los llanos, y en las regiones de Dor al occidente;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 11, 3, 'Y al Cananeo que estaba al oriente y al occidente, y al Amorrheo, y al Hetheo, y al Pherezeo, y al Jebuseo en las montañas, y al Heveo debajo de Hermón en tierra de Mizpa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 11, 4, 'Estos salieron, y con ellos todos sus ejércitos, pueblo mucho en gran manera, como la arena que está á la orilla del mar, con gran muchedumbre de caballos y carros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 11, 5, 'Todos estos reyes se juntaron, y viniendo reunieron los campos junto á las aguas de Merom, para pelear contra Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 11, 6, 'Mas Jehová dijo á Josué: No tengas temor de ellos, que mañana á esta hora yo entregaré á todos éstos, muertos delante de Israel: á sus caballos desjarretarás, y sus carros quemarás al fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 11, 7, 'Y vino Josué, y con él todo el pueblo de guerra, contra ellos, y dió de repente sobre ellos junto á las aguas de Merom.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 11, 8, 'Y entrególos Jehová en manos de Israel, los cuales los hirieron y siguieron hasta Sidón la grande, y hasta las aguas calientes, y hasta el llano de Mizpa al oriente, hiriéndolos hasta que no les dejaron ninguno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 11, 9, 'Y Josué hizo con ellos como Jehová le había mandado: desjarretó sus caballos, y sus carros quemó al fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 11, 10, 'Y tornándose Josué, tomó en el mismo tiempo á Hasor, é hirió á cuchillo á su rey: la cual Hasor había sido antes cabeza de todos estos reinos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 11, 11, 'E hirieron á cuchillo todo cuanto en ella había vivo, destruyendo y no dejando cosa con vida; y á Asor pusieron á fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 11, 12, 'Asimismo tomó Josué todas las ciudades de aquestos reyes, y á todos los reyes de ellas, y los metió á cuchillo, y los destruyó, como Moisés siervo de Jehová lo había mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 11, 13, 'Empero todas las ciudades que estaban en sus cabezos, no las quemó Israel, sacando á sola Asor, la cual quemó Josué.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 11, 14, 'Y los hijos de Israel tomaron para sí todos los despojos y bestias de aquestas ciudades: pero á todos los hombres metieron á cuchillo hasta destruirlos, sin dejar alguno con vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 11, 15, 'De la manera que Jehová lo había mandado á Moisés su siervo, así Moisés lo mandó á Josué: y así Josué lo hizo, sin quitar palabra de todo lo que Jehová había mandado á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 11, 16, 'Tomó pues Josué toda aquella tierra, las montañas, y toda la región del mediodía, y toda la tierra de Gosén, y los bajos y los llanos, y la montaña de Israel y sus valles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 11, 17, 'Desde el monte de Halac, que sube hasta Seir, hasta Baal-gad en la llanura del Líbano, á las raíces del monte Hermón: tomó asimismo todos sus reyes, los cuales hirió y mató.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 11, 18, 'Por muchos días tuvo guerra Josué con estos reyes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 11, 19, 'No hubo ciudad que hiciese paz con los hijos de Israel, sacados los Heveos, que moraban en Gabaón: todo lo tomaron por guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 11, 20, 'Porque esto vino de Jehová, que endurecía el corazón de ellos para que resistiesen con guerra á Israel, para destruirlos, y que no les fuese hecha misericordia, antes fuesen desarraigados, como Jehová lo había mandado á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 11, 21, 'También en el mismo tiempo vino Josué y destruyó los Anaceos de los montes, de Hebrón, de Debir, y de Anab, y de todos los montes de Judá, y de todos los montes de Israel: Josué los destruyó á ellos y á sus ciudades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 11, 22, 'Ninguno de los Anaceos quedó en la tierra de los hijos de Israel; solamente quedaron en Gaza, en Gath, y en Asdod.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 11, 23, 'Tomó, pues, Josué toda la tierra, conforme á todo lo que Jehová había dicho á Moisés; y entrególa Josué á los Israelitas por herencia, conforme á sus repartimientos de sus tribus: y la tierra reposó de guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 12, 1, 'ESTOS son los reyes de la tierra que los hijos de Israel hirieron, y cuya tierra poseyeron de la otra parte del Jordán al nacimiento del sol, desde el arroyo de Arnón hasta el monte Hermón, y toda la llanura oriental:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 12, 2, 'Sehón rey de los Amorrheos, que habitaba en Hesbón, y señoreaba desde Aroer, que está á la ribera del arroyo de Arnón, y desde en medio del arroyo, y la mitad de Galaad, hasta el arroyo Jaboc, el término de los hijos de Ammón;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 12, 3, 'Y desde la campiña hasta la mar de Cinneroth, al oriente; y hasta la mar de la llanura, el mar Salado, al oriente, por el camino de Beth-jesimoth; y desde el mediodía debajo de las vertientes del Pisga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 12, 4, 'Y los términos de Og rey de Basán, que había quedado de los Rapheos, el cual habitaba en Astaroth y en Edrei,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 12, 5, 'Y señoreaba en el monte de Hermón, y en Salca, y en todo Basán hasta los términos de Gessuri y de Maachâti, y la mitad de Galaad, término de Sehón rey de Hesbón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 12, 6, 'A estos hirieron Moisés siervo de Jehová y los hijos de Israel; y Moisés siervo de Jehová dió aquella tierra en posesión á los Rubenitas, Gaditas, y á la media tribu de Manasés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 12, 7, 'Y estos son los reyes de la tierra que hirió Josué con los hijos de Israel, de esta parte del Jordán al occidente, desde Baal-gad en el llano del Líbano hasta el monte de Halac que sube á Seir; la cual tierra dió Josué en posesión á las tribus de Israel, conforme á sus repartimientos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 12, 8, 'En montes y en valles, en llanos y en vertientes, al desierto y al mediodía; el Hetheo, y el Amorrheo, y el Cananeo, y el Pherezeo, y el Heveo, y el Jebuseo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 12, 9, 'El rey de Jericó, uno: el rey de Hai, que está al lado de Beth-el, otro:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 12, 10, 'El rey de Jerusalem, otro: el rey de Hebrón, otro:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 12, 11, 'El rey de Jarmuth, otro: el rey de Lachîs, otro:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 12, 12, 'El rey de Eglón, otro: el rey de Gezer, otro:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 12, 13, 'El rey de Debir, otro: el rey de Geder, otro:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 12, 14, 'El rey de Horma, otro: el rey de Arad, otro:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 12, 15, 'El rey de Libna, otro: el rey de Adullam, otro:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 12, 16, 'El rey de Maceda, otro: el rey de Beth-el, otro:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 12, 17, 'El rey de Tappua, otro: el rey de Hepher, otro:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 12, 18, 'El rey de Aphec, otro: el rey de Lasarón, otro:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 12, 19, 'El rey de Madón, otro: el rey de Hasor, otro:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 12, 20, 'El rey de Simrom-meron, otro: el rey de Achsaph, otro:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 12, 21, 'El rey de Taanach, otro: el rey de Megiddo, otro:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 12, 22, 'El rey de Chêdes, otro: el rey de Jocneam de Carmel, otro:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 12, 23, 'El rey de Dor, de la provincia de Dor, otro; el rey de Gentes en Gilgal, otro:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 12, 24, 'El rey de Tirsa, otro: treinta y un reyes en todo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 1, 'Y SIENDO Josué ya viejo, entrado en días, Jehová le dijo: Tú eres ya viejo, de edad avanzada, y queda aún muy mucha tierra por poseer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 2, 'Esta es la tierra que queda; todos los términos de los Philisteos, y toda Gessuri;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 3, 'Desde Sihor, que está delante de Egipto, hasta el término de Accarón al norte, repútase de los Cananeos: cinco provincias de los Philisteos; los Gazeos, Asdodios, Ascalonitas, Getheos, y Accaronitas; y los Heveos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 4, 'Al mediodía toda la tierra de los Cananeos, y Mehara que es de los Sidonios, hasta Aphec, hasta el término del Amorrheo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 5, 'Y la tierra de los Gibleos, y todo el Líbano hacia donde sale el sol, desde Baal-gad á las raíces del monte Hermón, hasta entrar en Hamath;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 6, 'Todos los que habitan en las montañas desde el Líbano hasta las aguas calientes, todos los Sidonios; yo los desarraigaré delante de lo hijos de Israel: solamente repartirás tú por suerte el país á los Israelitas por heredad, como te he mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 7, 'Parte, pues, tú ahora esta tierra en heredad á las nueve tribus, y á la media tribu de Manasés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 8, 'Porque la otra media recibió su heredad con los Rubenitas y Gaditas, la cual les dió Moisés de la otra parte del Jordán al oriente, según que se la dió Moisés siervo de Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 9, 'Desde Aroer, que está á la orilla del arroyo de Arnón, y la ciudad que está en medio del arroyo, y toda la campiña de Medeba, hasta Dibón;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 10, 'Y todas las ciudades de Sehón rey de los Amorrheos, el cual reinó en Hesbón, hasta los términos de los hijos de Ammón;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 11, 'Y Galaad, y los términos de Gessuri, y de Maachâti, y todo el monte de Hermón, y toda la tierra de Basán hasta Salchâ:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 12, 'Todo el reino de Og en Basán, el cual reinó en Astaroth y Edrei, el cual había quedado del residuo de los Rapheos; pues Moisés los hirió, y echó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 13, 'Mas á los de Gessuri y Maachâti no echaron los hijos de Israel; antes Gessur y Maachât habitaron entre los Israelitas hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 14, 'Empero á la tribu de Leví no dió heredad: los sacrificios de Jehová Dios de Israel son su heredad, como él les había dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 15, 'Dió, pues, Moisés á la tribu de los hijos de Rubén conforme á sus familias:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 16, 'Y fué el término de ellos desde Aroer, que está á la orilla del arroyo de Arnón, y la ciudad que está en medio del arroyo, y toda la campiña, hasta Medeba;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 17, 'Hesbón, con todas sus villas que están en la llanura; Dibón, y Bamoth-baal, y Beth-baal-meón;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 18, 'Y Jaas, y Keddemoth, y Mephaath,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 19, 'Y Chîriataim, y Sibma, y Zerethshahar en el monte del valle;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 20, 'Y Beth-peor, y Asdoth-pisga, y Beth-jesimoth;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 21, 'Y todas las ciudades de la campiña, y todo el reino de Sehón rey de los Amorrheos, que reinó en Hesbón, al cual hirió Moisés, y á los príncipes de Madián, Hevi, Recem, y Sur, y Hur, y Reba, príncipes de Sehón que habitaban en aquella tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 22, 'También mataron á cuchillo los hijos de Israel á Balaam adivino, hijo de Beor, con los demás que mataron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 23, 'Y fueron los términos de los hijos de Rubén el Jordán con su término. Esta fué la herencia de los hijos de Rubén conforme á sus familias, estas ciudades con sus villas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 24, 'Dió asimismo Moisés á la tribu de Gad, á los hijos de Gad, conforme á sus familias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 25, 'Y el término de ellos fué Jacer, y todas las ciudades de Galaad, y la mitad de la tierra de los hijos de Ammón hasta Aroer, que está delante de Rabba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 26, 'Y desde Hesbón hasta Ramath-mispe, y Betonim; y desde Mahanaim hasta el término de Debir:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 27, 'Y la campiña de Beth-aram, y Beth-nimra, y Sucoth, y Saphón, resto del reino de Sehón, rey en Hesbón: el Jordán y su término hasta el cabo de la mar de Cinnereth de la otra parte del Jordán al oriente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 28, 'Esta es la herencia de los hijos de Gad, por sus familias, estas ciudades con sus villas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 29, 'También dió Moisés herencia á la media tribu de Manasés: y fué de la media tribu de los hijos de Manasés, conforme á sus familias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 30, 'El término de ellos fué desde Mahanaim, todo Basán, todo el reino de Og rey de Basán, y todas las aldeas de Jair que están en Basán, sesenta poblaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 31, 'Dióse además la mitad de Galaad, y Astaroth, y Edrei, ciudades del reino de Og en Basán, á los hijos de Machîr, hijo de Manasés, á la mitad de los hijos de Machîr conforme á sus familias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 32, 'Esto es lo que Moisés repartió en heredad en los llanos de Moab, de la otra parte del Jordán de Jericó, al oriente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 13, 33, 'Mas á la tribu de Leví no dió Moisés heredad: Jehová Dios de Israel es la heredad de ellos como él les había dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 14, 1, 'ESTO pues es lo que los hijos de Israel tomaron por heredad en la tierra de Canaán, lo cual les repartieron Eleazar sacerdote, y Josué hijo de Nun, y los principales de los padres de las tribus de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 14, 2, 'Por suerte dióseles su heredad, como Jehová lo había mandado por Moisés, que diese á las nueve tribus y á la media tribu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 14, 3, 'Porque á las dos tribus, y á la media tribu, les había Moisés dado heredad de la otra parte del Jordán: mas á los Levitas no dió heredad entre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 14, 4, 'Porque los hijos de José fueron dos tribus, Manasés y Ephraim: y no dieron parte á los Levitas en la tierra, sino ciudades en que morasen, con sus ejidos para sus ganados y rebaños.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 14, 5, 'De la manera que Jehová lo había mandado á Moisés, así lo hicieron los hijos de Israel en el repartimiento de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 14, 6, 'Y los hijos de Judá vinieron á Josué en Gilgal; y Caleb, hijo de Jephone Cenezeo, le dijo: Tú sabes lo que Jehová dijo á Moisés, varón de Dios, en Cades-barnea, tocante á mí y á ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 14, 7, 'Yo era de edad de cuarenta años, cuando Moisés siervo de Jehová me envió de Cades-barnea á reconocer la tierra; y yo le referí el negocio como lo tenía en mi corazón:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 14, 8, 'Mas mis hermanos, los que habían subido conmigo, menguaron el corazón del pueblo; empero yo cumplí siguiendo á Jehová mi Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 14, 9, 'Entonces Moisés juró, diciendo: Si la tierra que holló tu pie no fuere para ti, y para tus hijos en herencia perpetua: por cuanto cumpliste siguiendo á Jehová mi Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 14, 10, 'Ahora bien, Jehová me ha hecho vivir, como él dijo, estos cuarenta y cinco años, desde el tiempo que Jehová habló estas palabras á Moisés, cuando Israel andaba por el desierto: y ahora, he aquí soy hoy día de ochenta y cinco años:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 14, 11, 'Pero aun hoy estoy tan fuerte como el día que Moisés me envió: cual era entonces mi fuerza, tal es ahora, para la guerra, y para salir y para entrar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 14, 12, 'Dame, pues, ahora este monte, del cual habló Jehová aquel día; porque tú oíste en aquel día que los Anaceos están allí, y grandes y fuertes ciudades. Quizá Jehová será conmigo, y los echaré como Jehová ha dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 14, 13, 'Josué entonces le bendijo, y dió á Caleb hijo de Jephone á Hebrón por heredad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 14, 14, 'Por tanto Hebrón fué de Caleb, hijo de Jephone Cenezeo, en heredad hasta hoy; porque cumplió siguiendo á Jehová Dios de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 14, 15, 'Mas Hebrón fué antes llamada Chîriath-arba; fué Arba un hombre grande entre los Anaceos. Y la tierra tuvo reposo de las guerras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 1, 'Y FUÉ la suerte de la tribu de los hijos de Judá, por sus familias, junto al término de Edom, del desierto de Zin al mediodía, al lado del sur.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 2, 'Y su término de la parte del mediodía fué desde la costa del mar Salado, desde la lengua que mira hacia el mediodía;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 3, 'Y salía hacia el mediodía á la subida de Acrabim, pasando hasta Zin; y subiendo por el mediodía hasta Cades-barnea, pasaba á Hebrón, y subiendo por Addar daba vuelta á Carca;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 4, 'De allí pasaba á Azmón, y salía al arroyo de Egipto; y sale este término al occidente. Este pues os será el término del mediodía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 5, 'El término del oriente es el mar Salado hasta el fin del Jordán. Y el término de la parte del norte, desde la lengua del mar, desde el fin del Jordán:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 6, 'Y sube este término por Beth-hogla, y pasa del norte á Beth-araba, y de aquí sube este término á la piedra de Bohán, hijo de Rubén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 7, 'Y torna á subir este término á Debir desde el valle de Achôr: y al norte mira sobre Gilgal, que está delante de la subida de Adumin, la cual está al mediodía del arroyo: y pasa este término á las aguas de En-semes, y sale á la fuente de Rogel:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 8, 'Y sube este término por el valle del hijo de Hinnom al lado del Jebuseo al mediodía: esta es Jerusalem. Luego sube este término por la cumbre del monte que está delante del valle de Hinnom hacia el occidente, el cual está al cabo del valle de los gigantes al norte:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 9, 'Y rodea este término desde la cumbre del monte hasta la fuente de las aguas de Nephtoa, y sale á la ciudades del monte de Ephrón, rodeando luego el mismo término á Baala, la cual es Chîriath-jearim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 10, 'Después torna este término desde Baala hacia el occidente al monte de Seir: y pasa al lado del monte de Jearim hacia el norte, esta es Chesalón, y desciende á Beth-semes, y pasa á Timna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 11, 'Sale luego este término al lado de Ecrón hacia el norte; y rodea el mismo término á Sichêron, y pasa por el monte de Baala, y sale á Jabneel: y sale este término á la mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 12, 'El término del occidente es la mar grande. Este pues, es el término de los hijos de Judá en derredor, por sus familias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 13, 'Mas á Caleb, hijo de Jephone, dió parte entre los hijos de Judá, conforme al mandamiento de Jehová á Josué: esto es, á Chîriath-arba, del padre de Anac, que es Hebrón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 14, 'Y Caleb echó de allí tres hijos de Anac, á Sesai, Aiman, y Talmai, hijos de Anac.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 15, 'De aquí subió á los que moraban en Debir: y el nombre de Debir era antes Chîriath-sepher.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 16, 'Y dijo Caleb: Al que hiriere á Chîriath-sepher, y la tomare, yo le daré á mi hija Axa por mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 17, 'Y tomóla Othoniel, hijo de Cenez, hermano de Caleb; y él le dió por mujer á su hija Axa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 18, 'Y aconteció que cuando la llevaba, él la persuadió que pidiese á su padre tierras para labrar. Ella entonces se apeó del asno. Y Caleb le dijo: ¿Qué tienes?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 19, 'Y ella respondió: Dame bendición: pues que me has dado tierra de secadal, dame también fuentes de aguas. El entonces le dió las fuentes de arriba, y las de abajo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 20, 'Esta pues es la herencia de las tribu de los hijos de Judá por sus familias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 21, 'Y fueron las ciudades del término de la tribu de los hijos de Judá hacia el término de Edom al mediodía: Cabseel, y Eder, y Jagur,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 22, 'Y Cina, y Dimona, y Adada,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 23, 'Y Cedes, y Asor, é Itnán,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 24, 'Ziph, y Telem, Bealoth,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 25, 'Y Asor-hadatta, y Chêrioth-hesron, que es Asor,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 26, 'Amam, y Sema, y Molada,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 27, 'Y Asar-gadda, y Hesmón, y Beth-pelet,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 28, 'Y Hasar-sual, Beersebah, y Bizotia,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 29, 'Baala, é Iim, y Esem,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 30, 'Y Eltolad, y Cesil, y Horma,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 31, 'Y Siclag, y Madmanna, Sansana,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 32, 'Y Lebaoth, Silim, y Aín, y Rimmón; en todas veintinueve ciudades con sus aldeas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 33, 'En las llanuras, Estaol, y Sorea, y Asena,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 34, 'Y Zanoa, y Engannim, Tappua, y Enam,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 35, 'Jerimoth, y Adullam, Sochô, y Aceca,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 36, 'Y Saraim, y Adithaim, y Gedera, y Gederothaim; catorce ciudades con sus aldeas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 37, 'Senán, y Hadasa, y Migdalgad,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 38, 'Y Dilán, y Mizpa, y Jocteel,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 39, 'Lachîs, y Boscath, y Eglón,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 40, 'Y Cabón, y Lamas, y Chîtlis,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 41, 'Y Gederoh, Beth-dagón, y Naama, y Maceda; dieciséis ciudades con sus aldeas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 42, 'Libna, y Ether, y Asán,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 43, 'Y Jiphta, y Asna, y Nesib,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 44, 'Y Ceila, y Achzib, y Maresa; nueve ciudades con sus aldeas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 45, 'Ecrón con sus villas y sus aldeas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 46, 'Desde Ecrón hasta la mar, todas las que están á la costa de Asdod con sus aldeas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 47, 'Asdod con sus villas y sus aldeas: Gaza con sus villas y sus aldeas hasta el río de Egipto, y la gran mar con sus términos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 48, 'Y en las montañas, Samir, y Jattir, y Succoth,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 49, 'Y Danna, y Chîriath-sanna, que es Debir,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 50, 'Y Anab, y Estemo, y Anim,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 51, 'Y Gosén, y Olón, y Gilo; once ciudades con sus aldeas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 52, 'Arab, y Dumah, y Esán,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 53, 'Y Janum, y Beth-tappua, y Apheca,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 54, 'Y Humta, y Chîriath-arba, que es Hebrón, y Sior; nueve ciudades con sus aldeas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 55, 'Maón, Carmel, y Ziph, y Juta,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 56, 'E Izreel, Jocdeam, y Zanoa,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 57, 'Caín, Gibea, y Timna; diez ciudades con sus aldeas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 58, 'Halhul, y Bethfur, y Gedor,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 59, 'Y Maarath, y Beth-anoth, y Eltecón; seis ciudades con sus aldeas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 60, 'Chîriath-baal, que es Chîriath-jearim, y Rabba; dos ciudades con sus aldeas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 61, 'En el desierto, Beth-araba, Middín, y Sechâchâ,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 62, 'Y Nibsan, y la ciudad de la sal, y Engedi; seis ciudades con sus aldeas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 15, 63, 'Mas á los Jebuseos que habitaban en Jerusalem, los hijos de Judá no los pudieron desarraigar; antes quedó el Jebuseo en Jerusalem con los hijos de Judá, hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 16, 1, 'Y LA suerte del los hijos de José salió desde el Jordán de Jericó hasta las aguas de Jericó hacia el oriente, al desierto que sube de Jericó al monte de Beth-el:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 16, 2, 'Y de Beth-el sale á Luz, y pasa al término de Archi en Ataroth;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 16, 3, 'Y torna á descender hacia la mar al término de Japhlet, hasta el término de Beth-oron la de abajo, y hasta Gezer; y sale á la mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 16, 4, 'Recibieron pues heredad los hijos de José, Manasés y Ephraim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 16, 5, 'Y fué el término de los hijos de Ephraim por sus familias, fué el término de su herencia á la parte oriental, desde Ataroth-addar hasta Beth-oron la de arriba:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 16, 6, 'Y sale este término á la mar, y á Michmetat al norte, y da vuelta este término hacia el oriente á Tanath-silo, y de aquí pasa al oriente á Janoa:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 16, 7, 'Y de Janoa desciende á Ataroth, y á Naaratha, y toca en Jericó, y sale al Jordán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 16, 8, 'Y de Tappua torna este término hacia la mar al arroyo de Cana, y sale á la mar. Esta es la heredad de la tribu de los hijos de Ephraim por sus familias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 16, 9, 'Hubo también ciudades que se apartaron para los hijos de Ephraim en medio de la herencia de los hijos de Manasés, todas ciudades con sus aldeas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 16, 10, 'Y no echaron al Cananeo que habitaba en Gezer; antes quedó el Cananeo en medio de Ephraim, hasta hoy, y fué tributario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 17, 1, 'Y TUVO también suerte la tribu de Manasés, porque fué primogénito de José. Machîr, primogénito de Manasés, y padre de Galaad, el cual fué hombre de guerra, tuvo á Galaad y á Basán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 17, 2, 'Tuvieron también suerte los otros hijos de Manasés conforme á sus familias: los hijos de Abiezer, y los hijos de Helec, y los hijos de Esriel, y los hijos de Sichêm, y los hijos de Hepher, y los hijos de Semida; estos fueron los hijos varones de Manasés hijo de José, por sus familias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 17, 3, 'Pero Salphaad, hijo de Hepher, hijo de Galaad, hijo de Machîr, hijo de Manasés, no tuvo hijos, sino hijas, los nombres de las cuales son estos: Maala, Noa, Hogla, Milchâ, y Tirsa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 17, 4, 'Estas vinieron delante de Eleazar sacerdote, y de Josué hijo de Nun, y de los príncipes, y dijeron: Jehová mandó á Moisés que nos diese herencia entre nuestros hermanos. Y él les dió herencia entre los hermanos del padre de ellas, conforme al dicho de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 17, 5, 'Y cayeron á Manasés diez suertes á más de la tierra de Galaad y de Basán, que está de la otra parte del Jordán:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 17, 6, 'Porque las hijas de Manasés poseyeron herencia entre sus hijos: y la tierra de Galaad fué de los otros hijos de Manasés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 17, 7, 'Y fué el término de Manasés desde Aser hasta Michmetat, la cual está delante de Sichêm; y va este término á la mano derecha, á los que habitan en Tappua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 17, 8, 'Y la tierra de Tappua fué de Manasés; pero Tappua, que está junto al término de Manasés, es de los hijos de Ephraim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 17, 9, 'Y desciende este término al arroyo de Cana, hacia el mediodía del arroyo. Estas ciudades de Ephraim están entre las ciudades de Manasés: y el término de Manasés es desde el norte del mismo arroyo, y sus salidas son á la mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 17, 10, 'Ephraim al mediodía, y Manasés al norte, y la mar es su término: y encuéntranse con Aser á la parte del norte, y con Issachâr al oriente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 17, 11, 'Tuvo también Manasés en Issachâr y en Aser á Beth-san y sus aldeas, é Ibleam y sus aldeas, y los moradores de Dor y sus aldeas, y los moradores de Endor y sus aldeas, y los moradores de Taanach y sus aldeas, y los moradores de Megiddo y sus aldeas: tres provincias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 17, 12, 'Mas los hijos de Manasés no pudieron echar á los de aquellas ciudades; antes el Cananeo quiso habitar en la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 17, 13, 'Empero cuando los hijos de Israel tomaron fuerzas, hicieron tributario al Cananeo, mas no lo echaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 17, 14, 'Y los hijos de José hablaron á Josué, diciendo: ¿Por qué me has dado por heredad una sola suerte y una sola parte, siendo yo un pueblo tan grande y que Jehová me ha así bendecido hasta ahora?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 17, 15, 'Y Josué les respondió: Si eres pueblo tan grande, sube tú al monte, y corta para ti allí en la tierra del Pherezeo y de los gigantes, pues que el monte de Ephraim es angosto para ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 17, 16, 'Y los hijos de José dijeron: No nos bastará á nosotros este monte: y todos los Cananeos que habitan la tierra de la campiña, tienen carros herrados; los que están en Beth-san y en sus aldeas, y los que están en el valle de Jezreel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 17, 17, 'Entonces Josué respondió á la casa de José, á Ephraim y Manasés, diciendo: Tú eres gran pueblo, y tienes gran fuerza; no tendrás una sola suerte;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 17, 18, 'Mas aquel monte será tuyo; que bosque es, y tú lo cortarás, y serán tuyos sus términos: porque tú echarás al Cananeo, aunque tenga carros herrados, y aunque sea fuerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 18, 1, 'Y TODA la congregación de los hijos de Israel se juntó en Silo, y asentaron allí el tabernáculo del testimonio, después que la tierra les fué sujeta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 18, 2, 'Mas habían quedado en los hijos de Israel siete tribus, á las cuales aun no habían repartido su posesión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 18, 3, 'Y Josué dijo á los hijos de Israel: ¿Hasta cuando seréis negligentes para venir á poseer la tierra que os ha dado Jehová el Dios de vuestros padres?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 18, 4, 'Señalad tres varones de cada tribu, para que yo los envíe, y que ellos se levanten, y recorran la tierra, y la describan conforme á sus heredades, y se tornen á mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 18, 5, 'Y la dividirán en siete partes: y Judá estará en su término al mediodía, y los de la casa de José estarán en el suyo al norte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 18, 6, 'Vosotros, pues, delinearéis la tierra en siete partes, y me traeréis la descripción aquí, y yo os echaré las suertes aquí delante de Jehová nuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 18, 7, 'Empero los Levitas ninguna parte tienen entre vosotros; porque el sacerdocio de Jehová es la heredad de ellos: Gad también y Rubén, y la media tribu de Manasés, ya han recibido su heredad de la otra parte del Jordán al oriente, la cual les dió Moisés siervo de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 18, 8, 'Levantándose pues aquellos varones, fueron: y mandó Josué á los que iban para delinear la tierra, diciéndoles: Id, recorred la tierra, y delineadla, y tornad á mí, para que yo os eche las suertes aquí delante de Jehová en Silo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 18, 9, 'Fueron pues aquellos varones y pasearon la tierra, delineándola por ciudades en siete partes en un libro, y tornaron á Josué al campo en Silo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 18, 10, 'Y Josué les echó las suertes delante de Jehová en Silo; y allí repartió Josué la tierra á los hijos de Israel por sus porciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 18, 11, 'Y sacóse la suerte de la tribu de los hijos de Benjamín por sus familias: y salió el término de su suerte entre los hijos de Judá y los hijos de José.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 18, 12, 'Y fué el término de ellos al lado del norte desde el Jordán: y sube aquel término al lado de Jericó al norte; sube después al monte hacia el occidente, y viene á salir al desierto de Beth-aven:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 18, 13, 'Y de allí pasa aquel término á Luz, por el lado de Luz (esta es Beth-el) hacia el mediodía. Y desciende este término de Ataroth-addar al monte que está al mediodía de Beth-oron la de abajo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 18, 14, 'Y torna este término, y da vuelta al lado de la mar, al mediodía hasta el monte que está delante de Beth-oron al mediodía; y viene á salir á Chîriath-baal, que es Chîriath-jearim, ciudad de los hijos de Judá. Este es el lado del occidente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 18, 15, 'Y el lado del mediodía es desde el cabo de Chîriath-jearim, y sale el término al occidente, y sale á la fuente de las aguas de Nephtoa:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 18, 16, 'Y desciende aqueste término al cabo del monte que está delante del valle del hijo de Hinnom, que está en la campiña de los gigantes hacia el norte: desciende luego al valle de Hinnom, al lado del Jebuseo al mediodía, y de allí desciende á la fuente de Rogel:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 18, 17, 'Y del norte torna y sale á Ensemes, y de allí sale á Geliloth, que está delante de la subida de Adummim, y descendía á la piedra de Bohan, hijo de Rubén:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 18, 18, 'Y pasa al lado que está delante de la campiña del norte, y desciende á los llanos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 18, 19, 'Y torna á pasar este término por el lado de Beth-hogla hacia el norte, y viene á salir el término á la lengua del mar Salado al norte, al cabo del Jordán al mediodía. Este es el término de hacia el mediodía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 18, 20, 'Y el Jordán acaba aqueste término al lado del oriente. Esta es la heredad de los hijos de Benjamín por sus términos alrededor, conforme á sus familias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 18, 21, 'Las ciudades de la tribu de los hijos de Benjamín, por sus familias, fueron Jericó, Beth-hogla, y el valle de Casis,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 18, 22, 'Beth-araba, Samaraim, y Beth-el;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 18, 23, 'Y Avim, y Para, y Ophra,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 18, 24, 'Y Cephar-hammonai, Ophni, y Gaba; doce ciudades con sus aldeas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 18, 25, 'Gabaón, Rama, Beeroth,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 18, 26, 'Y Mizpa, Chephira, y Moza,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 18, 27, 'Recom, Irpeel y Tarala,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 18, 28, 'Y Sela, Eleph, Jebus, que es Jerusalem, Gibeath, y Chîriath; catorce ciudades con sus aldeas. Esta es la heredad de los hijos de Benjamín, conforme á sus familias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 1, 'LA SEGUNDA suerte salió por Simeón, por la tribu de los hijos de Simeón conforme á sus familias; y su heredad fué entre la heredad de los hijos de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 2, 'Y tuvieron en su heredad á Beer-seba, Seba, y Molada,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 3, 'Hasar-sual, Bala, y Esem,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 4, 'Heltolad, Betul, y Horma,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 5, 'Siclag, Beth-marchâboth, y Hasar-susa,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 6, 'Beth-lebaoth, y Saruhén; trece ciudades con sus aldeas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 7, 'Aín, Rimmón, Eter, y Asán; cuatro ciudades con sus aldeas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 8, 'Y todas las aldeas que estaban alrededor de estas ciudades hasta Baalath-beer, que es Ramat del mediodía. Esta es la heredad de la tribu de los hijos de Simeón, según sus familias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 9, 'De la suerte de los hijos de Judá fué sacada la heredad de los hijos de Simeón; por cuanto la parte de los hijos de Judá era excesiva para ellos: así que los hijos de Simeón tuvieron su heredad en medio de la de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 10, 'La tercera suerte salió por los hijos de Zabulón conforme á sus familias: y el término de su heredad fué hasta Sarid.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 11, 'Y su término sube hasta la mar y hasta Merala, y llega hasta Dabbe-seth, y de allí llega al arroyo que está delante de Jocneam.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 12, 'Y tornando de Sarid hacia oriente, donde nace el sol al término de Chisiloth-tabor, sale á Dabrath, y sube á Japhia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 13, 'Y pasando de allí hacia el lado oriental á Gith-hepher y á Itta-kazin, sale á Rimmón rodeando á Nea;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 14, 'Y de aquí torna este término al norte á Hanatón, viniendo á salir al valle de Iphtael;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 15, 'Y abraza Catah, y Naalal, y Simrón, é Ideala, y Beth-lehem; doce ciudades con sus aldeas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 16, 'Esta es la heredad de los hijos de Zabulón por sus familias; estas ciudades con sus aldeas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 17, 'La cuarta suerte salió por Issachâr, por los hijos de Issachâr conforme á sus familias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 18, 'Y fué su término Izreel, y Chesullot, y Sunem,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 19, 'Y Hapharaim, y Sión, y Anaarath,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 20, 'Y Rabbit, y Chisión, y Ebes,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 21, 'Y Rameth, y En-gannim, y En-hadda y Beth-passes;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 22, 'Y llega este término hasta Tabor, y Sahasim, y Beth-semes; y sale su término al Jordán: diez y seis ciudades con sus aldeas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 23, 'Esta es la heredad de la tribu de los hijos de Issachâr conforme á sus familias; estas ciudades con sus aldeas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 24, 'Y salió la quinta suerte por la tribu de los hijos de Aser por sus familias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 25, 'Y su término fué Helchât, y Halí, y Betén, y Axaph,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 26, 'Y Alammelec, y Amead, y Miseal; y llega hasta Carmel al occidente, y á Sihor-libnath;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 27, 'Y tornando de donde nace el sol á Beth-dagón, llega á Zabulón, y al valle de Iphtael al norte, á Beth-emec, y á Nehiel, y sale á Cabul á la izquierda;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 28, 'Y abraza á Hebrón, y Rehob, y Hammón, y Cana, hasta la gran Sidón;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 29, 'Y torna de allí este término á Horma, y hasta la fuerte ciudad de Tiro, y torna este término á Hosa, y sale á la mar desde el territorio de Achzib:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 30, 'Abraza también Umma, y Aphec, y Rehob: veinte y dos ciudades con sus aldeas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 31, 'Esta es la heredad de la tribu de los hijos de Aser por sus familias; estas ciudades con sus aldeas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 32, 'La sexta suerte salió por los hijos de Nephtalí, por los hijos de Nephtalí conforme á sus familias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 33, 'Y fué su término desde Heleph, y Allón-saananim, y Adami-neceb, y Jabneel, hasta Lacum; y sale al Jordán;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 34, 'Y tornando de allí este término hacia el occidente á Aznot-tabor, pasa de allí á Hucuca, y llega hasta Zabulón al mediodía, y al occidente confina con Aser, y con Judá al Jordán hacia donde nace el sol.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 35, 'Y las ciudades fuertes son Siddim, Ser, y Hamath, Raccath, y Cinneroth,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 36, 'Y Adama, y Rama, y Asor,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 37, 'Y Cedes, y Edrei, y En-hasor,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 38, 'E Irón, y Migdalel, y Horem, y Beth-anath, y Beth-semes: diez y nueve ciudades con sus aldeas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 39, 'Esta es la heredad de la tribu de los hijos de Nephtalí por sus familias; estas ciudades con sus aldeas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 40, 'La séptima suerte salió por la tribu de los hijos de Dan por sus familias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 41, 'Y fué el término de su heredad, Sora, y Estaol, é Ir-semes,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 42, 'Y Saalabín, y Ailón, y Jeth-la,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 43, 'Y Elón, y Timnatha, y Ecrón,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 44, 'Y Eltechê, Gibbethón, y Baalath,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 45, 'Y Jehud, y Bene-berác, y Gath-rimmón,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 46, 'Y Mejarcón, y Raccón, con el término que está delante de Joppa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 47, 'Y faltóles término á los hijos de Dan; y subieron los hijos de Dan y combatieron á Lesem, y tomándola metiéronla á filo de espada, y la poseyeron, y habitaron en ella; y llamaron á Lesem, Dan, del nombre de Dan su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 48, 'Esta es la heredad de la tribu de los hijos de Dan conforme á sus familias; estas ciudades con sus aldeas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 49, 'Y después que acabaron de repartir la tierra en heredad por sus términos, dieron los hijos de Israel heredad á Josué hijo de Nun en medio de ellos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 50, 'Según la palabra de Jehová, le dieron la ciudad que él pidió, Timnath-sera, en el monte de Ephraim; y él reedificó la ciudad, y habitó en ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 19, 51, 'Estas son las heredades que Eleazar sacerdote, y Josué hijo de Nun, y los principales de los padres, entregaron por suerte en posesión á las tribus de los hijos de Israel en Silo delante de Jehová, á la entrada del tabernáculo del testimonio; y acabaron de repartir la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 20, 1, 'Y HABLO Jehová á Josué, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 20, 2, 'Habla á los hijos de Israel, diciendo: Señalaos las ciudades de refugio, de las cuales yo os hablé por Moisés;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 20, 3, 'Para que se acoja allí el homicida que matare á alguno por yerro y no á sabiendas; que os sean por acogimiento del cercano del muerto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 20, 4, 'Y el que se acogiere á alguna de aquellas ciudades, presentaráse á la puerta de la ciudad, y dirá sus causas, oyéndolo los ancianos de aquella ciudad: y ellos le recibirán consigo dentro de la ciudad, y le darán lugar que habite con ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 20, 5, 'Y cuando el cercano del muerto le siguiere, no entregarán en su mano al homicida, por cuanto hirió á su prójimo por yerro, ni tuvo con él antes enemistad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 20, 6, 'Y quedará en aquella ciudad hasta que parezca en juicio delante del ayuntamiento, hasta la muerte del gran sacerdote que fuere en aquel tiempo: entonces el homicida tornará y vendrá á su ciudad y á su casa y á la ciudad de donde huyó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 20, 7, 'Entonces señalaron á Cedes en Galilea, en el monte de Nephtalí, y á Sichêm en el monte de Ephraim, y á Chîriath-arba, que es Hebrón, en el monte de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 20, 8, 'Y de la otra parte del Jordán de Jericó, al oriente, señalaron á Beser en el desierto, en la llanura de la tribu de Rubén, y á Ramoth en Galaad de la tribu de Gad, y á Gaulón en Basán de la tribu de Manasés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 20, 9, 'Estas fueron las ciudades señaladas para todos los hijos de Israel, y para el extranjero que morase entre ellos, para que se acogiese á ellas cualquiera que hiriese hombre por yerro, y no muriese por mano del cercano del muerto, hasta que compareciese delante del ayuntamiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 1, 'Y LOS principales de los padres de los Levitas vinieron á Eleazar sacerdote, y á Josué hijo de Nun, y á los principales de los padres de las tribus de los hijos de Israel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 2, 'Y habláronles en Silo en la tierra de Canaán, diciendo: Jehová mandó por Moisés que nos fuesen dadas villas para habitar, con sus ejidos para nuestras bestias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 3, 'Entonces los hijos de Israel dieron á los Levitas de sus posesiones, conforme á la palabra de Jehová, estas villas con sus ejidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 4, 'Y salió la suerte por las familias de los Coathitas; y fueron dadas por suerte á los hijos de Aarón sacerdote, que eran de los Levitas, por la tribu de Judá, por la de Simeón y por la de Benjamín, trece villas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 5, 'Y á los otros hijos de Coath se dieron por suerte diez villas de las familias de la tribu de Ephraim, y de la tribu de Dan, y de la media tribu de Manasés;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 6, 'Y á los hijos de Gersón, por las familias de la tribu de Issachâr, y de la tribu de Aser, y de la tribu de Nephtalí, y de la media tribu de Manasés en Basán, fueron dadas por suerte trece villas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 7, 'A los hijos de Merari por sus familias se dieron doce villas por la tribu de Rubén, y por la tribu de Gad, y por la tribu de Zabulón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 8, 'Y así dieron por suerte los hijos de Israel á los Levitas estas villas con sus ejidos, como Jehová lo había mandado por Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 9, 'Y de la tribu de los hijos de Judá, y de la tribu de los hijos de Simeón dieron estas villas que fueron nombradas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 10, 'Y la primera suerte fué de los hijos de Aarón, de la familia de Coath, de los hijos de Leví;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 11, 'A los cuales dieron Chîriath-arba, del padre de Anac, la cual es Hebrón, en el monte de Judá, con sus ejidos en sus contornos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 12, 'Mas el campo de aquesta ciudad y sus aldeas dieron á Caleb hijo de Jephone, por su posesión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 13, 'Y á los hijos de Aarón sacerdote dieron la ciudad de refugio para los homicidas, á Hebrón con sus ejidos; y á Libna con sus ejidos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 14, 'Y á Jattir con sus ejidos, y á Estemoa con sus ejidos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 15, 'A Helón con sus ejidos, y á Debir con sus ejidos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 16, 'A Ain con sus ejidos, á Jutta con sus ejidos, y á Beth-semes con sus ejidos; nueve villas de estas dos tribus:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 17, 'Y de la tribu de Benjamín, á Gibeón con sus ejidos, á Geba con sus ejidos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 18, 'A Anathoth con sus ejidos, á Almón con sus ejidos: cuatro villas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 19, 'Todas las villas de los sacerdotes, hijos de Aarón, son trece con sus ejidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 20, 'Mas las familias de los hijos de Coath, Levitas, los que quedaban de los hijos de Coath, recibieron por suerte villas de la tribu de Ephraim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 21, 'Y diéronles á Sichêm, villa de refugio para los homicidas, con sus ejidos, en el monte de Ephraim; y á Geser con sus ejidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 22, 'Y á Kibsaim con sus ejidos, y á Beth-oron con sus ejidos: cuatro villas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 23, 'Y de la tribu de Dan á Eltheco con sus ejidos, á Gibethón con sus ejidos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 24, 'A Ayalón con sus ejidos, á Gath-rimmón con sus ejidos: cuatro villas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 25, 'Y de la media tribu de Manasés, á Taanach con sus ejidos, y á Gath-rimmón con sus ejidos: dos villas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 26, 'Todas las villas para el resto de las familias de los hijos de Coath fueron diez con sus ejidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 27, 'A los hijos de Gersón de las familias de los Levitas, dieron la villa de refugio para los homicidas, de la media tribu de Manasés: á Gaulón en Basán con sus ejidos, y á Bosra con sus ejidos: dos villas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 28, 'Y de la tribu de Issachâr, á Cesión con sus ejidos, á Dabereth con sus ejidos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 29, 'A Jarmuth con sus ejidos, y á En-gannim con sus ejidos: cuatro villas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 30, 'Y de la tribu de Aser, á Miseal con sus ejidos, á Abdón con sus ejidos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 31, 'A Helchâth con sus ejidos, y á Rehob con sus ejidos: cuatro villas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 32, 'Y de la tribu de Nephtalí, la villa de refugio para los homicidas, á Cedes en Galilea con sus ejidos, á Hammoth-dor con sus ejidos, y á Cartán con sus ejidos: tres villas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 33, 'Todas las villas de los Gersonitas por sus familias fueron trece villas con sus ejidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 34, 'Y á las familias de los hijos de Merari, Levitas que quedaban, dióseles de la tribu de Zabulón, á Jocneam con sus ejidos, Cartha con sus ejidos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 35, 'Dimna con sus ejidos, Naalal con sus ejidos: cuatro villas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 36, 'Y de la tribu de Rubén, á Beser con sus ejidos, á Jasa con sus ejidos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 37, 'A Cedemoth con sus ejidos, y Mephaat con sus ejidos: cuatro villas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 38, 'De la tribu de Gad, la villa de refugio para los homicidas, Ramoth en Galaad con sus ejidos, y Mahanaim con sus ejidos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 39, 'Hesbón con sus ejidos, y Jacer con sus ejidos: cuatro villas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 40, 'Todas las villas de los hijos de Merari por sus familias, que restaban de las familias de los Levitas, fueron por sus suertes doce villas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 41, 'Y todas la villas de los Levitas en medio de la posesión de los hijos de Israel, fueron cuarenta y ocho villas con sus ejidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 42, 'Y estas ciudades estaban apartadas la una de la otra cada cual con sus ejidos alrededor de ellas: lo cual fué en todas estas ciudades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 43, 'Así dió Jehová á Israel toda la tierra que había jurado dar á sus padres; y poseyéronla, y habitaron en ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 44, 'Y Jehová les dió reposo alrededor, conforme á todo lo que había jurado á sus padres: y ninguno de todos los enemigos les paró delante, sino que Jehová entregó en sus manos á todos sus enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 21, 45, 'No faltó palabra de todas la buenas que habló Jehová á la casa de Israel; todo se cumplió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 1, 'ENTONCES Josué llamó á los Rubenitas y á los Gaditas, y á la media tribu de Manasés,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 2, 'Y díjoles: Vosotros habéis guardado todo lo que Moisés siervo de Jehová os mandó, y habéis obedecido á mi voz en todo lo que os he mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 3, 'No habéis dejado á vuestros hermanos en estos muchos días hasta hoy, antes habéis guardado la observancia de los mandamientos de Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 4, 'Ahora pues que Jehová vuestro Dios ha dado reposo á vuestros hermanos, como se lo había prometido, volved, y tornad á vuestras tiendas, á la tierra de vuestras posesiones, que Moisés siervo de Jehová os dió de la otra parte del Jordán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 5, 'Solamente que con diligencia cuidéis de poner por obra el mandamiento y la ley, que Moisés siervo de Jehová os intimó: que améis á Jehová vuestro Dios, y andéis en todos sus caminos; que guardéis sus mandamientos, y os alleguéis á él, y le sirváis de todo vuestro corazón y de toda vuestra alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 6, 'Y bendiciéndolos Josué, los envió: y fuéronse á sus tiendas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 7, 'También á la media tribu de Manasés había dado Moisés posesión en Basán; mas á la otra media dió Josué heredad entre sus hermanos de estotra parte del Jordán al occidente: y también á éstos envió Josué á sus tiendas, después de haberlos bendecido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 8, 'Y hablóles, diciendo: Volveos á vuestras tiendas con grandes riquezas, y con grande copia de ganado, con plata, y con oro, y metal, y muchos vestidos: partid con vuestros hermanos el despojo de vuestros enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 9, 'Y los hijos de Rubén y los hijos de Gad, y la media tribu de Manasés, se tornaron, y partiéronse de los hijos de Israel, de Silo, que está en la tierra de Canaán, para ir á la tierra de Galaad, á la tierra de sus posesiones, de la cual eran poseedores, según palabra de Jehová por mano de Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 10, 'Y llegando á los términos del Jordán, que está en la tierra de Canaán, los hijos de Rubén y los hijos de Gad, y la media tribu de Manasés, edificaron allí un altar junto al Jordán, un altar de grande apariencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 11, 'Y los hijos de Israel oyeron decir como los hijos de Rubén y los hijos de Gad, y la media tribu de Manasés, habían edificado un altar delante de la tierra de Canaán, en los términos del Jordán, al paso de los hijos de Israel:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 12, 'Lo cual como los hijos de Israel oyeron, juntóse toda la congregación de los hijos de Israel en Silo, para subir á pelear contra ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 13, 'Y enviaron los hijos de Israel á los hijos de Rubén y á los hijos de Gad y á la media tribu de Manasés en la tierra de Galaad, á Phinees hijo de Eleazar sacerdote,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 14, 'Y á diez príncipes con él; un príncipe de cada casa paterna de todas las tribus de Israel, cada uno de los cuales era cabeza de familia de sus padres en la multitud de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 15, 'Los cuales vinieron á los hijos de Rubén y á los hijos de Gad, y á la media tribu de Manasés, en la tierra de Galaad; y habláronles, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 16, 'Toda la congregación de Jehová dice así: ¿Qué transgresión es ésta con que prevaricáis contra el Dios de Israel, volviéndoos hoy de seguir á Jehová, edificándoos altar para ser hoy rebeldes contra Jehová?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 17, '¿Nos ha sido poco la maldad de Peor, de la que no estamos aún limpios hasta este día, por la cual fué la mortandad en la congregación de Jehová?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 18, 'Y vosotros os volvéis hoy de seguir á Jehová; mas será que vosotros os rebelaréis hoy contra Jehová, y mañana se airará él contra toda la congregación de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 19, 'Que si os parece que la tierra de vuestra posesión es inmunda, pasaos á la tierra de la posesión de Jehová, en la cual está el tabernáculo de Jehová, y tomad posesión entre nosotros; pero no os rebeléis contra Jehová, ni os rebeléis contra nosotros, edificándoos altar á más del altar de Jehová nuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 20, '¿No cometió Achân, hijo de Zera, prevaricación en el anatema, y vino ira sobre toda la congregación de Israel? y aquel hombre no pereció solo en su iniquidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 21, 'Entonces los hijos de Rubén y los hijos de Gad, y la media tribu de Manasés, respondieron y dijeron á los principales de la multitud de Israel:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 22, 'El Dios de los dioses, Jehová, el Dios de los dioses, Jehová, él sabe, y sabrá Israel: si por rebelión ó por prevaricación contra Jehová (no nos salves hoy,)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 23, 'Nos hemos edificado altar para tornarnos de en pos de Jehová, ó para sacrificar holocausto ó presente, ó para hacer sobre él sacrificios pacíficos, el mismo Jehová nos lo demande.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 24, 'Asimismo, si no lo hicimos por temor de esto, diciendo: Mañana vuestros hijos dirán á nuestros hijos: ¿Qué tenéis vosotros con Jehová el Dios de Israel?;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 25, 'Jehová ha puesto por término el Jordán entre nosotros y vosotros, oh hijos de Rubén é hijos de Gad; no tenéis vosotros parte en Jehová: y así vuestros hijos harán que nuestros hijos no teman á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 26, 'Por esto dijimos: Hagamos ahora por edificarnos un altar, no para holocausto ni para sacrificio,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 27, 'Sino para que sea un testimonio entre nosotros y vosotros, y entre los que vendrán después de nosotros, de que podemos hacer el servicio de Jehová delante de él con nuestros holocaustos, con nuestros sacrificios, y con nuestros pacíficos; y no digan mañana vuestros hijos á los nuestros: Vosotros no tenéis parte en Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 28, 'Nosotros, pues, dijimos: Si aconteciere que tal digan á nosotros, ó á nuestras generaciones en lo por venir, entonces responderemos: Mirad el símil del altar de Jehová, el cual hicieron nuestros padres, no para holocaustos ó sacrificios, sino para que fuese testimonio entre nosotros y vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 29, 'Nunca tal acontezca que nos rebelemos contra Jehová, ó que nos apartemos hoy de seguir á Jehová, edificando altar para holocaustos, para presente, ó para sacrificio, á más del altar de Jehová nuestro Dios que está delante de su tabernáculo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 30, 'Y oyendo Phinees el sacerdote y los príncipes de la congregación, y las cabezas de la multitud de Israel que con él estaban, las palabras que hablaron los hijos de Rubén y los hijos de Gad y los hijos de Manasés, fueron contentos de ello.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 31, 'Y dijo Phinees hijo del sacerdote Eleazar, á los hijos de Rubén, á los hijos de Gad, y á los hijos de Manasés: Hoy hemos entendido que Jehová está entre nosotros, pues que no habéis intentado esta traición contra Jehová. Ahora habéis librado á los hijos de Israel de la mano de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 32, 'Y Phinees hijo del sacerdote Eleazar, y los príncipes, volviéronse de con los hijos de Rubén, y de con los hijos de Gad, de la tierra de Galaad á la tierra de Canaán, á los hijos de Israel: á los cuales dieron la respuesta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 33, 'Y el negocio plugo á los hijos de Israel, y bendijeron á Dios los hijos de Israel; y no hablaron más de subir contra ellos en guerra, para destruir la tierra en que habitaban los hijos de Rubén y los hijos de Gad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 22, 34, 'Y los hijos de Rubén y los hijos de Gad pusieron por nombre al altar Ed; porque es testimonio entre nosotros que Jehová es Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 23, 1, 'Y ACONTECIO, pasados muchos días después que Jehová dió reposo á Israel de todos sus enemigos al contorno, que Josué, siendo viejo, y entrado en días,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 23, 2, 'Llamó á todo Israel, á sus ancianos, á sus príncipes, á sus jueces y á sus oficiales, y díjoles: Yo soy ya viejo y entrado en días:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 23, 3, 'Y vosotros habéis visto todo lo que Jehová vuestro Dios ha hecho con todas estas gentes en vuestra presencia; porque Jehová vuestro Dios ha peleado por vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 23, 4, 'He aquí os he repartido por suerte, en herencia para vuestras tribus, estas gentes, así las destruídas como las que quedan, desde el Jordán hasta la gran mar hacia donde el sol se pone.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 23, 5, 'Y Jehová vuestro Dios las echará de delante de vosotros, y las lanzará de vuestra presencia: y vosotros poseeréis sus tierras, como Jehová vuestro Dios os ha dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 23, 6, 'Esforzaos pues mucho á guardar y hacer todo lo que está escrito en el libro de la ley de Moisés, sin apartaros de ello ni á la diestra ni á la siniestra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 23, 7, 'Que cuando entrareis á estas gentes que han quedado con vosotros, no hagáis mención ni juréis por el nombre de sus dioses, ni los sirváis, ni os inclinéis á ellos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 23, 8, 'Mas á Jehová vuestro Dios os allegaréis, como habéis hecho hasta hoy;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 23, 9, 'Pues ha echado Jehová delante de vosotros grandes y fuertes naciones, y hasta hoy nadie ha podido parar delante de vuestro rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 23, 10, 'Un varón de vosotros perseguirá á mil: porque Jehová vuestro Dios pelea por vosotros, como él os dijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 23, 11, 'Por tanto, cuidad mucho por vuestras almas, que améis á Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 23, 12, 'Porque si os apartareis, y os allegareis á lo que resta de aquestas gentes que han quedado con vosotros, y si concertareis con ellas matrimonios, y entrareis á ellas, y ellas á vosotros;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 23, 13, 'Sabed que Jehová vuestro Dios no echará más estas gentes delante de vosotros; antes os serán por lazo, y por tropiezo, y por azote para vuestros costados, y por espinas para vuestros ojos, hasta tanto que perezcáis de aquesta buena tierra que Jehová vuestro Dios os ha dado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 23, 14, 'Y he aquí que yo estoy para entrar hoy por el camino de toda la tierra: reconoced, pues, con todo vuestro corazón y con toda vuestra alma, que no se ha perdido una palabra de todas la buenas palabras que Jehová vuestro Dios había dicho de vosotros: todas os han venido, no se ha perdido de ellas ni una.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 23, 15, 'Mas será, que como ha venido sobre vosotros toda palabra buena que Jehová vuestro Dios os había dicho, así también traerá Jehová sobre vosotros toda palabra mala, hasta destruiros de sobre la buena tierra que Jehová vuestro Dios os ha dado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 23, 16, 'Cuando traspasareis el pacto de Jehová vuestro Dios que él os ha mandado, yendo y honrando dioses ajenos, é inclinándoos á ellos. Y el furor de Jehová se inflamará contra vosotros, y luego pereceréis de aquesta buena tierra que él os ha dado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 1, 'Y JUNTANDO Josué todas las tribus de Israel en Sichêm, llamó á los ancianos de Israel, y á sus príncipes, á sus jueces, y á sus oficiales; y presentáronse delante de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 2, 'Y dijo Josué á todo el pueblo: Así dice Jehová, Dios de Israel: Vuestros padres habitaron antiguamente de esotra parte del río, es á saber, Tharé, padre de Abraham y de Nachôr; y servían á dioses extraños.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 3, 'Y yo tomé á vuestro padre Abraham de la otra parte del río, y trájelo por toda la tierra de Canaán, y aumenté su generación, y díle á Isaac.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 4, 'Y á Isaac dí á Jacob y á Esaú: y á Esaú dí el monte de Seir, que lo poseyese: mas Jacob y sus hijos descendieron á Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 5, 'Y yo envié á Moisés y á Aarón, y herí á Egipto, al modo que lo hice en medio de él, y después os saqué.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 6, 'Y saqué á vuestros padres de Egipto: y como llegaron á la mar, los Egipcios siguieron á vuestros padres hasta el mar Bermejo con carros y caballería.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 7, 'Y como ellos clamasen á Jehová, él puso oscuridad entre vosotros y los Egipcios, é hizo venir sobre ellos la mar, la cual los cubrió: y vuestros ojos vieron lo que hice en Egipto. Después estuvisteis muchos días en el desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 8, 'Y os introduje en la tierra de los Amorrheos, que habitaban de la otra parte del Jordán, los cuales pelearon contra vosotros; mas yo los entregué en vuestras manos, y poseísteis su tierra, y los destruí de delante de vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 9, 'Y levantóse después Balac hijo de Sephor, rey de los Moabitas, y peleó contra Israel; y envió á llamar á Balaam hijo de Beor, para que os maldijese.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 10, 'Mas yo no quise escuchar á Balaam, antes os bendijo repetidamente, y os libré de sus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 11, 'Y pasado el Jordán, vinisteis á Jericó; y los moradores de Jericó pelearon contra vosotros: los Amorrheos, Pherezeos, Cananeos, Hetheos, Gergeseos, Heveos, y Jebuseos: y yo los entregué en vuestras manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 12, 'Y envié tábanos delante de vosotros, los cuales los echaron de delante de vosotros, á saber, á los dos reyes de los Amorrheos; no con tu espada, ni con tu arco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 13, 'Y os dí la tierra por la cual nada trabajasteis, y las ciudades que no edificasteis, en las cuales moráis; y de las viñas y olivares que no plantasteis, coméis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 14, 'Ahora pues, temed á Jehová, y servidle con integridad y en verdad; y quitad de en medio los dioses á los cuales sirvieron vuestros padres de esotra parte del río, y en Egipto; y servid á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 15, 'Y si mal os parece servir á Jehová, escogeos hoy á quién sirváis; si á los dioses á quienes siervieron vuestros padres, cuando estuvieron de esotra parte del río, ó á los dioses de los Amorrheos en cuya tierra habitáis: que yo y mi casa serviremos á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 16, 'Entonces el pueblo repondió, y dijo: Nunca tal acontezca, que dejemos á Jehová por servir á otros dioses:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 17, 'Porque Jehová nuestro Dios es el que nos sacó á nosotros y á nuestros padres de la tierra de Egipto, de la casa de sevidumbre; el cual delante de nuestros ojos ha hecho estas grandes señales, y nos ha guardado por todo el camino por donde hemos andado, y en todos los pueblos por entre los cuales pasamos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 18, 'Y Jehová echó de delante de nosotros á todos los pueblos, y al Amorrheo que habitaba en la tierra: nosotros, pues, también serviremos á Jehová, porque él es nuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 19, 'Entonces Josué dijo al pueblo: No podréis servir á Jehová, porque él es Dios santo, y Dios celoso; no sufrirá vuestras rebeliones y vuestros pecados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 20, 'Si dejareis á Jehová y sirviereis á dioses ajenos, se volverá, y os maltratará, y os consumirá, después que os ha hecho bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 21, 'El pueblo entonces dijo á Josué: No, antes á Jehová serviremos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 22, 'Y Josué respondió al pueblo: Vosotros sois testigos contra vosotros mismos, de que os habéis elegido á Jehová para servirle. Y ellos respondieron: Testigos somos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 23, 'Quitad, pues, ahora los dioses ajenos que están entre vosotros, é inclinad vuestro corazón á Jehová Dios de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 24, 'Y el pueblo respondió á Josué: A Jehová nuestro Dios serviremos, y á su voz obedeceremos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 25, 'Entonces Josué hizo alianza con el pueblo el mismo día, y púsole ordenanzas y leyes en Sichêm.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 26, 'Y escribió Josué estas palabras en el libro de la ley de Dios; y tomando una grande piedra, levantóla allí debajo de un alcornoque que estaba junto al santuario de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 27, 'Y dijo Josué á todo el pueblo: He aquí esta piedra será entre nosotros por testigo, la cual ha oído todas las palabras de Jehová que él ha hablado con nosotros: será, pues, testigo contra vosotros, porque no mintáis contra vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 28, 'Y envió Josué al pueblo, cada uno á su heredad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 29, 'Y después de estas cosas murió Josué, hijo de Nun, siervo de Jehová siendo de ciento y diez años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 30, 'Y enterráronlo en el término de su posesión en Timnath-sera, que está en el monte de Ephraim, al norte del monte de Gaas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 31, 'Y sirvió Israel á Jehová todo el tiempo de Josué, y todo el tiempo de los ancianos que vivieron después de Josué, y que sabían todas las obras de Jehová, que había hecho por Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 32, 'Y enterraron en Sichêm los huesos de José que los hijos de Israel habían traído de Egipto, en la parte del campo que Jacob compró de los hijos de Hemor padre de Sichêm, por cien corderas; y fué en posesión á los hijos de José.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOS', 'Josué', 24, 33, 'También murió Eleazar, hijo de Aarón; al cual enterraron en el collado de Phinees su hijo, que le fué dado en el monte de Ephraim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 1, 'Y ACONTECIO después de la muerte de Josué, que los hijos de Israel consultaron á Jehová, diciendo: ¿Quién subirá por nosotros el primero á pelear contra los Cananeos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 2, 'Y Jehová respondió: Judá subirá; he aquí que yo he entregado la tierra en sus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 3, 'Y Judá dijo á Simeón su hermano: Sube conmigo á mi suerte, y peleemos contra el Cananeo, y yo también iré contigo á tu suerte. Y Simeón fué con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 4, 'Y subió Judá, y Jehová entregó en sus manos al Cananeo y al Pherezeo; y de ellos hirieron en Bezec diez mil hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 5, 'Y hallaron á Adoni-bezec en Bezec, y pelearon contra él: é hirieron al Cananeo y al Pherezeo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 6, 'Mas Adoni-bezec huyó; y siguiéronle, y prendiéronle, y cortáronle los pulgares de las manos y de los pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 7, 'Entonces dijo Adoni-bezec: Setenta reyes, cortados los pulgares de sus manos y de sus pies, cogían las migajas debajo de mi mesa: como yo hice, así me ha pagado Dios. Y metiéronle en Jerusalem, donde murió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 8, 'Y habían combatido los hijos de Judá á Jerusalem, y la habían tomado, y metido á cuchillo, y puesto á fuego la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 9, 'Después los hijos de Judá descendieron para pelear contra el Cananeo que habitaba en las montañas, y al mediodía, y en los llanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 10, 'Y partió Judá contra el Cananeo que habitaba en Hebrón, la cual se llamaba antes Chîriath-arba; é hirieron á Sesai, y á Ahiman, y á Talmai.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 11, 'Y de allí fué á los que habitaban en Debir, que antes se llamaba Chîriath-sepher.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 12, 'Y dijo Caleb: El que hiriere á Chîriath-sepher, y la tomare, yo le daré á Axa mi hija por mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 13, 'Y tomóla Othoniel hijo de Cenez, hermano menor de Caleb: y él le dió á Axa su hija por mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 14, 'Y cuando la llevaban, persuadióle que pidiese á su padre un campo. Y ella se apeó del asno, y Caleb le dijo: ¿Qué tienes?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 15, 'Ella entonces le respondió: Dame una bendición: que pues me has dado tierra de secadal, me des también fuentes de aguas. Entonces Caleb le dió las fuentes de arriba y las fuentes de abajo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 16, 'Y los hijos de Cineo, suegro de Moisés, subieron de la ciudad de las palmas con los hijos de Judá al desierto de Judá, que está al mediodía de Arad: y fueron y habitaron con el pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 17, 'Y fué Judá á su hermano Simeón, é hirieron al Cananeo que habitaba en Sephath, y asoláronla: y pusieron por nombre á la ciudad, Horma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 18, 'Tomó también Judá á Gaza con su término, y á Ascalón con su término, y á Ecrón con su término.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 19, 'Y fué Jehová con Judá, y echó á los de las montañas; mas no pudo echar á los que habitaban en los llanos, los cuales tenían carros herrados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 20, 'Y dieron Hebrón á Caleb, como Moisés había dicho: y él echó de allí tres hijos de Anac.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 21, 'Mas al Jebuseo que habitaba en Jerusalem, no echaron los hijos de Benjamín, y así el Jebuseo habitó con los hijos de Benjamín en Jerusalem hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 22, 'También los de la casa de José subieron á Beth-el; y fué Jehová con ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 23, 'Y los de la casa de José pusieron espías en Beth-el, la cual ciudad antes se llamaba Luz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 24, 'Y los que espiaban vieron un hombre que salía de la ciudad, y dijéronle: Muéstranos ahora la entrada de la ciudad, y haremos contigo misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 25, 'Y él les mostró la entrada á la ciudad, é hiriéronla á filo de espada; mas dejaron á aquel hombre con toda su familia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 26, 'Y fuese el hombre á la tierra de los Hetheos, y edificó una ciudad, á la cual llamó Luz: y este es su nombre hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 27, 'Tampoco Manasés echó á los de Beth-sean, ni á los de sus aldeas, ni á los de Taanach y sus aldeas, ni á los de Dor y sus aldeas, ni á los habitantes de Ibleam y sus aldeas, ni á los que habitaban en Megiddo y en sus aldeas: mas el Cananeo quiso habitar en esta tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 28, 'Empero cuando Israel tomó fuerzas hizo al Cananeo tributario, mas no lo echó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 29, 'Tampoco Ephraim echó al Cananeo que habitaba en Gezer; antes habitó el Cananeo en medio de ellos en Gezer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 30, 'Tampoco Zabulón echó á los que habitaban en Chîtron y á los que habitaban en Naalol; mas el Cananeo habitó en medio de él, y le fueron tributarios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 31, 'Tampoco Aser echó á los que habitaban en Achô, y á los que habitaban en Sidón, y en Ahlab, y en Achzib, y en Helba, y en Aphec, y en Rehod:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 32, 'Antes moró Aser entre los Cananeos que habitaban en la tierra; pues no los echó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 33, 'Tampoco Nephtalí echó á los que habitaban en Beth-semes, y á los que habitaban en Beth-anath, sino que moró entre los Cananeos que habitaban en la tierra; mas fuéronle tributarios los moradores de Beth-semes, y los moradores de Beth-anath.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 34, 'Los Amorrheos apretaron á los hijos de Dan hasta el monte; que no los dejaron descender á la campiña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 35, 'Y quiso el Amorrheo habitar en el monte de Heres, en Ajalón y en Saalbín; mas como la mano de la casa de José tomó fuerzas, hiciéronlos tributarios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 1, 36, 'Y el término del Amorrheo fué desde la subida de Acrabim, desde la piedra, y arriba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 2, 1, 'Y El ángel de Jehová subió de Gilgal á Bochîm, y dijo: Yo os saqué de Egipto, y os introduje en la tierra de la cual había jurado á vuestros padres; y dije: No invalidaré jamás mi pacto con vosotros;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 2, 2, 'Con tal que vosotros no hagáis alianza con los moradores de aquesta tierra, cuyos altares habéis de derribar: mas vosotros no habéis atendido á mi voz: ¿por qué habéis hecho esto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 2, 3, 'Por tanto yo también dije: No los echaré de delante de vosotros, sino que os serán por azote para vuestros costados, y sus dioses por tropiezo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 2, 4, 'Y como el ángel de Jehová habló estas palabras á todos los hijos de Israel, el pueblo lloró en alta voz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 2, 5, 'Y llamaron por nombre aquel lugar Bochîm: y sacrificaron allí á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 2, 6, 'Porque ya Josué había despedido al pueblo, y los hijos de Israel se habían ido cada uno á su heredad para poseerla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 2, 7, 'Y el pueblo había servido á Jehová todo el tiempo de Josué, y todo el tiempo de los ancianos que vivieron largos días después de Josué, los cuales habían visto todas las grandes obras de Jehová, que el había hecho por Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 2, 8, 'Y murió Josué hijo de Nun, siervo de Jehová, siendo de ciento y diez años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 2, 9, 'Y enterráronlo en el término de su heredad en Timnath-sera, en el monte de Ephraim, el norte del monte de Gaas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 2, 10, 'Y toda aquella generación fué también recogida con sus padres. Y levantóse después de ellos otra generación, que no conocían á Jehová, ni la obra que él había hecho por Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 2, 11, 'Y los hijos de Israel hicieron lo malo en ojos de Jehová, y sirvieron á los Baales:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 2, 12, 'Y dejaron á Jehová el Dios de sus padres, que los había sacado de la tierra de Egipto, y fuéronse tras otros dioses, los dioses de los pueblos que estaban en sus alrededores, á los cuales adoraron; y provocaron á ira á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 2, 13, 'Y dejaron á Jehová, y adoraron á Baal y á Astaroth.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 2, 14, 'Y el furor de Jehová se encendió contra Israel, el cual los entregó en manos de robadores que los despojaron, y los vendió en manos de sus enemigos de alrededor: y no pudieron parar más delante de sus enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 2, 15, 'Por donde quiera que salían, la mano de Jehová era contra ellos para mal, como Jehová había dicho, y como Jehová se lo había jurado; así los afligió en gran manera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 2, 16, 'Mas Jehová suscitó jueces que los librasen de mano de los que los despojaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 2, 17, 'Y tampoco oyeron á sus jueces, sino que fornicaron tras dioses ajenos, á los cuales adoraron: apartáronse bien presto del camino en que anduvieron sus padres obedeciendo á los mandamientos de Jehová; mas ellos no hicieron así.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 2, 18, 'Y cuando Jehová les suscitaba jueces, Jehová era con el juez, y librábalos de mano de los enemigos todo el tiempo de aquel juez: porque Jehová se arrepentía por sus gemidos á causa de los que los oprimían y afligían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 2, 19, 'Mas en muriendo el juez, ellos se tornaban, y se corrompían más que sus padres, siguiendo dioses ajenos para servirles, é inclinándose delante de ellos; y nada disminuían de sus obras, ni de su duro camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 2, 20, 'Y la ira de Jehová se encendió contra Israel, y dijo: Pues que esta gente traspasa mi pacto que ordené á sus padres, y no obedecen mi voz,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 2, 21, 'Tampoco yo echaré más de delante de ellos á ninguna de aquestas gentes que dejó Josué cuando murió;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 2, 22, 'Para que por ellas probara yo á Israel, si guardarían ellos el camino de Jehová andando por él, como sus padres lo guardaron, ó no.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 2, 23, 'Por esto dejó Jehová aquellas gentes, y no las desarraigó luego, ni las entregó en mano de Josué.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 1, 'ESTAS, pues, son las gentes que dejó Jehová para probar con ellas á Israel, á todos aquellos que no habían conocido todas las guerras de Canaán;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 2, 'Para que al menos el linaje de los hijos de Israel conociese, para enseñarlos en la guerra, siquiera fuese á los que antes no la habían conocido:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 3, 'Cinco príncipes de los Philisteos, y todos los Cananeos, y los Sidonios, y los Heveos que habitaban en el monte Líbano: desde el monte de Baal-hermón hasta llegar á Hamath.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 4, 'Estos pues fueron para probar por ellos á Israel, para saber si obedecerían á los mandamientos de Jehová, que él había prescrito á sus padres por mano de Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 5, 'Así los hijos de Israel habitaban entre los Cananeos, Hetheos, Amorrheos, Pherezeos, Heveos, y Jebuseos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 6, 'Y tomaron de sus hijas por mujeres, y dieron sus hijas á los hijos de ellos, y sirvieron á sus dioses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 7, 'Hicieron, pues, los hijos de Israel lo malo en ojos de Jehová: y olvidados de Jehová su Dios, sirvieron á los Baales, y á los ídolos de los bosques.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 8, 'Y la saña de Jehová se encendió contra Israel, y vendiólos en manos de Chusan-risathaim rey de Mesopotamia; y sirvieron los hijos de Israel á Chusan-risathaim ocho años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 9, 'Y clamaron los hijos de Israel á Jehová; y Jehová suscitó salvador á los hijos de Israel y librólos; es á saber, á Othoniel hijo de Cenez, hermano menor de Caleb.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 10, 'Y el espíritu de Jehová fué sobre él, y juzgó á Israel, y salió á batalla, y Jehová entregó en su mano á Chusan-risathaim, rey de Siria, y prevaleció su mano contra Chusan-risathaim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 11, 'Y reposó la tierra cuarenta años; y murió Othoniel, hijo de Cenez.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 12, 'Y tornaron los hijos de Israel á hacer lo malo ante los ojos de Jehová; y Jehová esforzó á Eglón rey de Moab contra Israel, por cuanto habían hecho lo malo ante los ojos de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 13, 'Y Juntó consigo á los hijos de Ammón y de Amalec, y fué, é hirió á Israel, y tomó la ciudad de las palmas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 14, 'Y sirvieron los hijos de Israel á Eglón rey de los Moabitas diez y ocho años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 15, 'Y clamaron los hijos de Israel á Jehová; y Jehová les suscitó salvador, á Aod, hijo de Gera, Benjamita, el cual tenía cerrada la mano derecha. Y los hijos de Israel enviaron con él un presente á Eglón rey de Moab.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 16, 'Y Aod se había hecho un puñal de dos filos, de un codo de largo; y ciñósele debajo de sus vestidos á su lado derecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 17, 'Y presentó el presente á Eglón rey de Moab; y era Eglón hombre muy grueso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 18, 'Y luego que hubo presentado el don, despidió á la gente que lo había traído.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 19, 'Mas él se volvió desde los ídolos que están en Gilgal, y dijo: Rey, una palabra secreta tengo que decirte. El entonces dijo: Calla. Y saliéronse de con él todos los que delante de él estaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 20, 'Y llegóse Aod á él, el cual estaba sentado solo en una sala de verano. Y Aod dijo: Tengo palabra de Dios para ti. El entonces se levantó de la silla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 21, 'Mas Aod metió su mano izquierda, y tomó el puñal de su lado derecho, y metióselo por el vientre;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 22, 'De tal manera que la empuñadura entró también tras la hoja, y la grosura encerró la hoja, que él no sacó el puñal de su vientre: y salió el estiércol.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 23, 'Y saliendo Aod al patio, cerró tras sí las puertas de la sala.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 24, 'Y salido él, vinieron sus siervos, los cuales viendo las puertas de la sala cerradas, dijeron: Sin duda él cubre sus pies en la sala de verano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 25, 'Y habiendo esperado hasta estar confusos, pues que él no abría las puertas de la sala, tomaron la llave y abrieron: y he aquí su señor caído en tierra muerto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 26, 'Mas entre tanto que ellos se detuvieron, Aod se escapó, y pasando los ídolos, salvóse en Seirath.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 27, 'Y como hubo entrado, tocó el cuerno en el monte de Ephraim, y los hijos de Israel descendieron con él del monte, y él iba delante de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 28, 'Entonces él les dijo: Seguidme, porque Jehová ha entregado vuestros enemigos los Moabitas en vuestras manos. Y descendieron en pos de él, y tomaron los vados del Jordán á Moab, y no dejaron pasar á ninguno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 29, 'Y en aquel tiempo hirieron de los Moabitas como diez mil hombres, todos valientes y todos hombres de guerra; no escapó hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 30, 'Así quedó Moab sojuzgado aquel día bajo la mano de Israel: y reposó la tierra ochenta años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 3, 31, 'Después de éste fué Samgar hijo de Anat, el cual hirió seiscientos hombres de los Filisteos con una aguijada de bueyes; y él también salvó á Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 4, 1, 'MAS los hijos de Israel tornaron á hacer lo malo en ojos de Jehová, después de la muerte de Aod.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 4, 2, 'Y Jehová los vendió en mano de Jabín rey de Canaán, el cual reinó en Asor: y el capitán de su ejército se llamaba Sísara, y él habitaba en Haroseth de las Gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 4, 3, 'Y los hijos de Israel clamaron á Jehová, porque aquél tenía nuevecientos carros herrados: y había afligido en gran manera á los hijos de Israel por veinte años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 4, 4, 'Y gobernaba en aquel tiempo á Israel una mujer, Débora, profetisa, mujer de Lapidoth:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 4, 5, 'La cual Débora habitaba debajo de una palma entre Rama y Beth-el, en el monte de Ephraim: y los hijos de Israel subían á ella á juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 4, 6, 'Y ella envió á llamar á Barac hijo de Abinoam, de Cedes de Nephtalí, y díjole: ¿No te ha mandado Jehová Dios de Israel, diciendo: Ve, y haz gente en el monte de Tabor, y toma contigo diez mil hombres de los hijos de Nephtalí, y de los hijos de Zabulón:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 4, 7, 'Y yo atraeré á ti al arroyo de Cisón á Sísara, capitán del ejército de Jabín, con sus carros y su ejército, y entregarélo en tus manos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 4, 8, 'Y Barac le respondió: Si tú fueres conmigo, yo iré: pero si no fueres conmigo, no iré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 4, 9, 'Y ella dijo: Iré contigo; mas no será tu honra en el camino que vas; porque en mano de mujer venderá Jehová á Sísara. Y levantándose Débora fué con Barac á Cedes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 4, 10, 'Y juntó Barac á Zabulón y á Nephtalí en Cedes, y subió con diez mil hombres á su mando, y Débora subió con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 4, 11, 'Y Heber Cineo, de los hijos de Hobab suegro de Moisés, se había apartado de los Cineos, y puesto su tienda hasta el valle de Zaananim, que está junto á Cedes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 4, 12, 'Vinieron pues las nuevas á Sísara como Barac hijo de Abinoam había subido al monte de Tabor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 4, 13, 'Y reunió Sísara todos sus carros, nuevecientos carros herrados, con todo el pueblo que con él estaba, desde Haroseth de las Gentes hasta el arroyo de Cisón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 4, 14, 'Entonces Débora dijo á Barac: Levántate; porque este es el día en que Jehová ha entregado á Sísara en tus manos: ¿No ha salido Jehová delante de ti? Y Barac descendió del monte de Tabor, y diez mil hombres en pos de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 4, 15, 'Y Jehová desbarató á Sísara, y á todos sus carros y á todo su ejército, á filo de espada delante de Barac: y Sísara descendió del carro, y huyó á pie.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 4, 16, 'Mas Barac siguió los carros y el ejército hasta Haroseth de las Gentes, y todo el ejército de Sísara cayó á filo de espada hasta no quedar ni uno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 4, 17, 'Y Sísara se acogió á pie á la tienda de Jael mujer de Heber Cineo; porque había paz entre Jabín rey de Asor y la casa de Heber Cineo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 4, 18, 'Y saliendo Jael á recibir á Sísara, díjole: Ven, señor mío, ven á mi, no tengas temor. Y él vino á ella á la tienda, y ella le cubrió con una manta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 4, 19, 'Y él le dijo: Ruégote me des á beber una poca de agua, que tengo sed. Y ella abrió un odre de leche y dióle de beber, y tornóle á cubrir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 4, 20, 'Y él le dijo: Estáte á la puerta de la tienda, y si alguien viniere, y te preguntare, diciendo: ¿Hay aquí alguno? Tú responderás que no.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 4, 21, 'Y Jael, mujer de Heber, tomó una estaca de la tienda, y poniendo un mazo en su mano, vino á él calladamente, y metióle la estaca por las sienes, y enclavólo en la tierra, pues él estaba cargado de sueño y cansado; y así murió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 4, 22, 'Y siguiendo Barac á Sísara, Jael salió á recibirlo, y díjole: Ven, y te mostraré al varón que tú buscas. Y él entró donde ella estaba, y he aquí Sísara yacía muerto con la estaca por la sien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 4, 23, 'Así abatió Dios aquel día á Jabín, rey de Canaán, delante de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 4, 24, 'Y la mano de los hijos de Israel comenzó á crecer y á fortificarse contra Jabín rey de Canaán, hasta que lo destruyeron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 1, 'Y AQUEL día cantó Débora, con Barac, hijo de Abinoam, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 2, 'Porque ha vengado las injurias de Israel, Porque el pueblo se ha ofrecido de su voluntad, Load á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 3, 'Oid, reyes; estad, oh príncipes, atentos: Yo cantaré á Jehová, Cantaré salmos á Jehová Dios de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 4, 'Cuando saliste de Seir, oh Jehová, Cuando te apartaste del campo de Edom, La tierra tembló, y los cielos destilaron, Y las nubes gotearon aguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 5, 'Los montes se derritieron delante de Jehová, Aqueste Sinaí, delante de Jehová Dios de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 6, 'En los días de Samgar hijo de Anath, En los días de Jael, cesaron los caminos, Y los que andaban por las sendas apartábanse por torcidos senderos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 7, 'Las aldeas habían cesado en Israel, habían decaído; Hasta que yo Débora me levanté, Me levanté madre en Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 8, 'En escogiendo nuevos dioses, La guerra estaba á las puertas: ¿Se veía escudo ó lanza Entre cuarenta mil en Israel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 9, 'Mi corazón está por los príncipes de Israel, Los que con buena voluntad se ofrecieron entre el pueblo: Load á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 10, 'Vosotros los que cabalgáis en asnas blancas, Los que presidís en juicio, Y vosotros los que viajáis, hablad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 11, 'Lejos del ruido de los archeros, en los abrevaderos, Allí repetirán las justicias de Jehová, Las justicias de sus villas en Israel; Entonces bajará el pueblo de Jehová á las puertas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 12, 'Despierta, despierta, Débora; Despierta, despierta, profiere un cántico. Levántate, Barac, y lleva tus cautivos, hijo de Abinoam.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 13, 'Entonces ha hecho que el que quedó del pueblo, señoree á los magníficos: Jehová me hizo enseñorear sobre los fuertes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 14, 'De Ephraim salió su raíz contra Amalec, Tras ti, Benjamín, contra tus pueblos; De Machîr descendieron príncipes, Y de Zabulón los que solían manejar punzón de escribiente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 15, 'Príncipes también de Issachâr fueron con Débora; Y como Issachâr, también Barac Se puso á pie en el valle. De las divisiones de Rubén Hubo grandes impresiones del corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 16, '¿Por qué te quedaste entre las majadas, Para oir los balidos de los rebaños? De las divisiones de Rubén Grandes fueron las disquisiciones del corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 17, 'Galaad se quedó de la otra parte del Jordán: Y Dan ¿por qué se estuvo junto á los navíos? Mantúvose Aser á la ribera de la mar, Y quedóse en sus puertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 18, 'El pueblo de Zabulón expuso su vida á la muerte, Y Nephtalí en las alturas del campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 19, 'Vinieron reyes y pelearon: Entonces pelearon los reyes de Canaán En Taanac, junto á las aguas de Megiddo, Mas no llevaron ganancia alguna de dinero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 20, 'De los cielos pelearon: Las estrellas desde sus órbitas pelearon contra Sísara.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 21, 'Barriólos el torrente de Cisón, El antiguo torrente, el torrente de Cisón. Hollaste, oh alma mía, con fortaleza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 22, 'Despalmáronse entonces las uñas de los caballos Por las arremetidas, por los brincos de sus valientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 23, 'Maldecid á Meroz, dijo el ángel de Jehová: Maldecid severamente á sus moradores, Porque no vinieron en socorro a Jehová, En socorro á Jehová contra los fuertes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 24, 'Bendita sea entre las mujeres Jael, Mujer de Heber Cineo; Sobre las mujeres bendita sea en la tienda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 25, 'El pidió agua, y dióle ella leche; En tazón de nobles le presentó manteca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 26, 'Su mano tendió á la estaca, Y su diestra al mazo de trabajadores; Y majó á Sísara, hirió su cabeza, Llagó y atravesó sus sienes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 27, 'Cayó encorvado entre sus pies, quedó tendido: Entre sus pies cayó encorvado; Donde se encorvó, allí cayó muerto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 28, 'La madre de Sísara se asoma á la ventana, Y por entre las celosías á voces dice: ¿Por qué se detiene su carro, que no viene? ¿Por qué las ruedas de sus carros se tardan?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 29, 'Las más avisadas de sus damas le respondían; Y aun ella se respondía á sí misma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 30, '¿No han hallado despojos, y los están repartiendo? A cada uno una moza, ó dos: Los despojos de colores para Sísara, Los despojos bordados de colores: La ropa de color bordada de ambos lados, para los cuellos de los que han tomado los despojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 5, 31, 'Así perezcan todos tus enemigos, oh Jehová: Mas los que le aman, sean como el sol cuando nace en su fuerza. Y la tierra reposó cuarenta años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 1, 'MAS los hijos de Israel hicieron lo malo en los ojos de Jehová; y Jehová los entregó en las manos de Madián por siete años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 2, 'Y la mano de Madián prevaleció contra Israel. Y los hijos de Israel, por causa de los Madianitas, se hicieron cuevas en los montes, y cavernas, y lugares fuertes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 3, 'Pues como los de Israel habían sembrado, subían los Madianitas, y Amalecitas, y los orientales: subían contra ellos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 4, 'Y asentando campo contra ellos destruían los frutos de la tierra, hasta llegar á Gaza; y no dejaban qué comer en Israel, ni ovejas, ni bueyes, ni asnos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 5, 'Porque subían ellos y sus ganados, y venían con sus tiendas en grande multitud como langosta, que no había número en ellos ni en sus camellos: así venían á la tierra para devastarla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 6, 'Era pues Israel en gran manera empobrecido por los Madianitas; y los hijos de Israel clamaron á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 7, 'Y cuando los hijos de Israel hubieron clamado á Jehová, á causa de los Madianitas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 8, 'Jehová envió un varón profeta á los hijos de Israel, el cual les dijo: Así ha dicho Jehová Dios de Israel: Yo os hice salir de Egipto, y os saqué de la casa de servidumbre:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 9, 'Yo os libré de mano de los Egipcios, y de mano de todos los que os afligieron, á los cuales eché de delante de vosotros, y os dí su tierra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 10, 'Y díjeos: Yo soy Jehová vuestro Dios; no temáis á los dioses de los Amorrheos, en cuya tierra habitáis: mas no habéis obedecido á mi voz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 11, 'Y vino el ángel de Jehová, y sentóse debajo del alcornoque que está en Ophra, el cual era de Joas Abiezerita; y su hijo Gedeón estaba sacudiendo el trigo en el lagar, para hacerlo esconder de los Madianitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 12, 'Y el ángel de Jehová se le apareció, y díjole: Jehová es contigo, varón esforzado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 13, 'Y Gedeón le respondió: Ah, Señor mío, si Jehová es con nosotros, ¿por qué nos ha sobrevenido todo esto? ¿Y dónde están todas sus maravillas, que nuestros padres nos han contado, diciendo: ¿No nos sacó Jehová de Egipto? Y ahora Jehová nos ha desamparado, y nos ha entregado en manos de los Madianitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 14, 'Y mirándole Jehová, díjole: Ve con esta tu fortaleza, y salvarás á Israel de la mano de los Madianitas. ¿No te envío yo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 15, 'Entonces le respondió: Ah, Señor mío, ¿con qué tengo de salvar á Israel? He aquí que mi familia es pobre en Manasés, y yo el menor en la casa de mi padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 16, 'Y Jehová le dijo: Porque yo seré contigo, y herirás á los Madianitas como á un solo hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 17, 'Y él respondió: Yo te ruego, que si he hallado gracia delante de ti, me des señal de que tú has hablado conmigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 18, 'Ruégote que no te vayas de aquí, hasta que á ti vuelva, y saque mi presente, y lo ponga delante de ti. Y él respondió: Yo esperaré hasta que vuelvas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 19, 'Y entrándose Gedeón aderezó un cabrito, y panes sin levadura de un epha de harina; y puso la carne en un canastillo, y el caldo en una olla, y sacándolo presentóselo debajo de aquel alcornoque.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 20, 'Y el ángel de Dios le dijo: Toma la carne, y los panes sin levadura, y ponlo sobre esta peña, y vierte el caldo. Y él lo hizo así.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 21, 'Y extendiendo el ángel de Jehová el bordón que tenía en su mano, tocó con la punta en la carne y en los panes sin levadura; y subió fuego de la peña, el cual consumió la carne y los panes sin levadura. Y el ángel de Jehová desapareció de delante de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 22, 'Y viendo Gedeón que era el ángel de Jehová, dijo: Ah, Señor Jehová, que he visto el ángel de Jehová cara á cara.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 23, 'Y Jehová le dijo: Paz á ti; no tengas temor, no morirás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 24, 'Y edificó allí Gedeón altar á Jehová, al que llamó Jehová-salom: está hasta hoy en Ophra de los Abiezeritas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 25, 'Y aconteció que la misma noche le dijo Jehová: Toma un toro del hato de tu padre, y otro toro de siete años, y derriba el altar de Baal que tu padre tiene, y corta también el bosque que está junto á él:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 26, 'Y edifica altar á Jehová tu Dios en la cumbre de este peñasco en lugar conveniente; y tomando el segundo toro, sacrifícalo en holocausto sobre la leña del bosque que habrás cortado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 27, 'Entonces Gedeón tomó diez hombres de sus siervos, é hizo como Jehová le dijo. Mas temiendo hacerlo de día, por la familia de su padre y por los hombres de la ciudad, hízolo de noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 28, 'Y á la mañana, cuando los de la ciudad se levantaron, he aquí que el altar de Baal estaba derribado, y cortado el bosque que junto á él estaba, y sacrificado aquel segundo toro en holocausto sobre el altar edificado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 29, 'Y decíanse unos á otros: ¿Quién ha hecho esto? Y buscando é inquiriendo, dijéronles: Gedeón hijo de Joas lo ha hecho. Entonces los hombres de la ciudad dijeron á Joas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 30, 'Saca fuera tu hijo para que muera, por cuanto ha derribado el altar de Baal y ha cortado el bosque que junto á él estaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 31, 'Y Joas respondió á todos los que estaban junto á él: ¿Tomaréis vosotros la demanda por Baal? ¿le salvaréis vosotros? Cualquiera que tomare la demanda por él, que muera mañana. Si es Dios, contienda por sí mismo con el que derribó su altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 32, 'Y aquel día llamó él á Gedeón Jerobaal; porque dijo: Pleitee Baal contra el que derribó su altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 33, 'Y todos los Madianitas, y Amalecitas, y orientales, se juntaron á una, y pasando asentaron campo en el valle de Jezreel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 34, 'Y el espíritu de Jehová se envistió en Gedeón, y como éste hubo tocado el cuerno, Abiezer se juntó con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 35, 'Y envió mensajeros por todo Manasés, el cual también se juntó con él: asimismo envió mensajeros á Aser, y á Zabulón, y á Nephtalí, los cuales salieron á encontrarles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 36, 'Y Gedeón dijo á Dios: Si has de salvar á Israel por mi mano, como has dicho,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 37, 'He aquí que yo pondré un vellón de lana en la era; y si el rocío estuviere en el vellón solamente, quedando seca toda la otra tierra, entonces entenderé que has de salvar á Israel por mi mano, como lo has dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 38, 'Y aconteció así: porque como se levantó de mañana, exprimiendo el vellón sacó de él el rocío, un vaso lleno de agua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 39, 'Mas Gedeón dijo á Dios: No se encienda tu ira contra mí, si aun hablare esta vez: solamente probaré ahora otra vez con el vellón. Ruégote que la sequedad sea sólo en el vellón, y el rocío sobre la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 6, 40, 'Y aquella noche lo hizo Dios así: porque la sequedad fué sólo en el vellón, y en toda la tierra estuvo el rocío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 7, 1, 'LEVANTANDOSE pues de mañana Jerobaal, el cual es Gedeón, y todo el pueblo que estaba con él, asentaron el campo junto á la fuente de Harod: y tenía el campo de los Madianitas al norte, de la otra parte del collado de More, en el valle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 7, 2, 'Y Jehová dijo á Gedeón: El pueblo que está contigo es mucho para que yo dé á los Madianitas en su mano: porque no se alabe Israel contra mí, diciendo: Mi mano me ha salvado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 7, 3, 'Haz pues ahora pregonar, que lo oiga el pueblo, diciendo: El que teme y se estremece, madrugue y vuélvase desde el monte de Galaad. Y volviéronse de los del pueblo veintidós mil: y quedaron diez mil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 7, 4, 'Y Jehová dijo á Gedeón: Aun es mucho el pueblo; llévalos á las aguas, y allí yo te los probaré; y del que yo te dijere: Vaya este contigo, vaya contigo: mas de cualquiera que yo te dijere: Este no vaya contigo, el tal no vaya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 7, 5, 'Entonces llevó el pueblo á las aguas: y Jehová dijo á Gedeón: Cualquiera que lamiere las aguas con su lengua como lame el perro, aquél pondrás aparte; asimismo cualquiera que se doblare sobre sus rodillas para beber.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 7, 6, 'Y fué el número de los que lamieron las aguas, llegándola con la mano á la boca, trescientos hombres: y todo el resto del pueblo se dobló sobre sus rodillas para beber las aguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 7, 7, 'Entonces Jehová dijo á Gedeón: Con estos trescientos hombres que lamieron el agua os salvaré, y entregaré á los Madianitas en tus manos: y váyase toda la gente cada uno á su lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 7, 8, 'Y tomada provisión para el pueblo en sus manos, y sus bocinas, envió á todos los Israelitas cada uno á su tienda, y retuvo á aquellos trescientos hombres: y tenía el campo de Madián abajo en el valle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 7, 9, 'Y aconteció que aquella noche Jehová le dijo: Levántate, y desciende al campo; porque yo lo he entregado en tus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 7, 10, 'Y si tienes temor de descender, baja tú con Phara tu criado al campo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 7, 11, 'Y oirás lo que hablan; y entonces tus manos se esforzarán, y descenderás al campo. Y él descendió con Phara su criado al principio de la gente de armas que estaba en el campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 7, 12, 'Y Madián, y Amalec, y todos los orientales, estaban tendidos en el valle como langostas en muchedumbre, y sus camellos eran innumerables, como la arena que está á la ribera de la mar en multitud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 7, 13, 'Y luego que llegó Gedeón, he aquí que un hombre estaba contando á su compañero un sueño, diciendo: He aquí yo soñé un sueño: que veía un pan de cebada que rodaba hasta el campo de Madián, y llegaba á las tiendas, y las hería de tal manera que caían, y las trastornaba de arriba abajo, y las tiendas caían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 7, 14, 'Y su compañero respondió, y dijo: Esto no es otra cosa sino la espada de Gedeón hijo de Joas, varón de Israel: Dios ha entregado en sus manos á los Madianitas con todo el campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 7, 15, 'Y como Gedeón oyó la historia del sueño y su interpretación, adoró; y vuelto al campo de Israel, dijo: Levantaos, que Jehová ha entregado el campo de Madián en vuestras manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 7, 16, 'Y repartiendo los trescientos hombres en tres escuadrones, dió á cada uno de ellos bocinas en sus manos, y cántaros vacíos con teas ardiendo dentro de los cántaros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 7, 17, 'Y díjoles: Miradme á mí, y haced como yo hiciere; he aquí que cuando yo llegare al principio del campo, como yo hiciere, así haréis vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 7, 18, 'Yo tocaré la bocina y todos los que estarán conmigo; y vosotros tocaréis entonces las bocinas alrededor de todo el campo, y diréis: ¡Por Jehová y Gedeón!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 7, 19, 'Llegó pues Gedeón, y los cien hombres que llevaba consigo, al principio del campo, á la entrada de la vela del medio, cuando acababan de renovar las centinelas; y tocaron las bocinas, y quebraron los cántaros que llevaban en sus manos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 7, 20, 'Y los tres escuadrones tocaron las bocinas, y quebrando los cántaros tomaron en las manos izquierdas las teas, y en las derechas los cuernos con que tañian, y dieron grita: ¡La espada de Jehová y de Gedeón!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 7, 21, 'Y estuviéronse en sus lugares en derredor del campo: y todo el campo fué alborotado, y huyeron gritando.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 7, 22, 'Mas los trescientos tocaban las bocinas: y Jehová puso la espada de cada uno contra su compañero en todo el campo. Y el ejército huyó hasta Beth-sitta, hacia Cerera, y hasta el término de Abel-mehola en Tabbat.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 7, 23, 'Y juntándose los de Israel, de Nephtalí, y de Aser, y de todo Manasés, siguieron á los Madianitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 7, 24, 'Gedeón también envió mensajeros á todo el monte de Ephraim, diciendo: Descended al encuentro de los Madianitas, y tomadles las aguas hasta Beth-bara y el Jordán. Y juntos todos los hombres de Ephraim, tomaron las aguas de Beth-bara y el Jordán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 7, 25, 'Y tomaron dos príncipes de los Madianitas, Oreb y Zeeb: y mataron á Oreb en la peña de Oreb, y á Zeeb lo mataron en el lagar de Zeeb: y después que siguieron á los Madianitas, trajeron las cabezas de Oreb y de Zeeb á Gedeón de la otra parte del Jordán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 1, 'Y LOS de Ephraim le dijeron: ¿Qué es esto que has hecho con nosotros, no llamándonos cuando ibas á la guerra contra Madián? Y reconviniéronlo fuertemente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 2, 'A los cuales él respondió: ¿Qué he hecho yo ahora como vosotros? ¿No es el rebusco de Ephraim mejor que la vendimia de Abiezer?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 3, 'Dios ha entregado en vuestras manos á Oreb y á Zeeb, príncipes de Madián: ¿y qué pude yo hacer como vosotros? Entonces el enojo de ellos contra él se aplacó, luego que él habló esta palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 4, 'Y vino Gedeón al Jordán para pasar, él y los trescientos hombres que traía consigo, cansados del alcance.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 5, 'Y dijo á los de Succoth: Yo os ruego que deis á la gente que me sigue algunos bocados de pan; porque están cansados, y yo persigo á Zeba y á Zalmunna, reyes de Madián.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 6, 'Y los principales de Succoth respondieron: ¿Está ya la mano de Zeba y Zalmunna en tu mano, para que hayamos nosotros de dar pan á tu ejército?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 7, 'Y Gedeón dijo: Pues cuando Jehová hubiere entregado en mi mano á Zeba y á Zalmunna, yo trillaré vuestra carne con espinas y abrojos del desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 8, 'Y de allí subió á Penuel, y hablóles las mismas palabras. Y los de Penuel le respondieron como habían respondido los de Succoth.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 9, 'Y él habló también á los de Penuel, diciendo: Cuando yo tornare en paz, derribaré esta torre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 10, 'Y Zeba y Zalmunna estaban en Carcor, y con ellos su ejército de como quince mil hombres, todos los que habían quedado de todo el campo de los orientales: y los muertos habían sido ciento veinte mil hombres que sacaban espada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 11, 'Y subiendo Gedeón hacia los que habitaban en tiendas, á la parte oriental de Noba y de Jogbea, hirió el campo, porque estaba el ejército sin recelo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 12, 'Y huyendo Zeba y Zalmunna, él los siguió; y tomados los dos reyes de Madián, Zeba y Zalmunna, espantó á todo el ejército.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 13, 'Y Gedeón hijo de Joas volvió de la batalla antes que el sol subiese;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 14, 'Y tomó un mozo de los de Succoth, y preguntándole, él le dió por escrito los principales de Succoth y sus ancianos, setenta y siete varones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 15, 'Y entrando á los de Succoth, dijo: He aquí á Zeba y á Zalmunna, sobre los cuales me zaheristeis, diciendo: ¿Está ya la mano de Zeba y de Zalmunna en tu mano, para que demos nosotros pan á tus hombres cansados?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 16, 'Y tomó á los ancianos de la ciudad, y espinas y abrojos del desierto, y castigó con ellos á los de Succoth.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 17, 'Asimismo derribó la torre de Penuel, y mató á los de la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 18, 'Luego dijo á Zeba y á Zalmunna: ¿Qué manera de hombres tenían aquellos que matasteis en Tabor? Y ellos respondieron: Como tú, tales eran aquellos ni más ni menos, que parecían hijos de rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 19, 'Y él dijo: Mis hermanos eran, hijos de mi madre: ¡Vive Jehová, que si los hubierais guardado en vida, yo no os mataría!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 20, 'Y dijo á Jether su primogénito: Levántate, y mátalos. Mas el joven no desenvainó su espada, porque tenía temor; que aun era muchacho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 21, 'Entonces dijo Zeba y Zalmunna: Levántate tú, y mátanos; porque como es el varón, tal es su valentía. Y Gedeón se levantó, y mató á Zeba y á Zalmunna; y tomó los adornos de lunetas que sus camellos traían al cuello.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 22, 'Y los Israelitas dijeron á Gedeón: Sé nuestro señor, tú, y tu hijo, y tu nieto; pues que nos has librado de mano de Madián.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 23, 'Mas Gedeón respondió: No seré señor sobre vosotros, ni mi hijo os señoreará: Jehová será vuestro Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 24, 'Y díjoles Gedeón: Deseo haceros una petición, que cada uno me dé los zarcillos de su despojo. (Porque traían zarcillos de oro, que eran Ismaelitas.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 25, 'Y ellos respondieron: De buena gana los daremos. Y tendiendo una ropa de vestir, echó allí cada uno los zarcillos de su despojo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 26, 'Y fué el peso de los zarcillos de oro que él pidió, mil y setecientos siclos de oro; sin las planchas, y joyeles, y vestidos de púrpura, que traían los reyes de Madián, y sin los collares que traían sus camellos al cuello.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 27, 'Y Gedeón hizo de ellos un ephod, el cual hizo guardar en su ciudad de Ophra: y todo Israel fornicó tras de ese ephod en aquel lugar; y fué por tropiezo á Gedeón y á su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 28, 'Así fué humillado Madián delante de los hijos de Israel, y nunca más levantaron su cabeza. Y reposó la tierra cuarenta años en los días de Gedeón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 29, 'Y Jerobaal hijo de Joas fué, y habitó en su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 30, 'Y tuvo Gedeón setenta hijos que salieron de su muslo, porque tuvo muchas mujeres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 31, 'Y su concubina que estaba en Sichêm, también le parió un hijo; y púsole por nombre Abimelech.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 32, 'Y murió Gedeón hijo de Joas en buena vejez, y fué sepultado en el sepulcro de su padre Joas, en Ophra de los Abiezeritas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 33, 'Y aconteció que como murió Gedeón, los hijos de Israel tornaron, y fornicaron en pos de los Baales, y se pusieron por Dios á Baal-berith.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 34, 'Y no se acordaron los hijos de Israel de Jehová su Dios, que los había librado de todos sus enemigos alrededor:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 8, 35, 'Ni hicieron misericordia con la casa de Jerobaal Gedeón conforme á todo el bien que él había hecho á Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 1, 'Y FUÉSE Abimelech hijo de Jerobaal á Sichêm, á los hermanos de su madre, y habló con ellos, y con toda la familia de la casa del padre de su madre, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 2, 'Yo os ruego que habléis á oídos de todos los de Sichêm: ¿Qué tenéis por mejor, que os señoreen setenta hombres, todos los hijos de Jerobaal; ó que os señoree un varón? Acordaos que yo soy hueso vuestro, y carne vuestra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 3, 'Y hablaron por él los hermanos de su madre á oídos de todos los de Sichêm todas estas palabras: y el corazón de ellos se inclinó en favor de Abimelech, porque decían: Nuestro hermano es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 4, 'Y diéronle setenta siclos de plata del templo de Baal-berith, con los cuales Abimelech alquiló hombres ociosos y vagabundos, que le siguieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 5, 'Y viniendo á la casa de su padre en Ophra, mató á sus hermanos los hijos de Jerobaal, setenta varones, sobre una piedra: mas quedó Jotham, el más pequeño hijo de Jerobaal, que se escondió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 6, 'Y reunidos todos los de Sichêm con toda la casa de Millo, fueron y eligieron á Abimelech por rey, cerca de la llanura del pilar que estaba en Sichêm.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 7, 'Y como se lo dijesen á Jotham, fué y púsose en la cumbre del monte de Gerizim, y alzando su voz clamó, y díjoles: Oidme, varones de Sichêm; que Dios os oiga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 8, 'Fueron los árboles á elegir rey sobre sí, y dijeron á la oliva: Reina sobre nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 9, 'Mas la oliva respondió: ¿Tengo de dejar mi pingüe jugo, con el que por mi causa Dios y los hombres son honrados, por ir á ser grande sobre los árboles?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 10, 'Y dijeron los árboles á la higuera: Anda tú, reina sobre nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 11, 'Y respondió la higuera: ¿Tengo de dejar mi dulzura y mi buen fruto, por ir á ser grande sobre los árboles?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 12, 'Dijeron luego los árboles á la vid: Pues ven tú, reina sobre nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 13, 'Y la vid les respondió: ¿Tengo de dejar mi mosto, que alegra á Dios y á los hombres, por ir á ser grande sobre los árboles?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 14, 'Dijeron entonces todos los árboles al escaramujo: Anda tú, reina sobre nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 15, 'Y el escaramujo respondió á los árboles: Si en verdad me elegís por rey sobre vosotros, venid, y aseguraos debajo de mi sombra: y si no, fuego salga del escaramujo que devore los cedros del Líbano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 16, 'Ahora pues, si con verdad y con integridad habéis procedido en hacer rey á Abimelech, y si lo habéis hecho bien con Jerobaal y con su casa, y si le habéis pagado conforme á la obra de sus manos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 17, '(Pues que mi padre peleó por vosotros, y echó lejos su vida por libraros de mano de Madián;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 18, 'Y vosotros os levantasteis hoy contra la casa de mi padre, y matasteis sus hijos, setenta varones, sobre una piedra; y habéis puesto por rey sobre los de Sichêm á Abimelech, hijo de su criada, por cuanto es vuestro hermano:)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 19, 'Si con verdad y con integridad habéis obrado hoy con Jerobaal y con su casa, que gocéis de Abimelech, y él goce de vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 20, 'Y si no, fuego salga de Abimelech, que consuma á los de Sichêm y á la casa de Millo; y fuego salga de los de Sichêm y de la casa de Millo, que consuma á Abimelech.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 21, 'Y huyó Jotham, y se fugó, y fuése á Beer, y allí se estuvo por causa de Abimelech su hermano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 22, 'Y después que Abimelech hubo dominado sobre Israel tres años,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 23, 'Envió Dios un espíritu malo entre Abimelech y los hombres de Sichêm: que los de Sichêm se levantaron contra Abimelech:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 24, 'Para que el agravio de los setenta hijos de Jerobaal, y la sangre de ellos, viniera á ponerse sobre Abimelech su hermano que los mató, y sobre los hombres de Sichêm que corroboraron las manos de él para matar á sus hermanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 25, 'Y pusiéronle los de Sichêm asechadores en las cumbres de los montes, los cuales salteaban á todos los que pasaban junto á ellos por el camino; de lo que fué dado aviso á Abimelech.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 26, 'Y Gaal hijo de Ebed vino con sus hermanos, y pasáronse á Sichêm: y los de Sichêm se confiaron en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 27, 'Y saliendo al campo, vendimiaron sus viñas, y pisaron la uva, é hicieron alegrías; y entrando en el templo de sus dioses, comieron y bebieron, y maldijeron á Abimelech.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 28, 'Y Gaal hijo de Ebed dijo: ¿Quién es Abimelech y qué es Sichêm, para que nosotros á él sirvamos? ¿no es hijo de Jerobaal? ¿y no es Zebul su asistente? Servid á los varones de Hemor padre de Sichêm: mas ¿por qué habíamos de servir á él?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 29, 'Fuérame dado este pueblo bajo de mi mano, yo echaría luego á Abimelech. Y decía á Abimelech: Aumenta tus escuadrones, y sal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 30, 'Y Zebul asistente de la ciudad, oyendo las palabras de Gaal hijo de Ebed, encendióse su ira;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 31, 'Y envió sagazmente mensajeros á Abimelech, diciendo: He aquí que Gaal hijo de Ebed y sus hermanos han venido á Sichêm, y he aquí, que han cercado la ciudad contra ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 32, 'Levántate pues ahora de noche, tú y el pueblo que está contigo, y pon emboscada en el campo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 33, 'Y por la mañana al salir del sol te levantarás y acometerás la ciudad: y él y el pueblo que está con él saldrán contra ti, y tu harás con él según que se te ofrecerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 34, 'Levantándose pues de noche Abimelech y todo el pueblo que con él estaba, pusieron emboscada contra Sichêm con cuatro compañías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 35, 'Y Gaal hijo de Ebed salió, y púsose á la entrada de la puerta de la ciudad: y Abimelech y todo el pueblo que con él estaba, se levantaron de la emboscada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 36, 'Y viendo Gaal el pueblo, dijo á Zebul: He allí pueblo que desciende de las cumbres de los montes. Y Zebul le respondió: La sombra de los montes te parece hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 37, 'Mas Gaal tornó á hablar, y dijo: He allí pueblo que desciende por medio de la tierra, y un escuadrón viene camino de la campiña de Meonenim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 38, 'Y Zebul le respondió: ¿Dónde está ahora aquel tu hablar, diciendo; Quién es Abimelech para que le sirvamos? ¿No es este el pueblo que tenías en poco? Sal pues ahora, y pelea con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 39, 'Y Gaal salió delante de los de Sichêm, y peleó contra Abimelech.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 40, 'Mas persiguiólo Abimelech, delante del cual él huyó; y cayeron heridos muchos hasta la entrada de la puerta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 41, 'Y Abimilech se quedó en Aruma; y Zebul echó fuera á Gaal y á sus hermanos, para que no morasen en Sichêm.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 42, 'Y aconteció al siguiente día, que el pueblo salió al campo: y fué dado aviso á Abimelech.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 43, 'El cual, tomando gente, repartióla en tres compañías, y puso emboscadas en el campo: y como miró, he aquí el pueblo que salía de la ciudad; y levantóse contra ellos, é hiriólos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 44, 'Pues Abimelech y el escuadrón que estaba con él, acometieron con ímpetu, y pararon á la entrada de la puerta de la ciudad; y las dos compañías acometieron á todos los que estaban en el campo, y los hirieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 45, 'Y después de combatir Abimelech la ciudad todo aquel día, tomóla, y mató el pueblo que en ella estaba, y asoló la ciudad, y sembróla de sal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 46, 'Como oyeron esto todos los que estaban en la torre de Sichêm, entráronse en la fortaleza del templo del dios Berith.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 47, 'Y fué dicho á Abimelech como todos los de la torre de Sichêm estaban reunidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 48, 'Entonces subió Abimelech al monte de Salmón, él y toda la gente que con él estaba; y tomó Abimelech un hacha en su mano, y cortó una rama de los árboles, y levantándola púsosela sobre sus hombros, diciendo al pueblo que estaba con él: Lo que me veis á mí que hago, haced vosotros prestamente como yo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 49, 'Y así todo el pueblo cortó también cada uno su rama, y siguieron á Abimelech, y pusiéronlas junto á la fortaleza, y prendieron fuego con ellas á la fortaleza: por manera que todos los de la torre de Sichêm murieron, como unos mil hombres y mujeres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 50, 'Después Abimelech se fué á Thebes; y puso cerco á Thebes, y tomóla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 51, 'En medio de aquella ciudad había una torre fuerte, á la cual se retiraron todos los hombres y mujeres, y todos los señores de la ciudad; y cerrando tras sí las puertas, subiéronse al piso alto de la torre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 52, 'Y vino Abimelech á la torre, y combatiéndola, llegóse á la puerta de la torre para pegarle fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 53, 'Mas una mujer dejó caer un pedazo de una rueda de molino sobre la cabeza de Abimelech, y quebróle los cascos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 54, 'Y luego llamó él á su escudero, y díjole: Saca tu espada y mátame, porque no se diga de mí: Una mujer lo mató. Y su escudero le atravesó, y murió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 55, 'Y como los Israelitas vieron muerto á Abimelech, fuéronse cada uno á su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 56, 'Así pues pagó Dios á Abimelech el mal que hizo contra su padre matando á sus setenta hermanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 9, 57, 'Y aun todo el mal de los hombres de Sichêm tornó Dios sobre sus cabezas: y la maldición de Jotham, hijo de Jerobaal, vino sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 10, 1, 'Y DESPUÉS de Abimelech levantóse para librar á Israel, Tola hijo de Púa, hijo de Dodo, varón de Issachâr, el cual habitaba en Samir, en el monte de Ephraim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 10, 2, 'Y juzgó á Israel veintitrés años, y murió, y fué sepultado en Samir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 10, 3, 'Tras él se levantó Jair, Galaadita, el cual juzgó á Israel veintidós años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 10, 4, 'Este tuvo treinta hijos que cabalgaban sobre treinta asnos, y tenían treinta villas, que se llamaron las villas de Jair hasta hoy, las cuales están en la tierra de Galaad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 10, 5, 'Y murió Jair, y fué sepultado en Camón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 10, 6, 'Mas los hijos de Israel tornaron á hacer lo malo en los ojos de Jehová, y sirvieron á los Baales y á Astaroth, y á los dioses de Siria, y á los dioses de Sidón, y á los dioses de Moab, y á los dioses de los hijos de Ammón, y á los dioses de los Filisteos: y dejaron á Jehová, y no le sirvieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 10, 7, 'Y Jehová se airó contra Israel, y vendiólos en mano de los Filisteos, y en mano de los hijos de Ammón:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 10, 8, 'Los cuales molieron y quebrantaron á los hijos de Israel en aquel tiempo dieciocho años, á todos los hijos de Israel que estaban de la otra parte del Jordán en la tierra del Amorrheo, que es en Galaad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 10, 9, 'Y los hijos de Ammón pasaron el Jordán para hacer también guerra contra Judá, y contra Benjamín, y la casa de Ephraim: y fué Israel en gran manera afligido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 10, 10, 'Y los hijos de Israel clamaron á Jehová, diciendo: Nosotros hemos pecado contra ti; porque hemos dejado á nuestro Dios, y servido á los Baales.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 10, 11, 'Y Jehová respondió á los hijos de Israel: ¿No habéis sido oprimidos de Egipto, de los Amorrheos, de Losammonitas, de los Filisteos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 10, 12, 'De los de Sidón, de Amalec, y de Maón, y clamando á mí os he librado de sus manos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 10, 13, 'Mas vosotros me habéis dejado, y habéis servido á dioses ajenos: por tanto, yo no os libraré más.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 10, 14, 'Andad, y clamad á los dioses que os habéis elegido, que os libren en el tiempo de vuestra aflicción.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 10, 15, 'Y los hijos de Israel respondieron á Jehová: Hemos pecado; haz tú con nosotros como bien te pareciere: solamente que ahora nos libres en este día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 10, 16, 'Y quitaron de entre sí los dioses ajenos, y sirvieron á Jehová: y su alma fué angustiada á causa del trabajo de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 10, 17, 'Y juntándose los hijos de Ammón, asentaron campo en Galaad: juntáronse asimismo los hijos de Israel, y asentaron su campo en Mizpa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 10, 18, 'Y los príncipes y el pueblo de Galaad dijeron el uno al otro: ¿Quién será el que comenzará la batalla contra los hijos de Ammón? él será cabeza sobre todos los que habitan en Galaad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 1, 'EXISTIA entonces Jephté, Galaadita, hombre valiente, hijo de una ramera, al cual había engendrado Galaad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 2, 'Y la mujer de Galaad también le había parido hijos; los cuales cuando fueron grandes, echaron fuera á Jephté, diciéndole: No heredarás en la casa de nuestro padre, porque eres bastardo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 3, 'Huyendo pues Jephté á causa de sus hermanos, habitó en tierra de Tob; y juntáronse con él hombres ociosos, los cuales con él salían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 4, 'Y aconteció que después de días los hijos de Ammón hicieron guerra contra Israel:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 5, 'Y como los hijos de Ammón tenían guerra contra Israel, los ancianos de Galaad fueron para volver á Jephté de tierra de Tob;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 6, 'Y dijeron á Jephté: Ven, y serás nuestro capitán, para que peleemos con los hijos de Ammón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 7, 'Y Jephté respondió á los ancianos de Galaad: ¿No me habéis vosotros aborrecido, y me echasteis de la casa de mi padre? ¿por qué pues venís ahora á mí cuando estáis en aflicción?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 8, 'Y los ancianos de Galaad respondieron á Jephté: Por esta misma causa tornamos ahora á ti, para que vengas con nosotros, y pelees contra los hijos de Ammón, y nos seas cabeza á todos los que moramos en Galaad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 9, 'Jephté entonces dijo á los ancianos de Galaad: Si me volvéis para que pelee contra los hijos de Ammón, y Jehová los entregare delante de mí, ¿seré yo vuestra cabeza?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 10, 'Y los ancianos de Galaad respondieron á Jephté: Jehová oiga entre nosotros, si no hiciéremos como tú dices.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 11, 'Entonces Jephté vino con los ancianos de Galaad, y el pueblo lo eligió por su cabeza y príncipe; y Jephté habló todas sus palabras delante de Jehová en Mizpa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 12, 'Y envió Jephté embajadores al rey de los Ammonitas, diciendo: ¿Qué tienes tú conmigo que has venido á mí para hacer guerra en mi tierra?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 13, 'Y el rey de los Ammonitas respondió á los embajadores de Jephté: Por cuanto Israel tomó mi tierra, cuando subió de Egipto, desde Arnón hasta Jaboc y el Jordán; por tanto, devuélvelas ahora en paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 14, 'Y Jephté tornó á enviar otros embajadores al rey de los Ammonitas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 15, 'Para decirle: Jephté ha dicho así: Israel no tomó tierra de Moab, ni tierra de los hijos de Ammón:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 16, 'Mas subiendo Israel de Egipto, anduvo por el desierto hasta el mar Bermejo, y llegó á Cades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 17, 'Entonces Israel envió embajadores al rey de Edom, diciendo: Yo te ruego que me dejes pasar por tu tierra. Mas el rey de Edom no los escuchó. Envió también al rey de Moab; el cual tampoco quiso: quedóse por tanto Israel en Cades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 18, 'Después, yendo por el desierto, rodeó la tierra de Edom y la tierra de Moab, y viniendo por el lado oriental de la tierra de Moab, asentó su campo de estotra parte de Arnón, y no entraron por el término de Moab: porque Arnón término es de Moab.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 19, 'Y envió Israel embajadores á Sehón rey de los Amorrheos, rey de Hesbón, diciéndole: Ruégote que me dejes pasar por tu tierra hasta mi lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 20, 'Mas Sehón no se fió de Israel para darle paso por su término; antes juntando Sehón toda su gente, puso campo en Jaas, y peleó contra Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 21, 'Empero Jehová el Dios de Israel entregó á Sehón y á todo su pueblo en mano de Israel, y venciólos: y poseyó Israel toda la tierra del Amorrheo que habitaba en aquel país.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 22, 'Poseyeron también todo el término del Amorrheo desde Arnón hasta Jaboc, y desde el desierto hasta el Jordán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 23, 'Así que Jehová el Dios de Israel echó los Amorrheos delante de su pueblo Israel: ¿y lo has de poseer tú?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 24, 'Si Chêmos tu Dios te echase alguno, ¿no lo poseerías tú? Así poseeremos nosotros á todo aquel que echó Jehová nuestro Dios de delante de nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 25, '¿Eres tú ahora en algo mejor que Balac hijo de Sephor, rey de Moab? ¿tuvo él cuestión contra Israel, ó hizo guerra contra ellos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 26, 'Cuando Israel ha estado habitando por trescientos años á Hesbón y sus aldeas, á Aroer y sus aldeas, y todas las ciudades que están á los términos de Arnón, ¿por qué no las habéis reclamado en ese tiempo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 27, 'Así que, yo nada he pecado contra ti, mas tú haces mal conmigo haciéndome guerra: Jehová, que es el juez, juzgue hoy entre los hijos de Israel y los hijos de Ammón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 28, 'Mas el rey de los hijos de Ammón no atendió las razones de Jephté que le envió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 29, 'Y el espíritu de Jehová fué sobre Jephté: y pasó por Galaad y Manasés; y de allí pasó á Mizpa de Galaad; y de Mizpa de Galaad pasó á los hijos de Ammón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 30, 'Y Jephté hizo voto á Jehová, diciendo: Si entregares á los Ammonitas en mis manos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 31, 'Cualquiera que me saliere á recibir de las puertas de mi casa, cuando volviere de los Ammonitas en paz, será de Jehová, y le ofreceré en holocausto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 32, 'Pasó pues Jephté á los hijos de Ammón para pelear contra ellos; y Jehová los entregó en su mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 33, 'Y los hirió de grandísimo estrago desde Aroer hasta llegar á Minnith, veinte ciudades; y hasta la vega de las viñas. Así fueron domeñados los Ammonitas delante de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 34, 'Y volviendo Jephté á Mizpa á su casa, he aquí que su hija le salió á recibir con adufes y danzas, y era la sola, la única suya; no tenía fuera de ella otro hijo ni hija.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 35, 'Y como él la vió, rompió sus vestidos diciendo: ¡Ay, hija mía! de verdad me has abatido, y tú eres de los que me afligen: porque yo he abierto mi boca á Jehová, y no podré retractarme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 36, 'Ella entonces le respondió: Padre mío, si has abierto tu boca á Jehová, haz de mí como salió de tu boca, pues que Jehová ha hecho venganza en tus enemigos los hijos de Ammón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 37, 'Y tornó á decir á su padre: Hágasme esto: déjame por dos meses que vaya y descienda por los montes, y llore mi virginidad, yo y mis compañeras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 38, 'El entonces dijo: Ve. Y dejóla por dos meses. Y ella fué con sus compañeras, y lloró su virginidad por los montes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 39, 'Pasados los dos meses volvió á su padre, é hizo de ella conforme á su voto que había hecho. Y ella nunca conoció varón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 11, 40, 'De aquí fué la costumbre en Israel que de año en año iban las doncellas de Israel á endechar á la hija de Jephté Galaadita, cuatro días en el año.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 12, 1, 'Y JUNTANDOSE los varones de Ephraim, pasaron hacia el aquilón, y dijeron á Jephté: ¿Por qué fuiste á hacer guerra contra los hijos de Ammón, y no nos llamaste para que fuéramos contigo? Nosotros quemaremos á fuego tu casa contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 12, 2, 'Y Jephté les respondió: Yo tuve, y mi pueblo, una gran contienda con los hijos de Ammón, y os llamé, y no me defendisteis de sus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 12, 3, 'Viendo pues que no me defendíais, puse mi alma en mi palma, y pasé contra los hijos de Ammón, y Jehová los entregó en mi mano: ¿por qué pues habéis subido hoy contra mí para pelear conmigo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 12, 4, 'Y juntando Jephté á todos los varones de Galaad, peleó contra Ephraim; y los de Galaad hirieron á Ephraim, porque habían dicho: Vosotros sois fugitivos de Ephraim, vosotros sois Galaaditas entre Ephraim y Manasés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 12, 5, 'Y los Galaaditas tomaron los vados del Jordán á Ephraim; y era que, cuando alguno de los de Ephraim que había huído, decía, ¿pasaré? los de Galaad le preguntaban: ¿Eres tú Ephrateo? Si él respondía, No;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 12, 6, 'Entonces le decían: Ahora pues, di, Shiboleth. Y él decía, Siboleth; porque no podía pronunciar de aquella suerte. Entonces le echaban mano, y le degollaban junto á los vados del Jordán. Y murieron entonces de los de Ephraim cuarenta y dos mil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 12, 7, 'Y Jephté juzgó á Israel seis años: luego murió Jephté Galaadita, y fué sepultado en una de las ciudades de Galaad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 12, 8, 'Después de él juzgó á Israel Ibzan de Beth-lehem;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 12, 9, 'El cual tuvo treinta hijos y treinta hijas, las cuales casó fuera, y tomó de fuera treinta hijas para sus hijos: y juzgó á Israel siete años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 12, 10, 'Y murió Ibzan, y fué sepultado en Beth-lehem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 12, 11, 'Después de él juzgó á Israel Elón, Zabulonita, el cual juzgó á Israel diez años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 12, 12, 'Y murió Elón, Zabulonita, y fué sepultado en Ajalón en la tierra de Zabulón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 12, 13, 'Después de él juzgó á Israel Abdón hijo de Hillel, Piratonita.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 12, 14, 'Este tuvo cuarenta hijos y treinta nietos, que cabalgaban sobre setenta asnos: y juzgó á Israel ocho años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 12, 15, 'Y murió Abdón hijo de Hillel, Piratonita, y fué sepultado en Piratón, en la tierra de Ephraim, en el monte de Amalec.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 13, 1, 'Y LOS hijos de Israel tornaron á hacer lo malo en los ojos de Jehová; y Jehová los entregó en mano de los Filisteos, por cuarenta años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 13, 2, 'Y había un hombre de Sora, de la tribu de Dan, el cual se llamaba Manoa; y su mujer era estéril, que nunca había parido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 13, 3, 'A esta mujer apareció el ángel de Jehová, y díjole: He aquí que tú eres estéril, y no has parido: mas concebirás y parirás un hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 13, 4, 'Ahora, pues, mira que ahora no bebas vino, ni sidra, ni comas cosa inmunda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 13, 5, 'Porque tú te harás embarazada, y parirás un hijo: y no subirá navaja sobre su cabeza, porque aquel niño será Nazareo á Dios desde el vientre, y él comenzará á salvar á Israel de mano de los Filisteos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 13, 6, 'Y la mujer vino y contólo á su marido, diciendo: Un varón de Dios vino á mí, cuyo aspecto era como el aspecto de un ángel de Dios, terrible en gran manera; y no le pregunté de dónde ni quién era, ni tampoco él me dijo su nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 13, 7, 'Y díjome: He aquí que tú concebirás, y parirás un hijo: por tanto, ahora no bebas vino, ni sidra, ni comas cosa inmunda; porque este niño desde el vientre será Nazareo á Dios hasta el día de su muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 13, 8, 'Entonces oró Manoa á Jehová, y dijo: Ah, Señor mío, yo te ruego que aquel varón de Dios que enviaste, torne ahora á venir á nosotros, y nos enseñe lo que hayamos de hacer con el niño que ha de nacer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 13, 9, 'Y Dios oyó la voz de Manoa: y el ángel de Dios volvió otra vez á la mujer, estando ella en el campo; mas su marido Manoa no estaba con ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 13, 10, 'Y la mujer corrió prontamente, y noticiólo á su marido, diciéndole: Mira que se me ha aparecido aquel varón que vino á mí el otro día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 13, 11, 'Y levantóse Manoa, y siguió á su mujer; y así que llegó al varón, díjole: ¿Eres tú aquel varón que hablaste á la mujer? Y él dijo: Yo soy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 13, 12, 'Entonces Manoa dijo: Cúmplase pues tu palabra. ¿Qué orden se tendrá con el niño, y qué ha de hacer?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 13, 13, 'Y el ángel de Jehová respondió á Manoa: La mujer se guardará de todas las cosas que yo le dije:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 13, 14, 'Ella no comerá cosa que proceda de vid que da vino; no beberá vino ni sidra, y no comerá cosa inmunda: ha de guardar todo lo que le mandé.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 13, 15, 'Entonces Manoa dijo al ángel de Jehová: Ruégote permitas que te detengamos, y aderezaremos un cabrito que poner delante de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 13, 16, 'Y el ángel de Jehová respondió á Manoa: Aunque me detengas no comeré de tu pan: mas si quisieres hacer holocausto, sacrifícalo á Jehová. Y no sabía Manoa que aquél fuese ángel de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 13, 17, 'Entonces dijo Manoa al ángel de Jehová: ¿Cómo es tu nombre, para que cuando se cumpliere tu palabra te honremos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 13, 18, 'Y el ángel de Jehová respondió: ¿Por qué preguntas por mi nombre, que es oculto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 13, 19, 'Y Manoa tomó un cabrito de las cabras y un presente, y sacrificólo sobre una peña á Jehová: y el ángel hizo milagro á vista de Manoa y de su mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 13, 20, 'Porque aconteció que como la llama subía del altar hacia el cielo, el ángel de Jehová subió en la llama del altar á vista de Manoa y de su mujer, los cuales se postraron en tierra sobre sus rostros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 13, 21, 'Y el ángel de Jehová no tornó á aparecer á Manoa ni á su mujer. Entonces conoció Manoa que era el ángel de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 13, 22, 'Y dijo Manoa á su mujer: Ciertamente moriremos, porque á Dios hemos visto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 13, 23, 'Y su mujer le respondió: Si Jehová nos quisiera matar, no tomara de nuestras manos el holocausto y el presente, ni nos hubiera mostrado todas estas cosas, ni en tal tiempo nos habría anunciado esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 13, 24, 'Y la mujer parió un hijo, y llamóle por nombre Samsón. Y el niño creció, y Jehová lo bendijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 13, 25, 'Y el espíritu de Jehová comenzó á manifestarse en él en los campamentos de Dan, entre Sora y Esthaol.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 14, 1, 'Y DESCENDIENDO Samsón á Timnah, vió en Timnah una mujer de las hijas de los Filisteos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 14, 2, 'Y subió, y declarólo á su padre y á su madre, diciendo: Yo he visto en Timnah una mujer de las hijas de los Filisteos: ruégoos que me la toméis por mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 14, 3, 'Y su padre y su madre le dijeron: ¿No hay mujer entre las hijas de tus hermanos, ni en todo mi pueblo, para que vayas tú á tomar mujer de los Filisteos incircuncisos? Y Samsón respondió á su padre: Tómamela por mujer, porque ésta agradó á mis ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 14, 4, 'Mas su padre y su madre no sabían que esto venía de Jehová, y que él buscaba ocasión contra los Filisteos: porque en aquel tiempo los Filisteos dominaban sobre Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 14, 5, 'Y Samsón descendió con su padre y con su madre á Timnah: y como llegaron á las viñas de Timnah, he aquí un cachorro de león que venía bramando hacia él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 14, 6, 'Y el espíritu de Jehová cayó sobre él, y despedazólo como quien despedaza un cabrito, sin tener nada en su mano: y no dió á entender á su padre ni á su madre lo que había hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 14, 7, 'Vino pues, y habló á la mujer que había agradado á Samsón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 14, 8, 'Y volviendo después de algunos días para tomarla, apartóse para ver el cuerpo muerto del león, y he aquí en el cuerpo del león un enjambre de abejas, y un panal de miel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 14, 9, 'Y tomándolo en sus manos, fuése comiéndolo por el camino: y llegado que hubo á su padre y á su madre, dióles también á ellos que comiesen; mas no les descubrió que había tomado aquella miel del cuerpo del león.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 14, 10, 'Vino pues su padre á la mujer, y Samsón hizo allí banquete; porque así solían hacer los mancebos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 14, 11, 'Y como ellos le vieron, tomaron treinta compañeros que estuviesen con él;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 14, 12, 'A los cuales Samsón dijo: Yo os propondré ahora un enigma, el cual si en los siete días del banquete vosotros me declarareis y descubriereis, yo os daré treinta sábanas y treinta mudas de vestidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 14, 13, 'Mas si no me lo supiereis declarar, vosotros me daréis las treinta sábanas y las treinta mudas de vestidos. Y ellos respondieron: Propónnos tu enigma, y lo oiremos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 14, 14, 'Entonces les dijo: Del comedor salió comida, Y del fuerte salió dulzura. Y ellos no pudieron declararle el enigma en tres días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 14, 15, 'Y al séptimo día dijeron á la mujer de Samsón: Induce á tu marido á que nos declare este enigma, porque no te quememos á ti y á la casa de tu padre. ¿Habéisnos llamado aquí para poseernos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 14, 16, 'Y lloró la mujer de Samsón delante de él, y dijo: Solamente me aborreces y no me amas, pues que no me declaras el enigma que propusiste á los hijos de mi pueblo. Y él respondió: He aquí que ni á mi padre ni á mi madre lo he declarado; y ¿habíalo de declarar á ti?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 14, 17, 'Y ella lloró delante de él los siete días que ellos tuvieron banquete: mas al séptimo día él se lo declaró, porque le constriñó; y ella lo declaró á los hijos de su pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 14, 18, 'Y al séptimo día, antes que el sol se pusiese, los de la ciudad le dijeron: ¿Qué cosa más dulce que la miel? ¿Y qué cosa más fuerte que el león? Si no araseis con mi novilla, Nunca hubierais descubierto mi enigma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 14, 19, '(14-20) Y el espíritu de Jehová cayó sobre él, y descendió á Ascalón, é hirió treinta hombres de ellos; y tomando sus despojos, dió las mudas de vestidos á los que habían explicado el enigma: y encendido en enojo fuése á casa de su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 14, 20, '(14-21) Y la mujer de Samsón fué dada á su compañero, con el cual él antes se acompañaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 15, 1, 'Y ACONTECIO después de días, que en el tiempo de la siega del trigo, Samsón visitó á su mujer con un cabrito, diciendo: Entraré á mi mujer á la cámara. Mas el padre de ella no lo dejó entrar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 15, 2, 'Y dijo el padre de ella: Persuadíme que la aborrecías, y díla á tu compañero. Mas su hermana menor, ¿no es más hermosa que ella? tómala, pues, en su lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 15, 3, 'Y Samsón les repondió: Yo seré sin culpa esta vez para con los Filisteos, si mal les hiciere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 15, 4, 'Y fué Samsón y cogió trescientas zorras, y tomando teas, y trabando aquéllas por las colas, puso entre cada dos colas una tea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 15, 5, 'Después, encendiendo las teas, echó las zorras en los sembrados de los Filisteos, y quemó hacinas y mieses, y viñas y olivares.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 15, 6, 'Y dijeron los Filisteos: ¿Quién hizo esto? Y fuéles dicho: Samsón, el yerno del Timnateo, porque le quitó su mujer y la dió á su compañero. Y vinieron los Filisteos, y quemaron á fuego á ella y á su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 15, 7, 'Entonces Samsón les dijo: ¿Así lo habíais de hacer? mas yo me vengaré de vosotros, y después cesaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 15, 8, 'E hiriólos pierna y muslo con gran mortandad; y descendió, y fijóse en la cueva de la peña de Etam.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 15, 9, 'Y los Filisteos subieron y pusieron campo en Judá, y tendiéronse por Lehi.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 15, 10, 'Y los varones de Judá les dijeron: ¿Por qué habéis subido contra nosotros? Y ellos respondieron: A prender á Samsón hemos subido, para hacerle como él nos ha hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 15, 11, 'Y vinieron tres mil hombres de Judá á la cueva de la peña de Etam, y dijeron á Samsón: ¿No sabes tú que los Filisteos dominan sobre nosotros? ¿por qué nos has hecho esto? Y él les respondió: Yo les he hecho como ellos me hicieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 15, 12, 'Ellos entonces le dijeron: Nosotros hemos venido para prenderte, y entregarte en mano de los Filisteos. Y Samsón les respondió: Juradme que vosotros no me mataréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 15, 13, 'Y ellos le respondieron, diciendo: No, solamente te prenderemos, y te entregaremos en sus manos; mas no te mataremos. Entonces le ataron con dos cuerdas nuevas, é hiciéronle venir de la peña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 15, 14, 'Y así que vino hasta Lehi, los Filisteos le salieron á recibir con algazara: y el espíritu de Jehová cayó sobre él, y las cuerdas que estaban en sus brazos se tornaron como lino quemado con fuego, y las ataduras se cayeron de sus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 15, 15, 'Y hallando una quijada de asno fresca, extendió la mano y tomóla, é hirió con ella á mil hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 15, 16, 'Entonces Samsón dijo: Con la quijada de un asno, un montón, dos montones; Con la quijada de un asno herí mil hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 15, 17, 'Y acabando de hablar, echó de su mano la quijada, y llamó á aquel lugar Ramath-lehi.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 15, 18, 'Y teniendo gran sed, clamó luego á Jehová, y dijo: Tú has dado esta gran salud por mano de tu siervo: ¿y moriré yo ahora de sed, y caeré en mano de los incircuncisos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 15, 19, 'Entonces quebró Dios una muela que estaba en la quijada, y salieron de allí aguas, y bebió, y recobró su espíritu, y reanimóse. Por tanto llamó su nombre de aquel lugar, En-haccore, el cual es en Lehi, hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 15, 20, 'Y juzgó á Israel en días de los Filisteos veinte años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 1, 'Y FUÉ Samsón á Gaza, y vió allí una mujer ramera, y entró á ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 2, 'Y fué dicho á los de Gaza: Samsón es venido acá. Y cercáronlo, y pusiéronle espías toda aquella noche á la puerta de la ciudad: y estuvieron callados toda aquella noche, diciendo: Hasta la luz de la mañana; entonces lo mataremos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 3, 'Mas Samsón durmió hasta la media noche; y á la media noche se levantó, y tomando las puertas de la ciudad con sus dos pilares y su cerrojo, echóselas al hombro, y fuése, y subióse con ellas á la cumbre del monte que está delante de Hebrón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 4, 'Después de esto aconteció que se enamoró de una mujer en el valle de Sorec, la cual se llamaba Dalila.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 5, 'Y vinieron á ella los príncipes de los Filisteos, y dijéronle: Engáñale y sabe en qué consiste su grande fuerza, y cómo lo podríamos vencer, para que lo atemos y lo atormentemos; y cada uno de nosotros te dará mil y cien siclos de plata.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 6, 'Y Dalila dijo á Samsón: Yo te ruego que me declares en qué consiste tu grande fuerza, y cómo podrás ser atado para ser atormentado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 7, 'Y respondióle Samsón: Si me ataren con siete mimbres verdes que aun no estén enjutos, entonces me debilitaré, y seré como cualquiera de los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 8, 'Y los príncipes de los Filisteos le trajeron siete mimbres verdes que aun no se habían enjugado, y atóle con ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 9, 'Y estaban espías en casa de ella en una cámara. Entonces ella le dijo: ¡Samsón, los Filisteos sobre ti! Y él rompió los mimbres, como se rompe una cuerda de estopa cuando siente el fuego: y no se supo su fuerza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 10, 'Entonces Dalila dijo á Samsón: He aquí tú me has engañado, y me has dicho mentiras: descúbreme pues ahora, yo te ruego, cómo podrás ser atado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 11, 'Y él le dijo: Si me ataren fuertemente con cuerdas nuevas, con las cuales ninguna cosa se haya hecho, yo me debilitaré, y seré como cualquiera de los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 12, 'Y Dalila tomó cuerdas nuevas, y atóle con ellas, y díjole: ¡Samsón, los Filisteos sobre ti! Y los espías estaban en una cámara. Mas él las rompió de sus brazos como un hilo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 13, 'Y Dalila dijo á Samsón: Hasta ahora me engañas, y tratas conmigo con mentiras. Descúbreme pues ahora cómo podrás ser atado. El entonces le dijo: Si tejieres siete guedejas de mi cabeza con la tela.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 14, 'Y ella hincó la estaca, y díjole: ¡Samsón, los Filisteos sobre ti! Mas despertando él de su sueño, arrancó la estaca del telar con la tela.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 15, 'Y ella le dijo: ¿Cómo dices, Yo te amo, pues que tu corazón no está conmigo? Ya me has engañado tres veces, y no me has aún descubierto en qué está tu gran fuerza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 16, 'Y aconteció que, apretándole ella cada día con sus palabras é importunándole, su alma fué reducida á mortal angustia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 17, 'Descubrióle pues todo su corazón, y díjole: Nunca á mi cabeza llegó navaja; porque soy Nazareo de Dios desde el vientre de mi madre. Si fuere rapado, mi fuerza se apartará de mí, y seré debilitado, y como todos los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 18, 'Y viendo Dalila que él le había descubierto todo su corazón, envió á llamar á los príncipes de los Filisteos, diciendo: Venid esta vez, porque él me ha descubierto todo su corazón. Y los príncipes de los Filisteos vinieron á ella, trayendo en su mano el dinero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 19, 'Y ella hizo que él se durmiese sobre sus rodillas; y llamado un hombre, rapóle siete guedejas de su cabeza, y comenzó á afligirlo, pues su fuerza se apartó de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 20, 'Y díjole: ¡Samsón, los Filisteos sobre ti! Y luego que despertó él de su sueño, se dijo: Esta vez saldré como las otras, y me escaparé: no sabiendo que Jehová ya se había de él apartado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 21, 'Mas los Filisteos echaron mano de él, y sacáronle los ojos, y le llevaron á Gaza; y le ataron con cadenas, para que moliese en la cárcel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 22, 'Y el cabello de su cabeza comenzó á crecer, después que fué rapado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 23, 'Entonces los príncipes de los Filisteos se juntaron para ofrecer sacrificio á Dagón su dios, y para alegrarse; y dijeron: Nuestro dios entregó en nuestras manos á Samsón nuestro enemigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 24, 'Y viéndolo el pueblo, loaron á su dios, diciendo: Nuestro dios entregó en nuestras manos á nuestro enemigo, y al destruidor de nuestra tierra, el cual había muerto á muchos de nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 25, 'Y aconteció que, yéndose alegrando el corazón de ellos, dijeron: Llamad á Samsón, para que divierta delante de nosotros. Y llamaron á Samsón de la cárcel, y hacía de juguete delante de ellos; y pusiéronlo entre las columnas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 26, 'Y Samsón dijo al mozo que le guiaba de la mano: Acércame, y hazme tentar las columnas sobre que se sustenta la casa, para que me apoye sobre ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 27, 'Y la casa estaba llena de hombres y mujeres: y todos los príncipes de los Filisteos estaban allí; y en el alto piso había como tres mil hombres y mujeres, que estaban mirando el escarnio de Samsón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 28, 'Entonces clamó Samsón á Jehová, y dijo: Señor Jehová, acuérdate ahora de mí, y esfuérzame, te ruego, solamente esta vez, oh Dios, para que de una vez tome venganza de los Filisteos, por mis dos ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 29, 'Asió luego Samsón las dos columnas del medio sobre las cuales se sustentaba la casa, y estribó en ellas, la una con la mano derecha, y la otra con la izquierda;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 30, 'Y dijo Samsón: Muera yo con los Filisteos. Y estribando con esfuerzo, cayó la casa sobre los príncipes, y sobre todo el pueblo que estaba en ella. Y fueron muchos más los que de ellos mató muriendo, que los que había muerto en su vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 16, 31, 'Y descendieron sus hermanos y toda la casa de su padre, y tomáronle, y lleváronle, y le sepultaron entre Sora y Esthaol, en el sepulcro de su padre Manoa. Y él juzgó á Israel veinte años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 17, 1, 'HUBO un hombre del monte de Ephraim, que se llamaba Michâs.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 17, 2, 'El cual dijo á su madre: Los mil y cien siclos de plata que te fueron hurtados, por lo que tú maldecías oyéndolo yo, he aquí que yo tengo este dinero: yo lo había tomado. Entonces la madre dijo: Bendito seas de Jehová, hijo mío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 17, 3, 'Y luego que él hubo vuelto á su madre los mil y cien siclos de plata, su madre dijo: Yo he dedicado este dinero á Jehová de mi mano para ti, hijo mío, para que hagas una imagen de talla y de fundición: ahora pues, yo te lo devuelvo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 17, 4, 'Mas volviendo él á su madre los dineros, tomó su madre doscientos siclos de plata, y diólos al fundidor: y él le hizo de ellos una imagen de talla y de fundición, la cual fué puesta en casa de Michâs.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 17, 5, 'Y tuvo este hombre Michâs casa de dioses, é hízose hacer ephod y teraphim, y consagró uno de sus hijos; y fuéle por sacerdote.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 17, 6, 'En estos días no había rey en Israel: cada uno hacía como mejor le parecía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 17, 7, 'Y había un joven de Beth-lehem de Judá, de la tribu de Judá, el cual era Levita; y peregrinaba allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 17, 8, 'Este hombre se había partido de la ciudad de Beth-lehem de Judá, para ir á vivir donde hallase; y llegando al monte de Ephraim, vino á casa de Michâs, para de allí hacer su camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 17, 9, 'Y Michâs le dijo: ¿De dónde vienes? Y el Levita le respondió: Soy de Beth-lehem de Judá, y voy á vivir donde hallare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 17, 10, 'Entonces Michâs le dijo: Quédate en mi casa, y me serás en lugar de padre y sacerdote; y yo te daré diez siclos de plata por año, y el ordinario de vestidos, y tu comida. Y el Levita se quedó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 17, 11, 'Acordó pues el Levita en morar con aquel hombre, y él lo tenía como á uno de sus hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 17, 12, 'Y Michâs consagró al Levita, y aquel joven le servía de sacerdote, y estaba en casa de Michâs.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 17, 13, 'Y Michâs dijo: Ahora sé que Jehová me hará bien, pues que el Levita es hecho mi sacerdote.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 1, 'EN aquellos días no había rey en Israel. Y en aquellos días la tribu de Dan buscaba posesión para sí donde morase, porque hasta entonces no le había caído suerte entre las tribus de Israel por heredad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 2, 'Y los hijos de Dan enviaron de su tribu cinco hombres de sus términos, hombres valientes, de Sora y Esthaol, para que reconociesen y explorasen bien la tierra; y dijéronles: Id y reconoced la tierra. Estos vinieron al monte de Ephraim, hasta la casa de Michâs, y allí posaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 3, 'Y como estaban cerca de la casa de Michâs, reconocieron la voz del joven Levita; y llegándose allá, dijéronle: ¿Quién te ha traído por acá? ¿y qué haces aquí? ¿y qué tienes tú por aquí?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 4, 'Y él les respondió: De esta y de esta manera ha hecho conmigo Michâs, y me ha tomado para que sea su sacerdote.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 5, 'Y ellos le dijeron: Pregunta pues ahora á Dios, para que sepamos si ha de prosperar nuestro viaje que hacemos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 6, 'Y el sacerdote les respondió: Id en paz, que vuestro viaje que hacéis es delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 7, 'Entonces aquellos cinco hombres se partieron, y vinieron á Lais: y vieron que el pueblo que habitaba en ella estaba seguro, ocioso y confiado, conforme á la costumbre de los de Sidón; no había nadie en aquella región que los perturbase en cosa alguna para poseer aquel estado; demás de esto, estaban lejos de los Sidonios, y no tenían negocios con nadie.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 8, 'Volviendo pues ellos á sus hermanos en Sora y Esthaol, sus hermanos les dijeron: ¿Qué hay? y ellos respondieron:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 9, 'Levantaos, subamos contra ellos; porque nosotros hemos explorado la región, y hemos visto que es muy buena: ¿y vosotros os estáis quedos? no seáis perezosos en poneros en marcha para ir á poseer la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 10, 'Cuando allá llegareis, vendréis á una gente segura, y á una tierra de ancho asiento; pues que Dios la ha entregado en vuestras manos; lugar donde no hay falta de cosa que sea en la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 11, 'Y partiendo los de Dan de allí, de Sora y de Esthaol, seiscientos hombres armados de armas de guerra,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 12, 'Fueron y asentaron campo en Chîriath-jearim, en Judá; de donde aquel lugar fué llamado el campo de Dan, hasta hoy: está detrás de Chîriath-jearim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 13, 'Y pasando de allí al monte de Ephraim, vinieron hasta la casa de Michâs.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 14, 'Entonces aquellos cinco hombres que habían ido á reconocer la tierra de Lais, dijeron á sus hermanos: ¿No sabéis como en estas casas hay ephod y teraphim, é imagen de talla y de fundición? Mirad pues lo que habéis de hacer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 15, 'Y llegándose allá, vinieron á la casa del joven Levita en casa de Michâs, y preguntáronle cómo estaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 16, 'Y los seiscientos hombres, que eran de los hijos de Dan, estaban armados de sus armas de guerra á la entrada de la puerta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 17, 'Y subiendo los cinco hombres que habían ido á reconocer la tierra, entraron allá, y tomaron la imagen de talla, y el ephod, y el teraphim, y la imagen de fundición, mientras estaba el sacerdote á la entrada de la puerta con los seiscientos hombres armados de armas de guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 18, 'Entrando pues aquellos en la casa de Michâs, tomaron la imagen de talla, el ephod, y el teraphim, y la imagen de fundición. Y el sacerdote les dijo: ¿Qué hacéis vosotros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 19, 'Y ellos le respondieron: Calla, pon la mano sobre tu boca, y vente con nosotros, para que seas nuestro padre y sacerdote. ¿Es mejor que seas tú sacerdote en casa de un hombre solo, que de una tribu y familia de Israel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 20, 'Y alegróse el corazón del sacerdote; el cual tomando el ephod y el teraphim, y la imagen, vínose entre la gente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 21, 'Y ellos tornaron y fuéronse; y pusieron los niños, y el ganado y el bagaje, delante de sí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 22, 'Y cuando ya se habían alejado de la casa de Michâs, los hombres que habitaban en las casas cercanas á la casa de Michâs, se juntaron, y siguieron á los hijos de Dan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 23, 'Y dando voces á los de Dan, éstos volvieron sus rostros, y dijeron á Michâs: ¿Qué tienes que has juntado gente?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 24, 'Y él respondió: Mis dioses que yo hice, que lleváis juntamente con el sacerdote, y os vais: ¿qué más me queda? ¿y á qué propósito me decís: Qué tienes?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 25, 'Y los hijos de Dan le dijeron: No des voces tras nosotros, no sea que los de ánimo colérico os acometan, y pierdas también tu vida, y la vida de los tuyos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 26, 'Y yéndose los hijos de Dan su camino, y viendo Michâs que eran más fuertes que él, volvióse y regresó á su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 27, 'Y ellos llevando las cosas que había hecho Michâs, juntamente con el sacerdote que tenía, llegaron á Lais, al pueblo reposado y seguro; y metiéronlos á cuchillo, y abrasaron la ciudad con fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 28, 'Y no hubo quien los defendiese, porque estaban lejos de Sidón, y no tenían comercio con nadie. Y la ciudad estaba en el valle que hay en Beth-rehob. Luego reedificaron la ciudad, y habitaron en ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 29, 'Y llamaron el nombre de aquella ciudad Dan, conforme al nombre de Dan su padre, hijo de Israel, bien que antes se llamaba la ciudad Lais.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 30, 'Y los hijos de Dan se levantaron imagen de talla; y Jonathán, hijo de Gersón, hijo de Manasés, él y sus hijos fueron sacerdotes en la tribu de Dan, hasta el día de la transmigración de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 18, 31, 'Y levantáronse la imagen de Michâs, la cual él había hecho, todo el tiempo que la casa de Dios estuvo en Silo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 19, 1, 'EN aquellos días, cuando no había rey en Israel, hubo un Levita que moraba como peregrino en los lados del monte de Ephraim, el cual se había tomado mujer concubina de Beth-lehem de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 19, 2, 'Y su concubina adulteró contra él, y fuese de él á casa de su padre, á Beth-lehem de Judá, y estuvo allá por tiempo de cuatro meses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 19, 3, 'Y levantóse su marido, y siguióla, para hablarle amorosamente y volverla, llevando consigo un criado suyo y un par de asnos; y ella le metió en la casa de su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 19, 4, 'Y viéndole el padre de la moza, salióle á recibir gozoso; y detúvole su suegro, padre de la moza, y quedó en su casa tres días, comiendo y bebiendo, y reposando allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 19, 5, 'Y al cuarto día, como se levantaron de mañana, levantóse también el Levita para irse, y el padre de la moza dijo á su yerno: Conforta tu corazón con un bocado de pan, y después os iréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 19, 6, 'Y sentáronse ellos dos juntos, y comieron y bebieron. Y el padre de la moza dijo al varón: Yo te ruego que te quieras quedar aquí esta noche, y alegraráse tu corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 19, 7, 'Y levantándose el varón para irse, el suegro le constriñó á que tornase y tuviese allí la noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 19, 8, 'Y al quinto día levantándose de mañana para irse, díjole el padre de la moza: Conforta ahora tu corazón. Y habiendo comido ambos á dos, detuviéronse hasta que ya declinaba el día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 19, 9, 'Levantóse luego el varón para irse, él, y su concubina, y su criado. Entonces su suegro, el padre de la moza, le dijo: He aquí el día declina para ponerse el sol, ruégote que os estéis aquí la noche; he aquí que el día se acaba, ten aquí la noche, para que se alegre tu corazón; y mañana os levantaréis temprano á vuestro camino, y llegarás á tus tiendas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 19, 10, 'Mas el hombre no quiso quedar allí la noche, sino que se levantó y partió, y llegó hasta enfrente de Jebus, que es Jerusalem, con su par de asnos aparejados, y con su concubina.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 19, 11, 'Y estando ya junto á Jebus, el día había declinado mucho: y dijo el criado á su señor: Ven ahora, y vámonos á esta ciudad de los Jebuseos, para que tengamos en ella la noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 19, 12, 'Y su señor le respondió: No iremos á ninguna ciudad de extranjeros, que no sea de los hijos de Israel: antes pasaremos hasta Gabaa. Y dijo á su criado:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 19, 13, 'Ven, lleguemos á uno de esos lugares, para tener la noche en Gabaa, ó en Rama.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 19, 14, 'Pasando pues, caminaron, y púsoseles el sol junto á Gabaa, que era de Benjamín.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 19, 15, 'Y apartáronse del camino para entrar á tener allí la noche en Gabaa; y entrando, sentáronse en la plaza de la ciudad, porque no hubo quien los acogiese en casa para pasar la noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 19, 16, 'Y he aquí un hombre viejo, que á la tarde venía del campo de trabajar; el cual era del monte de Ephraim, y moraba como peregrino en Gabaa, pero los moradores de aquel lugar eran hijos de Benjamín.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 19, 17, 'Y alzando el viejo los ojos, vió á aquel viajante en la plaza de la ciudad, y díjole: ¿A dónde vas, y de dónde vienes?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 19, 18, 'Y él respondió: Pasamos de Beth-lehem de Judá á los lados del monte de Ephraim, de donde yo soy; y partí hasta Beth-lehem de Judá; y voy á la casa de Jehová, y no hay quien me reciba en casa,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 19, 19, 'Aunque nosotros tenemos paja y de comer para nuestros asnos, y también tenemos pan y vino para mí y para tu sierva, y para el criado que está con tu siervo; de nada tenemos falta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 19, 20, 'Y el hombre viejo dijo: Paz sea contigo; tu necesidad toda sea solamente á mi cargo, con tal que no tengas la noche en la plaza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 19, 21, 'Y metiéndolos en su casa, dió de comer á sus asnos; y ellos se lavaron los pies, y comieron y bebieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 19, 22, 'Y cuando estaban gozosos, he aquí, que los hombres de aquella ciudad, hombres hijos de Belial, cercan la casa, y batían las puertas, diciendo al hombre viejo dueño de la casa: Saca fuera el hombre que ha entrado en tu casa, para que lo conozcamos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 19, 23, 'Y saliendo á ellos aquel varón, amo de la casa, díjoles: No, hermanos míos, ruégoos que no cometáis este mal, pues que este hombre ha entrado en mi casa, no hagáis esta maldad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 19, 24, 'He aquí mi hija virgen, y la concubina de él: yo os las sacaré ahora; humilladlas, y haced con ellas como os pareciere, y no hagáis á este hombre cosa tan infame.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 19, 25, 'Mas aquellos hombres no le quisieron oir; por lo que tomando aquel hombre su concubina, sacósela fuera: y ellos la conocieron, y abusaron de ella toda la noche hasta la mañana, y dejáronla cuando apuntaba el alba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 19, 26, 'Y ya que amanecía, la mujer vino, y cayó delante de la puerta de la casa de aquel hombre donde su señor estaba, hasta que fué de día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 19, 27, 'Y levantándose de mañana su señor, abrió las puertas de la casa, y salió para ir su camino, y he aquí, la mujer su concubina estaba tendida delante de la puerta de la casa, con las manos sobre el umbral.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 19, 28, 'Y él le dijo: Levántate, y vámonos. Mas ella no respondió. Entonces la levantó el varón, y echándola sobre su asno, levantóse y fuése á su lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 19, 29, 'Y en llegando á su casa, toma un cuchillo, y echa mano de su concubina, y despedázala con sus huesos en doce partes, y enviólas por todos los términos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 19, 30, 'Y todo el que lo veía, decía: Jamás se ha hecho ni visto tal cosa, desde el tiempo que los hijos de Israel subieron de la tierra de Egipto hasta hoy. Considerad esto, dad consejo, y hablad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 1, 'ENTONCES salieron todos los hijos de Israel, y reunióse la congregación como un solo hombre, desde Dan hasta Beer-seba y la tierra de Galaad, á Jehová en Mizpa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 2, 'Y los principales de todo el pueblo, de todas las tribus de Israel, se hallaron presentes en la reunión del pueblo de Dios, cuatrocientos mil hombres de á pie que sacaban espada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 3, 'Y los hijos de Benjamín oyeron que los hijos de Israel habían subido á Mizpa. Y dijeron los hijos de Israel: Decid cómo fué esta maldad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 4, 'Entonces el varón Levita, marido de la mujer muerta, respondió y dijo: Yo llegué á Gabaa de Benjamín con mi concubina, para tener allí la noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 5, 'Y levantándose contra mí los de Gabaa, cercaron sobre mí la casa de noche, con idea de matarme, y oprimieron mi concubina de tal manera, que ella fué muerta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 6, 'Entonces tomando yo mi concubina, cortéla en piezas, y enviélas por todo el término de la posesión de Israel: por cuanto han hecho maldad y crimen en Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 7, 'He aquí que todos vosotros los hijos de Israel estáis presentes; daos aquí parecer y consejo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 8, 'Entonces todo el pueblo, como un solo hombre, se levantó, y dijeron: Ninguno de nosotros irá á su tienda, ni nos apartaremos cada uno á su casa,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 9, 'Hasta que hagamos esto sobre Gabaa: que echemos suertes contra ella;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 10, 'Y tomaremos diez hombres de cada ciento por todas las tribus de Israel, y de cada mil ciento, y mil de cada diez mil, que lleven bastimento para el pueblo que ha de hacer, yendo contra Gabaa de Benjamín, conforme á toda la abominación que ha cometido en Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 11, 'Y juntáronse todos los hombres de Israel contra la ciudad, ligados como un solo hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 12, 'Y las tribus de Israel enviaron varones por toda la tribu de Benjamín, diciendo: ¿Qué maldad es ésta que ha sido hecha entre vosotros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 13, 'Entregad pues ahora aquellos hombres, hijos de Belial, que están en Gabaa, para que los matemos, y barramos el mal de Israel. Mas los de Benjamín no quisieron oir la voz de sus hermanos los hijos de Israel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 14, 'Antes los de Benjamín se juntaron de las ciudades de Gabaa, para salir á pelear contra los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 15, 'Y fueron contados en aquel tiempo los hijos de Benjamín de las ciudades, veintiséis mil hombres que sacaban espada, sin los que moraban en Gabaa, que fueron por cuenta setecientos hombres escogidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 16, 'De toda aquella gente había setecientos hombres escogidos, que eran ambidextros, todos los cuales tiraban una piedra con la honda á un cabello, y no erraban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 17, 'Y fueron contados los varones de Israel, fuera de Benjamín, cuatrocientos mil hombres que sacaban espada, todos estos hombres de guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 18, 'Levantáronse luego los hijos de Israel, y subieron á la casa de Dios, y consultaron á Dios, diciendo: ¿Quién subirá de nosotros el primero en la guerra contra los hijos de Benjamín? Y Jehová respondió: Judá el primero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 19, 'Levantándose pues de mañana los hijos de Israel, pusieron campo contra Gabaa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 20, 'Y salieron los hijos de Israel á combatir contra Benjamín; y los varones de Israel ordenaron la batalla contra ellos junto á Gabaa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 21, 'Saliendo entonces de Gabaa los hijos de Benjamín, derribaron en tierra aquel día veintidós mil hombres de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 22, 'Mas reanimándose el pueblo, los varones de Israel tornaron á ordenar la batalla en el mismo lugar donde la habían ordenado el primer día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 23, 'Porque los hijos de Israel subieron, y lloraron delante de Jehová hasta la tarde, y consultaron con Jehová, diciendo: ¿Tornaré á pelear con los hijos de Benjamín mi hermano? Y Jehová les respondió: Subid contra él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 24, 'Los hijos pues de Israel se acercaron el siguiente día á los hijos de Benjamín.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 25, 'Y aquel segundo día, saliendo Benjamín de Gabaa contra ellos, derribaron por tierra otros diez y ocho mil hombres de los hijos de Israel, todos los cuales sacaban espada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 26, 'Entonces subieron todos los hijos de Israel, y todo el pueblo, y vinieron á la casa de Dios; y lloraron, y sentáronse allí delante de Jehová, y ayunaron aquel día hasta la tarde; y sacrificaron holocaustos y pacíficos delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 27, 'Y los hijos de Israel preguntaron á Jehová, (porque el arca del pacto de Dios estaba allí en aquellos días,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 28, 'Y Phinees, hijo de Eleazar, hijo de Aarón, se presentaba delante de ella en aquellos días,) y dijeron: ¿Tornaré á salir en batalla contra los hijos de Benjamín mi hermano, ó estaréme quedo? Y Jehová dijo: Subid, que mañana yo lo entregaré en tu mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 29, 'Y puso Israel emboscadas alrededor de Gabaa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 30, 'Subiendo entonces los hijos de Israel contra los hijos de Benjamín el tercer día, ordenaron la batalla delante de Gabaa, como las otras veces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 31, 'Y saliendo los hijos de Benjamín contra el pueblo, alejados que fueron de la ciudad, comenzaron á herir algunos del pueblo, matando como las otras veces por los caminos, uno de los cuales sube á Beth-el, y el otro á Gabaa en el campo: y mataron unos treinta hombres de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 32, 'Y los hijos de Benjamín decían: Vencidos son delante de nosotros, como antes. Mas los hijos de Israel decían: Huiremos, y los alejaremos de la ciudad hasta los caminos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 33, 'Entonces, levantándose todos los de Israel de su lugar, pusiéronse en orden en Baal-tamar: y también las emboscadas de Israel salieron de su lugar, del prado de Gabaa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 34, 'Y vinieron contra Gabaa diez mil hombres escogidos de todo Israel, y la batalla comenzó á agravarse: mas ellos no sabían que el mal se acercaba sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 35, 'E hirió Jehová á Benjamín delante de Israel; y mataron los hijos de Israel aquel día veinticinco mil y cien hombres de Benjamín, todos los cuales sacaban espada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 36, 'Y vieron los hijos de Benjamín que eran muertos; pues los hijos de Israel habían dado lugar á Benjamín, porque estaban confiados en las emboscadas que habían puesto detrás de Gabaa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 37, 'Entonces las emboscadas acometieron prestamente Gabaa, y se extendieron, y pasaron á cuchillo toda la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 38, 'Ya los Israelitas estaban concertados con las emboscadas, que hiciesen mucho fuego, para que subiese gran humo de la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 39, 'Luego, pues, que los de Israel se volvieron en la batalla, los de Benjamín comenzaron á derribar heridos de Israel unos treinta hombres, y ya decían: Ciertamente ellos han caído delante de nosotros, como en la primera batalla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 40, 'Mas cuando la llama comenzó á subir de la ciudad, una columna de humo, Benjamín tornó á mirar atrás; y he aquí que el fuego de la ciudad subía al cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 41, 'Entonces revolvieron los hombres de Israel, y los de Benjamín se llenaron de temor: porque vieron que el mal había venido sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 42, 'Volvieron, por tanto, espaldas delante de Israel hacia el camino del desierto; mas el escuadrón los alcanzó, y los salidos de la ciudad los mataban, habiéndolos encerrado en medio de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 43, 'Así envolvieron á los de Benjamín, y los acosaron y hollaron, desde Menuchâ hasta enfrente de Gabaa hacia donde nace el sol.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 44, 'Y cayeron de Benjamín diez y ocho mil hombres, todos ellos hombres de guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 45, 'Volviéndose luego, huyeron hacia el desierto, á la peña de Rimmón, y de ellos rebuscaron cinco mil hombres en los caminos: fueron aún acosándolos hasta Gidom, y mataron de ellos dos mil hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 46, 'Así todos los que de Benjamín murieron aquel día, fueron veinticinco mil hombres que sacaban espada, todos ellos hombres de guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 47, 'Pero se volvieron y huyeron al desierto á la peña de Rimmón seiscientos hombres, los cuales estuvieron en la peña de Rimmón cuatro meses:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 20, 48, 'Y los hombres de Israel tornaron á los hijos de Benjamín, y pasáronlos á cuchillo, á hombres y bestias en la ciudad, y todo lo que fué hallado: asimismo pusieron fuego á todas ls ciudades que hallaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 21, 1, 'Y LOS varones de Israel habían jurado en Mizpa, diciendo: Ninguno de nosotros dará su hija á los de Benjamín por mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 21, 2, 'Y vino el pueblo á la casa de Dios, y estuviéronse allí hasta la tarde delante de Dios; y alzando su voz hicieron gran llanto, y dijeron:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 21, 3, 'Oh Jehová Dios de Israel, ¿por qué ha sucedido esto en Israel, que falte hoy de Israel una tribu?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 21, 4, 'Y al día siguiente el pueblo se levantó de mañana, y edificaron allí altar, y ofrecieron holocaustos y pacíficos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 21, 5, 'Y dijeron los hijos de Israel: ¿Quién de todas las tribus de Israel no subió á la reunión cerca de Jehová? Porque se había hecho gran juramento contra el que no subiese á Jehová en Mizpa, diciendo: Sufrirá muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 21, 6, 'Y los hijos de Israel se arrepintieron á causa de Benjamín su hermano, y dijeron: Una tribu es hoy cortada de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 21, 7, '¿Qué haremos en cuanto á mujeres para los que han quedado? Nosotros hemos jurado por Jehová que no les hemos de dar nuestras hijas por mujeres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 21, 8, 'Y dijeron: ¿Hay alguno de las tribus de Israel que no haya subido á Jehová en Mizpa? Y hallaron que ninguno de Jabes-galaad había venido al campo á la reunión:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 21, 9, 'Porque el pueblo fué contado, y no hubo allí varón de los moradores de Jabes-galaad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 21, 10, 'Entonces la congregación envió allá doce mil hombres de los más valientes, y mandáronles, diciendo: Id y poned á cuchillo á los moradores de Jabes-galaad, y las mujeres y niños.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 21, 11, 'Mas haréis de esta manera: mataréis á todo varón, y á toda mujer que hubiere conocido ayuntamiento de varón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 21, 12, 'Y hallaron de los moradores de Jabes-galaad cuatrocientas doncellas que no habían conocido hombre en ayuntamiento de varón, y trajéronlas al campo en Silo, que es en la tierra de Canaán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 21, 13, 'Toda la congregación envió luego á hablar á los hijos de Benjamín que estaban en la peña de Rimmón, y llamáronlos en paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 21, 14, 'Y volvieron entonces los de Benjamín; y diéronles por mujeres las que habían guardado vivas de las mujeres de Jabes-galaad: mas no les bastaron éstas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 21, 15, 'Y el pueblo tuvo dolor á causa de Benjamín, de que Jehová hubiese hecho mella en las tribus de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 21, 16, 'Entonces los ancianos de la congregación dijeron: ¿Qué haremos acerca de mujeres para los que han quedado? Porque el sexo de las mujeres había sido raído de Benjamín.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 21, 17, 'Y dijeron: La heredad de los que han escapado ha de ser lo que era de Benjamín, porque no sea una tribu raída de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 21, 18, 'Nosotros empero, no les podemos dar mujeres de nuestras hijas, porque los hijos de Israel han jurado, diciendo: Maldito el que diere mujer á Benjamín.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 21, 19, 'Ahora bien, dijeron, he aquí cada un año hay solemnidad de Jehová en Silo, que está al aquilón de Beth-el, y al lado oriental del camino que sube de Beth-el á Sichêm, y al mediodía de Lebona.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 21, 20, 'Y mandaron á los hijos de Benjamín, diciendo: Id, y poned emboscada en las viñas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 21, 21, 'Y estad atentos: y cuando viereis salir la hijas de Silo á bailar en corros, vosotros saldréis de las viñas, y arrebataréis cada uno mujer para sí de las hijas de Silo, y os iréis á tierra de Benjamín:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 21, 22, 'Y cuando vinieren los padres de ellas ó sus hermanos á demandárnoslo, nosotros les diremos: Tened piedad de nosotros en lugar de ellos: pues que nosotros en la guerra no tomamos mujeres para todos: que vosotros no se las habéis dado, para que ahora seáis culpables.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 21, 23, 'Y los hijos de Benjamín lo hicieron así; pues tomaron mujeres conforme á su número, pillando de las que danzaban; y yéndose luego, tornáronse á su heredad, y reedificaron las ciudades, y habitaron en ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 21, 24, 'Entonces los hijos de Israel se fueron también de allí, cada uno á su tribu y á su familia, saliendo de allí cada uno á su heredad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JDG', 'Jueces', 21, 25, 'En estos días no había rey en Israel: cada uno hacía lo recto delante de sus ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 1, 1, 'Y ACONTECIO en los días que gobernaban los jueces, que hubo hambre en la tierra. Y un varón de Beth-lehem de Judá, fué á peregrinar en los campos de Moab, él y su mujer, y dos hijos suyos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 1, 2, 'El nombre de aquel varón era Elimelech, y el de su mujer Noemi; y los nombres de sus dos hijos eran, Mahalón y Chelión, Ephrateos de Beth-lehem de Judá. Llegaron pues á los campos de Moab, y asentaron allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 1, 3, 'Y murió Elimelech, marido de Noemi, y quedó ella con sus dos hijos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 1, 4, 'Los cuales tomaron para sí mujeres de Moab, el nombre de la una Orpha, y el nombre de la otra Ruth; y habitaron allí unos diez años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 1, 5, 'Y murieron también los dos, Mahalón y Chelión, quedando así la mujer desamparada de sus dos hijos y de su marido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 1, 6, 'Entonces se levantó con sus nueras, y volvióse de los campos de Moab: porque oyó en el campo de Moab que Jehová había visitado á su pueblo para darles pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 1, 7, 'Salió pues del lugar donde había estado, y con ella sus dos nueras, y comenzaron á caminar para volverse á la tierra de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 1, 8, 'Y Noemi dijo á sus dos nueras: Andad, volveos cada una á la casa de su madre: Jehová haga con vosotras misericordia, como la habéis hecho con los muertos y conmigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 1, 9, 'Déos Jehová que halléis descanso, cada una en casa de su marido: besólas luego, y ellas lloraron á voz en grito.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 1, 10, 'Y dijéronle: Ciertamente nosotras volveremos contigo á tu pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 1, 11, 'Y Noemi respondió: Volveos, hijas mías: ¿para qué habéis de ir conmigo? ¿tengo yo más hijos en el vientre, que puedan ser vuestros maridos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 1, 12, 'Volveos, hijas mías, é idos; que yo ya soy vieja para ser para varón. Y aunque dijese: Esperanza tengo; y esta noche fuese con varón, y aun pariese hijos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 1, 13, '¿Habíais vosotras de esperarlos hasta que fuesen grandes? ¿habías vosotras de quedaros sin casar por amor de ellos? No, hijas mías; que mayor amargura tengo yo que vosotras, pues la mano de Jehová ha salido contra mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 1, 14, 'Mas ellas alzando otra vez su voz, lloraron: y Orpha besó á su suegra, mas Ruth se quedó con ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 1, 15, 'Y Noemi dijo: He aquí tu cuñada se ha vuelto á su pueblo y á sus dioses; vuélvete tú tras ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 1, 16, 'Y Ruth respondió: No me ruegues que te deje, y que me aparte de ti: porque donde quiera que tú fueres, iré yo; y donde quiera que vivieres, viviré. Tu pueblo será mi pueblo, y tu Dios mi Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 1, 17, 'Donde tú murieres, moriré yo, y allí seré sepultada: así me haga Jehová, y así me dé, que sólo la muerte hará separación entre mí y ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 1, 18, 'Y viendo Noemi que estaba tan resuelta á ir con ella, dejó de hablarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 1, 19, 'Anduvieron pues ellas dos hasta que llegaron á Beth-lehem: y aconteció que entrando en Beth-lehem, toda la ciudad se conmovió por razón de ellas, y decían: ¿No es ésta Noemi?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 1, 20, 'Y ella les respondiá: No me llaméis Noemi, sino llamadme Mara: porque en grande amargura me ha puesto el Todopoderoso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 1, 21, 'Yo me fuí llena, mas vacía me ha vuelto Jehová. ¿Por qué me llamaréis Noemi, ya que Jehová ha dado testimonio contra mí, y el Todopoderoso me ha afligido?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 1, 22, 'Así volvió Noemi y Ruth Moabita su nuera con ella; volvió de los campos de Moab, y llegaron á Beth-lehem en el principio de la siega de las cebadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 2, 1, 'Y TENIA Noemi un pariente de su marido, varón poderoso y de hecho, de la familia de Elimelech, el cual se llamaba Booz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 2, 2, 'Y Ruth la Moabita dijo á Noemi: Ruégote que me dejes ir al campo, y cogeré espigas en pos de aquel á cuyos ojos hallare gracia. Y ella le respondió: Ve, hija mía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 2, 3, 'Fué pues, y llegando, espigó en el campo en pos de los segadores: y aconteció por ventura, que la suerte del campo era de Booz, el cual era de la parentela de Elimelech.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 2, 4, 'Y he aquí que Booz vino de Beth-lehem, y dijo á los segadores: Jehová sea con vosotros. Y ellos respondieron: Jehová te bendiga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 2, 5, 'Y Booz dijo á su criado el sobrestante de los segadores: ¿Cúya es esta moza?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 2, 6, 'Y el criado, sobrestante de los segadores, respondió y dijo: Es la moza de Moab, que volvió con Noemi de los campos de Moab;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 2, 7, 'Y ha dicho: Ruégote que me dejes coger y juntar tras los segadores entre las gavillas: entró pues, y está desde por la mañana hasta ahora, menos un poco que se detuvo en casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 2, 8, 'Entonces Booz dijo á Ruth: Oye, hija mía, no vayas á espigar á otro campo, ni pases de aquí: y aquí estarás con mis mozas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 2, 9, 'Mira bien el campo que segaren, y síguelas: porque yo he mandado á los mozos que no te toquen. Y si tuvieres sed, ve á los vasos, y bebe del agua que sacaren los mozos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 2, 10, 'Ella entonces bajando su rostro inclinóse á tierra, y díjole: ¿Por qué he hallado gracia en tus ojos para que tú me reconozcas, siendo yo extranjera?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 2, 11, 'Y respondiendo Booz, díjole: Por cierto se me ha declarado todo lo que has hecho con tu suegra después de la muerte de tu marido, y que dejando á tu padre y á tu madre y la tierra donde naciste, has venido á pueblo que no conociste antes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 2, 12, 'Jehová galardone tu obra, y tu remuneración sea llena por Jehová Dios de Israel, que has venido para cubrirte debajo de sus alas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 2, 13, 'Y ella dijo: Señor mío, halle yo gracia delante de tus ojos; porque me has consolado, y porque has hablado al corazón de tu sierva, no siendo yo como una de tus criadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 2, 14, 'Y Booz le dijo á la hora de comer: Allégate aquí, y come del pan, y moja tu bocado en el vinagre. Y sentóse ella junto á los segadores, y él le dió del potaje, y comió hasta que se hartó y le sobró.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 2, 15, 'Levantóse luego para espigar. Y Booz mandó á sus criados, diciendo: Coja también espigas entre las gavillas, y no la avergoncéis;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 2, 16, 'Antes echaréis á sabiendas de los manojos, y la dejaréis que coja, y no la reprendáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 2, 17, 'Y espigó en el campo hasta la tarde, y desgranó lo que había cogido, y fué como un epha de cebada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 2, 18, 'Y tomólo, y vínose á la ciudad; y su suegra vió lo que había cogido. Sacó también luego lo que le había sobrado después de harta, y dióselo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 2, 19, 'Y díjole su suegra: ¿Dónde has espigado hoy? ¿y dónde has trabajado? bendito sea el que te ha reconocido. Y ella declaró á su suegra lo que le había acontecido con aquél, y dijo: El nombre del varón con quien hoy he trabajado es Booz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 2, 20, 'Y dijo Noemi á su nuera: Sea él bendito de Jehová, pues que no ha rehusado á los vivos la benevolencia que tuvo para con los finados. Díjole después Noemi: Nuestro pariente es aquel varón, y de nuestros redentores es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 2, 21, 'Y Ruth Moabita dijo: á más de esto me ha dicho: Júntate con mis criados, hasta que hayan acabado toda mi siega.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 2, 22, 'Y Noemi respondió á Ruth su nuera: Mejor es, hija mía, que salgas con sus criadas, que no que te encuentren en otro campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 2, 23, 'Estuvo pues junta con las mozas de Booz espigando, hasta que la siega de las cebadas y la de los trigos fué acabada; mas con su suegra habitó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 3, 1, 'Y DIJOLE su suegra Noemi: Hija mía, ¿no te tengo de buscar descanso, que te sea bueno?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 3, 2, '¿No es Booz nuestro pariente, con cuyas mozas tú has estado? He aquí que él avienta esta noche la parva de las cebadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 3, 3, 'Te lavarás pues, y te ungirás, y vistiéndote tus vestidos, pasarás á la era; mas no te darás á conocer al varón hasta que él haya acabado de comer y de beber.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 3, 4, 'Y cuando él se acostare, repara tú el lugar donde él se acostará, é irás, y descubrirás los pies, y te acostarás allí; y él te dirá lo que hayas de hacer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 3, 5, 'Y le respondió: Haré todo lo que tú me mandares.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 3, 6, 'Descendió pues á la era, é hizo todo lo que su suegra le había mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 3, 7, 'Y como Booz hubo comido y bebido, y su corazón estuvo contento, retiróse á dormir á un lado del montón. Entonces ella vino calladamente, y descubrió los pies, y acostóse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 3, 8, 'Y aconteció, que á la media noche se estremeció aquel hombre, y palpó: y he aquí, la mujer que estaba acostada á sus pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 3, 9, 'Entonces él dijo: ¿Quién eres? Y ella respondió: Yo soy Ruth tu sierva: extiende el borde de tu capa sobre tu sierva, por cuanto eres pariente cercano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 3, 10, 'Y él dijo: Bendita seas tú de Jehová, hija mía; que has hecho mejor tu postrera gracia que la primera, no yendo tras los mancebos, sean pobres ó ricos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 3, 11, 'Ahora pues, no temas, hija mía: yo haré contigo lo que tú dijeres, pues que toda la puerta de mi pueblo sabe que eres mujer virtuosa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 3, 12, 'Y ahora, aunque es cierto que yo soy pariente cercano, con todo eso hay pariente más cercano que yo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 3, 13, 'Reposa esta noche, y cuando sea de día, si él te redimiere, bien, redímate; mas si él no te quisiere redimir, yo te redimiré, vive Jehová. Descansa pues hasta la mañana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 3, 14, 'Y después que reposó á sus pies hasta la mañana, levantóse, antes que nadie pudiese conocer á otro. Y él dijo: No se sepa que haya venido mujer á la era.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 3, 15, 'Después le dijo: Llega el lienzo que traes sobre ti, y ten de él. Y teniéndolo ella, él midió seis medidas de cebada, y púsoselas á cuestas: y vínose ella á la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 3, 16, 'Así que vino á su suegra, ésta le dijo: ¿Qué pues, hija mía? Y declaróle ella todo lo que con aquel varón le había acontecido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 3, 17, 'Y dijo: Estas seis medidas de cebada me dió, diciéndome: Porque no vayas vacía á tu suegra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 3, 18, 'Entonces Noemi dijo: Reposa, hija mía, hasta que sepas como cae la cosa: porque aquel hombre no parará hasta que hoy concluya el negocio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 4, 1, 'Y BOOZ subió á la puerta y sentóse allí: y he aquí pasaba aquel pariente del cual había Booz hablado, y díjole: Eh, fulano, ven acá y siéntate. Y él vino, y sentóse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 4, 2, 'Entonces él tomó diez varones de los ancianos de la ciudad, y dijo: Sentaos aquí. Y ellos se sentaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 4, 3, 'Luego dijo al pariente: Noemi, que ha vuelto del campo de Moab, vende una parte de las tierras que tuvo nuestro hermano Elimelech;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 4, 4, 'Y yo decidí hacértelo saber, y decirte que la tomes delante de los que están aquí sentados, y delante de los ancianos de mi pueblo. Si hubieres de redimir, redime; y si no quisieres redimir, decláramelo para que yo lo sepa: porque no hay otro que redima sino tú, y yo después de ti. Y él respondió: Yo redimiré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 4, 5, 'Entonces replicó Booz: El mismo día que tomares las tierras de mano de Noemi, has de tomar también á Ruth Moabita, mujer del difunto, para que suscites el nombre del muerto sobre su posesión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 4, 6, 'Y respondió el pariente: No puedo redimir por mi parte, porque echaría á perder mi heredad: redime tú usando de mi derecho, porque yo no podré redimir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 4, 7, 'Había ya de largo tiempo esta costumbre en Israel en la redención ó contrato, que para la confirmación de cualquier negocio, el uno se quitaba el zapato y lo daba á su compañero: y este era el testimonio en Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 4, 8, 'Entonces el pariente dijo á Booz: Tómalo tú. Y descalzó su zapato.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 4, 9, 'Y Booz dijo á los ancianos y á todo el pueblo: Vosotros sois hoy testigos de que tomo todas las cosas que fueron de Elimelech, y todo lo que fué de Chelión y de Mahalón, de mano de Noemi.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 4, 10, 'Y que también tomo por mi mujer á Ruth Moabita, mujer de Mahalón, para suscitar el nombre del difunto sobre su heredad, para que el nombre del muerto no se borre de entre sus hermanos y de la puerta de su lugar. Vosotros sois hoy testigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 4, 11, 'Y dijeron todos los del pueblo que estaban á la puerta con los ancianos: Testigos somos. Jehová haga á la mujer que entra en tu casa como á Rachêl y á Lea, las cuales dos edificaron la casa de Israel; y tú seas ilustre en Ephrata, y tengas nombradía en Beth-lehem;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 4, 12, 'Y de la simiente que Jehová te diere de aquesta moza, sea tu casa como la casa de Phares, al que parió Thamar á Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 4, 13, 'Booz pues tomó á Ruth, y ella fué su mujer; y luego que entró á ella, Jehová le dió que concibiese y pariese un hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 4, 14, 'Y las mujeres decían á Noemi: Loado sea Jehová, que hizo que no te faltase hoy pariente, cuyo nombre será nombrado en Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 4, 15, 'El cual será restaurador de tu alma, y el que sustentará tu vejez; pues que tu nuera, la cual te ama y te vale más que siete hijos, le ha parido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 4, 16, 'Y tomando Noemi el hijo, púsolo en su regazo, y fuéle su ama.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 4, 17, 'Y las vecinas diciendo, á Noemi ha nacido un hijo, le pusieron nombre; y llamáronle Obed. Este es padre de Isaí, padre de David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 4, 18, 'Y estas son las generaciones de Phares: Phares engendró á Hesrón;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 4, 19, 'Y Hesrón engendró á Ram, y Ram engendró á Aminadab;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 4, 20, 'Y Aminadab engendró á Nahasón, y Nahasón engendró á Salmón;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 4, 21, 'Y Salmón engendró á Booz, y Booz engendró á Obed;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('RUT', 'Rut', 4, 22, 'Y Obed engendró á Isaí, é Isaí engendró á David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 1, 1, 'HUBO un varón de Ramathaim de Sophim, del monte de Ephraim, que se llamaba Elcana, hijo de Jeroham, hijo de Eliú, hijo de Thohu, hijo de Suph, Ephrateo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 1, 2, 'Y tenía él dos mujeres; el nombre de la una era Anna, y el nombre de la otra Peninna. Y Peninna tenía hijos, mas Anna no los tenía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 1, 3, 'Y subía aquel varón todos los años de su ciudad, á adorar y sacrificar á Jehová de los ejércitos en Silo, donde estaban dos hijos de Eli, Ophni y Phinees, sacerdotes de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 1, 4, 'Y cuando venía el día, Elcana sacrificaba, y daba á Peninna su mujer, y á todos sus hijos y á todas sus hijas, á cada uno su parte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 1, 5, 'Mas á Anna daba una parte escogida; porque amaba á Anna, aunque Jehová había cerrado su matriz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 1, 6, 'Y su competidora la irritaba, enojándola y entristeciéndola, porque Jehová había cerrado su matriz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 1, 7, 'Y así hacía cada año: cuando subía á la casa de Jehová, enojaba así á la otra; por lo cual ella lloraba, y no comía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 1, 8, 'Y Elcana su marido le dijo: Anna, ¿por qué lloras? ¿y por qué no comes? ¿y por qué está afligido tu corazón? ¿No te soy yo mejor que diez hijos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 1, 9, 'Y levantóse Anna después que hubo comido y bebido en Silo; y mientras el sacerdote Eli estaba sentado en una silla junto á un pilar del templo de Jehová,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 1, 10, 'Ella con amargura de alma oró á Jehová, y lloró abundantemente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 1, 11, 'E hizo voto, diciendo: Jehová de los ejércitos, si te dignares mirar la aflicción de tu sierva, y te acordares de mí, y no te olvidares de tu sierva, mas dieres á tu sierva un hijo varón, yo lo dedicaré á Jehová todos los días de su vida, y no subirá navaja sobre su cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 1, 12, 'Y fué que como ella orase largamente delante de Jehová, Eli estaba observando la boca de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 1, 13, 'Mas Anna hablaba en su corazón, y solamente se movían sus labios, y su voz no se oía; y túvola Eli por borracha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 1, 14, 'Entonces le dijo Eli: ¿Hasta cuándo estarás borracha?; digiere tu vino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 1, 15, 'Y Anna le respondió, diciendo: No, señor mío: mas yo soy una mujer trabajada de espíritu: no he bebido vino ni sidra, sino que he derramado mi alma delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 1, 16, 'No tengas á tu sierva por una mujer impía: porque por la magnitud de mis congojas y de mi aflicción he hablado hasta ahora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 1, 17, 'Y Eli respondió, y dijo: Ve en paz, y el Dios de Israel te otorgue la petición que le has hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 1, 18, 'Y ella dijo: Halle tu sierva gracia delante de tus ojos. Y fuése la mujer su camino, y comió, y no estuvo más triste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 1, 19, 'Y levantándose de mañana, adoraron delante de Jehová, y volviéronse, y vinieron á su casa en Ramatha. Y Elcana conoció á Anna su mujer, y Jehová se acordó de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 1, 20, 'Y fué que corrido el tiempo, después de haber concebido Anna, parió un hijo, y púsole por nombre Samuel, diciendo: Por cuanto lo demandé á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 1, 21, 'Después subió el varón Elcana, con toda su familia, á sacrificar á Jehová el sacrificio acostumbrado, y su voto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 1, 22, 'Mas Anna no subió, sino dijo á su marido: Yo no subiré hasta que el niño sea destetado; para que lo lleve y sea presentado delante de Jehová, y se quede allá para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 1, 23, 'Y Elcana su marido le respondió: Haz lo que bien te pareciere; quédate hasta que lo destetes; solamente Jehová cumpla su palabra. Y quedóse la mujer, y crió su hijo hasta que lo destetó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 1, 24, 'Y después que lo hubo destetado, llevólo consigo, con tres becerros, y un epha de harina, y una vasija de vino, y trájolo á la casa de Jehová en Silo: y el niño era pequeño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 1, 25, 'Y matando el becerro, trajeron el niño á Eli.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 1, 26, 'Y ella dijo: ¡Oh, señor mío! vive tu alma, señor mío, yo soy aquella mujer que estuvo aquí junto á ti orando á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 1, 27, 'Por este niño oraba, y Jehová me dió lo que le pedí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 1, 28, 'Yo pues le vuelvo también á Jehová: todos los días que viviere, será de Jehová. Y adoró allí á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 1, 'Y ANNA oró y dijo: Mi corazón se regocija en Jehová, Mi cuerno es ensalzado en Jehová; Mi boca se ensanchó sobre mis enemigos, Por cuanto me alegré en tu salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 2, 'No hay santo como Jehová: Porque no hay ninguno fuera de ti; Y no hay refugio como el Dios nuestro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 3, 'No multipliquéis hablando grandezas, altanerías; Cesen las palabras arrogantes de vuestra boca; Porque el Dios de todo saber es Jehová, Y á él toca el pesar las acciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 4, 'Los arcos de los fuertes fueron quebrados, Y los flacos se ciñeron de fortaleza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 5, 'Los hartos se alquilaron por pan: Y cesaron los hambrientos: Hasta parir siete la estéril, Y la que tenía muchos hijos enfermó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 6, 'Jehová mata, y él da vida: El hace descender al sepulcro, y hace subir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 7, 'Jehová empobrece, y él enriquece: Abate, y ensalza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 8, 'El levanta del polvo al pobre, Y al menesteroso ensalza del estiércol, Para asentarlo con los príncipes; Y hace que tengan por heredad asiento de honra: Porque de Jehová son las columnas de la tierra, Y él asentó sobre ellas el mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 9, 'El guarda los pies de sus santos, Mas los impíos perecen en tinieblas; Porque nadie será fuerte por su fuerza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 10, 'Delante de Jehová serán quebrantados sus adversarios, Y sobre ellos tronará desde los cielos: Jehová juzgará los términos de la tierra, Y dará fortaleza á su Rey, Y ensalzará el cuerno de su Mesías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 11, 'Y Elcana se volvió á su casa en Ramatha; y el niño ministraba á Jehová delante del sacerdote Eli.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 12, 'Mas los hijos de Eli eran hombres impíos, y no tenían conocimiento de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 13, 'Y la costumbre de los sacerdotes con el pueblo era que, cuando alguno ofrecía sacrificio, venía el criado del sacerdote mientras la carne estaba á cocer, trayendo en su mano un garfio de tres ganchos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 14, 'Y hería con él en la caldera, ó en la olla, ó en el caldero, ó en el pote; y todo lo que sacaba el garfio, el sacerdote lo tomaba para si. De esta manera hacían á todo Israelita que venía á Silo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 15, 'Asimismo, antes de quemar el sebo, venía el criado del sacerdote, y decía al que sacrificaba: Da carne que ase para el sacerdote; porque no tomará de ti carne cocida, sino cruda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 16, 'Y si le respondía el varón, Quemen luego el sebo hoy, y después toma tanta como quisieres; él respondía: No, sino ahora la has de dar: de otra manera yo la tomaré por fuerza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 17, 'Era pues el pecado de los mozos muy grande delante de Jehová; porque los hombres menospreciaban los sacrificios de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 18, 'Y el joven Samuel ministraba delante de Jehová, vestido de un ephod de lino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 19, 'Y hacíale su madre una túnica pequeña, y traíasela cada año, cuando subía con su marido á ofrecer el sacrificio acostumbrado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 20, 'Y Eli bendijo á Elcana y á su mujer, diciendo: Jehová te dé simiente de esta mujer en lugar de esta petición que hizo á Jehová. Y volviéronse á su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 21, 'Y visitó Jehová á Anna, y concibió, y parió tres hijos, y dos hijas. Y el joven Samuel crecía delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 22, 'Eli empero era muy viejo, y oyó todo lo que sus hijos hacían á todo Israel, y como dormían con las mujeres que velaban á la puerta del tabernáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 23, 'Y díjoles: ¿Por qué hacéis cosas semejantes? Porque yo oigo de todo este pueblo vuestros malos procederes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 24, 'No, hijos míos; porque no es buena fama la que yo oigo: que hacéis pecar al pueblo de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 25, 'Si pecare el hombre contra el hombre, los jueces le juzgarán; mas si alguno pecare contra Jehová, ¿quién rogará por él? Mas ellos no oyeron la voz de su padre, porque Jehová los quería matar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 26, 'Y el joven Samuel iba creciendo, y adelantando delante de Dios y delante de los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 27, 'Y vino un varón de Dios á Eli, y díjole: Así ha dicho Jehová: ¿No me manifesté yo claramente á la casa de tu padre, cuando estaban en Egipto en casa de Faraón?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 28, 'Y yo le escogí por mi sacerdote entre todas las tribus de Israel, para que ofreciese sobre mi altar, y quemase perfume, y trajese ephod delante de mí; y dí á la casa de tu padre todas las ofrendas de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 29, '¿Por qué habéis hollado mis sacrificios y mis presentes, que yo mandé ofrecer en el tabernáculo; y has honrado á tus hijos más que á mí, engordándoos de lo principal de todas las ofrendas de mi pueblo Israel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 30, 'Por tanto, Jehová el Dios de Israel dice: Yo había dicho que tu casa y la casa de tu padre andarían delante de mí perpetuamente; mas ahora ha dicho Jehová: Nunca yo tal haga, porque yo honraré á los que me honran, y los que me tuvieren en poco, serán viles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 31, 'He aquí vienen días, en que cortaré tu brazo, y el brazo de la casa de tu padre, que no haya viejo en tu casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 32, 'Y verás competidor en el tabernáculo, en todas las cosas en que hiciere bien á Israel; y en ningún tiempo habrá viejo en tu casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 33, 'Y no te cortaré del todo varón de mi altar, para hacerte marchitar tus ojos, y henchir tu ánimo de dolor; mas toda la cría de tu casa morirá en la edad varonil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 34, 'Y te será por señal esto que acontecerá á tus dos hijos, Ophni y Phinees: ambos morirán en un día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 35, 'Y yo me suscitaré un sacerdote fiel, que haga conforme á mi corazón y á mi alma; y yo le edificaré casa firme, y andará delante de mi ungido todo los días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 2, 36, 'Y será que el que hubiere quedado en tu casa, vendrá á postrársele por un dinero de plata y un bocado de pan, diciéndole: Ruégote que me constituyas en algún ministerio, para que coma un bocado de pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 3, 1, 'Y EL joven Samuel ministraba á Jehová delante de Eli: y la palabra de Jehová era de estima en aquellos días; no había visión manifiesta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 3, 2, 'Y aconteció un día, que estando Eli acostado en su aposento, cuando sus ojos comenzaban á oscurecerse, que no podía ver,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 3, 3, 'Samuel estaba durmiendo en el templo de Jehová, donde el arca de Dios estaba: y antes que la lámpara de Dios fuese apagada,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 3, 4, 'Jehová llamó á Samuel; y él respondió: Heme aquí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 3, 5, 'Y corriendo luego á Eli, dijo: Heme aquí; ¿para qué me llamaste? Y Eli le dijo: Yo no he llamado; vuélvete á acostar. Y él se volvió, y acostóse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 3, 6, 'Y Jehová volvió á llamar otra vez á Samuel. Y levantándose Samuel vino á Eli, y dijo: Heme aquí; ¿para qué me has llamado? Y él dijo: Hijo mío, yo no he llamado; vuelve, y acuéstate.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 3, 7, 'Y Samuel no había conocido aún á Jehová, ni la palabra de Jehová le había sido revelada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 3, 8, 'Jehová pues llamó la tercera vez á Samuel. Y él levantándose vino á Eli, y dijo: Heme aquí; ¿para qué me has llamado? Entonces entendió Eli que Jehová llamaba al joven.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 3, 9, 'Y dijo Eli á Samuel: Ve, y acuéstate: y si te llamare, dirás: Habla, Jehová, que tu siervo oye. Así se fué Samuel, y acostóse en su lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 3, 10, 'Y vino Jehová, y paróse, y llamó como las otras veces: ¡Samuel, Samuel! Entonces Samuel dijo: Habla, que tu siervo oye.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 3, 11, 'Y Jehová dijo á Samuel: He aquí haré yo una cosa en Israel, que á quien la oyere, le retiñirán ambos oídos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 3, 12, 'Aquel día yo despertaré contra Eli todas las cosas que he dicho sobre su casa. En comenzando, acabaré también.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 3, 13, 'Y mostraréle que yo juzgaré su casa para siempre, por la iniquidad que él sabe; porque sus hijos se han envilecido, y él no los ha estorbado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 3, 14, 'Y por tanto yo he jurado á la casa de Eli, que la iniquidad de la casa de Eli no será expiada jamás, ni con sacrificios ni con presentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 3, 15, 'Y Samuel estuvo acostado hasta la mañana, y abrió las puertas de la casa de Jehová. Y Samuel temía descubrir la visión á Eli.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 3, 16, 'Llamando pues Eli á Samuel, díjole: Hijo mío, Samuel. Y él respondió: Heme aquí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 3, 17, 'Y dijo: ¿Qué es la palabra que te habló Jehová?; ruégote que no me la encubras: así te haga Dios y así te añada, si me encubrieres palabra de todo lo que habló contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 3, 18, 'Y Samuel se lo manifestó todo, sin encubrirle nada. Entonces él dijo: Jehová es; haga lo que bien le pareciere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 3, 19, 'Y Samuel creció, y Jehová fué con él, y no dejó caer á tierra ninguna de sus palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 3, 20, 'Y conoció todo Israel desde Dan hasta Beer-sebah, que Samuel era fiel profeta de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 3, 21, 'Así tornó Jehová á aparecer en Silo: porque Jehová se manifestó á Samuel en Silo con palabra de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 4, 1, 'Y SAMUEL habló á todo Israel. Por aquel tiempo salió Israel á encontrar en batalla á los Filisteos, y asentó campo junto á Eben-ezer, y los Filisteos asentaron el suyo en Aphec.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 4, 2, 'Y los Filisteos presentaron la batalla á Israel; y trabándose el combate, Israel fué vencido delante de los Filisteos, los cuales hirieron en la batalla por el campo como cuatro mil hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 4, 3, 'Y vuelto que hubo el pueblo al campamento, los ancianos de Israel dijeron: ¿Por qué nos ha herido hoy Jehová delante de los Filisteos? Traigamos á nosotros de Silo el arca del pacto de Jehová, para que viniendo entre nosotros nos salve de la mano de nuestros enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 4, 4, 'Y envió el pueblo á Silo, y trajeron de allá el arca del pacto de Jehová de los ejércitos, que estaba asentado entre los querubines; y los dos hijos de Eli, Ophni y Phinees, estaban allí con el arca del pacto de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 4, 5, 'Y aconteció que, como el arca del pacto de Jehová vino al campo, todo Israel dió grita con tan grande júbilo, que la tierra tembló.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 4, 6, 'Y cuando los Filisteos oyeron la voz de júbilo, dijeron: ¿Qué voz de gran júbilo es esta en el campo de los Hebreos? Y supieron que el arca de Jehová había venido al campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 4, 7, 'Y los Filisteos tuvieron miedo, porque decían: Ha venido Dios al campo. Y dijeron: ¡Ay de nosotros! pues antes de ahora no fué así.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 4, 8, '¡Ay de nosotros! ¿Quién nos librará de las manos de estos dioses fuertes? Estos son los dioses que hirieron á Egipto con toda plaga en el desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 4, 9, 'Esforzaos, oh Filisteos, y sed hombres, porque no sirváis á los Hebreos, como ellos os han servido á vosotros: sed hombres, y pelead.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 4, 10, 'Pelearon pues los Filisteos, é Israel fué vencido, y huyeron cada cual á sus tiendas; y fué hecha muy grande mortandad, pues cayeron de Israel treinta mil hombres de á pie.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 4, 11, 'Y el arca de Dios fué tomada, y muertos los dos hijos de Eli, Ophni y Phinees.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 4, 12, 'Y corriendo de la batalla un hombre de Benjamín, vino aquel día á Silo, rotos sus vestidos y tierra sobre su cabeza:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 4, 13, 'Y cuando llegó, he aquí Eli que estaba sentado en una silla atalayando junto al camino; porque su corazón estaba temblando por causa del arca de Dios. Llegado pues aquel hombre á la ciudad, y dadas las nuevas, toda la ciudad gritó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 4, 14, 'Y como Eli oyó el estruendo de la gritería, dijo: ¿Qué estruendo de alboroto es éste? Y aquel hombre vino apriesa, y dió las nuevas á Eli.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 4, 15, 'Era ya Eli de edad de noventa y ocho años, y sus ojos se habían entenebrecido, de modo que no podía ver.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 4, 16, 'Dijo pues aquel hombre á Eli: Yo vengo de la batalla, yo he escapado hoy del combate. Y él dijo: ¿Qué ha acontecido, hijo mío?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 4, 17, 'Y el mensajero respondió, y dijo: Israel huyó delante de los Filisteos, y también fué hecha gran mortandad en el pueblo; y también tus dos hijos, Ophni y Phinees, son muertos, y el arca de Dios fué tomada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 4, 18, 'Y aconteció que como él hizo mención del arca de Dios, Eli cayó hacia atrás de la silla al lado de la puerta, y quebrósele la cerviz, y murió: porque era hombre viejo y pesado. Y había juzgado á Israel cuarenta años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 4, 19, 'Y su nuera, la mujer de Phinees, que estaba preñada, cercana al parto, oyendo el rumor que el arca de Dios era tomada, y muertos su suegro y su marido, encorvóse y parió; porque sus dolores se habían ya derramado por ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 4, 20, 'Y al tiempo que se moría, decíanle las que estaban junto á ella: No tengas temor, porque has parido un hijo. Mas ella no respondió, ni paró mientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 4, 21, 'Y llamó al niño Ichâbod, diciendo: ¡Traspasada es la gloria de Israel! por el arca de Dios que fué tomada, y porque era muerto su suegro, y su marido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 4, 22, 'Dijo pues: Traspasada es la gloria de Israel: porque el arca de Dios fué tomada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 5, 1, 'Y LOS Filisteos, tomada el arca de Dios, trajéronla desde Eben-ezer á Asdod.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 5, 2, 'Y tomaron los Filisteos el arca de Dios, y metiéronla en la casa de Dagón, y pusiéronla junto á Dagón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 5, 3, 'Y el siguiente día los de Asdod se levantaron de mañana, y he aquí Dagón postrado en tierra delante del arca de Jehová: y tomaron á Dagón, y volviéronlo á su lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 5, 4, 'Y tornándose á levantar de mañana el siguiente día, he aquí que Dagón había caído postrado en tierra delante del arca de Jehová; y la cabeza de Dagón, y las dos palmas de sus manos estaban cortadas sobre el umbral, habiéndole quedado á Dagón el tronco solamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 5, 5, 'Por esta causa los sacerdotes de Dagón, y todos los que en el templo de Dagón entran, no pisan el umbral de Dagón en Asdod, hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 5, 6, 'Empero agravóse la mano de Jehová sobre los de Asdod, y destruyólos, é hiriólos con hemorroides en Asdod y en todos sus términos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 5, 7, 'Y viendo esto los de Asdod, dijeron: No quede con nosotros el arca del Dios de Israel, porque su mano es dura sobre nosotros, y sobre nuestro dios Dagón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 5, 8, 'Enviaron pues á juntar á sí todos los príncipes de los Filisteos, y dijeron: ¿Qué haremos del arca del Dios de Israel? Y ellos respondieron: Pásese el arca del Dios de Israel á Gath. Y pasaron allá el arca del Dios de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 5, 9, 'Y aconteció que como la hubieron pasado, la mano de Jehová fué contra la ciudad con grande quebrantamiento; é hirió los hombres de aquella ciudad desde el chico hasta el grande, que se llenaron de hemorroides.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 5, 10, 'Entonces enviaron el arca de Dios á Ecrón. Y como el arca de Dios vino á Ecrón, los Ecronitas dieron voces diciendo: Han pasado á mí el arca del Dios de Israel por matarme á mí y á mi pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 5, 11, 'Y enviaron á juntar todos los príncipes de los Filisteos, diciendo: Despachad el arca del Dios de Israel, y tórnese á su lugar, y no mate á mí ni á mi pueblo: porque había quebrantamiento de muerte en toda la ciudad, y la mano de Dios se había allí agravado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 5, 12, 'Y los que no morían, eran heridos de hemorroides; y el clamor de la ciudad subía al cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 6, 1, 'Y ESTUVO el arca de Jehová en la tierra de los Filisteos siete meses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 6, 2, 'Entonces los Filisteos, llamando los sacerdotes y adivinos, preguntaron: ¿Qué haremos del arca de Jehová? Declaradnos cómo la hemos de tornar á enviar á su lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 6, 3, 'Y ellos dijeron: Si enviáis el arca del Dios de Israel, no la enviéis vacía; mas le pagaréis la expiación: y entonces seréis sanos, y conoceréis por qué no se apartó de vosotros su mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 6, 4, 'Y ellos dijeron: ¿Y qué será la expiación que le pagaremos? Y ellos respondieron: Conforme al número de los príncipes de los Filisteos, cinco hermorroides de oro, y cinco ratones de oro, porque la misma plaga que todos tienen, tienen también vuestros príncipes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 6, 5, 'Haréis pues las formas de vuestras hemorroides, y las formas de vuestros ratones que destruyen la tierra, y daréis gloria al Dios de Israel: quizá aliviará su mano de sobre vosotros, y de sobre vuestros dioses, y de sobre vuestra tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 6, 6, 'Mas ¿por qué endurecéis vuestro corazón, como los Egipcios y Faraón endurecieron su corazón? Después que los hubo así tratado, ¿no los dejaron que se fuesen, y se fueron?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 6, 7, 'Haced pues ahora un carro nuevo, y tomad luego dos vacas que críen, á las cuales no haya sido puesto yugo, y uncid las vacas al carro, y haced tornar de detrás de ellas sus becerros á casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 6, 8, 'Tomaréis luego el arca de Jehová, y la pondréis sobre el carro; y poned en una caja al lado de ella las alhajas de oro que le pagáis en expiación: y la dejaréis que se vaya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 6, 9, 'Y mirad: si sube por el camino de su término á Beth-semes, él nos ha hecho este mal tan grande; y si no, seremos ciertos que su mano no nos hirió, nos ha sido accidente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 6, 10, 'Y aquellos hombres lo hicieron así; pues tomando dos vacas que criaban, unciéronlas al carro, y encerraron en casa sus becerros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 6, 11, 'Luego pusieron el arca de Jehová sobre el carro, y la caja con los ratones de oro y con las formas de sus hemorroides.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 6, 12, 'Y las vacas se encaminaron por el camino de Beth-semes, é iban por un mismo camino andando y bramando, sin apartarse ni á diestra ni á siniestra: y los príncipes de los Filisteos fueron tras ellas hasta el término de Beth-semes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 6, 13, 'Y los de Beth-semes segaban el trigo en el valle; y alzando sus ojos vieron el arca, y holgáronse cuando la vieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 6, 14, 'Y el carro vino al campo de Josué Beth-semita, y paró allí porque allí había una gran piedra; y ellos cortaron la madera del carro, y ofrecieron las vacas en holocausto á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 6, 15, 'Y los Levitas bajaron el arca de Jehová, y la caja que estaba junto á ella, en la cual estaban las alhajas de oro, y pusiéronlas sobre aquella gran piedra; y los hombre de Beth-semes sacrificaron holocaustos y mataron víctimas á Jehová en aquel día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 6, 16, 'Lo cual viendo los cinco príncipes de los Filisteos, volviéronse á Ecrón el mismo día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 6, 17, 'Estas pues son las hemorroides de oro que pagaron los Filisteos á Jehová en expiación: por Asdod una, por Gaza una, por Ascalón una, por Gath una, por Ecrón una;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 6, 18, 'Y ratones de oro conforme al número de todas las ciudades de los Filisteos pertenecientes á los cinco príncipes, desde las ciudades fuertes hasta las aldeas sin muro; y hasta la gran piedra sobre la cual pusieron el arca de Jehová, piedra que está en el campo de Josué Beth-semita hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 6, 19, 'Entonces hirió Dios á los de Beth-semes, porque habían mirado en el arca de Jehová; hirió en el pueblo cincuenta mil y setenta hombres. Y el pueblo puso luto, porque Jehová le había herido de tan gran plaga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 6, 20, 'Y dijeron los de Beth-semes: ¿Quién podrá estar delante de Jehová el Dios santo? ¿y á quién subirá desde nosotros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 6, 21, 'Y enviaron mensajeros á los de Chîriath-jearim, diciendo: Los Filisteos han vuelto el arca de Jehová: descended pues, y llevadla á vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 7, 1, 'Y VINIERON los de Chîriath-jearim, y llevaron el arca de Jehová, y metiéronla en casa de Abinadab, situada en el collado; y santificaron á Eleazar su hijo, para que guardase el arca de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 7, 2, 'Y aconteció que desde el día que llegó el arca á Chîriath-jearim pasaron mucho días, veinte años; y toda la casa de Israel lamentaba en pos de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 7, 3, 'Y habló Samuel á toda la casa de Israel, diciendo: Si de todo vuestro corazón os volvéis á Jehová, quitad los dioses ajenos y á Astaroth de entre vosotros, y preparad vuestro corazón á Jehová, y á sólo él servid, y os librará de mano de los Filisteos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 7, 4, 'Entonces los hijos de Israel quitaron á los Baales y á Astaroth, y sirvieron á solo Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 7, 5, 'Y Samuel dijo: Juntad á todo Israel en Mizpa, y yo oraré por vosotros á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 7, 6, 'Y juntándose en Mizpa, sacaron agua, y derramáronla delante de Jehová, y ayunaron aquel día, y dijeron allí: Contra Jehová hemos pecado. Y juzgó Samuel á los hijos de Israel en Mizpa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 7, 7, 'Y oyendo los Filisteos que los hijos de Israel estaban reunidos en Mizpa, subieron los príncipes de los Filisteos contra Israel: lo cual como hubieron oído los hijos de Israel, tuvieron temor de los Filisteos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 7, 8, 'Y dijeron los hijos de Israel á Samuel: No ceses de clamar por nosotros á Jehová nuestro Dios, que nos guarde de mano de los filisteos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 7, 9, 'Y Samuel tomó un cordero de leche, y sacrificólo entero á Jehová en holocausto: y clamó Samuel á Jehová por Israel, y Jehová le oyó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 7, 10, 'Y aconteció que estando Samuel sacrificando el holocausto, los Filisteos llegaron para pelear con los hijos de Israel. Mas Jehová tronó aquel día con grande estruendo sobre los Filisteos, y desbaratólos, y fueron vencidos delante de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 7, 11, 'Y saliendo los hijos de Israel de Mizpa, siguieron á los Filisteos, hiriéndolos hasta abajo de Beth-car.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 7, 12, 'Tomó luego Samuel una piedra, y púsola entre Mizpa y Sen, y púsole por nombre Eben-ezer, diciendo: Hasta aquí nos ayudó Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 7, 13, 'Fueron pues los Filisteos humillados, que no vinieron más al término de Israel; y la mano de Jehová fué contra los Filisteos todo el tiempo de Samuel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 7, 14, 'Y fueron restituídas á los hijos de Israel las ciudades que los Filisteos habían tomado á los Isrelitas, desde Ecrón hasta Gath, con sus términos: é Israel las libró de mano de los Filisteos. Y hubo paz entre Israel y el Amorrheo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 7, 15, 'Y juzgó Samuel á Israel todo el tiempo que vivió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 7, 16, 'Y todos los años iba y daba vuelta á Beth-el, y á Gilgal, y á Mizpa, y juzgaba á Israel en todos estos lugares.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 7, 17, 'Volvíase después á Rama, porque allí estaba su casa, y allí juzgaba á Israel; y edificó allí altar á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 8, 1, 'Y ACONTECIO que habiendo Samuel envejecido, puso sus hijos por jueces sobre Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 8, 2, 'Y el nombre de su hijo primogénito fué Joel, y el nombre del segundo, Abia: fueron jueces en Beer-sebah.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 8, 3, 'Mas no anduvieron los hijos por los caminos de su padre, antes se ladearon tras la avaricia, recibiendo cohecho y pervirtiendo el derecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 8, 4, 'Entonces todos los ancianos de Israel se juntaron, y vinieron á Samuel en Rama,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 8, 5, 'Y dijéronle: He aquí tú has envejecido, y tus hijos no van por tus caminos: por tanto, constitúyenos ahora un rey que nos juzgue, como todas las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 8, 6, 'Y descontentó á Samuel esta palabra que dijeron: Danos rey que nos juzgue. Y Samuel oró á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 8, 7, 'Y dijo Jehová á Samuel: Oye la voz del pueblo en todo lo que te dijeren: porque no te han desechado á ti, sino á mí me han desechado, para que no reine sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 8, 8, 'Conforme á todas las obras que han hecho desde el día que los saqué de Egipto hasta hoy, que me han dejado y han servido á dioses ajenos, así hacen también contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 8, 9, 'Ahora pues, oye su voz: mas protesta contra ellos declarándoles el derecho del rey que ha de reinar sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 8, 10, 'Y dijo Samuel todas las palabras de Jehová al pueblo que le había pedido rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 8, 11, 'Dijo pues: Este será el derecho del rey que hubiere de reinar sobre vosotros: tomará vuestros hijos, y pondrálos en sus carros, y en su gente de á caballo, para que corran delante de su carro:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 8, 12, 'Y se elegirá capitanes de mil, y capitanes de cincuenta: pondrálos asimismo á que aren sus campos, y sieguen sus mieses, y á que hagan sus armas de guerra, y los pertrechos de sus carros:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 8, 13, 'Tomará también vuestras hijas para que sean perfumadoras, cocineras, y amasadoras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 8, 14, 'Asimismo tomará vuestras tierras, vuestras viñas, y vuestros buenos olivares, y los dará á sus siervos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 8, 15, 'El diezmará vuestras simientes y vuestras viñas, para dar á sus eunucos y á sus siervos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 8, 16, 'El tomará vuestros siervos, y vuestras siervas, y vuestros buenos mancebos, y vuestros asnos, y con ellos hará sus obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 8, 17, 'Diezmará también vuestro rebaño, y seréis sus siervos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 8, 18, 'Y clamaréis aquel día á causa de vuestro rey que os habréis elegido, mas Jehová no os oirá en aquel día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 8, 19, 'Empero el pueblo no quiso oir la voz de Samuel; antes dijeron: No, sino que habrá rey sobre nosotros:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 8, 20, 'Y nosotros seremos también como todas las gentes, y nuestro rey nos gobernará, y saldrá delante de nosotros, y hará nuestras guerras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 8, 21, 'Y oyó Samuel todas las palabras del pueblo, y refiriólas en oídos de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 8, 22, 'Y Jehová dijo á Samuel: Oye su voz, y pon rey sobre ellos. Entonces dijo Samuel á los varones de Israel: Idos cada uno á su ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 9, 1, 'Y HABIA un varón de Benjamín, hombre valeroso, el cual se llamaba Cis, hijo de Abiel, hijo de Seor, hijo de Bechôra, hijo de Aphia, hijo de un hombre de Benjamín.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 9, 2, 'Y tenía él un hijo que se llamaba Saúl, mancebo y hermoso, que entre los hijos de Israel no había otro más hermoso que él; del hombro arriba sobrepujaba á cualquiera del pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 9, 3, 'Y habíanse perdido las asnas de Cis, padre de Saúl; por lo que dijo Cis á Saúl su hijo: Toma ahora contigo alguno de los criados, y levántate, y ve á buscar las asnas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 9, 4, 'Y él pasó al monte de Ephraim, y de allí á la tierra de Salisa, y no las hallaron. Pasaron luego por la tierra de Saalim, y tampoco. Después pasaron por la tierra de Benjamín, y no las encontraron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 9, 5, 'Y cuando vinieron á la tierra de Suph, Saúl dijo á su criado que tenía consigo: Ven, volvámonos; porque quizá mi padre, dejado el cuidado de las asnas, estará congojado por nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 9, 6, 'Y él le respondió: He aquí ahora hay en esta ciudad un hombre de Dios, que es varón insigne: todas las cosas que él dijere, sin duda vendrán. Vamos pues allá: quizá nos enseñará nuestro camino por donde hayamos de ir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 9, 7, 'Y Saúl respondió á su criado: Vamos ahora: ¿mas qué llevaremos al varón? Porque el pan de nuestras alforjas se ha acabado, y no tenemos qué presentar al varón de Dios: ¿qué tenemos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 9, 8, 'Entonces tornó el criado á responder á Saúl, diciendo: He aquí se halla en mi mano la cuarta parte de un siclo de plata: esto daré al varón de Dios, porque nos declare nuestro camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 9, 9, '(Antiguamente en Israel cualquiera que iba á consultar á Dios, decía así: Venid y vamos hasta el vidente: porque el que ahora se llama profeta, antiguamente era llamado vidente).');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 9, 10, 'Dijo entonces Saúl á su criado: Bien dices; ea pues, vamos. Y fueron á la ciudad donde estaba el varón de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 9, 11, 'Y cuando subían por la cuesta de la ciudad, hallaron unas mozas que salían por agua, á las cuales dijeron: ¿Está en este lugar el vidente?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 9, 12, 'Y ellas respondiéndoles, dijeron: Sí; helo aquí delante de ti: date pues priesa, porque hoy ha venido á la ciudad en atención á que el pueblo tiene hoy sacrificio en el alto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 9, 13, 'Y cuando entrareis en la ciudad, le encontraréis luego, antes que suba al alto á comer; pues el pueblo no comerá hasta que él haya venido, por cuanto él haya de bendecir el sacrificio, y después comerán los convidados. Subid pues ahora, porque ahora le hallaréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 9, 14, 'Ellos entonces subieron á la ciudad; y cuando en medio de la ciudad estuvieron, he aquí Samuel que delante de ellos salía para subir al alto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 9, 15, 'Y un día antes que Saúl viniese, Jehová había revelado al oído de Samuel, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 9, 16, 'Mañana á esta misma hora yo enviaré á ti un varón de la tierra de Benjamín, al cual ungirás por príncipe sobre mi pueblo Israel, y salvará mi pueblo de mano de los Filisteos: pues yo he mirado á mi pueblo, porque su clamor ha llegado hasta mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 9, 17, 'Y luego que Samuel vió á Saúl, Jehová le dijo: He aquí éste es el varón del cual te hablé; éste señoreará á mi pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 9, 18, 'Y llegando Saúl á Samuel en medio de la puerta, díjole: Ruégote que me enseñes dónde está la casa del vidente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 9, 19, 'Y Samuel respondió á Saúl, y dijo: Yo soy el vidente: sube delante de mí al alto, y comed hoy conmigo, y por la mañana te despacharé, y te descubriré todo lo que está en tu corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 9, 20, 'Y de las asnas que se te perdieron hoy ha tres días, pierde cuidado de ellas, porque se han hallado. Mas ¿por quién es todo el deseo de Israel, sino por ti y por toda la casa de tu padre?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 9, 21, 'Y Saúl respondió, y dijo: ¿No soy yo hijo de Benjamín, de las más pequeñas tribus de Israel? y mi familia ¿no es la más pequeña de todas las familias de la tribu de Benjamín? ¿por qué pues me has dicho cosa semejante?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 9, 22, 'Y trabando Samuel de Saúl y de su criado, metiólos en la sala, y dióles lugar á la cabecera de los convidados, que eran como unos treinta hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 9, 23, 'Y dijo Samuel al cocinero: Trae acá la porción que te dí, la cual te dije que guardases aparte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 9, 24, 'Entonces alzó el cocinero una espaldilla, con lo que estaba sobre ella, y púsola delante de Saúl. Y Samuel dijo: He aquí lo que estaba reservado: ponlo delante de ti, y come; porque de industria se guardó para ti, cuando dije: Yo he convidado al pueblo. Y Saúl comió aquel día con Samuel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 9, 25, 'Y cuando hubieron descendido de lo alto á la ciudad, él habló con Saúl en el terrado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 9, 26, 'Y al otro día madrugaron: y como al apuntar del alba, Samuel llamó á Saúl, que estaba en el terrado; y dijo: Levántate, para que te despache. Levantóse luego Saúl, y salieron fuera ambos, él y Samuel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 9, 27, 'Y descendiendo ellos al cabo de la ciudad, dijo Samuel á Saúl: Di al mozo que vaya delante, (y adelantóse el mozo); mas espera tú un poco para que te declare palabra de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 10, 1, 'TOMANDO entonces Samuel una ampolla de aceite, derramóla sobre su cabeza, y besólo, y díjole: ¿No te ha ungido Jehová por capitán sobre su heredad?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 10, 2, 'Hoy, después que te hayas apartado de mí, hallarás dos hombres junto al sepulcro de Rachêl, en el término de Benjamín, en Selsah, los cuales te dirán: Las asnas que habías ido á buscar, se han hallado; tu padre pues ha dejado ya el negocio de las asnas, si bien está angustioso por vosotros, diciendo: ¿Qué haré acerca de mi hijo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 10, 3, 'Y como de allí te fueres más adelante, y llegares á la campiña de Tabor, te saldrán al encuentro tres hombres que suben á Dios en Beth-el, llevando el uno tres cabritos, y el otro tres tortas de pan, y el tercero una vasija de vino:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 10, 4, 'Los cuales, luego que te hayan saludado, te darán dos panes, los que tomarás de manos de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 10, 5, 'De allí vendrás al collado de Dios donde está la guarnición de los Filisteos; y cuando entrares allá en la ciudad encontrarás una compañía de profetas que descienden del alto, y delante de ellos salterio, y adufe, y flauta, y arpa, y ellos profetizando:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 10, 6, 'Y el espíritu de Jehová te arrebatará, y profetizarás con ellos, y serás mudado en otro hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 10, 7, 'Y cuando te hubieren sobrevenido estas señales, haz lo que te viniere á la mano, porque Dios es contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 10, 8, 'Y bajarás delante de mí á Gilgal; y luego descenderé yo á ti para sacrificar holocaustos, é inmolar víctimas pacíficas. Espera siete días, hasta que yo venga á ti, y te enseñe lo que has de hacer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 10, 9, 'Y fué que así como tornó él su hombro para partirse de Samuel, mudóle Dios su corazón; y todas estas señales acaecieron en aquel día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 10, 10, 'Y cuando llegaron allá al collado, he aquí la compañía de los profetas que venía á encontrarse con él, y el espíritu de Dios lo arrebató, y profetizó entre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 10, 11, 'Y aconteció que, cuando todos los que le conocían de ayer y de antes, vieron como profetizaba con los profetas, el pueblo decía el uno al otro: ¿Qué ha sucedido al hijo de Cis? ¿Saúl también entre los profetas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 10, 12, 'Y alguno de allí respondió, y dijo: ¿Y quién es el padre de ellos? Por esta causa se tornó en proverbio: ¿También Saúl entre los profetas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 10, 13, 'Y cesó de profetizar, y llegó al alto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 10, 14, 'Y un tío de Saúl dijo á él y á su criado: ¿Dónde fuisteis? Y él respondió: A buscar las asnas; y como vimos que no parecían, fuimos á Samuel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 10, 15, 'Y dijo el tío de Saúl: Yo te ruego me declares qué os dijo Samuel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 10, 16, 'Y Saúl respondió á su tío: Declarónos expresamente que las asnas habían parecido. Mas del negocio del reino, de que Samuel le había hablado, no le descubrió nada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 10, 17, 'Y Samuel convocó el pueblo á Jehová en Mizpa;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 10, 18, 'Y dijo á los hijos de Israel: Así ha dicho Jehová el Dios de Israel: Yo saqué á Israel de Egipto, y os libré de mano de los Egipcios, y de mano de todos los reinos que os afligieron:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 10, 19, 'Mas vosotros habéis desechado hoy á vuestro Dios, que os guarda de todas vuestras aflicciones y angustias, y dijisteis: No, sino pon rey sobre nosotros. Ahora pues, poneos delante de Jehová por vuestras tribus y por vuestros millares.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 10, 20, 'Y haciendo allegar Samuel todas las tribus de Israel, fué tomada la tribu de Benjamín.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 10, 21, 'E hizo llegar la tribu de Benjamín por sus linajes, y fué tomada la familia de Matri; y de ella fué tomado Saúl hijo de Cis. Y le buscaron, mas no fué hallado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 10, 22, 'Preguntaron pues otra vez á Jehová, si había aún de venir allí aquel varón. Y respondió Jehová: He aquí que él está escondido entre el bagaje.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 10, 23, 'Entonces corrieron, y tomáronlo de allí, y puesto en medio del pueblo, desde el hombro arriba era más alto que todo el pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 10, 24, 'Y Samuel dijo á todo el pueblo: ¿Habéis visto al que ha elegido Jehová, que no hay semejante á él en todo el pueblo? Entonces el pueblo clamó con alegría, diciendo: Viva el rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 10, 25, 'Samuel recitó luego al pueblo el derecho del reino, y escribiólo en un libro, el cual guardó delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 10, 26, 'Y envió Samuel á todo el pueblo cada uno á su casa. Y Saúl también se fué á su casa en Gabaa, y fueron con él el ejército, el corazón de los cuales Dios había tocado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 10, 27, 'Pero los impíos dijeron: ¿Cómo nos ha de salvar éste? Y tuviéronle en poco, y no le trajeron presente: mas él disimuló.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 11, 1, 'Y SUBIO Naas Ammonita, y asentó campo contra Jabes de Galaad. Y todos los de Jabes dijeron á Naas: Haz alianza con nosotros, y te serviremos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 11, 2, 'Y Naas Ammonita les respondió: Con esta condición haré alianza con vosotros, que á cada uno de todos vosotros saque el ojo derecho, y ponga esta afrenta sobre todo Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 11, 3, 'Entonces los ancianos de Jabes le dijeron: Danos siete días, para que enviemos mensajeros á todos los términos de Israel; y si nadie hubiere que nos defienda, saldremos á ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 11, 4, 'Y llegando los mensajeros á Gabaa de Saúl, dijeron estas palabras en oídos del pueblo; y todo el pueblo lloró á voz en grito.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 11, 5, 'Y he aquí Saúl que venía del campo, tras los bueyes; y dijo Saúl: ¿Qué tiene el pueblo, que lloran? Y contáronle las palabras de los hombres de Jabes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 11, 6, 'Y el espíritu de Dios arrebató á Saúl en oyendo estas palabras, y encendióse en ira en gran manera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 11, 7, 'Y tomando un par de bueyes, cortólos en piezas, y enviólas por todos los términos de Israel por mano de mensajeros, diciendo: Cualquiera que no saliere en pos de Saúl y en pos de Samuel, así será hecho á sus bueyes. Y cayó temor de Jehová sobre el pueblo, y salieron como un solo hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 11, 8, 'Y contóles en Bezec; y fueron los hijos de Israel trescientos mil, y treinta mil los hombres de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 11, 9, 'Y respondieron á los mensajeros que habían venido: Así diréis á los de Jabes de Galaad: Mañana en calentando el sol, tendréis salvamento. Y vinieron los mensajeros, y declaráronlo á los de Jabes, los cuales se holgaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 11, 10, 'Y los de Jabes dijeron: Mañana saldremos á vosotros, para que hagáis con nosotros todo lo que bien os pareciere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 11, 11, 'Y el día siguiente dispuso Saúl el pueblo en tres escuadrones, y entraron en medio del real á la vela de la mañana, é hirieron á los Ammonitas hasta que el día calentaba: y los que quedaron fueron dispersos, tal que no quedaron dos de ellos juntos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 11, 12, 'El pueblo entonces dijo á Samuel: ¿Quiénes son lo que decían: Reinará Saúl sobre nosotros? Dad nos esos hombres, y los mataremos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 11, 13, 'Y Saúl dijo: No morirá hoy ninguno, porque hoy ha obrado Jehová salud en Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 11, 14, 'Mas Samuel dijo al pueblo: Venid, vamos á Gilgal para que renovemos allí el reino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 11, 15, 'Y fué todo el pueblo á Gilgal, é invistieron allí á Saúl por rey delante de Jehová en Gilgal. Y sacrificaron allí víctimas pacíficas delante de Jehová; y alegráronse mucho allí Saúl y todos los de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 12, 1, 'Y DIJO Samuel á todo Israel: He aquí, yo he oído vuestra voz en todas las cosas que me habéis dicho, y os he puesto rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 12, 2, 'Ahora pues, he aquí vuestro rey va delante de vosotros. Yo soy ya viejo y cano: mas mis hijos están con vosotros, y yo he andado delante de vosotros desde mi mocedad hasta este día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 12, 3, 'Aquí estoy; atestiguad contra mí delante de Jehová y delante de su ungido, si he tomado el buey de alguno, ó si he tomado el asno de alguno, ó si he calumniado á alguien, ó si he agraviado á alguno, ó si de alguien he tomado cohecho por el cual haya cubierto mis ojos: y os satisfaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 12, 4, 'Entonces dijeron: Nunca nos has calumniado, ni agraviado, ni has tomado algo de mano de ningún hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 12, 5, 'Y él les dijo: Jehová es testigo contra vosotros, y su ungido también es testigo en este día, que no habéis hallado en mi mano cosa ninguna. Y ellos respondieron: Así es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 12, 6, 'Entonces Samuel dijo al pueblo: Jehová es quien hizo á Moisés y á Aarón, y que sacó á vuestros padres de la tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 12, 7, 'Ahora pues, aguardad, y yo os haré cargo delante de Jehová de todas las justicias de Jehová, que ha hecho con vosotros y con vuestros padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 12, 8, 'Después que Jacob hubo entrado en Egipto y vuestros padres clamaron á Jehová, Jehová envió á Moisés y á Aarón, los cuales sacaron á vuestros padres de Egipto, y los hicieron habitar en este lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 12, 9, 'Y olvidaron á Jehová su Dios, y él los vendió en la mano de Sísara capitán del ejército de Asor, y en la mano de los Filisteos, y en la mano del rey de Moab, los cuales les hicieron guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 12, 10, 'Y ellos clamaron á Jehová, y dijeron: Pecamos, que hemos dejado á Jehová, y hemos servido á los Baales y á Astaroth: líbranos pues ahora de la mano de nuestros enemigos, y te serviremos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 12, 11, 'Entonces Jehová envió á Jero-baal, y á Bedán, y á Jephté, y á Samuel, y os libró de mano de vuestros enemigos alrededor, y habitasteis seguros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 12, 12, 'Y habiendo visto que Naas rey de lo hijos de Ammón venía contra vosotros, me dijisteis: No, sino rey reinará sobre nosotros; siendo vuestro rey Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 12, 13, 'Ahora pues, ved aquí vuestro rey que habéis elegido, el cual pedisteis; ya veis que Jehová ha puesto sobre vosotros rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 12, 14, 'Si temiereis á Jehová y le sirviereis, y oyereis su voz, y no fuereis rebeldes á la palabra de Jehová, así vosotros como el rey que reina sobre vosotros, seréis en pos de Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 12, 15, 'Mas si no oyereis la voz de Jehová, y si fuereis rebeldes á las palabras de Jehová, la mano de Jehová será contra vosotros como contra vuestros padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 12, 16, 'Esperad aún ahora, y mirad esta gran cosa que Jehová hará delante de vuestros ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 12, 17, '¿No es ahora la siega de los trigos? Yo clamaré á Jehová, y él dará truenos y aguas; para que conozcáis y veáis que es grande vuestra maldad que habéis hecho en los ojos de Jehová, pidiéndoos rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 12, 18, 'Y Samuel clamó á Jehová; y Jehová dió truenos y aguas en aquel día; y todo el pueblo temió en gran manera á Jehová y á Samuel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 12, 19, 'Entonces dijo todo el pueblo á Samuel: Ruega por tus siervos á Jehová tu Dios, que no muramos: porque á todos nuestros pecados hemos añadido este mal de pedir rey para nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 12, 20, 'Y Samuel respondió al pueblo: No temáis: vosotros habéis cometido todo este mal; mas con todo eso no os apartéis de en pos de Jehová, sino servid á Jehová con todo vuestro corazón:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 12, 21, 'No os apartéis en pos de las vanidades, que no aprovechan ni libran, porque son vanidades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 12, 22, 'Pues Jehová no desamparará á su pueblo por su grande nombre: porque Jehová ha querido haceros pueblo suyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 12, 23, 'Así que, lejos sea de mí que peque yo contra Jehová cesando de rogar por vosotros; antes yo os enseñaré por el camino bueno y derecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 12, 24, 'Solamente temed á Jehová, y servidle de verdad con todo vuestro corazón, porque considerad cuán grandes cosas ha hecho con vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 12, 25, 'Mas si perseverareis en hacer mal, vosotros y vuestro rey pereceréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 13, 1, 'HABIA ya Saúl reinado un año; y reinado que hubo dos años sobre Israel,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 13, 2, 'Escogióse luego tres mil de Israel: los dos mil estuvieron con Saúl en Michmas y en el monte de Beth-el, y los mil estuvieron con Jonathán en Gabaa de Benjamín; y envió á todo el otro pueblo cada uno á sus tiendas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 13, 3, 'Y Jonathán hirió la guarnición de los Filisteos que había en el collado, y oyéronlo los Filisteos. E hizo Saúl tocar trompetas por toda la tierra, diciendo: Oigan los Hebreos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 13, 4, 'Y todo Israel oyó lo que se decía: Saúl ha herido la guarnición de los Filisteos; y también que Israel olía mal á los Filisteos. Y juntóse el pueblo en pos de Saúl en Gilgal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 13, 5, 'Entonces los Filisteos se juntaron para pelear con Israel, treinta mil carros, y seis mil caballos, y pueblo como la arena que está á la orilla de la mar en multitud; y subieron, y asentaron campo en Michmas, al oriente de Beth-aven.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 13, 6, 'Mas los hombres de Israel, viéndose puestos en estrecho, (porque el pueblo estaba en aprieto), escondióse el pueblo en cuevas, en fosos, en peñascos, en rocas y en cisternas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 13, 7, 'Y algunos de los Hebreos pasaron el Jordán á la tierra de Gad y de Galaad: y Saúl se estaba aún en Gilgal, y todo el pueblo iba tras él temblando.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 13, 8, 'Y él esperó siete días, conforme al plazo que Samuel había dicho; pero Samuel no venía á Gilgal, y el pueblo se le desertaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 13, 9, 'Entonces dijo Saúl: Traedme holocausto y sacrificios pacíficos. Y ofreció el holocausto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 13, 10, 'Y como él acababa de hacer el holocausto, he aquí Samuel que venía; y Saúl le salió á recibir para saludarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 13, 11, 'Entonces Samuel dijo: ¿Qué has hecho? Y Saúl respondió: Porque vi que el pueblo se me iba, y que tú no venías al plazo de los días, y que los Filisteos estaban juntos en Michmas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 13, 12, 'Me dije: Los Filisteos descenderán ahora contra mí á Gilgal, y yo no he implorado el favor de Jehová. Esforcéme pues, y ofrecí holocausto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 13, 13, 'Entonces Samuel dijo á Saúl: Locamente has hecho; no guardaste el mandamiento de Jehová tu Dios, que él te había intimado; porque ahora Jehová hubiera confirmado tu reino sobre Israel para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 13, 14, 'Mas ahora tu reino no será durable: Jehová se ha buscado varón según su corazón, al cual Jehová ha mandado que sea capitán sobre su pueblo, por cuanto tú no has guardado lo que Jehová te mandó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 13, 15, 'Y levantándose Samuel, subió de Gilgal á Gabaa de Benjamín. Y Saúl contó la gente que se hallaba con él, como seiscientos hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 13, 16, 'Saúl pues y Jonathán su hijo, y el pueblo que con ellos se hallaba, quedáronse en Gabaa de Benjamín: mas los Filisteos habían puesto su campo en Michmas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 13, 17, 'Y salieron del campo de los Filisteos en correría tres escuadrones. El un escuadrón tiró por el camino de Ophra hacia la tierra de Sual.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 13, 18, 'El otro escuadrón marchó hacia Beth-oron, y el tercer escuadrón marchó hacia la región que mira al valle de Seboim hacia el desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 13, 19, 'Y en toda la tierra de Israel no se hallaba herrero; porque los Filisteos habían dicho: Para que los Hebreos no hagan espada ó lanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 13, 20, 'Y todos los de Israel descendían á los Filisteos cada cual á amolar su reja, su azadón, su hacha, ó su sacho,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 13, 21, 'Y cuando se hacían bocas en las rejas, ó en los azadones, ó en las horquillas, ó en las hachas; hasta para una ahijada que se hubiera de componer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 13, 22, 'Así aconteció que el día de la batalla no se halló espada ni lanza en mano de alguno de todo el pueblo que estaba con Saúl y con Jonathán, excepto Saúl y Jonathán su hijo, que las tenían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 13, 23, 'Y la guarnición de los Filisteos salió al paso de Michmas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 1, 'Y UN día aconteció, que Jonathán hijo de Saúl dijo á su criado que le traía las armas: Ven, y pasemos á la guarnición de los Filisteos, que está á aquel lado. Y no lo hizo saber á su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 2, 'Y Saúl estaba en el término de Gabaa, debajo de un granado que hay en Migrón, y el pueblo que estaba con él era como seiscientos hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 3, 'Y Achîas hijo de Achîtob, hermano de Ichâbod, hijo de Phinees, hijo de Eli, sacerdote de Jehová en Silo, llevaba el ephod; y no sabía el pueblo que Jonathán se hubiese ido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 4, 'Y entre los pasos por donde Jonathán procuraba pasar á la guarnición de los Filisteos, había un peñasco agudo de la una parte, y otro de la otra parte; el uno se llamaba Boses y el otro Sene:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 5, 'El un peñasco situado al norte hacia Michmas, y el otro al mediodía hacia Gabaa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 6, 'Dijo pues Jonathán á su criado que le traía las armas: Ven, pasemos á la guarnición de estos incircuncisos: quizá hará Jehová por nosotros; que no es difícil á Jehová salvar con multitud ó con poco número.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 7, 'Y su paje de armas le respondió: Haz todo lo que tienes en tu corazón: ve, que aquí estoy contigo á tu voluntad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 8, 'Y Jonathán dijo: He aquí, nosotros pasaremos á los hombres, y nos mostraremos á ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 9, 'Si nos dijeren así: Esperad hasta que lleguemos á vosotros; entonces nos estaremos en nuestro lugar, y no subiremos á ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 10, 'Mas si nos dijeren así: Subid á nosotros: entonces subiremos, porque Jehová los ha entregado en nuestras manos: y esto nos será por señal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 11, 'Mostráronse pues ambos á la guarnición de los Filisteos, y los Filisteos dijeron: He aquí los Hebreos, que salen de las cavernas en que se habían escondido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 12, 'Y los hombres de la guarnición respondieron á Jonathán y á su paje de armas, y dijeron: Subid á nosotros, y os haremos saber una cosa. Entonces Jonathán dijo á su paje de armas: Sube tras mí, que Jehová los ha entregado en la mano de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 13, 'Y subió Jonathán trepando con sus manos y sus pies, y tras él su paje de armas; y los que caían delante de Jonathán, su paje de armas que iba tras él, los mataba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 14, 'Esta fué la primera rota, en la cual Jonathán con su paje de armas, mataron como unos veinte hombres en el espacio de una media yugada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 15, 'Y hubo temblor en el real y por el campo, y entre toda la gente de la guarnición; y los que habían ido á hacer correrías, también ellos temblaron, y alborotóse la tierra: hubo pues gran consternación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 16, 'Y las centinelas de Saúl vieron desde Gabaa de Benjamín cómo la multitud estaba turbada, é iba de una parte á otra, y era deshecha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 17, 'Entonces Saúl dijo al pueblo que tenía consigo: Reconoced luego, y mirad quién haya ido de los nuestros. Y reconocido que hubieron, hallaron que faltaban Jonathán y su paje de armas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 18, 'Y Saúl dijo á Achîas: Trae el arca de Dios. Porque el arca de Dios estaba entonces con los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 19, 'Y aconteció que estando aún hablando Saúl con el sacerdote, el alboroto que había en el campo de los Filisteos se aumentaba, é iba creciendo en gran manera. Entonces dijo Saúl al sacerdote: Detén tu mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 20, 'Y juntando Saúl todo el pueblo que con él estaba, vinieron hasta el lugar de la batalla: y he aquí que la espada de cada uno era vuelta contra su compañero, y la mortandad era grande.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 21, 'Y los Hebreos que habían estado con los Filisteos de tiempo antes, y habían venido con ellos de los alrededores al campo, también éstos se volvieron para ser con los Israelitas que estaban con Saúl y con Jonathán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 22, 'Asimismo todos los Israelitas que se habían escondido en el monte de Ephraim, oyendo que los Filisteos huían, ellos también los persiguieron en aquella batalla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 23, 'Así salvó Jehová á Israel aquel día. Y llegó el alcance hasta Beth-aven.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 24, 'Pero los hombres de Israel fueron puestos en apuro aquel día; porque Saúl había conjurado al pueblo, diciendo: Cualquiera que comiere pan hasta la tarde, hasta que haya tomado venganza de mis enemigos, sea maldito. Y todo el pueblo no había gustado pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 25, 'Y todo el pueblo del país llegó á un bosque donde había miel en la superficie del campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 26, 'Entró pues el pueblo en el bosque, y he aquí que la miel corría; mas ninguno hubo que llegase la mano á su boca: porque el pueblo temía el juramento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 27, 'Empero Jonathán no había oído cuando su padre conjuró al pueblo, y alargó la punta de una vara que traía en su mano, y mojóla en un panal de miel, y llegó su mano á su boca; y sus ojos fueron aclarados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 28, 'Entonces habló uno del pueblo, diciendo: Tu padre ha conjurado expresamente al pueblo, diciendo: Maldito sea el hombre que comiere hoy manjar. Y el pueblo desfallecía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 29, 'Y respondió Jonathán: Mi padre ha turbado el país. Ved ahora cómo han sido aclarados mis ojos, por haber gustado un poco de esta miel:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 30, '¿Cuánto más si el pueblo hubiera hoy comido del despojo de sus enemigos que halló? ¿no se habría hecho ahora mayor estrago en los Filisteos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 31, 'E hirieron aquel día á los Filisteos desde Michmas hasta Ajalón: mas el pueblo se cansó mucho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 32, 'Tornóse por tanto el pueblo al despojo, y tomaron ovejas y vacas y becerros, y matáronlos en tierra, y el pueblo comió con sangre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 33, 'Y dándole de ello aviso á Saúl, dijéronle: El pueblo peca contra Jehová comiendo con sangre. Y él dijo: Vosotros habéis prevaricado; rodadme ahora acá una grande piedra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 34, 'Y Saúl tornó á decir: Esparcíos por el pueblo, y decidles que me traigan cada uno su vaca, y cada cual su oveja, y degolladlos aquí, y comed; y no pecaréis contra Jehová comiendo con sangre. Y trajo todo el pueblo cada cual por su mano su vaca aquella noche, y degollaron allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 35, 'Y edificó Saúl altar á Jehová, el cual altar fué el primero que edificó á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 36, 'Y dijo Saúl: Descendamos de noche contra los Filisteos, y los saquearemos hasta la mañana, y no dejaremos de ellos ninguno. Y ellos dijeron: Haz lo que bien te pareciere. Dijo luego el sacerdote: Lleguémonos aquí á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 37, 'Y Saúl consultó á Dios: ¿Descenderé tras los Filisteos? ¿los entregarás en mano de Israel? Mas Jehová no le dió respuesta aquel día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 38, 'Entonces dijo Saúl: Llegaos acá todos los principales del pueblo; y sabed y mirad por quién ha sido hoy este pecado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 39, 'Porque vive Jehová, que salva á Israel, que si fuere en mi hijo Jonathán, el morirá de cierto. Y no hubo en todo el pueblo quien le respondiese.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 40, 'Dijo luego á todo Israel: Vosotros estaréis á un lado, y yo y Jonathán mi hijo estaremos á otro lado. Y el pueblo respondió á Saúl: Haz lo que bien te pareciere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 41, 'Entonces dijo Saúl á Jehová Dios de Israel: Da perfección. Y fueron tomados Jonathán y Saúl, y el pueblo salió libre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 42, 'Y Saúl dijo: Echad suerte entre mí y Jonathán mi hijo. Y fué tomado Jonathán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 43, 'Entonces Saúl dijo á Jonathán: Declárame qué has hecho. Y Jonathán se lo declaró, y dijo: Cierto que gusté con la punta de la vara que traía en mi mano, un poco de miel: ¿y he aquí he de morir?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 44, 'Y Saúl respondió: Así me haga Dios y así me añada, que sin duda morirás, Jonathán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 45, 'Mas el pueblo dijo á Saúl: ¿Ha pues de morir Jonathán, el que ha hecho esta salud grande en Israel? No será así. Vive Jehová, que no ha de caer un cabello de su cabeza en tierra, pues que ha obrado hoy con Dios. Así libró el pueblo á Jonathán, para que no muriese.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 46, 'Y Saúl dejó de seguir á los Filisteos; y los Filisteos se fueron á su lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 47, 'Y ocupando Saúl el reino sobre Israel, hizo guerra á todos sus enemigos alrededor: contra Moab, contra los hijos de Ammón, contra Edom, contra los reyes de Soba, y contra los Filisteos: y á donde quiera que se tornaba era vencedor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 48, 'Y reunió un ejército, é hirió á Amalec, y libró á Israel de mano de los que le robaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 49, 'Y los hijos de Saúl fueron Jonathán, Isui, y Melchi-sua. Y los nombres de sus dos hijas eran, el nombre de la mayor, Merab, y el de la menor, Michâl.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 50, 'Y el nombre de la mujer de Saúl era Ahinoam, hija de Aimaas. Y el nombre del general de su ejército era Abner, hijo de Ner tío de Saúl.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 51, 'Porque Cis padre de Saúl, y Ner padre de Abner, fueron hijos de Abiel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 14, 52, 'Y la guerra fué fuerte contra los Filisteos todo el tiempo de Saúl; y á cualquiera que Saúl veía hombre valiente y hombre de esfuerzo, juntábale consigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 1, 'Y SAMUEL dijo á Saúl: Jehová me envió á que te ungiese por rey sobre su pueblo Israel: oye pues la voz de las palabras de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 2, 'Así ha dicho Jehová de los ejércitos: Acuérdome de lo que hizo Amalec á Israel; que se le opuso en el camino, cuando subía de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 3, 'Ve pues, y hiere á Amalec, y destuiréis en él todo lo que tuviere: y no te apiades de él: mata hombres y mujeres, niños y mamantes, vacas y ovejas, camellos y asnos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 4, 'Saúl pues juntó el pueblo, y reconociólos en Telaim, doscientos mil de á pie, y diez mil hombres de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 5, 'Y viniendo Saúl á la ciudad de Amalec, puso emboscada en el valle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 6, 'Y dijo Saúl al Cineo: Idos, apartaos, y salid de entre los de Amalec, para que no te destruya juntamente con él: pues que tú hiciste misericordia con todos los hijos de Israel, cuando subían de Egipto. Apartóse pues el Cineo de entre los de Amalec.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 7, 'Y Saúl hirió á Amalec, desde Havila hasta llegar á Shur, que está á la frontera de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 8, 'Y tomó vivo á Agag rey de Amalec, mas á todo el pueblo mató á filo de espada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 9, 'Y Saúl y el pueblo perdonaron á Agag, y á lo mejor de las ovejas, y al ganado mayor, á los gruesos y á los carneros, y á todo lo bueno: que no lo quisieron destruir: mas todo lo que era vil y flaco destruyeron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 10, 'Y fué palabra de Jehová á Samuel, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 11, 'Pésame de haber puesto por rey á Saúl, porque se ha vuelto de en pos de mí, y no ha cumplido mis palabras. Y apesadumbróse Samuel, y clamó á Jehová toda aquella noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 12, 'Madrugó luego Samuel para ir á encontrar á Saúl por la mañana; y fue dado aviso á Samuel, diciendo: Saúl ha venido al Carmel, y he aquí él se ha levantado un trofeo, y después volviendo, ha pasado y descendido á Gilgal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 13, 'Vino pues Samuel á Saúl, y Saúl le dijo: Bendito seas tu de Jehová; yo he cumplido la palabra de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 14, 'Samuel entonces dijo: ¿Pues qué balido de ganados y bramido de bueyes es este que yo oigo con mis oídos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 15, 'Y Saúl respondió: De Amalec los han traído; porque el pueblo perdonó á lo mejor de las ovejas y de las vacas, para sacrificarlas á Jehová tu Dios; pero lo demás lo destruimos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 16, 'Entonces dijo Samuel á Saúl: Déjame declararte lo que Jehová me ha dicho esta noche. Y él le respondió: Di.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 17, 'Y dijo Samuel: Siendo tú pequeño en tus ojos ¿no has sido hecho cabeza á las tribus de Israel, y Jehová te ha ungido por rey sobre Israel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 18, 'Y envióte Jehová en jornada, y dijo: Ve, y destruye los pecadores de Amalec, y hazles guerra hasta que los acabes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 19, '¿Por qué pues no has oído la voz de Jehová, sino que vuelto al despojo, has hecho lo malo en los ojos de Jehová?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 20, 'Y Saúl respondió á Samuel: Antes he oído la voz de Jehová, y fuí á la jornada que Jehová me envió, y he traído á Agag rey de Amalec, y he destruído á los Amalecitas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 21, 'Mas el pueblo tomó del despojo ovejas y vacas, las primicias del anatema, para sacrificarlas á Jehová tu Dios en Gilgal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 22, 'Y Samuel dijo: ¿Tiene Jehová tanto contentamiento con los holocaustos y víctimas, como en obedecer á las palabras de Jehová? Ciertamente el obedecer es mejor que los sacrificios; y el prestar atención que el sebo de los carneros:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 23, 'Porque como pecado de adivinación es la rebelión, y como ídolos é idolatría el infringir. Por cuanto tú desechaste la palabra de Jehová, él también te ha desechado para que no seas rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 24, 'Entonces Saúl dijo á Samuel: Yo he pecado; que he quebrantado el dicho de Jehová y tus palabras, porque temí al pueblo, consentí á la voz de ellos. Perdona pues ahora mi pecado,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 25, 'Y vuelve conmigo para que adore á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 26, 'Y Samuel respondió á Saúl: No volveré contigo; porque desechaste la palabra de Jehová, y Jehová te ha desechado para que no seas rey sobre Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 27, 'Y volviéndose Samuel para irse, él echó mano de la orla de su capa, y desgarróse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 28, 'Entonces Samuel le dijo: Jehová ha desgarrado hoy de ti el reino de Israel, y lo ha dado á tu prójimo mejor que tú.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 29, 'Y también el Vencedor de Israel no mentirá, ni se arrepentirá: porque no es hombre para que se arrepienta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 30, 'Y él dijo: Yo he pecado: mas ruégote que me honres delante de los ancianos de mi pueblo, y delante de Israel; y vuelve conmigo para que adore á Jehová tu Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 31, 'Y volvió Samuel tras Saúl, y adoró Saúl á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 32, 'Después dijo Samuel: Traedme á Agag rey de Amalec. Y Agag vino á él delicadamente. Y dijo Agag: Ciertamente se pasó la amargura de la muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 33, 'Y Samuel dijo: Como tu espada dejó las mujeres sin hijos, así tu madre será sin hijo entre las mujeres. Entonces Samuel cortó en pedazos á Agag delante de Jehová en Gilgal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 34, 'Fuése luego Samuel á Rama, y Saúl subió á su casa en Gabaa de Saúl.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 15, 35, 'Y nunca después vió Samuel á Saúl en toda su vida: y Samuel lloraba á Saúl: mas Jehová se había arrepentido de haber puesto á Saúl por rey sobre Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 16, 1, 'Y DIJO Jehová á Samuel: ¿Hasta cuándo has tú de llorar á Saúl, habiéndolo yo desechado para que no reine sobre Israel? Hinche tu cuerno de aceite, y ven, te enviaré á Isaí de Beth-lehem: porque de sus hijos me he provisto de rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 16, 2, 'Y dijo Samuel: ¿Cómo iré? Si Saúl lo entendiere, me matará. Jehová respondió: Toma contigo una becerra de la vacada, y di: A sacrificar á Jehová he venido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 16, 3, 'Y llama á Isaí al sacrificio, y yo te enseñaré lo que has de hacer; y ungirme has al que yo te dijere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 16, 4, 'Hizo pues Samuel como le dijo Jehová: y luego que él llegó á Beth-lehem, los ancianos de la ciudad le salieron á recibir con miedo, y dijeron: ¿Es pacífica tu venida?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 16, 5, 'Y él respondió: Sí, vengo á sacrificar á Jehová; santificaos, y venid conmigo al sacrificio. Y santificando él á Isaí y á sus hijos, llamólos al sacrificio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 16, 6, 'Y aconteció que como ellos vinieron, él vió á Eliab, y dijo: De cierto delante de Jehová está su ungido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 16, 7, 'Y Jehová respondió á Samuel: No mires á su parecer, ni á lo grande de su estatura, porque yo lo desecho; porque Jehová mira no lo que el hombre mira; pues que el hombre mira lo que está delante de sus ojos, mas Jehová mira el corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 16, 8, 'Entonces llamó Isaí á Abinadab, é hízole pasar delante de Samuel, el cual dijo: Ni á éste ha elegido Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 16, 9, 'Hizo luego pasar Isaí á Samma. Y él dijo: Tampoco á éste ha elegido Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 16, 10, 'E hizo pasar Isaí sus siete hijos delante de Samuel; mas Samuel dijo á Isaí: Jehová no ha elegido á éstos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 16, 11, 'Entonces dijo Samuel á Isaí: ¿Hanse acabado los mozos? Y él respondió: Aun queda el menor, que apacienta las ovejas. Y dijo Samuel á Isaí: Envía por él, porque no nos asentaremos á la mesa hasta que él venga aquí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 16, 12, 'Envió pues por él, é introdújolo; el cual era rubio, de hermoso parecer y de bello aspecto. Entonces Jehová dijo: Levántate y úngelo, que éste es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 16, 13, 'Y Samuel tomó el cuerno del aceite, y ungiólo de entre sus hermanos: y desde aquel día en adelante el espíritu de Jehová tomó á David. Levantóse luego Samuel, y volvióse á Rama.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 16, 14, 'Y el espíritu de Jehová se apartó de Saúl, y atormentábale el espíritu malo de parte de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 16, 15, 'Y los criados de Saúl le dijeron: He aquí ahora, que el espíritu malo de parte de Dios te atormenta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 16, 16, 'Diga pues nuestro señor á tus siervos que están delante de ti, que busquen alguno que sepa tocar el arpa; para que cuando fuere sobre ti el espíritu malo de parte de Dios, él taña con su mano, y tengas alivio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 16, 17, 'Y Saúl respondió á sus criados: Buscadme pues ahora alguno que taña bien, y traédmelo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 16, 18, 'Entonces uno de los criados respondió, diciendo: He aquí yo he visto á un hijo de Isaí de Beth-lehem, que sabe tocar, y es valiente y vigoroso, y hombre de guerra, prudente en sus palabras, y hermoso, y Jehová es con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 16, 19, 'Y Saúl envió mensajeros á Isaí, diciendo: Envíame á David tu hijo, el que está con las ovejas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 16, 20, 'Y tomó Isaí un asno cargado de pan, y un vasija de vino y un cabrito, y enviólo á Saúl por mano de David su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 16, 21, 'Y viniendo David á Saúl, estuvo delante de él: y amólo él mucho, y fué hecho su escudero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 16, 22, 'Y Saúl envió á decir á Isaí: Yo te ruego que esté David conmigo; porque ha hallado gracia en mis ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 16, 23, 'Y cuando el espíritu malo de parte de Dios era sobre Saúl, David tomaba el arpa, y tañía con su mano; y Saúl tenía refrigerio, y estaba mejor, y el espíritu malo se apartaba de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 1, 'Y LOS Filisteos juntaron sus ejércitos para la guerra, y congregáronse en Sochô, que es de Judá, y asentaron el campo entre Sochô y Azeca, en Ephes-dammim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 2, 'Y también Saúl y los hombres de Israel se juntaron, y asentaron el campo en el valle del Alcornoque, y ordenaron la batalla contra los Filisteos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 3, 'Y los Filisteos estaban sobre el un monte de la una parte, é Israel estaba sobre el otro monte de la otra parte, y el valle entre ellos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 4, 'Salió entonces un varón del campo de los Filisteos que se puso entre los dos campos, el cual se llamaba Goliath, de Gath, y tenía de altura seis codos y un palmo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 5, 'Y traía un almete de acero en su cabeza, é iba vestido con corazas de planchas: y era el peso de la coraza cinco mil siclos de metal:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 6, 'Y sobre sus piernas traía grebas de hierro, y escudo de acero á sus hombros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 7, 'El asta de su lanza era como un enjullo de telar, y tenía el hierro de su lanza seiscientos siclos de hierro: é iba su escudero delante de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 8, 'Y paróse, y dió voces á los escuadrones de Israel, diciéndoles: ¿Para qué salís á dar batalla? ¿no soy yo el Filisteo, y vosotros los siervos de Saúl? Escoged de entre vosotros un hombre que venga contra mí:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 9, 'Si él pudiere pelear conmigo, y me venciere, nosotros seremos vuestros siervos: y si yo pudiere más que él, y lo venciere, vosotros seréis nuestros siervos y nos serviréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 10, 'Y añadió el Filisteo: Hoy yo he desafiado el campo de Israel; dadme un hombre que pelee conmigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 11, 'Y oyendo Saúl y todo Israel estas palabras del Filisteo, conturbáronse, y tuvieron gran miedo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 12, 'Y David era hijo de aquel hombre Ephrateo de Beth-lehem de Judá, cuyo nombre era Isaí, el cual tenía ocho hijos; y era este hombre en el tiempo de Saúl, viejo, y de grande edad entre los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 13, 'Y los tres hijos mayores de Isaí habían ido á seguir á Saúl en la guerra. Y los nombres de sus tres hijos que habían ido á la guerra, eran, Eliab el primogénito, el segundo Abinadab, y el tercero Samma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 14, 'Y David era el menor. Siguieron pues los tres mayores á Saúl.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 15, 'Empero David había ido y vuelto de con Saúl, para apacentar las ovejas de su padre en Beth-lehem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 16, 'Venía pues aquel Filisteo por la mañana y á la tarde, y presentóse por cuarenta días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 17, 'Y dijo Isaí á David su hijo: Toma ahora para tus hermanos un epha de este grano tostado, y estos diez panes, y llévalo presto al campamento á tus hermanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 18, 'Llevarás asimismo estos diez quesos de leche al capitán, y cuida de ver si tus hermanos están buenos, y toma prendas de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 19, 'Y Saúl y ellos y todos lo de Israel, estaban en el valle del Alcornoque, peleando con los Filisteos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 20, 'Levantóse pues David de mañana, y dejando las ovejas al cuidado de un guarda, fuése con su carga, como Isaí le había mandado; y llegó al atrincheramiento del ejército, el cual había salido en ordenanza, y tocaba alarma para la pelea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 21, 'Porque así los Israelitas como los Filisteos estaban en ordenanza, escuadrón contra escuadrón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 22, 'Y David dejó de sobre sí la carga en mano del que guardaba el bagaje, y corrió al escuadrón; y llegado que hubo, preguntaba por sus hermanos, si estaban buenos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 23, 'Y estando él hablando con ellos, he aquí aquel varón que se ponía en medio de los dos campos, que se llamaba Goliath, el Filisteo de Gath, salió de los escuadrones de los Filisteos, y habló las mismas palabras; las cuales oyó David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 24, 'Y todos los varones de Israel que veían aquel hombre, huían de su presencia, y tenían gran temor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 25, 'Y cada uno de los de Israel decía: ¿No habéis visto aquel hombre que ha salido? él se adelanta para provocar á Israel. Al que le venciere, el rey le enriquecerá con grandes riquezas, y le dará su hija, y hará franca la casa de su padre en Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 26, 'Entonces habló David á los que junto á él estaban, diciendo: ¿Qué harán al hombre que venciere á este Filisteo, y quitare el oprobio de Israel? Porque ¿quién es este Filisteo incircunciso, para que provoque á los escuadrones del Dios viviente?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 27, 'Y el pueblo le respondió las mismas palabras, diciendo: Así se hará al hombre que lo venciere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 28, 'Y oyéndole hablar Eliab su hermano mayor con aquellos hombres, Eliab se encendió en ira contra David, y dijo: ¿Para qué has descendido acá? ¿y á quién has dejado aquellas pocas ovejas en el desierto? Yo conozco tu soberbia y la malicia de tu corazón, que para ver la batalla has venido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 29, 'Y David respondió: ¿Qué he hecho yo ahora? Estas, ¿no son palabras?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 30, 'Y apartándose de él hacia otros, habló lo mismo; y respondiéronle los del pueblo como primero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 31, 'Y fueron oídas las palabras que David había dicho, las cuales como refiriesen delante de Saúl, él lo hizo venir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 32, 'Y dijo David á Saúl: No desmaye ninguno á causa de él; tu siervo irá y peleará con este Filisteo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 33, 'Y dijo Saúl á David: No podrás tú ir contra aquel Filisteo, para pelear con él; porque tú eres mozo, y él un hombre de guerra desde su juventud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 34, 'Y David respondió á Saúl: Tu siervo era pastor en las ovejas de su padre, y venía un león, ó un oso, y tomaba algún cordero de la manada,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 35, 'Y salía yo tras él, y heríalo, y librábale de su boca: y si se levantaba contra mí, yo le echaba mano de la quijada, y lo hería y mataba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 36, 'Fuese león, fuese oso, tu siervo lo mataba; pues este Filisteo incircunciso será como uno de ellos, porque ha provocado al ejército del Dios viviente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 37, 'Y añadió David: Jehová que me ha librado de las garras del león y de las garras del oso, él también me librará de la mano de este Filisteo. Y dijo Saúl á David: Ve, y Jehová sea contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 38, 'Y Saúl vistió á David de sus ropas, y puso sobre su cabeza un almete de acero, y armóle de coraza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 39, 'Y ciñó David su espada sobre sus vestidos, y probó á andar, porque nunca había probado. Y dijo David á Saúl: Yo no puedo andar con esto, porque nunca lo practiqué. Y echando de sí David aquellas cosas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 40, 'Tomó su cayado en su mano, y escogióse cinco piedras lisas del arroyo, y púsolas en el saco pastoril y en el zurrón que traía, y con su honda en su mano vase hacia el Filisteo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 41, 'Y el Filisteo venía andando y acercándose á David, y su escudero delante de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 42, 'Y como el Filisteo miró y vió á David túvole en poco; porque era mancebo, y rubio, y de hermoso parecer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 43, 'Y dijo el Filisteo á David: ¿Soy yo perro para que vengas á mí con palos? Y maldijo á David por sus dioses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 44, 'Dijo luego el Filisteo á David: Ven á mí, y daré tu carne á las aves del cielo, y á las bestias del campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 45, 'Entonces dijo David al Filisteo: Tú vienes á mí con espada y lanza y escudo; mas yo vengo á ti en el nombre de Jehová de los ejércitos, el Dios de los escuadrones de Israel, que tú has provocado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 46, 'Jehová te entregará hoy en mi mano, y yo te venceré, y quitaré tu cabeza de ti: y daré hoy los cuerpos de los Filisteos á las aves del cielo y á las bestias de la tierra: y sabrá la tierra toda que hay Dios en Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 47, 'Y sabrá toda esta congregación que Jehová no salva con espada y lanza; porque de Jehová es la guerra, y él os entregará en nuestras manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 48, 'Y aconteció que, como el Filisteo se levantó para ir y llegarse contra David, David se dió priesa, y corrió al combate contra el Filisteo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 49, 'Y metiendo David su mano en el saco, tomó de allí una piedra, y tirósela con la honda, é hirió al Filisteo en la frente: y la piedra quedó hincada en la frente, y cayó en tierra sobre su rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 50, 'Así venció David al Filisteo con honda y piedra; é hirió al Filisteo y matólo, sin tener David espada en su mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 51, 'Mas corrió David y púsose sobre el Filisteo, y tomando la espada de él, sacándola de su vaina, matólo, y cortóle con ella la cabeza. Y como los Filisteos vieron su gigante muerto, huyeron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 52, 'Y levantándose los de Israel y de Judá, dieron grita, y siguieron á los Filisteos hasta llegar al valle, y hasta las puertas de Ecrón. Y cayeron heridos de los Filisteos por el camino de Saraim, hasta Gath y Ecrón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 53, 'Tornando luego los hijos de Israel de seguir los Filisteos, despojaron su campamento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 54, 'Y David tomó la cabeza del Filisteo, y trájola á Jerusalem, mas puso sus armas en su tienda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 55, 'Y cuando Saúl vió á David que salía á encontrarse con el Filisteo, dijo á Abner general del ejército: Abner, ¿de quién es hijo aquel mancebo? Y Abner respondió:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 56, 'Vive tu alma, oh rey, que no lo sé. Y el rey dijo: Pregunta pues de quién es hijo aquel mancebo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 57, 'Y cuando David volvía de matar al Filisteo, Abner lo tomó, y llevólo delante de Saúl, teniendo la cabeza del Filisteo en su mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 17, 58, 'Y díjole Saúl: Mancebo, ¿de quién eres hijo? Y David respondió: Yo soy hijo de tu siervo Isaí de Beth-lehem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 18, 1, 'Y ASI que él hubo acabado de hablar con Saúl, el alma de Jonathán fué ligada con la de David, y amólo Jonathán como á su alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 18, 2, 'Y Saúl le tomó aquel día, y no le dejó volver á casa de su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 18, 3, 'E hicieron alianza Jonathán y David, porque él le amaba como á su alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 18, 4, 'Y Jonathán se desnudó la ropa que tenía sobre sí, y dióla á David, y otras ropas suyas, hasta su espada, y su arco, y su talabarte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 18, 5, 'Y salía David á donde quiera que Saúl le enviaba, y portábase prudentemente. Hízolo por tanto Saúl capitán de gente de guerra, y era acepto en los ojos de todo el pueblo, y en los ojos de los criados de Saúl.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 18, 6, 'Y aconteció que como volvían ellos, cuando David tornó de matar al Filisteo, salieron las mujeres de todas las ciudades de Israel cantando, y con danzas, con tamboriles, y con alegrías y sonajas, á recibir al rey Saúl.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 18, 7, 'Y cantaban las mujeres que danzaba, y decían: Saúl hirió sus miles, Y David sus diez miles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 18, 8, 'Y enojóse Saúl en gran manera, y desagradó esta palabra en sus ojos, y dijo: A David dieron diez miles, y á mí miles; no le falta más que el reino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 18, 9, 'Y desde aquel día Saúl miró de través á David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 18, 10, 'Otro día aconteció que el espíritu malo de parte de Dios tomó á Saúl, y mostrábase en su casa con trasportes de profeta: y David tañía con su mano como los otros días; y estaba una lanza á mano de Saúl.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 18, 11, 'Y arrojó Saúl la lanza, diciendo: Enclavaré á David en la pared. Y dos veces se apartó de él David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 18, 12, 'Mas Saúl se temía de David por cuanto Jehová era con él, y se había apartado de Saúl.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 18, 13, 'Apartólo pues Saúl de sí, é hízole capitán de mil; y salía y entraba delante del pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 18, 14, 'Y David se conducía prudentemente en todos sus negocios, y Jehová era con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 18, 15, 'Y viendo Saúl que se portaba tan prudentemente, temíase de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 18, 16, 'Mas todo Israel y Judá amaba á David, porque él salía y entraba delante de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 18, 17, 'Y dijo Saúl á David: He aquí yo te daré á Merab mi hija mayor por mujer: solamente que me seas hombre valiente, y hagas las guerras de Jehová. Mas Saúl decía: No será mi mano contra él, mas la mano de los Filisteos será contra él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 18, 18, 'Y David respondió á Saúl: ¿Quién soy yo, ó qué es mi vida, ó la familia de mi padre en Israel, para ser yerno del rey?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 18, 19, 'Y venido el tiempo en que Merab, hija de Saúl, se había de dar á David, fué dada por mujer á Adriel Meholatita.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 18, 20, 'Mas Michâl la otra hija de Saúl amaba á David; y fué dicho á Saúl, lo cual plugo en sus ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 18, 21, 'Y Saúl dijo: Yo se la daré, para que le sea por lazo, y para que la mano de los Filisteos sea contra él. Dijo pues Saúl á David: Con la otra serás mi yerno hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 18, 22, 'Y mandó Saúl á sus criados: Hablad en secreto á David, diciéndole: He aquí, el rey te ama, y todos sus criados te quieren bien; sé pues yerno del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 18, 23, 'Y los criados de Saúl hablaron estas palabras á los oídos de David. Y David dijo: ¿Paréceos á vosotros que es poco ser yerno del rey, siendo yo un hombre pobre y de ninguna estima?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 18, 24, 'Y los criados de Saúl le dieron la respuesta diciendo: Tales palabras ha dicho David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 18, 25, 'Y Saúl dijo: Decid así á David: No está el contentamiento del rey en el dote, sino en cien prepucios de Filisteos, para que sea tomada venganza de los enemigos del rey. Mas Saúl pensaba echar á David en manos de los Filisteos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 18, 26, 'Y como sus criados declararon á David estas palabras, plugo la cosa en los ojos de David, para ser yerno del rey. Y como el plazo no era aún cumplido,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 18, 27, 'Levantóse David, y partióse con su gente, é hirió doscientos hombres de los Filisteos; y trajo David los prepucios de ellos, y entregáronlos todos al rey, para que él fuese hecho yerno del rey. Y Saúl le dió á su hija Michâl por mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 18, 28, 'Pero Saúl, viendo y considerando que Jehová era con David, y que su hija Michâl lo amaba,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 18, 29, 'Temióse más de David; y fué Saúl enemigo de David todos los días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 18, 30, 'Y salían los príncipes de los Filisteos; y como ellos salían, portábase David más prudentemente que todos los siervos de Saúl: y era su nombre muy ilustre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 19, 1, 'Y HABLO Saúl á Jonathán su hijo, y á todos sus criados, para que matasen á David; mas Jonathán hijo de Saúl amaba á David en gran manera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 19, 2, 'Y dió aviso á David, diciendo: Saúl mi padre procura matarte; por tanto mira ahora por ti hasta la mañana, y estáte en paraje oculto, y escóndete:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 19, 3, 'Y yo saldré y estaré junto á mi padre en el campo donde estuvieres: y hablaré de ti á mi padre, y te haré saber lo que notare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 19, 4, 'Y Jonathán habló bien de David á Saúl su padre, y díjole: No peque el rey contra su siervo David, pues que ninguna cosa ha cometido contra ti: antes sus obras te han sido muy buenas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 19, 5, 'Porque él puso su alma en su palma, é hirió al Filisteo, y Jehová hizo una gran salud á todo Israel. Tú lo viste, y te holgaste: ¿por qué pues pecarás contra la sangre inocente, matando á David sin causa?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 19, 6, 'Y oyendo Saúl la voz de Jonathán, juró: Vive Jehová, que no morirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 19, 7, 'Llamando entonces Jonathán á David, declaróle todas estas palabras; y él mismo presentó á David á Saúl, y estuvo delante de él como antes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 19, 8, 'Y tornó á hacerse guerra: y salió David y peleó contra los Filisteos, é hiriólos con grande estrago, y huyeron delante de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 19, 9, 'Y el espíritu malo de parte de Jehová fué sobre Saúl: y estando sentado en su casa tenía una lanza á mano, mientras David estaba tañendo con su mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 19, 10, 'Y Saúl procuró enclavar á David con la lanza en la pared; mas él se apartó de delante de Saúl, el cual hirió con la lanza en la pared; y David huyó, y escapóse aquella noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 19, 11, 'Saúl envió luego mensajeros á casa de David para que lo guardasen, y lo matasen á la mañana. Mas Michâl su mujer lo descubrió á David, diciendo: Si no salvares tu vida esta noche, mañana serás muerto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 19, 12, 'Y descolgó Michâl á David por una ventana; y él se fué, y huyó, y escapóse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 19, 13, 'Tomó luego Michâl una estatua, y púsola sobre la cama, y acomodóle por cabecera una almohada de pelos de cabra, y cubrióla con una ropa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 19, 14, 'Y cuando Saúl envió mensajeros que tomasen á David, ella respondió: Está enfermo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 19, 15, 'Y tornó Saúl á enviar mensajeros para que viesen á David, diciendo: Traédmelo en la cama para que lo mate.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 19, 16, 'Y como los mensajeros entraron, he aquí la estatua estaba en la cama, y una almohada de pelos de cabra por cabecera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 19, 17, 'Entonces Saúl dijo á Michâl: ¿Por qué me has así engañado, y has dejado escapar á mi enemigo? Y Michâl respondió á Saúl: Porque él me dijo: Déjame ir; si no, yo te mataré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 19, 18, 'Huyó pues David, y escapóse, y vino á Samuel en Rama, y díjole todo lo que Saúl había hecho con él. Y fuéronse él y Samuel, y moraron en Najoth.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 19, 19, 'Y fué dado aviso á Saúl, diciendo: He aquí que David está en Najoth en Rama.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 19, 20, 'Y envió Saúl mensajeros que trajesen á David, los cuales vieron una compañía de profetas que profetizaban, y á Samuel que estaba allí, y los presidía. Y fué el espíritu de Dios sobre los mensajeros de Saúl, y ellos también profetizaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 19, 21, 'Y hecho que fué saber á Saúl, él envió otros mensajeros, los cuales también profetizaron. Y Saúl volvió á enviar por tercera vez mensajeros, y ellos también profetizaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 19, 22, 'Entonces él mismo vino á Rama; y llegando al pozo grande que está en Sochô, preguntó diciendo: ¿Dónde están Samuel y David? Y fuéle respondido: He aquí están en Najoth en Rama.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 19, 23, 'Y fué allá á Najoth en Rama; y también vino sobre él el espíritu de Dios, é iba profetizando, hasta que llegó á Najoth en Rama.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 19, 24, 'Y él también se desnudó sus vestidos, y profetizó igualmente delante de Samuel, y cayó desnudo todo aquel día y toda aquella noche. De aquí se dijo: ¿También Saúl entre los profetas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 1, 'Y DAVID huyó de Najoth que es en Rama, y vínose delante de Jonathán, y dijo: ¿Qué he hecho yo? ¿cuál es mi maldad, ó cuál mi pecado contra tu padre, que él busca mi vida?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 2, 'Y él le dijo: En ninguna manera; no morirás. He aquí que mi padre ninguna cosa hará, grande ni pequeña, que no me la descubra; ¿por qué pues me encubrirá mi padre este negocio? No será así.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 3, 'Y David volvió á jurar, diciendo: Tu padre sabe claramente que yo he hallado gracia delante de tus ojos, y dirá: No sepa esto Jonathán, porque no tenga pesar: y ciertamente, vive Jehová y vive tu alma, que apenas hay un paso entre mí y la muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 4, 'Y Jonathán dijo á David: ¿Qué discurre tu alma, y harélo por ti?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 5, 'Y David respondió á Jonathán: He aquí que mañana será nueva luna, y yo acostumbro sentarme con el rey á comer: mas tú dejarás que me esconda en el campo hasta la tarde del tercer día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 6, 'Si tu padre hiciere mención de mí, dirás: Rogóme mucho que lo dejase ir presto á Beth-lehem su ciudad, porque todos los de su linaje tienen allá sacrificio aniversario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 7, 'Si él dijere, Bien está, paz tendrá tu siervo; mas si se enojare, sabe que la malicia es en él cosumada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 8, 'Harás pues misericordia con tu siervo, ya que has traído tu siervo á alianza de Jehová contigo: y si maldad hay en mí mátame tú, que no hay necesidad de llevarme hasta tu padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 9, 'Y Jonathán le dijo: Nunca tal te suceda; antes bien, si yo entendiera ser consumada la malicia de mi padre, para venir sobre ti, ¿no había yo de descubrírtelo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 10, 'Dijo entonces David á Jonathán: ¿Quién me dará aviso? ó ¿qué si tu padre te respondiere ásperamente?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 11, 'Y Jonathán dijo á David: Ven, salgamos al campo. Y salieron ambos al campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 12, 'Entonces dijo Jonathán á David: Oh Jehová Dios de Israel, cuando habré yo preguntado á mi padre mañana á esta hora, ó después de mañana, y él apareciere bien para con David, si entonces no enviare á ti, y te lo descubriere,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 13, 'Jehová haga así á Jonathán, y esto añada. Mas si á mi padre pareciere bien hacerte mal, también te lo descubriré, y te enviaré, y te irás en paz: y sea Jehová contigo, como fué con mi padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 14, 'Y si yo viviere, harás conmigo misericordia de Jehová; mas si fuere muerto,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 15, 'No quitarás perpetuamente tu misericordia de mi casa. Cuando desarraigare Jehová uno por uno los enemigos de David de la tierra, aun á Jonathán quite de su casa, si te faltare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 16, 'Así hizo Jonathán alianza con la casa de David, diciendo: Requiéralo Jehová de la mano de los enemigos de David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 17, 'Y tornó Jonathán á jurar á David, porque le amaba, porque le amaba como á su alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 18, 'Díjole luego Jonathán: Mañana es nueva luna, y tú serás echado de menos, porque tu asiento estará vacío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 19, 'Estarás pues tres días, y luego descenderás, y vendrás al lugar donde estabas escondido el día de trabajo, y esperarás junto á la piedra de Ezel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 20, 'Y yo tiraré tres saetas hacia aquel lado, como ejercitándome al blanco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 21, 'Y luego enviaré el criado diciéndole: Ve, busca las saetas. Y si dijere al mozo: He allí las saetas más acá de ti, tómalas: tú vendrás, porque paz tienes, y nada hay de mal, vive Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 22, 'Mas si yo dijere al mozo así: He allí las saetas más allá de ti: vete, porque Jehová te ha enviado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 23, 'Y cuanto á las palabras que yo y tú hemos hablado, sea Jehová entre mí y ti para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 24, 'David pues se escondió en el campo, y venida que fué la nueva luna, sentóse el rey á comer pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 25, 'Y el rey se sentó en su silla, como solía, en el asiento junto á la pared, y Jonathán se levantó, y sentóse Abner al lado de Saúl, y el lugar de David estaba vacío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 26, 'Mas aquel día Saúl no dijo nada, porque se decía: Habrále acontecido algo, y no está limpio; no estará purificado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 27, 'El día siguiente, el segundo día de la nueva luna, aconteció también que el asiento de David estaba vacío. Y Saúl dijo á Jonathán su hijo: ¿Por qué no ha venido á comer el hijo de Isaí hoy ni ayer?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 28, 'Y Jonathán respondió á Saúl: David me pidió encarecidamente le dejase ir hasta Beth-lehem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 29, 'Y dijo: Ruégote que me dejes ir, porque tenemos sacrificio los de nuestro linaje en la ciudad, y mi hermano mismo me lo ha mandado; por tanto, si he hallado gracia en tus ojos, haré una escapada ahora, y visitaré á mis hermanos. Por esto pues no ha venido á la mesa del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 30, 'Entonces Saúl se enardeció contra Jonathán, y díjole: Hijo de la perversa y rebelde, ¿no sé yo que tú has elegido al hijo de Isaí para confusión tuya, y para confusión de la vergüenza de tu madre?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 31, 'Porque todo el tiempo que el hijo de Isaí viviere sobre la tierra, ni tú serás firme, ni tu reino. Envía pues ahora, y traémelo, porque ha de morir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 32, 'Y Jonathán respondió á su padre Saúl, y díjole: ¿Por qué morirá? ¿qué ha hecho?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 33, 'Entonces Saúl le arrojó una lanza por herirlo: de donde entendió Jonathán que su padre estaba determinado á matar á David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 34, 'Y levantóse Jonathán de la mesa con exaltada ira, y no comió pan el segundo día de la nueva luna: porque tenía dolor á causa de David, porque su padre le había afrentado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 35, 'Al otro día de mañana, salió Jonathán al campo, al tiempo aplazado con David, y un mozo pequeño con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 36, 'Y dijo á su mozo: Corre y busca las saetas que yo tirare. Y como el muchacho iba corriendo, él tiraba la saeta que pasara más allá de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 37, 'Y llegando el muchacho adonde estaba la saeta que Jonathán había tirado, Jonathán dió voces tras el muchacho, diciendo: ¿No está la saeta más allá de ti?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 38, 'Y tornó á gritar Jonathán tras el muchacho: Date priesa, aligera, no te pares. Y el muchacho de Jonathán cogió las saetas, y vínose á su señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 39, 'Empero ninguna cosa entendió el muchacho: solamente Jonathán y David entendían el negocio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 40, 'Luego dió Jonathán sus armas á su muchacho, y díjole: Vete y llévalas á la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 41, 'Y luego que el muchacho se hubo ido, se levantó David de la parte del mediodía, é inclinóse tres veces postrándose hasta la tierra: y besándose el uno al otro, lloraron el uno con el otro, aunque David lloró más.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 20, 42, 'Y Jonathán dijo á David: Vete en paz, que ambos hemos jurado por el nombre de Jehová, diciendo: Jehová sea entre mí y ti, entre mi simiente y la simiente tuya, para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 21, 1, 'Y VINO David á Nob, á Ahimelech sacerdote: y sorprendióse Ahimelech de su encuentro, y díjole: ¿Cómo tú solo, y nadie contigo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 21, 2, 'Y respondió David al sacerdote Ahimelech: El rey me encomendó un negocio, y me dijo: Nadie sepa cosa alguna de este negocio á que yo te envío, y que yo te he mandado; y yo señalé á los criados un cierto lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 21, 3, 'Ahora pues, ¿qué tienes á mano? dame cinco panes, ó lo que se hallare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 21, 4, 'Y el sacerdote respondió á David, y dijo: No tengo pan común á la mano; solamente tengo pan sagrado: mas lo daré si los criados se han guardado mayormente de mujeres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 21, 5, 'Y David respondió al sacerdote, y díjole: Cierto las mujeres nos han sido reservadas desde anteayer cuando salí, y los vasos de los mozos fueron santos, aunque el camino es profano: cuanto más que hoy habrá otro pan santificado en los vasos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 21, 6, 'Así el sacerdote le dió el pan sagrado, porque allí no había otro pan que los panes de la proposición, los cuales habían sido quitados de delante de Jehová, para que se pusiesen panes calientes el día que los otros fueron quitados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 21, 7, 'Aquel día estaba allí uno de los siervos de Saúl detenido delante de Jehová, el nombre del cual era Doeg, Idumeo, principal de los pastores de Saúl.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 21, 8, 'Y David dijo á Ahimelech: ¿No tienes aquí á mano lanza ó espada? porque no tomé en mi mano mi espada ni mis armas, por cuanto el mandamiento del rey era apremiante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 21, 9, 'Y el sacerdote respondió: La espada de Goliath el Filisteo, que tú venciste en el valle del Alcornoque, está aquí envuelta en un velo detrás del ephod: si tú quieres tomarla, tómala: porque aquí no hay otra sino esa. Y dijo David: Ninguna como ella: dámela.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 21, 10, 'Y levantándose David aquel día, huyó de la presencia de Saúl, y vínose á Achîs rey de Gath.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 21, 11, 'Y los siervos de Achîs le dijeron: ¿No es éste David, el rey de la tierra? ¿no es éste á quien cantaban en corros, diciendo: Hirió Saúl sus miles, Y David sus diez miles?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 21, 12, 'Y David puso en su corazón estas palabras, y tuvo gran temor de Achîs rey de Gath.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 21, 13, 'Y mudó su habla delante de ellos, y fingióse loco entre sus manos, y escribía en las portadas de las puertas, dejando correr su saliva por su barba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 21, 14, 'Y dijo Achîs á sus siervos: He aquí estáis viendo un hombre demente; ¿por qué lo habéis traído á mí?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 21, 15, '¿Fáltanme á mí locos, para que hayáis traído éste que hiciese del loco delante de mí? ¿había de venir éste á mi casa?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 22, 1, 'Y YÉNDOSE David de allí escapóse á la cueva de Adullam; lo cual como oyeron sus hermanos y toda la casa de su padre, vinieron allí á él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 22, 2, 'Y juntáronse con él todos los afligidos, y todo el que estaba adeudado, y todos los que se hallaban en amargura de espíritu, y fué hecho capitán de ellos: y tuvo consigo como cuatrocientos hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 22, 3, 'Y fuése David de allí á Mizpa de Moab, y dijo al rey de Moab: Yo te ruego que mi padre y mi madre estén con vosotros, hasta que sepa lo que Dios hará de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 22, 4, 'Trájolos pues á la presencia del rey de Moab, y habitaron con él todo el tiempo que David estuvo en la fortaleza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 22, 5, 'Y Gad profeta dijo á David: No te estés en esta fortaleza, pártete, y vete á tierra de Judá. Y David se partió, y vino al bosque de Hareth.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 22, 6, 'Y oyó Saúl como había parecido David, y los que estaban con él. Estaba entonces Saúl en Gabaa debajo de un árbol en Rama, y tenía su lanza en su mano, y todos sus criados estaban en derredor de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 22, 7, 'Y dijo Saúl á sus criados que estaban en derredor de él: Oid ahora, hijos de Benjamín: ¿Os dará también á todos vosotros el hijo de Isaí tierras y viñas, y os hará á todos tribunos y centuriones;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 22, 8, 'Que todos vosotros habéis conspirado contra mí, y no hay quien me descubra al oído como mi hijo ha hecho alianza con el hijo de Isaí, ni alguno de vosotros que se duela de mí, y me descubra como mi hijo ha levantado á mi siervo contra mí, para que me aceche, según hace hoy día?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 22, 9, 'Entonces Doeg Idumeo, que era superior entre los siervos de Saúl, respondió y dijo: Yo vi al hijo de Isaí que vino á Nob, á Ahimelech hijo de Ahitob;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 22, 10, 'El cual consultó por él á Jehová, y dióle provisión, y también le dió la espada de Goliath el Filisteo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 22, 11, 'Y el rey envió por el sacerdote Ahimelech hijo de Ahitob, y por toda la casa de su padre, los sacerdotes que estaban en Nob: y todos vinieron al rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 22, 12, 'Y Saúl le dijo: Oye ahora, hijo de Ahitob. Y él dijo: Heme aquí, señor mío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 22, 13, 'Y díjole Saúl: ¿Por qué habéis conspirado contra mí, tú y el hijo de Isaí, cuando tú le diste pan y espada, y consultaste por él á Dios, para que se levantase contra mí y me acechase, como lo hace hoy día?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 22, 14, 'Entonces Ahimelech respondió al rey, y dijo: ¿Y quién entre todos tus siervos es tan fiel como David, yerno además del rey, y que va por tu mandado, y es ilustre en tu casa?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 22, 15, '¿He comenzado yo desde hoy á consultar por él á Dios? lejos sea de mí: no impute el rey cosa alguna á su siervo, ni á toda la casa de mi padre; porque tu siervo ninguna cosa sabe de este negocio, grande ni chica.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 22, 16, 'Y el rey dijo: Sin duda morirás, Ahimelech, tú y toda la casa de tu padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 22, 17, 'Entonces dijo el rey á la gente de su guardia que estaba alrededor de él: Cercad y matad á los sacerdotes de Jehová; porque también la mano de ellos es con David, pues sabiendo ellos que huía, no me lo descubrieron. Mas los siervos del rey no quisieron extender sus manos para matar á los sacerdotes de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 22, 18, 'Entonces dijo el rey á Doeg: Vuelve tú, y arremete contra los sacerdotes. Y revolviéndose Doeg Idumeo, arremetió contra los sacerdotes, y mató en aquel día ochenta y cinco varones que vestían ephod de lino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 22, 19, 'Y á Nob, ciudad de los sacerdotes, puso á cuchillo: así á hombres como á mujeres, niños y mamantes, bueyes y asnos y ovejas, todo á cuchillo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 22, 20, 'Mas uno de los hijos de Ahimelech hijo de Ahitob, que se llamaba Abiathar, escapó, y huyóse á David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 22, 21, 'Y Abiathar notició á David como Saúl había muerto los sacerdotes de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 22, 22, 'Y dijo David á Abiathar: Yo sabía que estando allí aquel día Doeg el Idumeo, él lo había de hacer saber á Saúl. Yo he dado ocasión contra todas las personas de la casa de tu padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 22, 23, 'Quédate conmigo, no temas: quien buscare mi vida, buscará también la tuya: bien que tú estarás conmigo guardado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 23, 1, 'Y DIERON aviso á David, dicendo: He aquí que los Filisteos combaten á Keila, y roban las eras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 23, 2, 'Y David consultó á Jehová, diciendo: ¿Iré á herir á estos Filisteos? Y Jehová respondió á David: Ve, hiere á los Filisteos, y libra á Keila.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 23, 3, 'Mas los que estaban con David le dijeron: He aquí que nosotros aquí en Judá estamos con miedo; ¿cuánto más si fuéremos á Keila contra el ejército de los Filisteos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 23, 4, 'Entonces David volvió á consultar á Jehová. Y Jehová le respondió, y dijo: Levántate, desciende á Keila, que yo entregaré en tus manos á los Filisteos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 23, 5, 'Partióse pues David con sus hombres á Keila, y peleó contra los Filisteos, y trajo antecogidos sus ganados, é hiriólos con grande estrago: y libró David á los de Keila.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 23, 6, 'Y aconteció que, huyendo Abiathar hijo de Ahimelech á David á Keila, vino también con él el ephod.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 23, 7, 'Y fué dicho á Saúl que David había venido á Keila. Entonces dijo Saúl: Dios lo ha traído á mis manos; porque él está encerrado, habiéndose metido en ciudad con puertas y cerraduras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 23, 8, 'Y convocó Saúl todo el pueblo á la batalla, para descender á Keila, y poner cerco á David y á los suyos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 23, 9, 'Mas entendiendo David que Saúl ideaba el mal contra él, dijo á Abiathar sacerdote: Trae el ephod.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 23, 10, 'Y dijo David: Jehová Dios de Israel, tu siervo tiene entendido que Saúl trata de venir contra Keila, á destruir la ciudad por causa mía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 23, 11, '¿Me entregarán los vecinos de Keila en sus manos? ¿descenderá Saúl, como tu siervo tiene oído? Jehová Dios de Israel, ruégote que lo declares á tu siervo. Y Jehová dijo: Sí, descenderá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 23, 12, 'Dijo luego David: ¿Me entregarán los vecinos de Keila á mí y á mis hombres en manos de Saúl? Y Jehová respondió: Te entregarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 23, 13, 'David entonces se levantó con sus hombres, que eran como seiscientos, y saliéronse de Keila, y fuéronse de una parte á otra. Y vino la nueva á Saúl de como David se había escapado de Keila; y dejó de salir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 23, 14, 'Y David se estaba en el desierto en peñas, y habitaba en un monte en el desieto de Ziph; y buscábalo Saúl todos los días, mas Dios no lo entregó en sus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 23, 15, 'Viendo pues David que Saúl había salido en busca de su alma, estábase él en el bosque en el desierto de Ziph.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 23, 16, 'Entonces se levantó Jonathán hijo de Saúl, y vino á David en el bosque, y confortó su mano en Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 23, 17, 'Y díjole: No temas, que no te hallará la mano de Saúl mi padre, y tú reinarás sobre Israel, y yo seré segundo después de ti; y aun Saúl mi padre así lo sabe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 23, 18, 'Y entrambos hicieron alianza delante de Jehová: y David se quedó en el bosque, y Jonathán se volvió á su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 23, 19, 'Y subieron los de Ziph á decir á Saúl en Gabaa: ¿No está David escondido en nuestra tierra en las peñas del bosque, en el collado de Hachîla que está á la mano derecha del desierto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 23, 20, 'Por tanto, rey, desciende ahora presto, según todo el deseo de tu alma, y nosotros lo entregaremos en la mano del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 23, 21, 'Y Saúl dijo: Benditos seáis vosotros de Jehová, que habéis tenido compasión de mí:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 23, 22, 'Id pues ahora, apercibid aún, considerad y ved su lugar donde tiene el pie, y quién lo haya visto allí; porque se me ha dicho que él es en gran manera astuto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 23, 23, 'Considerad pues, y ved todos los escondrijos donde se oculta, y volved á mí con la certidumbre, y yo iré con vosotros: que si él estuviere en la tierra, yo le buscaré entre todos los millares de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 23, 24, 'Y ellos se levantaron, y se fueron á Ziph delante de Saúl. Mas David y su gente estaban en el desierto de Maón, en la llanura que está á la diestra del desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 23, 25, 'Y partióse Saúl con su gente á buscarlo; pero fué dado aviso á David, y descendió á la peña, y quedóse en el desierto de Maón. Lo cual como Saúl oyó, siguió á David al desierto de Maón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 23, 26, 'Y Saúl iba por el un lado del monte, y David con los suyos por el otro lado del monte: y dábase priesa David para ir delante de Saúl; mas Saúl y los suyos habían encerrado á David y á su gente para tomarlos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 23, 27, 'Entonces vino un mensajero á Saúl, diciendo: Ven luego, porque los Filisteos han hecho una irrupción en el país.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 23, 28, 'Volvióse por tanto Saúl de perseguir á David, y partió contra los Filisteos. Por esta causa pusieron á aquel lugar por nombre Sela-hammah-lecoth.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 23, 29, '(24-1) ENTONCES David subió de allí, y habitó en los parajes fuertes en Engaddi.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 24, 1, '(24-2) Y como Saúl volvió de los Filisteos, diéronle aviso diciendo: He aquí que David está en el desierto de Engaddi.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 24, 2, '(24-3) Y tomando Saúl tres mil hombres escogidos de todo Israel, fué en busca de David y de los suyos, por las cumbres de los peñascos de las cabras monteses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 24, 3, '(24-4) Y como llegó á una majada de ovejas en el camino, donde había una cueva, entró Saúl en ella á cubrir sus pies: y David y los suyos estaban á los lados de la cueva.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 24, 4, '(24-5) Entonces los de David le dijeron: He aquí el día que te ha dicho Jehová: He aquí que entregó tu enemigo en tus manos, y harás con él como te pareciere. Y levantóse David, y calladamente cortó la orilla del manto de Saúl.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 24, 5, '(24-6) Después de lo cual el corazón de David le golpeaba, porque había cortado la orilla del manto de Saúl.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 24, 6, '(24-7) Y dijo á los suyos: Jehová me guarde de hacer tal cosa contra mi señor, el ungido de Jehová, que yo extienda mi mano contra él; porque es el ungido de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 24, 7, '(24-8) Así quebrantó David á los suyos con palabras, y no les permitió que se levantasen contra Saúl. Y Saúl, saliendo de la cueva, fuése su camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 24, 8, '(24-9) También David se levantó después, y saliendo de la cueva dió voces á las espaldas de Saúl, diciendo: ¡Mi señor el rey! Y como Saúl miró atrás, David inclinó su rotro á tierra, é hizo reverencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 24, 9, '(24-10) Y dijo David á Saúl: ¿Por qué oyes las palabras de los que dicen: Mira que David procura tu mal?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 24, 10, '(24-11) He aquí han visto hoy tus ojos como Jehová te ha puesto hoy en mis manos en la cueva: y dijeron que te matase, mas te perdoné, porque dije: No extenderé mi mano contra mi señor, porque ungido es de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 24, 11, '(24-12) Y mira, padre mío, mira aún la orilla de tu manto en mi mano: porque yo corté la orilla de tu manto, y no te maté. Conoce pues y ve que no hay mal ni traición en mi mano, ni he pecado contra ti; con todo, tú andas á caza de mi vida para quitármela.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 24, 12, '(24-13) Juzgue Jehová entre mí y ti, y véngueme de ti Jehová: empero mi mano no será contra ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 24, 13, '(24-14) Como dice el proverbio de los antiguos: De los impíos saldrá la impiedad: así que mi mano no será contra ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 24, 14, '(24-15) ¿Tras quién ha salido el rey de Israel? ¿á quién persigues? ¿á un perro muerto? ¿á una pulga?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 24, 15, '(24-16) Jehová pues será juez, y él juzgará entre mí y ti. El vea, y sustente mi causa, y me defienda de tu mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 24, 16, '(24-17) Y aconteció que, como David acabó de decir estas palabras á Saúl, Saúl dijo: ¿No es esta la voz tuya, hijo mío David? Y alzando Saúl su voz lloró.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 24, 17, '(24-18) Y dijo á David: Más justo eres tú que yo, que me has pagado con bien, habiéndote yo pagado con mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 24, 18, '(24-19) Tú has mostrado hoy que has hecho conmigo bien; pues no me has muerto, habiéndome Jehová puesto en tus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 24, 19, '(24-20) Porque ¿quién hallará á su enemigo, y lo dejará ir sano y salvo? Jehová te pague con bien por lo que en este día has hecho conmigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 24, 20, '(24-21) Y ahora, como yo entiendo que tú has de reinar, y que el reino de Israel ha de ser en tu mano firme y estable,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 24, 21, '(24-22) Júrame pues ahora por Jehová, que no cortarás mi simiente después de mí, ni raerás mi nombre de la casa de mi padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 24, 22, '(24-23) Entonces David juró á Saúl. Y fuése Saúl á su casa, y David y los suyos se subieron al sitio fuerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 1, 'Y MURIO Samuel, y juntóse todo Israel, y lo lloraron, y lo sepultaron en su casa en Rama. Y levantóse David, y se fué al desierto de Parán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 2, 'Y en Maón había un hombre que tenía su hacienda en el Carmelo, el cual era muy rico, que tenía tres mil ovejas y mil cabras. Y aconteció hallarse esquilando sus ovejas en el Carmelo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 3, 'El nombre de aquel varón era Nabal, y el nombre de su mujer, Abigail. Y era aquella mujer de buen entendimiento y de buena gracia; mas el hombre era duro y de malos hechos; y era del linaje de Caleb.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 4, 'Y oyó David en el desierto que Nabal esquilaba sus ovejas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 5, 'Entonces envió David diez criados, y díjoles: Subid al Carmelo, é id á Nabal, y saludadle en mi nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 6, 'Y decidle así: Que vivas y sea paz á ti, y paz á tu familia, y paz á todo cuanto tienes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 7, 'Ha poco supe que tienes esquiladores. Ahora, á los pastores tuyos que han estado con nosotros, nunca les hicimos fuerza, ni les faltó algo en todo el tiempo que han estado en el Carmelo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 8, 'Pregunta á tus criados, que ellos te lo dirán. Hallen por tanto estos criados gracia en tus ojos, pues que venimos en buen día: ruégote que des lo que tuvieres á mano á tus siervos, y á tu hijo David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 9, 'Y como llegaron los criados de David, dijeron á Nabal todas estas palabras en nombre de David, y callaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 10, 'Y Nabal respondió á los criados de David, y dijo: ¿Quién es David? ¿y quién es el hijo de Isaí? Muchos siervos hay hoy que se huyen de sus señores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 11, '¿He de tomar yo ahora mi pan, mi agua, y mi víctima que he preparado para mis esquiladores, y la daré á hombres que no sé de dónde son?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 12, 'Y tornándose los criados de David, volviéronse por su camino, y vinieron y dijeron á David todas estas palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 13, 'Entonces David dijo á sus hombres: Cíñase cada uno su espada. Y ciñóse cada uno su espada: también David ciñó su espada; y subieron tras David como cuatrocientos hombres, y dejaron doscientos con el bagaje.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 14, 'Y uno de los criados dió aviso á Abigail mujer de Nabal, diciendo: He aquí David envió mensajeros del desierto que saludasen á nuestro amo, y él los ha zaherido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 15, 'Mas aquellos hombres nos han sido muy buenos, y nunca nos han hecho fuerza, ni ninguna cosa nos ha faltado en todo el tiempo que hemos conversado con ellos, mientras hemos estado en el campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 16, 'Hannos sido por muro de día y de noche, todos los días que hemos estado con ellos apacentando las ovejas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 17, 'Ahora pues, entiende y mira lo que has de hacer, porque el mal está del todo resuelto contra nuestro amo y contra toda su casa: pues él es un hombre tan malo, que no hay quien pueda hablarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 18, 'Entonces Abigail tomó luego doscientos panes, y dos cueros de vino, y cinco ovejas guisadas, y cinco medidas de grano tostado, y cien hilos de uvas pasas, y doscientos panes de higos secos, y cargólo en asnos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 19, 'Y dijo á sus criados: Id delante de mí, que yo os seguiré luego. Y nada declaró á su marido Nabal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 20, 'Y sentándose sobre un asno descendió por una parte secreta del monte, y he aquí David y los suyos que venían frente á ella, y ella les fué al encuentro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 21, 'Y David había dicho: Ciertamente en vano he guardado todo lo que éste tiene en el desierto, sin que nada le haya faltado de todo cuanto es suyo; y él me ha vuelto mal por bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 22, 'Así haga Dios, y así añada á los enemigos de David, que de aquí á mañana no tengo de dejar de todo lo que fuere suyo ni aun meante á la pared.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 23, 'Y como Abigail vió á David, apeóse prestamente del asno, y postrándose delante de David sobre su rostro, inclinóse á tierra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 24, 'Y echóse á sus pies, y dijo: Señor mío, sobre mí sea el pecado; mas ruégote hable tu sierva en tus oídos, y oye las palabras de tu sierva.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 25, 'No ponga ahora mi señor su corazón á aquel hombre brusco, á Nabal; porque conforme á su nombre, así es. El se llama Nabal, y la locura está con él: mas yo tu sierva no vi los criados de mi señor, los cuales tú enviaste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 26, 'Ahora pues, señor mío, vive Jehová y vive tu alma, que Jehová te ha estorbado que vinieses á derramar sangre, y vengarte por tu propia mano. Sean pues como Nabal tus enemigos, y todos los que procuran mal contra mi señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 27, 'Y ahora esta bendición que tu sierva ha traído á mi señor, dése á los criados que siguen á mi señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 28, 'Y yo te ruego que perdones á tu sierva esta ofensa; pues Jehová de cierto hará casa firme á mi señor, por cuanto mi señor hace las guerras de Jehová, y mal no se ha hallado en ti en tus días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 29, 'Bien que alguien se haya levantado á perseguirte y atentar á tu vida, con todo, el alma de mi señor será ligada en el haz de los que viven con Jehová Dios tuyo, y él arrojará el alma de tus enemigos como de en medio de la palma de una honda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 30, 'Y acontecerá que cuando Jehová hiciere con mi señor conforme á todo el bien que ha hablado de ti, y te mandare que seas caudillo sobre Israel,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 31, 'Entonces, señor mío, no te será esto en tropiezo y turbación de corazón, el que hayas derramado sangre sin causa, ó que mi señor se haya vengado por sí mismo. Guárdese pues mi señor, y cuando Jehová hiciere bien á mi señor, acuérdate de tu sierva.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 32, 'Y dijo David á Abigail: Bendito sea Jehová Dios de Israel, que te envió para que hoy me encontrases;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 33, 'Y bendito sea tu razonamiento, y bendita tú, que me has estorbado hoy el ir á derramar sangre, y á vengarme por mi propia mano:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 34, 'Porque, vive Jehová Dios de Israel que me ha defendido de hacerte mal, que si no te hubieras dado priesa en venirme al encuentro, de aquí á mañana no le quedara á Nabal meante á la pared.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 35, 'Y recibió David de su mano lo que le había traído, y díjole: Sube en paz á tu casa, y mira que he oído tu voz, y tenídote respeto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 36, 'Y Abigail se vino á Nabal, y he aquí que él tenía banquete en su casa como banquete de rey: y el corazón de Nabal estaba alegre en él, y estaba muy borracho; por lo que ella no le declaró poco ni mucho, hasta que vino el día siguiente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 37, 'Pero á la mañana, cuando el vino había salido de Nabal, refirióle su mujer aquestas cosas; y se le amorteció el corazón, y quedóse como piedra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 38, 'Y pasados diez días Jehová hirió á Nabal, y murió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 39, 'Y luego que David oyó que Nabal era muerto, dijo: Bendito sea Jehová que juzgó la causa de mi afrenta recibida de la mano de Nabal, y ha preservado del mal á su siervo; y Jehová ha tornado la malicia de Nabal sobre su propia cabeza. Después envió David á hablar á Abigail, para tomarla por su mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 40, 'Y los criados de David vinieron á Abigail en el Carmelo, y hablaron con ella, diciendo: David nos ha enviado á ti, para tomarte por su mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 41, 'Y ella se levantó, é inclinó su rostro á tierra, diciendo: He aquí tu sierva, para que sea sierva que lave los pies de los siervos de mi señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 42, 'Y levantándose luego Abigail con cinco mozas que la seguían, montóse en un asno, y siguió los mensajeros de David, y fué su mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 43, 'También tomó David á Ahinoam de Jezreel, y ambas á dos fueron sus mujeres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 25, 44, 'Porque Saúl había dado su hija Michâl mujer de David, á Palti hijo de Lais, que era de Gallim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 26, 1, 'Y VINIERON los Zipheos á Saúl en Gabaa, diciendo: ¿No está David escondido en el collado de Hachîla delante del desierto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 26, 2, 'Saúl entonces se levantó, y descendió al desierto de Ziph, llevando consigo tres mil hombres escogidos de Israel, para buscar á David en el desierto de Ziph.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 26, 3, 'Y asentó Saúl el campo en el collado de Hachîla, que está delante del desierto junto al camino. Y estaba David en el desierto, y entendió que Saúl le seguía en el desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 26, 4, 'David por tanto envió espías, y entendió por cierto que Saúl había venido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 26, 5, 'Y levantóse David, y vino al sitio donde Saúl había asentado el campo; y miró David el lugar donde dormía Saúl, y Abner hijo de Ner, general de su ejército. Y estaba Saúl durmiendo en la trinchera, y el pueblo por el campo en derredor de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 26, 6, 'Entonces habló David, y requirió á Ahimelech Hetheo, y á Abisai hijo de Sarvia, hermano de Joab, diciendo: ¿Quién descenderá conmigo á Saúl al campo: Y dijo Abisai: Yo descenderé contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 26, 7, 'David pues y Abisai vinieron al pueblo de noche: y he aquí Saúl que estaba tendido durmiendo en la trinchera, y su lanza hincada en tierra á su cabecera; y Abner y el pueblo estaban alrededor de él tendidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 26, 8, 'Entonces dijo Abisai á David: Hoy ha Dios entregado á tu enemigo en tus manos: ahora pues, herirélo luego con la lanza, cosiéndole con la tierra de un golpe, y no segundaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 26, 9, 'Y David respondió á Abisai: No le mates: porque ¿quién extenderá su mano contra el ungido de Jehová, y será inocente?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 26, 10, 'Dijo además David: Vive Jehová, que si Jehová no lo hiriere, ó que su día llegue para que muera, ó que descendiendo en batalla perezca,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 26, 11, 'Guardeme Jehová de extender mi mano contra el ungido de Jehová; empero toma ahora la lanza que está á su cabecera, y la botija del agua, y vámonos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 26, 12, 'Llevóse pues David la lanza y la botija de agua de la cabecera de Saúl, y fuéronse; que no hubo nadie que viese, ni entendiese, ni velase, pues todos dormían: porque un profundo sueño enviado de Jehová había caído sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 26, 13, 'Y pasando David de la otra parte, púsose desviado en la cumbre del monte, habiendo grande distancia entre ellos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 26, 14, 'Y dió voces David al pueblo, y á Abner hijo de Ner, diciendo: ¿No respondes, Abner? Entonces Abner respondió y dijo: ¿Quién eres tú que das voces al rey?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 26, 15, 'Y dijo David á Abner: ¿No eres varón tú? ¿y quién hay como tú en Israel? ¿por qué pues no has guardado al rey tu señor? que ha entrado uno del pueblo á matar á tu señor el rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 26, 16, 'Esto que has hecho, no está bien. Vive Jehová, que sois dignos de muerte, que no habéis guardado á vuestro señor, al ungido de Jehová. Mira pues ahora dónde está la lanza del rey, y la botija del agua que estaba á su cabecera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 26, 17, 'Y conociendo Saúl la voz de David, dijo: ¿No es esta tu voz, hijo mío David? Y David respondió: Mi voz es, rey señor mío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 26, 18, 'Y dijo: ¿Por qué persigue así mi señor á su siervo? ¿qué he hecho? ¿qué mal hay en mi mano?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 26, 19, 'Ruego pues, que el rey mi señor oiga ahora las palabras de su siervo. Si Jehová te incita contra mí, acepte un sacrificio: mas si fueren hijos de hombres, malditos ellos en presencia de Jehová, que me han echado hoy para que no me junte en la heredad de Jehová, diciendo: Ve y sirve á dioses ajenos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 26, 20, 'No caiga pues ahora mi sangre en tierra delante de Jehová: porque ha salido el rey de Israel á buscar una pulga, así como quien persigue una perdiz por los montes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 26, 21, 'Entonces dijo Saúl: He pecado: vuélvete, hijo mío David, que ningún mal te haré más, pues que mi vida ha sido estimada hoy en tus ojos. He aquí, yo he hecho neciamente, y he errado en gran manera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 26, 22, 'Y David respondió, y dijo: He aquí la lanza del rey; pase acá uno de los criados, y tómela.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 26, 23, 'Y Jehová pague á cada uno su justicia y su lealtad: que Jehová te había entregado hoy en mi mano, mas yo no quise extender mi mano sobre el ungido de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 26, 24, 'Y he aquí, como tu vida ha sido estimada hoy en mis ojos, así sea mi vida estimada en los ojos de Jehová, y me libre de toda aflicción.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 26, 25, 'Y Saúl dijo á David: Bendito eres tú, hijo mío David; sin duda ejecutarás tú grandes empresas, y prevalecerás. Entonces David se fué su camino, y Saúl se volvió á su lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 27, 1, 'Y DIJO David en su corazón: Al fin seré muerto algún día por la mano de Saúl: nada por tanto me será mejor que fugarme á la tierra de los Filisteos, para que Saúl se deje de mí, y no me ande buscando más por todos los términos de Israel, y así me escaparé de sus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 27, 2, 'Levantóse pues David, y con los seiscientos hombres que tenía consigo pasóse á Achîs hijo de Maoch, rey de Gath.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 27, 3, 'Y moró David con Achîs en Gath, él y los suyos, cada uno con su familia: David con sus dos mujeres, Ahinoam Jezreelita, y Abigail, la que fué mujer de Nabal el del Carmelo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 27, 4, 'Y vino la nueva á Saúl que David se había huído á Gath, y no lo buscó más.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 27, 5, 'Y David dijo á Achîs: Si he hallado ahora gracia en tus ojos, séame dado lugar en algunas de las ciudades de la tierra, donde habite: porque ¿ha de morar tu siervo contigo en la ciudad real?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 27, 6, 'Y Achîs le dió aquel día á Siclag. De aquí fué Siclag de los reyes de Judá hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 27, 7, 'Y fué el número de los días que David habitó en la tierra de los Filisteos, cuatro meses y algunos días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 27, 8, 'Y subía David con los suyos, y hacían entradas en los Gesureos, y en los Gerzeos, y en los Amalecitas: porque estos habitaban de largo tiempo la tierra, desde como se va á Shur hasta la tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 27, 9, 'Y hería David el país, y no dejaba á vida hombre ni mujer: y llevábase las ovejas y las vacas y los asnos y los camellos y las ropas; y volvía, y veníase á Achîs.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 27, 10, 'Y decía Achîs: ¿Dónde habéis corrido hoy? Y David decía: Al mediodía de Judá, y al mediodía de Jerameel, ó contra el mediodía de Ceni.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 27, 11, 'Ni hombre ni mujer dejaba á vida David, que viniese á Gath; diciendo: Porque no den aviso de nosotros, diciendo: Esto hizo David. Y esta era su costumbre todo el tiempo que moró en tierra de los Filisteos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 27, 12, 'Y Achîs creía á David, diciendo así: El se hace abominable en su pueblo de Israel, y será siempre mi siervo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 28, 1, 'Y ACONTECIO que en aquellos días los Filisteos juntaron sus campos para pelear contra Israel. Y dijo Achîs á David: Sabe de cierto que has de salir conmigo á campaña, tú y los tuyos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 28, 2, 'Y David respondió á Achîs: Sabrás pues lo que hará tu siervo. Y Achîs dijo á David: Por tanto te haré guarda de mi cabeza todos los días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 28, 3, 'Ya Samuel era muerto, y todo Israel lo había lamentado, y habíanle sepultado en Rama, en su ciudad. Y Saúl había echado de la tierra los encantadores y adivinos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 28, 4, 'Pues como los Filisteos se juntaron, vinieron y asentaron campo en Sunam: y Saúl juntó á todo Israel, y asentaron campo en Gilboa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 28, 5, 'Y cuando vió Saúl el campo de los Filisteos, temió, y turbóse su corazón en gran manera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 28, 6, 'Y consultó Saúl á Jehová; pero Jehová no le respondió, ni por sueños, ni por Urim, ni por profetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 28, 7, 'Entonces Saúl dijo á sus criados: Buscadme una mujer que tenga espíritu de pythón, para que yo vaya á ella, y por medio de ella pregunte. Y sus criados le respondieron: He aquí hay una mujer en Endor que tiene espíritu de pythón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 28, 8, 'Y disfrazóse Saúl, y púsose otros vestidos, y fuése con dos hombres, y vinieron á aquella mujer de noche; y él dijo: Yo te ruego que me adivines por el espíritu de pythón, y me hagas subir á quien yo te dijere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 28, 9, 'Y la mujer le dijo: He aquí tú sabes lo que Saúl ha hecho, cómo ha separado de la tierra los pythones y los adivinos: ¿por qué pues pones tropiezo á mi vida, para hacerme matar?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 28, 10, 'Entoces Saúl le juró por Jehová, diciendo: Vive Jehová, que ningún mal te vendrá por esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 28, 11, 'La mujer entonces dijo: ¿A quién te haré venir? Y él respondió: Hazme venir á Samuel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 28, 12, 'Y viendo la mujer á Samuel, clamó en alta voz, y habló aquella mujer á Saúl, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 28, 13, '¿Por qué me has engañado? que tú eres Saúl. Y el rey le dijo: No temas: ¿qué has visto? Y la mujer respondió á Saúl: He visto dioses que suben de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 28, 14, 'Y él le dijo: ¿Cuál es su forma? Y ella respondió: Un hombre anciano viene, cubierto de un manto. Saúl entonces entendió que era Samuel, y humillando el rostro á tierra, hizo gran reverencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 28, 15, 'Y Samuel dijo á Saúl: ¿Por qué me has inquietado haciéndome venir? Y Saúl respondió: Estoy muy congojado; pues los Filisteos pelean contra mí, y Dios se ha apartado de mí, y no me responde más, ni por mano de profetas, ni por sueños: por esto te he llamado, para que me declares qué tengo de hacer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 28, 16, 'Entonces Samuel dijo: ¿Y para qué me preguntas á mí, habiéndose apartado de ti Jehová, y es tu enemigo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 28, 17, 'Jehová pues ha hecho como habló por medio de mí; pues ha cortado Jehová el reino de tu mano, y lo ha dado á tu compañero David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 28, 18, 'Como tú no obedeciste á la voz de Jehová, ni cumpliste el furor de su ira sobre Amalec, por eso Jehová te ha hecho esto hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 28, 19, 'Y Jehová entregará á Israel también contigo en manos de los Filisteos: y mañana seréis conmigo, tú y tus hijos: y aun el campo de Israel entregará Jehová en manos de los Filisteos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 28, 20, 'En aquel punto cayó Saúl en tierra cuan grande era, y tuvo gran temor por las palabras de Samuel; que no quedó en él esfuerzo ninguno, porque en todo aquel día y aquella noche no había comido pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 28, 21, 'Entonces la mujer vino á Saúl, y viéndole en grande manera turbado, díjole: He aquí que tu criada ha obedecido á tu voz, y he puesto mi vida en mi mano, y he oído las palabras que tú me has dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 28, 22, 'Ruégote pues, que tú también oigas la voz de tu sierva: pondré yo delante de ti un bocado de pan que comas, para que te corrobores, y vayas tu camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 28, 23, 'Y él lo rehusó, diciendo: No comeré. Mas sus criados juntamente con la mujer le constriñeron, y él los obedeció. Levantóse pues del suelo, y sentóse sobre una cama.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 28, 24, 'Y aquella mujer tenía en su casa un ternero grueso, el cual mató luego; y tomó harina y amasóla, y coció de ella panes sin levadura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 28, 25, 'Y lo trajo delante de Saúl y de sus criados; y luego que hubieron comido, se levantaron, y partieron aquella noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 29, 1, 'Y LOS Filisteos juntaron todos sus campos en Aphec; é Israel puso su campo junto á la fuente que está en Jezreel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 29, 2, 'Y reconociendo los príncipes de los Filisteos sus compañías de á ciento y de á mil hombres, David y los suyos iban en los postreros con Achîs.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 29, 3, 'Y dijeron los príncipes de los Filisteos: ¿Qué hacen aquí estos Hebreos? Y Achîs respondió á los príncipes de los Filisteos: ¿No es éste David, el siervo de Saúl rey de Israel, que ha estado conmigo algunos días ó algunos años, y no he hallado cosa en él desde el día que se pasó á mí hasta hoy?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 29, 4, 'Entonces los príncipes de los Filisteos se enojaron contra él, y dijéronle: Envía á este hombre, que se vuelva al lugar que le señalaste, y no venga con nosotros á la batalla, no sea que en la batalla se nos vuelva enemigo: porque ¿con qué cosa volvería mejor á la gracia de su señor que con las cabezas de estos hombres?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 29, 5, '¿No es este David de quien cantaba en los corros, diciendo: Saúl hirió sus miles, Y David sus diez miles?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 29, 6, 'Y Achîs llamó á David, y díjole: Vive Jehová, que tú has sido recto, y que me ha parecido bien tu salida y entrada en el campo conmigo, y que ninguna cosa mala he hallado en ti desde el día que viniste á mí hasta hoy: mas en los ojos de los príncipes no agradas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 29, 7, 'Vuélvete pues, y vete en paz; y no hagas lo malo en los ojos de los príncipes de los Filisteos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 29, 8, 'Y David respondió á Achîs: ¿Qué he hecho? ¿qué has hallado en tu siervo desde el día que estoy contigo hasta hoy, para que yo no vaya y pelee contra los enemigos de mi señor el rey?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 29, 9, 'Y Achîs respondió á David, y dijo: Yo sé que tú eres bueno en mis ojos, como un ángel de Dios; mas los príncipes de los Filisteos han dicho: No venga con nosotros á la batalla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 29, 10, 'Levántate pues de mañana, tú y los siervos de tu señor que han venido contigo; y levantándoos de mañana, luego al amanecer partíos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 29, 11, 'Y levantóse David de mañana, él y los suyos, para irse y volverse á la tierra de los Filisteos; y los Filisteos fueron á Jezreel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 1, 'Y CUANDO David y los suyos vinieron á Siclag el tercer día, los de Amalec habían invadido el mediodía y á Siclag, y habían desolado á Siclag, y puéstola á fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 2, 'Y habíanse llevado cautivas á las mujeres que estaban en ella, desde el menor hasta el mayor; mas á nadie habían muerto, sino llevado, é ídose su camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 3, 'Vino pues David con los suyos á la ciudad, y he aquí que estaba quemada á fuego, y sus mujeres y sus hijos é hijas llevadas cautivas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 4, 'Entonces David y la gente que con él estaba, alzaron su voz y lloraron, hasta que les faltaron las fuerzas para llorar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 5, 'Las dos mujeres de David, Ahinoam Jezreelita y Abigail la que fué mujer de Nabal del Carmelo, también eran cautivas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 6, 'Y David fué muy angustiado, porque el pueblo hablaba de apedrearlo; porque todo el pueblo estaba con ánimo amargo, cada uno por sus hijos y por sus hijas: mas David se esforzó en Jehová su Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 7, 'Y dijo David al sacerdote Abiathar hijo de Ahimelech: Yo te ruego que me acerques el ephod. Y Abiathar acercó el ephod á David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 8, 'Y David consultó á Jehová, diciendo: ¿Seguiré esta tropa? ¿podréla alcanzar? Y él le dijo: Síguela que de cierto la alcanzarás, y sin falta librarás la presa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 9, 'Partióse pues David, él y los seiscientos hombres que con él estaban, y vinieron hasta el torrente de Besor, donde se quedaron algunos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 10, 'Y David siguió el alcance con cuatrocientos hombres; porque se quedaron atrás doscientos, que cansados no pudieron pasar el torrente de Besor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 11, 'Y hallaron en el campo un hombre Egipcio, el cual trajeron á David, y diéronle pan que comiese, y á beber agua;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 12, 'Diéronle también un pedazo de masa de higos secos, y dos hilos de pasas. Y luego que comió, volvió en él su espíritu; porque no había comido pan ni bebido agua en tres días y tres noches.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 13, 'Y díjole David: ¿De quién eres tú? ¿y de dónde eres? Y respondió el mozo Egipcio: Yo soy siervo de un Amalecita, y dejóme mi amo hoy ha tres días, porque estaba enfermo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 14, 'Pues hicimos una incursión á la parte del mediodía de Cerethi, y á Judá, y al mediodía de Caleb; y pusimos fuego á Siclag.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 15, 'Y díjole David: ¿Me llevarás tú á esa tropa? Y él dijo: Hazme juramento por Dios que no me matarás, ni me entregarás en las manos de mi amo, y yo te llevaré á esa gente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 16, 'Llevólo pues: y he aquí que estaban derramados sobre la haz de toda aquella tierra, comiendo y bebiendo y haciendo fiesta, por toda aquella gran presa que habían tomado de la tierra de los Filisteos, y de la tierra de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 17, 'E hiriólos David desde aquella mañana hasta la tarde del día siguiente: y no escapó de ellos ninguno, sino cuatrocientos mancebos, que habían subido en camellos y huyeron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 18, 'Y libró David todo lo que los Amalecitas habían tomado: y asimismo libertó David á sus dos mujeres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 19, 'Y no les faltó cosa chica ni grande, así de hijos como de hijas, del robo, y de todas las cosas que les habían tomado: todo lo recobró David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 20, 'Tomó también David todas las ovejas y ganados mayores; y trayéndolo todo delante, decían: Esta es la presa de David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 21, 'Y vino David á los doscientos hombres que habían quedado cansados y no habían podido seguir á David, á los cuales habían hecho quedar en el torrente de Besor; y ellos salieron á recibir á David, y al pueblo que con él estaba. Y como David llegó á la gente, saludóles con paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 22, 'Entonces todos los malos y perversos de entre los que habían ido con David, respondieron y dijeron: Pues que no fueron con nosotros, no les daremos de la presa que hemos quitado, sino á cada uno su mujer y sus hijos; los cuales tomen y se vayan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 23, 'Y David dijo: No hagáis eso, hermanos míos, de lo que nos ha dado Jehová; el cual nos ha guardado, y ha entregado en nuestras manos la caterva que vino sobre nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 24, '¿Y quién os escuchará en este caso? porque igual parte ha de ser la de los que vienen á la batalla, y la de los que quedan con el bagaje: que partan juntamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 25, 'Y desde aquel día en adelante fué esto puesto por ley y ordenanza en Israel, hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 26, 'Y como David llegó á Siclag, envió de la presa á los ancianos de Judá, sus amigos, diciendo: He aquí una bendición para vosotros, de la presa de los enemigos de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 27, 'A los que estaban en Beth-el, y en Ramoth al mediodía, y á los que estaban en Jattir;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 28, 'Y á los que estaban en Aroer, y en Siphmoth, y á los que estaban en Esthemoa;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 29, 'Y á los que estaban en Rachâl, y á los que estaban en las ciudades de Jerameel, y á los que estaban en las ciudades del Cineo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 30, 'Y á los que estaban en Horma, y á los que estaban en Chôrasán, y á los que estaban en Athach;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 30, 31, 'Y á los que estaban en Hebrón, y en todos los lugares donde David había estado con los suyos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 31, 1, 'LOS Filisteos pues pelearon con Israel, y los de Israel huyeron delante de los Filisteos, y cayeron muertos en el monte de Gilboa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 31, 2, 'Y siguiendo los Filisteos á Saúl y á sus hijos, mataron á Jonathán, y á Abinadab, y á Melchîsua, hijos de Saúl.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 31, 3, 'Y agravóse la batalla sobre Saúl, y le alcanzaron los flecheros; y tuvo gran temor de los flecheros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 31, 4, 'Entonces dijo Saúl á su escudero: Saca tu espada, y pásame con ella, porque no vengan estos incircuncisos, y me pasen, y me escarnezcan. Mas su escudero no quería, porque tenía gran temor. Entonces tomó Saúl la espada, y echóse sobre ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 31, 5, 'Y viendo su escudero á Saúl muerto, él también se echó sobre su espada, y murió con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 31, 6, 'Así murió Saúl en aquel día, juntamente con sus tres hijos, y su escudero, y todos sus varones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 31, 7, 'Y los de Israel que eran de la otra parte del valle, y de la otra parte del Jordán, viendo que Israel había huído, y que Saúl y sus hijos eran muertos, dejaron las ciudades y huyeron; y los Filisteos vinieron y habitaron en ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 31, 8, 'Y aconteció el siguiente día, que viniendo los Filisteos á despojar los muertos, hallaron á Saúl y á sus tres hijos tendidos en el monte de Gilboa;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 31, 9, 'Y cortáronle la cabeza, y desnudáronle las armas; y enviaron á tierra de los Filisteos al contorno, para que lo noticiaran en el templo de sus ídolos, y por el pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 31, 10, 'Y pusieron sus armas en el templo de Astaroth, y colgaron su cuerpo en el muro de Beth-san.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 31, 11, 'Mas oyendo los de Jabes de Galaad esto que los Filisteos hicieron á Saúl,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 31, 12, 'Todos los hombres valientes se levantaron, y anduvieron toda aquella noche, y quitaron el cuerpo de Saúl y los cuerpos de sus hijos del muro de Beth-san; y viniendo á Jabes, quemáronlos allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1SA', '1 Samuel', 31, 13, 'Y tomando sus huesos, sepultáronlos debajo de un árbol en Jabes, y ayunaron siete días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 1, 1, 'Y ACONTECIO después de la muerte de Saúl, que vuelto David de la derrota de los Amalecitas, estuvo dos días en Siclag:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 1, 2, 'Y al tercer día acaeció, que vino uno del campo de Saúl, rotos sus vestidos, y tierra sobre su cabeza: y llegando á David, postróse en tierra, é hizo reverencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 1, 3, 'Y preguntóle David: ¿De dónde vienes? Y él respondió: Heme escapado del campo de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 1, 4, 'Y David le dijo: ¿Qué ha acontecido? ruégote que me lo digas. Y él respondió: El pueblo huyó de la batalla, y también muchos del pueblo cayeron y son muertos: también Saúl y Jonathán su hijo murieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 1, 5, 'Y dijo David á aquel mancebo que le daba las nuevas: ¿Cómo sabes que Saúl es muerto, y Jonathán su hijo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 1, 6, 'Y el mancebo que le daba las nuevas respondió: Casualmente vine al monte de Gilboa, y hallé á Saúl que estaba recostado sobre su lanza, y venían tras él carros y gente de á caballo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 1, 7, 'Y como él miró atrás, vióme y llamóme; y yo dije: Heme aquí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 1, 8, 'Y él me dijo: ¿Quién eres tú? Y yo le respondí: Soy Amalecita.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 1, 9, 'Y él me volvió á decir: Yo te ruego que te pongas sobre mí, y me mates, porque me toman angustias, y toda mi alma está aún en mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 1, 10, 'Yo entonces púseme sobre él, y matélo, porque sabía que no podía vivir después de su caída: y tomé la corona que tenía en su cabeza, y la ajorca que traía en su brazo, y helas traído acá á mi señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 1, 11, 'Entonces David trabando de sus vestidos, rompiólos; y lo mismo hicieron los hombres que estaban con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 1, 12, 'Y lloraron y lamentaron, y ayunaron hasta la tarde, por Saúl y por Jonathán su hijo, y por el pueblo de Jehová, y por la casa de Israel: porque habían caído á cuchillo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 1, 13, 'Y David dijo á aquel mancebo que le había traído las nuevas: ¿De dónde eres tú? Y él respondió: Yo soy hijo de un extranjero, Amalecita.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 1, 14, 'Y díjole David: ¿Cómo no tuviste temor de extender tu mano para matar al ungido de Jehová?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 1, 15, 'Entonces llamó David uno de los mancebos, y díjole: Llega, y mátalo. Y él lo hirió, y murió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 1, 16, 'Y David le dijo: Tu sangre sea sobre tu cabeza, pues que tu boca atestiguó contra ti, diciendo: Yo maté al ungido de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 1, 17, 'Y endechó David á Saúl y á Jonathán su hijo con esta endecha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 1, 18, '(Dijo también que enseñasen al arco á los hijos de Judá. He aquí que está escrito en el libro del derecho:)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 1, 19, '¡Perecido ha la gloria de Israel sobre tus montañas! ¡Cómo han caído los valientes!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 1, 20, 'No lo denunciéis en Gath, No deis las nuevas en las plazas de Ascalón; Porque no se alegren las hijas de los Filisteos, Porque no salten de gozo las hijas de los incircuncisos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 1, 21, 'Montes de Gilboa, Ni rocío ni lluvia caiga sobre vosotros, ni seáis tierras de ofrendas; Porque allí fué desechado el escudo de los valientes, El escudo de Saúl, como si no hubiera sido ungido con aceite.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 1, 22, 'Sin sangre de muertos, sin grosura de valientes, El arco de Jonathán nunca volvió, Ni la espada de Saúl se tornó vacía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 1, 23, 'Saúl y Jonathán, amados y queridos en su vida, En su muerte tampoco fueron apartados: Más ligeros que águilas, Más fuertes que leones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 1, 24, 'Hijas de Israel, llorad sobre Saúl, Que os vestía de escarlata en regocijos, Que adornaba vuestras ropas con ornamentos de oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 1, 25, '¡Cómo han caído los valientes en medio de la batalla! ¡Jonathán, muerto en tus alturas!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 1, 26, 'Angustia tengo por ti, hermano mío Jonathán, Que me fuiste muy dulce: Más maravilloso me fué tu amor, Que el amor de las mujeres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 1, 27, '¡Cómo han caído los valientes, Y perecieron las armas de guerra!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 1, 'DESPUÉS de esto aconteció que David consultó á Jehová, diciendo: ¿Subiré á alguna de las ciudades de Judá? Y Jehová le respondió: Sube. Y David tornó á decir: ¿A dónde subiré? Y él le dijo: A Hebrón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 2, 'Y David subió allá, y con él sus dos mujeres, Ahinoam Jezreelita y Abigail, la que fué mujer de Nabal del Carmelo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 3, 'Y llevó también David consigo los hombres que con él habían estado, cada uno con su familia; los cuales moraron en las ciudades de Hebrón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 4, 'Y vinieron los varones de Judá, y ungieron allí á David por rey sobre la casa de Judá. Y dieron aviso á David, diciendo: Los de Jabes de Galaad son los que sepultaron á Saúl.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 5, 'Y envió David mensajeros á los de Jabes de Galaad, diciéndoles: Benditos seáis vosotros de Jehová, que habéis hecho esta misericordia con vuestro señor Saúl en haberle dado sepultura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 6, 'Ahora pues, Jehová haga con vosotros misericordia y verdad; y yo también os haré bien por esto que habéis hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 7, 'Esfuércense pues ahora vuestras manos, y sed valientes; pues que muerto Saúl vuestro señor, los de la casa de Judá me han ungido por rey sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 8, 'Mas Abner hijo de Ner, general de ejército de Saúl, tomó á Is-boseth hijo de Saúl, é hízolo pasar al real:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 9, 'Y alzólo por rey sobre Galaad, y sobre Gessuri, y sobre Jezreel, y sobre Ephraim, y sobre Benjamín, y sobre todo Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 10, 'De cuarenta años era Is-boseth hijo de Saúl, cuando comenzó á reinar sobre Israel; y reinó dos años. Sola la casa de Judá seguía á David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 11, 'Y fué el número de los días que David reinó en Hebrón sobre la casa de Judá, siete años y seis meses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 12, 'Y Abner hijo de Ner salió de Mahanaim á Gabaón con los siervos de Is-boseth hijo de Saúl.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 13, 'Y Joab hijo de Sarvia, y los siervos de David, salieron y encontráronlos junto al estanque de Gabaón: y como se juntaron, paráronse los unos de la una parte del estanque, y los otros de la otra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 14, 'Y dijo Abner á Joab: Levántense ahora los mancebos, y maniobren delante de nosotros. Y Joab respondió: Levántense.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 15, 'Entonces se levantaron, y en número de doce, pasaron de Benjamín de la parte de Is-boseth hijo de Saúl; y doce de los siervos de David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 16, 'Y cada uno echó mano de la cabeza de su compañero, y metióle su espada por el costado, cayendo así á una; por lo que fué llamado aquel lugar, Helcath-assurim, el cual está en Gabaón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 17, 'Y hubo aquel día una batalla muy recia, y Abner y los hombres de Israel fueron vencidos de los siervos de David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 18, 'Y estaban allí los tres hijos de Sarvia: Joab, y Abisai, y Asael. Este Asael era suelto de pies como un corzo del campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 19, 'El cual Asael siguió á Abner, yendo tras de él sin apartarse á diestra ni á siniestra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 20, 'Y Abner miró atrás, y dijo: ¿No eres tú Asael? Y él respondió: Sí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 21, 'Entonces Abner le dijo: Apártate á la derecha ó á la izquierda, y agárrate alguno de los mancebos, y toma para ti sus despojos. Pero Asael no quiso apartarse de en pos de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 22, 'Y Abner tornó á decir á Asael: Apártate de en pos de mí, porque te heriré derribándote en tierra, y después ¿cómo levantaré mi rostro á tu hermano Joab?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 23, 'Y no queriendo él irse, hiriólo Abner con el regatón de la lanza por la quinta costilla, y salióle la lanza por las espaldas, y cayó allí, y murió en aquel mismo sitio. Y todos los que venían por aquel lugar donde Asael había caído y estaba muerto, se paraban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 24, 'Mas Joab y Abisai siguieron á Abner; y púsoseles el sol cuando llegaron al collado de Amma, que está delante de Gía, junto al camino del desierto de Gabaón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 25, 'Y juntáronse los hijos de Benjamín en un escuadrón con Abner, y paráronse en la cumbre del collado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 26, 'Y Abner dió voces á Joab, diciendo: ¿Consumirá la espada perpetuamente? ¿no sabes tú que al cabo se sigue amargura? ¿hasta cuándo no has de decir al pueblo que se vuelvan de seguir á sus hermanos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 27, 'Y Joab respondió: Vive Dios que si no hubieras hablado, ya desde esta mañana el pueblo hubiera dejado de seguir á sus hermanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 28, 'Entonces Joab tocó el cuerno, y todo el pueblo se detuvo, y no siguió más á los de Israel, ni peleó más.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 29, 'Y Abner y los suyos caminaron por la campiña toda aquella noche, y pasando el Jordán cruzaron por todo Bitrón, y llegaron á Mahanaim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 30, 'Joab también volvió de seguir á Abner, y juntando todo el pueblo, faltaron de los siervos de David diecinueve hombres, y Asael.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 31, 'Mas los siervos de David hirieron de los de Benjamín y de los de Abner, trescientos y sesenta hombres, que murieron. Tomaron luego á Asael, y sepultáronlo en el sepulcro de su padre en Beth-lehem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 2, 32, 'Y caminaron toda aquella noche Joab y los suyos, y amanecióles en Hebrón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 1, 'Y HUBO larga guerra entre la casa de Saúl y la casa de David; mas David se iba fortificando, y la casa de Saúl iba en disminución.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 2, 'Y nacieron hijos á David en Hebrón: su primogénito fué Ammón, de Ahinoam Jezreelita;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 3, 'Su segundo Chileab, de Abigail la mujer de Nabal, el del Carmelo; el tercero, Absalóm, hijo de Maachâ, hija de Talmai rey de Gessur:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 4, 'El cuarto, Adonías hijo de Haggith; el quinto, Saphatías hijo de Abital;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 5, 'El sexto, Jetream, de Egla mujer de David. Estos nacieron á David en Hebrón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 6, 'Y como había guerra entre la casa de Saúl y la de David, aconteció que Abner se esforzaba por la casa de Saúl.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 7, 'Y había Saúl tenido una concubina que se llamaba Rispa, hija de Aja. Y dijo Is-boseth á Abner: ¿Por qué has entrado á la concubina de mi padre?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 8, 'Y enojóse Abner en gran manera por las palabras de Is-boseth, y dijo: ¿Soy yo cabeza de perros respecto de Judá? Yo he hecho hoy misericordia con la casa de Saúl tu padre, con sus hermanos, y con sus amigos, y no te he entregado en las manos de David: ¿y tú me haces hoy cargo del pecado de esta mujer?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 9, 'Así haga Dios á Abner y así le añada, si como ha jurado Jehová á David no hiciere yo así con él,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 10, 'Trasladando el reino de la casa de Saúl, y confirmando el trono de David sobre Israel y sobre Judá, desde Dan hasta Beer-sebah.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 11, 'Y él no pudo responder palabra á Abner, porque le temía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 12, 'Y envió Abner mensajeros á David de su parte, diciendo: ¿Cúya es la tierra? Y que le dijesen: Haz alianza conmigo, y he aquí que mi mano será contigo para volver á ti á todo Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 13, 'Y David dijo: Bien; yo haré contigo alianza: mas una cosa te pido, y es, que no me vengas á ver sin que primero traigas á Michâl la hija de Saúl, cuando vinieres á verme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 14, 'Después de esto envió David mensajeros á Is-boseth hijo de Saúl, diciendo: Restitúyeme á mi mujer Michâl, la cual yo desposé conmigo por cien prepucios de Filisteos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 15, 'Entonces Is-boseth envió, y quitóla á su marido Paltiel, hijo de Lais.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 16, 'Y su marido fué con ella, siguiéndola y llorando hasta Bahurim. Y díjole Abner: Anda, vuélvete. Entonces él se volvió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 17, 'Y habló Abner con los ancianos de Israel, diciendo: Ayer y antes procurabais que David fuese rey sobre vosotros;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 18, 'Ahora, pues, hacedlo; porque Jehová ha hablado á David, diciendo: Por la mano de mi siervo David libraré á mi pueblo Israel de mano de los Filisteos, y de mano de todos sus enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 19, 'Y habló también Abner á los de Benjamín: y fué también Abner á Hebrón á decir á David todo el parecer de los de Israel y de toda la casa de Benjamín.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 20, 'Vino pues Abner á David en Hebrón, y con él veinte hombres: y David hizo banquete á Abner y á los que con él habían venido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 21, 'Y dijo Abner á David: Yo me levantaré é iré, y juntaré á mi señor el rey á todo Israel, para que hagan contigo alianza, y tú reines como deseas. David despidió luego á Abner, y él se fué en paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 22, 'Y he aquí los siervos de David y Joab, que venían del campo, y traían consigo gran presa. Mas Abner no estaba con David en Hebrón, que ya lo había él despedido, y él se había ido en paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 23, 'Y luego que llegó Joab y todo el ejército que con él estaba, fué dado aviso á Joab, diciendo: Abner hijo de Ner ha venido al rey, y él le ha despedido, y se fué en paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 24, 'Entonces Joab vino al rey, y díjole: ¿Qué has hecho? He aquí habíase venido Abner á ti; ¿por qué pues lo dejaste que se fuése?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 25, '¿Sabes tú que Abner hijo de Ner ha venido para engañarte, y á saber tu salida y tu entrada, y por entender todo lo que tú haces?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 26, 'Y saliéndose Joab de con David, envió mensajeros tras Abner, los cuales le volvieron desde el pozo de Sira, sin saberlo David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 27, 'Y como Abner volvió á Hebrón, apartólo Joab al medio de la puerta, hablando con él blandamente, y allí le hirió por la quinta costilla, á causa de la muerte de Asael su hermano, y murió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 28, 'Cuando David supo después esto, dijo: Limpio estoy yo y mi reino, por Jehová, para siempre, de la sangre de Abner hijo de Ner.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 29, 'Caiga sobre la cabeza de Joab, y sobre toda la casa de su padre; que nunca falte de la casa de Joab quien padezca flujo, ni leproso, ni quien ande con báculo, ni quien muera á cuchillo, ni quien tenga falta de pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 30, 'Joab pues y Abisai su hermano mataron á Abner, porque él había muerto á Asael, hermano de ellos en la batalla de Gabaón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 31, 'Entonces dijo David á Joab, y á todo el pueblo que con él estaba: Romped vuestros vestidos, y ceñíos de sacos, y haced duelo delante de Abner. Y el rey iba detrás del féretro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 32, 'Y sepultaron á Abner en Hebrón: y alzando el rey su voz, lloró junto al sepulcro de Abner; y lloró también todo el pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 33, 'Y endechando el rey al mismo Abner, decía: ¿Murío Abner como muere un villano?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 34, 'Tus manos no estaban atadas, ni tus pies ligados con grillos: Caíste como los que caen delante de malos hombres. Y todo el pueblo volvió á llorar sobre él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 35, 'Y como todo el pueblo viniese á dar de comer pan á David siendo aún de día, David juró, diciendo: Así me haga Dios y así me añada, si antes que se ponga el sol gustare yo pan, ú otra cualquier cosa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 36, 'Súpolo así todo el pueblo, y plugo en sus ojos; porque todo lo que el rey hacía parecía bien en ojos de todo el pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 37, 'Y todo el pueblo y todo Israel entendieron aquel día, que no había venido del rey que Abner hijo de Ner muriese.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 38, 'Y el rey dijo á sus siervos: ¿No sabéis que ha caído hoy en Israel un príncipe, y grande?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 3, 39, 'Que yo ahora aún soy tierno rey ungido; y estos hombres, los hijos de Sarvia, muy duros me son: Jehová dé el pago al que mal hace, conforme á su malicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 4, 1, 'LUEGO que oyó el hijo de Saúl que Abner había sido muerto en Hebrón, las manos se le descoyuntaron, y fué atemorizado todo Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 4, 2, 'Y tenía el hijo de Saúl dos varones, los cuales eran capitanes de compañía, el nombre de uno era Baana, y el del otro Rechâb, hijos de Rimmón Beerothita, de los hijos de Benjamín: (porque Beeroth era contada con Benjamín;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 4, 3, 'Estos Beerothitas se habían huído á Gittaim, y habían sido peregrinos allí hasta entonces.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 4, 4, 'Y Jonathán, hijo de Saúl, tenía un hijo lisiado de los pies de edad de cinco años: que cuando la noticia de la muerte de Saúl y de Jonathán vino de Jezreel, tomóle su ama y huyó; y como iba huyendo con celeridad, cayó el niño y quedó cojo. Su nombre era Mephi-boseth.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 4, 5, 'Los hijos pues de Rimmón Beerothita, Rechâb y Baana, fueron y entraron en el mayor calor del día en casa de Is-boseth, el cual estaba durmiendo en su cámara la siesta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 4, 6, 'Entonces entraron ellos en medio de la casa en hábito de mercaderes de grano, y le hirieron en la quinta costilla. Escapáronse luego Rechâb y Baana su hermano;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 4, 7, 'Pues como entraron en la casa, estando él en su cama en su cámara de dormir, lo hirieron y mataron, y cortáronle la cabeza, y habiéndola tomado, caminaron toda la noche por el camino de la campiña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 4, 8, 'Y trajeron la cabeza de Is-boseth á David en Hebrón, y dijeron al rey: He aquí la cabeza de Is-boseth hijo de Saúl tu enemigo, que procuraba matarte; y Jehová ha vengado hoy á mi señor el rey, de Saúl y de su simiente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 4, 9, 'Y David respondió á Rechâb y á su hermano Baana, hijos de Rimmón Beerothita, y díjoles: Vive Jehová que ha redimido mi alma de toda angustia,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 4, 10, 'Que cuando uno me dió nuevas, diciendo: He aquí Saúl es muerto imaginándose que traía buenas nuevas, yo lo prendí, y le maté en Siclag en pago de la nueva.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 4, 11, '¿Cuánto más á los malos hombres que mataron á un hombre justo en su casa, y sobre su cama? Ahora pues, ¿no tengo yo de demandar su sangre de vuestras manos, y quitaros de la tierra?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 4, 12, 'Entonces David mandó á los mancebos, y ellos los mataron, y cortáronles las manos y los pies, y colgáronlos sobre el estanque, en Hebrón. Luego tomaron la cabeza de Is-boseth, y enterráronla en el sepulcro de Abner en Hebrón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 5, 1, 'Y VINIERON todas las tribus de Israel á David en Hebrón, y hablaron, diciendo: He aquí nosotros somos tus huesos y tú carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 5, 2, 'Y aun ayer y antes, cuando Saúl reinaba sobre nosotros, tú sacabas y volvías á Israel. Además Jehová te ha dicho: Tú apacentarás á mi pueblo Israel, y tú serás sobre Israel príncipe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 5, 3, 'Vinieron pues todos los ancianos de Israel al rey en Hebrón, y el rey David hizo con ellos alianza en Hebrón delante de Jehová; y ungieron á David por rey sobre Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 5, 4, 'Era David de treinta años cuando comenzó á reinar, y reinó cuarenta años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 5, 5, 'En Hebrón reinó sobre Judá siete años y seis meses: y en Jerusalem reinó treinta y tres años sobre todo Israel y Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 5, 6, 'Entonces el rey y los suyos fueron á Jerusalem al Jebuseo que habitaba en la tierra; el cual habló á David, diciendo: Tú no entrarás acá, si no echares los ciegos y los cojos; diciendo: No entrará acá David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 5, 7, 'Empero David tomó la fortaleza de Sión, la cual es la ciudad de David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 5, 8, 'Y dijo David aquel día: ¿Quién llegará hasta las canales, y herirá al Jebuseo, y á los cojos y ciegos, á los cuales el alma de David aborrece? Por esto se dijo: Ciego ni cojo no entrará en casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 5, 9, 'Y David moró en la fortaleza y púsole por nombre la Ciudad de David: y edificó alrededor, desde Millo para adentro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 5, 10, 'Y David iba creciendo y aumentándose, y Jehová Dios de los ejércitos era con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 5, 11, 'E Hiram rey de Tiro envió también embajadores á David, y madera de cedro, y carpinteros, y canteros para los muros, los cuales edificaron la casa de David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 5, 12, 'Y entendió David que Jehová le había confirmado por rey sobre Israel, y que había ensalzado su reino por amor de su pueblo Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 5, 13, 'Y tomó David más concubinas y mujeres de Jerusalem después que vino de Hebrón, y naciéronle más hijos é hijas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 5, 14, 'Estos son los nombres de los que le nacieron en Jerusalem: Sammua, y Sobab, y Nathán, y Salomón,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 5, 15, 'E Ibhar, y Elisua, y Nepheg,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 5, 16, 'Y Japhia, y Elisama, y Eliada, y Eliphelet.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 5, 17, 'Y oyendo los Filisteos que habían ungido á David por rey sobre Israel, todos los Filisteos subieron á buscar á David: lo cual como David oyó, vino á la fortaleza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 5, 18, 'Y vinieron los Filisteos, y extendiéronse por el valle de Raphaim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 5, 19, 'Entonces consultó David á Jehová, diciendo: ¿Iré contra los Filisteos? ¿los entregarás en mis manos? Y Jehová respondió á David: Ve, porque ciertamente entregaré los Filisteos en tus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 5, 20, 'Y vino David á Baal-perasim, y allí los venció David, y dijo: Rompió Jehová mis enemigos delante de mí, como quien rompe aguas. Y por esto llamó el nombre de aquel lugar Baal-perasim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 5, 21, 'Y dejaron allí sus ídolos, los cuales quemó David y los suyos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 5, 22, 'Y los Filisteos tornaron á venir, y extendiéronse en el valle de Raphaim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 5, 23, 'Y consultando David á Jehová, él le respondió: No subas; mas rodéalos, y vendrás á ellos por delante de los morales:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 5, 24, 'Y cuando oyeres un estruendo que irá por las copas de los morales, entonces te moverás; porque Jehová saldrá delante de ti á herir el campo de los Filisteos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 5, 25, 'Y David lo hizo así, como Jehová se lo había mandado; é hirió á los Filisteos desde Gabaa hasta llegar á Gaza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 6, 1, 'Y DAVID tornó á juntar todos los escogidos de Israel, treinta mil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 6, 2, 'Y levantóse David, y fué con todo el pueblo que tenía consigo, de Baal de Judá, para hacer pasar de allí el arca de Dios, sobre la cual era invocado el nombre de Jehová de los ejércitos, que mora en ella entre los querubines.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 6, 3, 'Y pusieron el arca de Dios sobre un carro nuevo, y lleváronla de la casa de Abinadab, que estaba en Gabaa: y Uzza y Ahio, hijos de Abinadab, guiaban el carro nuevo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 6, 4, 'Y cuando lo llevaban de la casa de Abinadab que estaba en Gabaa, con el arca de Dios, Ahio iba delante del arca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 6, 5, 'Y David y toda la casa de Israel danzaban delante de Jehová con toda suerte de instrumentos de madera de haya; con arpas, salterios, adufes, flautas y címbalos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 6, 6, 'Y cuando llegaron á la era de Nachôn, Uzza extendió la mano al arca de Dios, y túvola; porque los bueyes daban sacudidas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 6, 7, 'Y el furor de Jehová se encendió contra Uzza, é hiriólo allí Dios por aquella temeridad, y cayó allí muerto junto al arca de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 6, 8, 'Y entristecióse David por haber herido Jehová á Uzza: y fué llamado aquel lugar Pérez-uzza, hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 6, 9, 'Y temiendo David á Jehová aquel día, dijo: ¿Cómo ha de venir á mí el arca de Jehová?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 6, 10, 'No quiso pues David traer á sí el arca de Jehová á la ciudad de David; mas llevóla David á casa de Obed-edom Getheo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 6, 11, 'Y estuvo el arca de Jehová en casa de Obed-edom Getheo tres meses: y bendijo Jehová á Obed-edom y á toda su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 6, 12, 'Y fué dado aviso al rey David, diciendo: Jehová ha bendecido la casa de Obed-edom, y todo lo que tiene, á causa del arca de Dios. Entonces David fué, y trajo el arca de Dios de casa de Obed-edom á la ciudad de David con alegría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 6, 13, 'Y como los que llevaban el arca de Dios habían andado seis pasos, sacrificaban un buey y un carnero grueso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 6, 14, 'Y David saltaba con toda su fuerza delante de Jehová; y tenía vestido David un ephod de lino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 6, 15, 'Así David y toda la casa de Israel llevaban el arca de Jehová con júbilo y sonido de trompeta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 6, 16, 'Y como el arca de Jehová llegó á la ciudad de David, aconteció que Michâl hija de Saúl miró desde una ventana, y vió al rey David que saltaba con toda su fuerza delante de Jehová: y menosprecióle en su corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 6, 17, 'Metieron pues el arca de Jehová, y pusiéronla en su lugar en medio de una tienda que David le había tendido: y sacrificó David holocaustos y pacíficos delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 6, 18, 'Y como David hubo acabado de ofrecer los holocaustos y pacíficos, bendijo al pueblo en el nombre de Jehová de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 6, 19, 'Y repartió á todo el pueblo, y á toda la multitud de Israel, así á hombres como á mujeres, á cada uno una torta de pan, y un pedazo de carne, y un frasco de vino. Y fuése todo el pueblo, cada uno á su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 6, 20, 'Volvió luego David para bendecir su casa: y saliendo Michâl á recibir á David, dijo: ¡Cuán honrado ha sido hoy el rey de Israel, desnudándose hoy delante de las criadas de sus siervos, como se desnudara un juglar!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 6, 21, 'Entonces David respondió á Michâl: Delante de Jehová, que me eligió más bien que á tu padre y á toda su casa, mandándome que fuese príncipe sobre el pueblo de Jehová, sobre Israel, danzaré delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 6, 22, 'Y aun me haré más vil que esta vez, y seré bajo á mis propios ojos; y delante de las criadas que dijiste, delante de ellas seré honrado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 6, 23, 'Y Michâl hija de Saúl nunca tuvo hijos hasta el día de su muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 7, 1, 'Y ACONTECIO que, estando ya el rey asentado en su casa, después que Jehová le había dado reposo de todos sus enemigos en derredor,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 7, 2, 'Dijo el rey al profeta Nathán: Mira ahora, yo moro en edificios de cedro, y el arca de Dios está entre cortinas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 7, 3, 'Y Nathán dijo al rey: Anda, y haz todo lo que está en tu corazón, que Jehová es contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 7, 4, 'Y aconteció aquella noche, que fué palabra de Jehová á Nathán, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 7, 5, 'Ve y di á mi siervo David: Así ha dicho Jehová: ¿Tú me has de edificar casa en que yo more?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 7, 6, 'Ciertamente no he habitado en casas desde el día que saqué á los hijos de Israel de Egipto hasta hoy, sino que anduve en tienda y en tabernáculo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 7, 7, 'Y en todo cuanto he andado con todos los hijos de Israel, ¿he hablado palabra en alguna de las tribus de Israel, á quien haya mandado que apaciente mi pueblo de Israel, para decir: ¿Por qué no me habéis edificado casa de cedros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 7, 8, 'Ahora pues, dirás así á mi siervo David: Así ha dicho Jehová de los ejércitos: Yo te tomé de la majada, de detrás de las ovejas, para que fueses príncipe sobre mi pueblo, sobre Israel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 7, 9, 'Y he sido contigo en todo cuanto has andado, y delante de ti he talado todos tus enemigos, y te he hecho nombre grande, como el nombre de los grandes que son en la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 7, 10, 'Además yo fijaré lugar á mi pueblo Israel; yo lo plantaré, para que habite en su lugar, y nunca más sea removido, ni los inicuos le aflijan más, como antes,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 7, 11, 'Desde el día que puse jueces sobre mi pueblo Israel; y yo te daré descanso de todos tus enemigos. Asimimso Jehová te hace saber, que él te quiere hacer casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 7, 12, 'Y cuando tus días fueren cumplidos, y durmieres con tus padres, yo estableceré tu simiente después de ti, la cual procederá de tus entrañas, y aseguraré su reino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 7, 13, 'El edificará casa á mi nombre, y yo afirmaré para siempre el trono de su reino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 7, 14, 'Yo le seré á él padre, y él me será á mí hijo. Y si él hiciere mal, yo le castigaré con vara de hombres, y con azotes de hijos de hombres;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 7, 15, 'Empero mi misericordia no se apartaré de él, como la aparté de Saúl, al cual quité de delante de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 7, 16, 'Y será afirmada tu casa y tu reino para siempre delante de tu rostro; y tu trono será estable eternalmente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 7, 17, 'Conforme á todas estas palabras, y conforme á toda esta visión, así habló Nathán á David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 7, 18, 'Y entró el rey David, y púsose delante de Jehová, y dijo: Señor Jehová, ¿Quién soy yo, y qué es mi casa, para que tú me traigas hasta aquí?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 7, 19, 'Y aun te ha parecido poco esto, Señor Jehová, pues que también has hablado de la casa de tu siervo en lo por venir. ¿Es ése el modo de obrar del hombre, Señor Jehová?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 7, 20, '¿Y qué más puede añadir David hablando contigo? Tú pues conoces tu siervo, Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 7, 21, 'Todas estas grandezas has obrado por tu palabra y conforme á tu corazón, haciéndolas saber á tu siervo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 7, 22, 'Por tanto tú te has engrandecido, Jehová Dios: por cuanto no hay como tú, ni hay Dios fuera de ti, conforme á todo lo que hemos oído con nuestros oídos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 7, 23, '¿Y quién como tu pueblo, como Israel, en la tierra? una gente por amor de la cual Dios fuese á redim��rsela por pueblo, y le pusiese nombre, é hiciese por vosotros, oh Israel, grandes y espantosas obras en tu tierra, por amor de tu pueblo, oh Dios, que tú redimiste de Egipto, de las gentes y de sus dioses?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 7, 24, 'Porque tú te has confirmado á tu pueblo Israel por pueblo tuyo para siempre: y tú, oh Jehová, fuiste á ellos por Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 7, 25, 'Ahora pues, Jehová Dios, la palabra que has hablado sobre tu siervo y sobre su casa, despiértala para siempre, y haz conforme á lo que has dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 7, 26, 'Que sea engrandecido tu nombre para siempre, y dígase: Jehová de los ejércitos es Dios sobre Israel; y que la casa de tu siervo David sea firme delante de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 7, 27, 'Porque tú, Jehová de los ejércitos, Dios de Israel, revelaste al oído de tu siervo, diciendo: Yo te edificaré casa. Por esto tu siervo ha hallado en su corazón para hacer delante de ti esta súplica.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 7, 28, 'Ahora pues, Jehová Dios, tú eres Dios, y tus palabras serán firmes, ya que has dicho á tu siervo este bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 7, 29, 'Tenlo pues ahora á bien, y bendice la casa de tu siervo, para que perpetuamente permanezca delante de ti: pues que tú, Jehová Dios, lo has dicho, y con tu bendición será bendita la casa de tu siervo para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 8, 1, 'DESPUÉS de esto aconteció, que David hirió á los Filisteos, y los humilló: y tomó David á Methegamma de mano de los Filisteos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 8, 2, 'Hirió también á los de Moab, y midiólos con cordel, haciéndolos echar por tierra; y midió con dos cordeles para muerte, y un cordel entero para vida; y fueron los Moabitas siervos debajo de tributo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 8, 3, 'Asimismo hirió David á Hadad-ezer hijo de Rehob, rey de Soba, yendo él á extender su término hasta el río de Eufrates.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 8, 4, 'Y tomó David de ellos mil y setecientos de á caballo, y veinte mil hombres de á pie; y desjarretó David los caballos de todos los carros, excepto cien carros de ellos que dejó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 8, 5, 'Y vinieron los Siros de Damasco á dar ayuda á Hadad-ezer rey de Soba; y David hirió de los Siros veinte y dos mil hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 8, 6, 'Puso luego David guarnición en Siria la de Damasco, y fueron los Siros siervos de David sujetos á tributo. Y Jehová guardó á David donde quiere que fué.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 8, 7, 'Y tomó David los escudos de oro que traían los siervos de Hadad-ezer, y llevólos á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 8, 8, 'Asimismo de Beta y de Beeroth, ciudades de Hadad-ezer, tomó el rey David gran copia de metal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 8, 9, 'Entonces oyendo Toi, rey de Hamath, que David había herido todo el ejército de Hadad-ezer,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 8, 10, 'Envió Toi á Joram su hijo al rey David, á saludarle pacíficamente y á bendecirle, porque había peleado con Hadad-ezer y lo había vencido: porque Toi era enemigo de Hadad-ezer. Y Joram llevaba en su mano vasos de plata, y vasos de oro, y de metal;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 8, 11, 'Los cuales el rey David dedicó á Jehová, con la plata y el oro que tenía dedicado de todas las naciones que había sometido:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 8, 12, 'De los Siros, de los Moabitas, de los Ammonitas, de los Filisteos, de los Amalecitas, y del despojo de Hadad-ezer hijo de Rehob, rey de Soba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 8, 13, 'Y ganó David fama cuando, volviendo de la rota de los Siros, hirió diez y ocho mil hombres en el valle de la sal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 8, 14, 'Y puso guarnición en Edom, por toda Edom puso guarnición; y todos los Idumeos fueron siervos de David. Y Jehová guardó á David por donde quiera que fué.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 8, 15, 'Y reinó David sobre todo Israel; y hacía David derecho y justicia á todo su pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 8, 16, 'Y Joab hijo de Sarvia era general de su ejército; y Josaphat hijo de Ahilud, canciller;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 8, 17, 'Y Sadoc hijo de Ahitud, y Ahimelech hijo de Abiathar, eran sacerdotes; y Seraía era escriba;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 8, 18, 'Y Benahía hijo de Joiada, era sobre los Ceretheos y Peletheos; y los hijos de David eran los príncipes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 9, 1, 'Y DIJO David: ¿Ha quedado alguno de la casa de Saúl, á quien haga yo misericordia por amor de Jonathán?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 9, 2, 'Y había un siervo de la casa de Saúl, que se llamaba Siba, al cual como llamaron que viniese á David, el rey le dijo: ¿Eres tú Siba? Y él respondió: Tu siervo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 9, 3, 'Y el rey dijo: ¿No ha quedado nadie de la casa de Saúl, á quien haga yo misericordia de Dios? Y Siba respondió al rey: Aun ha quedado un hijo de Jonathán, lisiado de los pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 9, 4, 'Entonces el rey le dijo: ¿Y ése dónde está? Y Siba respondió al rey: He aquí, está en casa de Machîr hijo de Amiel, en Lodebar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 9, 5, 'Y envió el rey David, y tomólo de casa de Machîr hijo de Amiel, de Lodebar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 9, 6, 'Y venido Mephi-boseth, hijo de Jonathán hijo de Saúl, á David, postróse sobre su rostro, é hizo reverencia. Y dijo David: Mephi-boseth. Y él respondió: He aquí tu siervo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 9, 7, 'Y díjole David: No tengas temor, porque yo á la verdad haré contigo misericordia por amor de Jonathán tu padre, y te haré volver todas las tierras de Saúl tu padre; y tú comerás siempre pan á mi mesa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 9, 8, 'Y él inclinándose, dijo: ¿Quién es tu siervo, para que mires á un perro muerto como yo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 9, 9, 'Entonces el rey llamó á Siba, siervo de Saúl, y díjole: Todo lo que fué de Saúl y de toda su casa, yo lo he dado al hijo de tu señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 9, 10, 'Tú pues le labrarás las tierras, tú con tus hijos, y tus siervos, y encerrarás los frutos, para que el hijo de tu Señor tenga con qué mantenerse; y Mephi-boseth el hijo de tu señor tenga con qué mantenerse; y Mephi-boseth el hijo de tu señor comerá siempre pan á mi mesa. Y tenía Siba quince hijos y veinte siervos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 9, 11, 'Y respondió Siba al rey: Conforme á todo lo que ha mandado mi Señor el rey á su siervo, así lo hará tu siervo. Mephi-boseth, dijo el rey, comerá á mi mesa, como uno de los hijos del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 9, 12, 'Y tenía Mephi-boseth un hijo pequeño, que se llamaba Michâ. Y toda la familia de la casa de Siba eran siervos de Mephi-boseth.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 9, 13, 'Y moraba Mephi-boseth en Jerusalem, porque comía siempre á la mesa del rey; y era cojo de ambos pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 10, 1, 'DESPUÉS de esto aconteció, que murió el rey de los hijos de Ammón: y reinó en lugar suyo Hanún su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 10, 2, 'Y dijo David: Yo haré misericordia con Hanún hijo de Naas, como su padre la hizo conmigo. Y envió David sus siervos á consolarlo por su padre. Mas llegados los siervos de David á la tierra de los hijos de Ammón,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 10, 3, 'Los príncipes de los hijos de Ammón dijeron á Hanún su señor: ¿Te parece que por honrar David á tu padre te ha enviado consoladores? ¿no ha enviado David sus siervos á ti por reconocer é inspeccionar la ciudad, para destruirla?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 10, 4, 'Entonces Hanún tomó los siervos de David, y rapóles la mitad de la barba, y cortóles los vestidos por la mitad hasta las nalgas, y despachólos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 10, 5, 'Lo cual como fué hecho saber á David, envió á encontrarles, porque ellos estaban en extremo avergonzados; y el rey hizo decir les: Estaos en Jericó hasta que os vuelva á nacer la barba, y entonces regresaréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 10, 6, 'Y viendo los hijos de Ammón que se habían hecho odiosos á David, enviaron los hijos de Ammón y tomaron á sueldo á los Siros de la casa de Rehob, y á los Siros de Soba, veinte mil hombres de á pie: y del rey de Maaca mil hombres, y de Is-tob doce mil hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 10, 7, 'Lo cual como oyó David, envió á Joab con todo el ejército de los valientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 10, 8, 'Y saliendo los hijos de Ammón, ordenaron sus escuadrones á la entrada de la puerta: mas los Siros de Soba, y de Rehob, y de Is-tob, y de Maaca, estaban de por sí en le campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 10, 9, 'Viendo pues Joab que había escuadrones delante y detrás de él, entresacó de todos los escogidos de Israel, y púsose en orden contra los Siros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 10, 10, 'Entregó luego lo que quedó del pueblo en mano de Abisai su hermano, y púsolo en orden para encontrar á los Ammonitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 10, 11, 'Y dijo: Si los Siros me fueren superiores, tú me ayudarás; y si los hijos de Ammón pudieren más que tú, yo te daré ayuda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 10, 12, 'Esfuérzate, y esforcémonos por nuestro pueblo, y por las ciudades de nuestro Dios: y haga Jehová lo que bien le pareciere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 10, 13, 'Y acercóse Joab, y el pueblo que con él estaba, para pelear con los Siros; mas ellos huyeron delante de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 10, 14, 'Entonces los hijos de Ammón, viendo que los Siros habían huído, huyeron también ellos delante de Abisai, y entráronse en la ciudad. Y volvió Joab de los hijos de Ammón, y vínose á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 10, 15, 'Mas viendo los Siros que habían caído delante de Israel, tornáronse á juntar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 10, 16, 'Y envió Hadad-ezer, y sacó los Siros que estaban de la otra parte del río, los cuales vinieron á Helam, llevando por jefe á Sobach general del ejército de Hadad-ezer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 10, 17, 'Y como fué dado aviso á David, juntó á todo Israel, y pasando el Jordán vino á Helam: y los Siros se pusieron en orden contra David, y pelearon con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 10, 18, 'Mas los Siros huyeron delante de Israel: é hirió David de los Siros la gente de setecientos carros, y cuarenta mil hombres de á caballo: hirió también á Sobach general del ejército, y murió allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 10, 19, 'Viendo pues todos los reyes que asistían á Hadad-ezer, como habían ellos sido derrotados delante de Israel, hicieron paz con Israel, y sirviéronle; y de allí adelante temieron los Siros de socorrer á los hijos de Ammón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 11, 1, 'Y ACONTECIO á la vuelta de un año, en el tiempo que salen los reyes á la guerra, que David envió á Joab, y á sus siervos con él, y á todo Israel; y destruyeron á los Ammonitas, y pusieron cerco á Rabba: mas David se quedó en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 11, 2, 'Y acaeció que levantándose David de su cama á la hora de la tarde, paseábase por el terrado de la casa real, cuando vió desde el terrado una mujer que se estaba lavando, la cual era muy hermosa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 11, 3, 'Y envió David á preguntar por aquella mujer, y dijéronle: Aquella es Bath-sheba hija de Eliam, mujer de Uría Hetheo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 11, 4, 'Y envió David mensajeros, y tomóla: y así que hubo entrado á él, él durmió con ella. Purificóse luego ella de su inmundicia, y se volvió á su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 11, 5, 'Y concibió la mujer, y enviólo á hacer saber á David, diciendo: Yo estoy embarazada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 11, 6, 'Entonces David envió á decir á Joab: Envíame á Uría Hetheo. Y enviólo Joab á David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 11, 7, 'Y como Uría vino á él, preguntóle David por la salud de Joab, y por la salud del pueblo, y asimismo de la guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 11, 8, 'Después dijo David á Uría: Desciende á tu casa, y lava tus pies. Y saliendo Uría de casa del rey, vino tras de él comida real.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 11, 9, 'Mas Uría durmió á la puerta de la casa del rey con todos los siervos de su señor, y no descendió á su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 11, 10, 'E hicieron saber esto á David, diciendo: Uría no ha descendido á su casa. Y dijo David á Uría: ¿No has venido de camino? ¿por qué pues no descendiste á tu casa?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 11, 11, 'Y Uría respondió á David: El arca, é Israel y Judá, están debajo de tiendas; y mi señor Joab, y los siervos de mi señor sobre la haz del campo: ¿y había yo de entrar en mi casa para comer y beber, y á dormir con mi mujer? Por vida tuya, y por vida de tu alma, que yo no haré tal cosa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 11, 12, 'Y David dijo á Uría: Estáte aquí aún hoy, y mañana te despacharé. Y quedóse Uría en Jerusalem aquel día y el siguiente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 11, 13, 'Y David lo convidó, é hízole comer y beber delante de sí, hasta embriagarlo. Y él salió á la tarde á dormir en su cama con los siervos de su señor; mas no descendió á su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 11, 14, 'Venida la mañana, escribió David á Joab una carta, la cual envió por mano de Uría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 11, 15, 'Y escribió en la carta, diciendo: Poned á Uría delante de la fuerza de la batalla, y desamparadle, para que sea herido y muera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 11, 16, 'Así fué que cuando Joab cercó la ciudad, puso á Uría en el lugar donde sabía que estaban los hombres más valientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 11, 17, 'Y saliendo luego los de la ciudad, pelearon con Joab, y cayeron algunos del pueblo de los siervos de David; y murió también Uría Hetheo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 11, 18, 'Entonces envió Joab, é hizo saber á David todos los negocios de la guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 11, 19, 'Y mandó al mensajero, diciendo: Cuando acabares de contar al rey todos los negocios de la guerra,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 11, 20, 'Si el rey comenzare á enojarse, y te dijere: ¿Por qué os acercasteis á la ciudad peleando? ¿no sabíais lo que suelen arrojar del muro?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 11, 21, '¿Quién hirió á Abimelech hjo de Jerobaal? ¿no echó una mujer del muro un pedazo de una rueda de molino, y murió en Thebes? ¿por qué os llegasteis al muro?: entonces tú le dirás: También tu siervo Uría Hetheo es muerto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 11, 22, 'Y fué el mensajero, y llegando, contó á David todas las cosas á que Joab le había enviado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 11, 23, 'Y dijo el mensajero á David: Prevalecieron contra nosotros los hombres, que salieron á nosotros al campo, bien que nosotros les hicimos retroceder hasta la entrada de la puerta;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 11, 24, 'Pero los flecheros tiraron contra tus siervos desde el muro, y murieron algunos de los siervos del rey; y murió también tu siervo Uría Hetheo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 11, 25, 'Y David dijo al mensajero: Dirás así á Joab: No tengas pesar de esto, que de igual y semejante manera suele consumir la espada: esfuerza la batalla contra la ciudad, hasta que la rindas. Y tú aliéntale.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 11, 26, 'Y oyendo la mujer de Uría que su marido Uría era muerto, hizo duelo por su marido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 11, 27, 'Y pasado el luto, envió David y recogióla á su casa: y fué ella su mujer, y parióle un hijo. Mas esto que David había hecho, fué desagradable á los ojos de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 1, 'Y ENVIO Jehová á Nathán á David, el cual viniendo á él, díjole: Había dos hombres en una ciudad, el uno rico, y el otro pobre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 2, 'El rico tenía numerosas ovejas y vacas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 3, 'Mas el pobre no tenía más que una sola cordera, que él había comprado y criado, y que había crecido con él y con sus hijos juntamente, comiendo de su bocado, y bebiendo de su vaso, y durmiendo en su seno: y teníala como á una hija.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 4, 'Y vino uno de camino al hombre rico; y él no quiso tomar de sus ovejas y de sus vacas, para guisar al caminante que le había venido, sino que tomó la oveja de aquel hombre pobre, y aderezóla para aquél que le había venido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 5, 'Entonces se encendió el furor de David en gran manera contra aquel hombre, y dijo á Nathán: Vive Jehová, que el que tal hizo es digno de muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 6, 'Y que él debe pagar la cordera con cuatro tantos, porque hizo esta tal cosa, y no tuvo misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 7, 'Entonces dijo Nathán á David: Tú eres aquel hombre. Así ha dicho Jehová, Dios de Israel: Yo te ungí por rey sobre Israel, y te libré de la mano de Saúl;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 8, 'Yo te dí la casa de tu señor, y las mujeres de tu señor en tu seno: demás de esto te dí la casa de Israel y de Judá; y si esto es poco, yo te añadiré tales y tales cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 9, '¿Por qué pues tuviste en poco la palabra de Jehová, haciendo lo malo delante de sus ojos? A Uría Hetheo heriste á cuchillo, y tomaste por tu mujer á su mujer, y á él mataste con el cuchillo de los hijos de Ammón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 10, 'Por lo cual ahora no se apartará jamás de tu casa la espada; por cuanto me menospreciaste, y tomaste la mujer de Uría Hetheo para que fuese tu mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 11, 'Así ha dicho Jehová: He aquí yo levantaré sobre ti el mal de tu misma casa, y tomaré tus mujeres delante de tus ojos, y las daré á tu prójimo, el cual yacerá con tus mujeres á la vista de este sol.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 12, 'Porque tú lo hiciste en secreto; mas yo haré esto delante de todo Israel, y delante del sol.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 13, 'Entonces dijo David á Nathán: Pequé contra Jehová. Y Nathán dijo á David: También Jehová ha remitido tu pecado: no morirás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 14, 'Mas por cuanto con este negocio hiciste blasfemar á los enemigos de Jehová, el hijo que te ha nacido morirá ciertamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 15, 'Y Nathán se volvió á su casa. Y Jehová hirió al niño que la mujer de Uría había parido á David, y enfermó gravemente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 16, 'Entonces rogó David á Dios por el niño; y ayunó David, recogióse, y pasó la noche acostado en tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 17, 'Y levantándose los ancianos de su casa fueron á él para hacerlo levantar de tierra; mas él no quiso, ni comió con ellos pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 18, 'Y al séptimo día murió el niño; pero sus siervos no osaban hacerle saber que el niño era muerto, diciendo entre sí: Cuando el niño aun vivía, le hablábamos, y no quería oir nuestra voz: ¿pues cuánto más mal le hará, si le dijéremos que el niño es muerto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 19, 'Mas David viendo á sus siervos hablar entre sí, entendió que el niño era muerto; por lo que dijo David á sus siervos: ¿Es muerto el niño? Y ellos respondieron: Muerto es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 20, 'Entonces David se levantó de tierra, y lavóse y ungióse, y mudó sus ropas, y entró á la casa de Jehová, y adoró. Y después vino á su casa, y demandó, y pusiéronle pan, y comió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 21, 'Y dijéronle sus siervos: ¿Qué es esto que has hecho? Por el niño, viviendo aún, ayunabas y llorabas; y él muerto, levantástete y comiste pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 22, 'Y él respondió: Viviendo aún el niño, yo ayunaba y lloraba, diciendo: ¿Quién sabe si Dios tendrá compasión de mí, por manera que viva el niño?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 23, 'Mas ahora que ya es muerto, ¿para qué tengo de ayunar? ¿podré yo hacerle volver? Yo voy á él, mas él no volverá á mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 24, 'Y consoló David á Bath-sheba su mujer, y entrando á ella, durmió con ella; y parió un hijo, y llamó su nombre Salomón, al cual amó Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 25, 'Que envió por mano de Nathán profeta, y llamó su nombre Jedidiah, á causa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 26, 'Y Joab peleaba contra Rabba de los hijos de Ammón, y tomó la ciudad real.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 27, 'Entonces envió Joab mensajeros á David, diciendo: Yo he peleado contra Rabba, y he tomado la ciudad de las aguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 28, 'Junta pues ahora el pueblo que queda, y asienta campo contra la ciudad, y tómala; porque tomando yo la ciudad, no se llame de mi nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 29, 'Y juntando David todo el pueblo fué contra Rabba, y combatióla, y tomóla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 30, 'Y tomó la corona de su rey de su cabeza, la cual pesaba un talento de oro, y tenía piedras preciosas; y fué puesta sobre la cabeza de David. Y trajo muy grande despojo de la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 12, 31, 'Sacó además el pueblo que estaba en ella, y púsolo debajo de sierras, y de trillos de hierro, y de hachas de hierro; é hízolos pasar por hornos de ladrillos: y lo mismo hizo á todas las ciudades de los hijos de Ammón. Volvióse luego David con todo el pueblo á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 1, 'ACONTECIO después de esto, que teniendo Absalom hijo de David una hermana hermosa que se llamaba Thamar, enamoróse de ella Amnón hijo de David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 2, 'Y estaba Amnón angustiado hasta enfermar, por Thamar su hermana: porque por ser ella virgen, parecía á Amnón que sería cosa dificultosa hacerle algo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 3, 'Y Amnón tenía un amigo que se llamaba Jonadab, hijo de Simea, hermano de David: y era Jonadab hombre muy astuto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 4, 'Y éste le dijo: Hijo del rey, ¿por qué de día en día vas así enflaqueciendo? ¿no me lo descubrirás á mí? Y Amnón le respondió: Yo amo á Thamar la hermana de Absalom mi hermano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 5, 'Y Jonadab le dijo: Acuéstate en tu cama, y finge que estás enfermo; y cuando tu padre viniere á visitarte, dile: Ruégote que venga mi hermana Thamar, para que me conforte con alguna comida, y aderece delante de mí alguna vianda, para que viendo yo, la coma de su mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 6, 'Acostóse pues Amnón, y fingió que estaba enfermo, y vino el rey: á visitarle: y dijo Amnón al rey: Yo te ruego que venga mi hermana Thamar, y haga delante de mí dos hojuelas, que coma yo de su mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 7, 'Y David envió á Thamar á su casa, diciendo: Ve ahora á casa de Amnón tu hermano, y hazle de comer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 8, 'Y fué Thamar á casa de su hermano Amnón, el cual estaba acostado; y tomó harina, y amasó é hizo hojuelas delante de él, y aderezólas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 9, 'Tomó luego la sartén, y sacólas delante de él: mas él no quiso comer. Y dijo Amnón: Echad fuera de aquí á todos. Y todos se salieron de allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 10, 'Entonces Amnón dijo á Thamar: Trae la comida á la alcoba, para que yo coma de tu mano. Y tomando Thamar las hojuelas que había aderezado, llevólas á su hermano Amnón á la alcoba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 11, 'Y como ella se las puso delante para que comiese, él trabó de ella, diciéndole: Ven, hermana mía acuéstate conmigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 12, 'Ella entonces le respondió: No, hermano mío, no me hagas fuerza; porque no se ha de hacer así con Israel. No hagas tal desacierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 13, 'Porque, ¿dónde iría yo con mi deshonra? Y aun tú serías estimado como uno de los perversos en Israel. Ruégote pues ahora que hables al rey, que no me negará á ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 14, 'Mas él no la quiso oir; antes pudiendo más que ella la forzó, y echóse con ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 15, 'Aborrecióla luego Amnón de tan grande aborrecimiento, que el odio con que la aborreció fué mayor que el amor con que la había amado. Y díjole Amnón: Levántate y vete.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 16, 'Y ella le respondió: No es razón; mayor mal es éste de echarme, que el que me has hecho. Mas él no la quiso oir:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 17, 'Antes llamando su criado que le servía dijo: Echame ésta allá fuera, y tras ella cierra la puerta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 18, 'Y tenía ella sobre sí una ropa de colores, traje que las hijas vírgenes de los reyes vestían. Echóla pues fuera su criado, y cerró la puerta tras ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 19, 'Entonces Thamar tomó ceniza, y esparcióla sobre su cabeza, y rasgó su ropa de colores de que estaba vestida, y puestas sus manos sobre su cabeza, fuése gritando.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 20, 'Y díjole su hermano Absalom: ¿Ha estado contigo tu hermano Amnón? Pues calla ahora, hermana mía: tu hermano es; no pongas tu corazón en este negocio. Y quedóse Thamar desconsolada en casa de Absalom su hermano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 21, 'Y luego que el rey David oyó todo esto, fué muy enojado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 22, 'Mas Absalom no habló con Amnón ni malo ni bueno, bien que Absalom aborrecía á Amnón, porque había forzado á Thamar su hermana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 23, 'Y aconteció pasados dos años, que Absalom tenía esquiladores en Bala-hasor, que está junto á Ephraim; y convidó Absalom á todos los hijos del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 24, 'Y vino Absalom al rey, y díjole: He aquí, tu siervo tiene ahora esquiladores: yo ruego que venga el rey y sus siervos con tu siervo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 25, 'Y respondió el rey á Absalom: No, hijo mío, no vamos todos, porque no te hagamos costa. Y aunque porfió con él, no quiso ir, mas bendíjolo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 26, 'Entonces dijo Absalom: Si no, ruégote que venga con nosotros Amnón mi hermano. Y el rey le respondió: ¿Para qué ha de ir contigo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 27, 'Y como Absalom lo importunase, dejó ir con él á Amnón y á todos los hijos del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 28, 'Y había Absalom dado orden á sus criados, diciendo: Ahora bien, mirad cuando el corazón de Amnón estará alegre del vino, y en diciéndoos yo: Herid á Amnón, entonces matadle, y no temáis; que yo os lo he mandado. Esforzaos pues, y sed valientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 29, 'Y los criados de Absalom hicieron con Amnón como Absalom lo había mandado. Levantáronse luego todos los hijos del rey, y subieron todos en sus mulos, y huyeron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 30, 'Y estando aún ellos en el camino, llegó á David el rumor que decía: Absalom ha muerto á todos los hijos del rey, que ninguno de ellos ha quedado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 31, 'Entonces levantándose David, rasgó sus vestidos, y echóse en tierra, y todos sus criados, rasgados sus vestidos, estaban delante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 32, 'Y Jonadab, hijo de Simea hermano de David, habló y dijo: No diga mi señor que han muerto á todos los jóvenes hijos del rey, que sólo Amnón es muerto: porque en boca de Absalom estaba puesto desde el día que Amnón forzó á Thamar su hermana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 33, 'Por tanto, ahora no ponga mi señor el rey en su corazón esa voz que dice: Todos los hijos del rey son muertos: porque sólo Amnón es muerto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 34, 'Absalom huyó luego. Entre tanto, alzando sus ojos el mozo que estaba en atalaya, miró, y he aquí mucho pueblo que venía á sus espaldas por el camino de hacia el monte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 35, 'Y dijo Jonadab al rey: He allí los hijos del rey que vienen: es así como tu siervo ha dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 36, 'Y como él acabó de hablar, he aquí los hijos del rey que vinieron, y alzando su voz lloraron. Y también el mismo rey y todos sus siervos lloraron con muy grandes lamentos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 37, 'Mas Absalom huyó, y fuése á Talmai hijo de Amiud, rey de Gessur. Y David lloraba por su hijo todos los días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 38, 'Y después que Absalom huyó y se fué á Gessur, estuvo allá tres años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 13, 39, 'Y el rey David deseó ver á Absalom: porque ya estaba consolado acerca de Amnón que era muerto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 1, 'Y CONOCIENDO Joab hijo de Sarvia, que el corazón del rey estaba por Absalom,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 2, 'Envió Joab á Tecoa, y tomó de allá una mujer astuta, y díjole: Yo te ruego que te enlutes, y te vistas de ropas de luto, y no te unjas con óleo, antes sé como mujer que ha mucho tiempo que trae luto por algún muerto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 3, 'Y entrando al rey, habla con él de esta manera. Y puso Joab las palabras en su boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 4, 'Entró pues aquella mujer de Tecoa al rey, y postrándose en tierra sobre su rostro hizo reverencia, y dijo: Oh rey, salva.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 5, 'Y el rey dijo: ¿Qué tienes? Y ella respondió: Yo á la verdad soy una mujer viuda y mi marido es muerto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 6, 'Y tu sierva tenía dos hijos y los dos riñeron en el campo; y no habiendo quien los despartiese, hirió el uno al otro, y matólo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 7, 'Y he aquí toda la parentela se ha levantado contra tu sierva, diciendo: Entrega al que mató á su hermano, para que le hagamos morir por la vida de su hermano á quien él mató, y quitemos también el heredero. Así apagarán el ascua que me ha quedado, no dejando á mi marido nombre ni reliquia sobre la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 8, 'Entonces el rey dijo á la mujer: Vete á tu casa, que yo mandaré acerca de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 9, 'Y la mujer de Tecoa dijo al rey: Rey señor mío, la maldad sea sobre mí y sobre la casa de mi padre; mas el rey y su trono sin culpa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 10, 'Y el rey dijo: Al que hablare contra tí, tráelo á mí, que no te tocará más.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 11, 'Dijo ella entonces: Ruégote, oh rey, que te acuerdes de Jehová tu Dios, que no dejes á los cercanos de la sangre aumentar el daño con destruir á mi hijo. Y él respondió: Vive Jehová, que no caerá ni un cabello de la cabeza de tu hijo en tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 12, 'Y la mujer dijo: Ruégote que hable tu criada una palabra á mi señor el rey. Y él dijo: Habla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 13, 'Entonces la mujer dijo: ¿Por qué pues piensas tú otro tanto contra el pueblo de Dios? que hablando el rey esta palabra, es como culpado, por cuanto el rey no hace volver á su fugitivo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 14, 'Porque de cierto morimos, y somos como aguas derramadas por tierra, que no pueden volver á recogerse: ni Dios quita la vida, sino que arbitra medio para que su desviado no sea de él excluido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 15, 'Y que yo he venido ahora para decir esto al rey mi señor, es porque el pueblo me ha puesto miedo. Mas tu sierva dijo: Hablaré ahora al rey: quizá él hará lo que su sierva diga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 16, 'Pues el rey oirá, para librar á su sierva de mano del hombre que me quiere raer á mí, y á mi hijo juntamente, de la heredad de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 17, 'Tu sierva pues dice: Que sea ahora la respuesta de mi señor el rey para descanso; pues que mi señor el rey es como un ángel de Dios para escuchar lo bueno y lo malo. Así Jehová tu Dios sea contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 18, 'Entonces él respondió, y dijo á la mujer: Yo te ruego que no me encubras nada de lo que yo te preguntare. Y la mujer dijo: Hable mi señor el rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 19, 'Y el rey dijo: ¿No ha sido la mano de Joab contigo en todas estas cosas? Y la mujer respondió y dijo: Vive tu alma, rey señor mío, que no hay que apartarse á derecha ni á izquierda de todo lo que mi señor el rey ha hablado: porque tu siervo Joab, él me mandó, y él puso en boca de tu sierva todas estas palabras;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 20, 'Y que trocara la forma de las palabras, Joab tu siervo lo ha hecho: mas mi señor es sabio, conforme á la sabiduría de un ángel de Dios, para conocer lo que hay en la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 21, 'Entonces el rey dijo á Joab: He aquí yo hago esto: ve, y haz volver al mozo Absalom.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 22, 'Y Joab se postró en tierra sobre su rostro, é hizo reverencia, y después que bendijo al rey, dijo: Hoy ha entendido tu siervo que he hallado gracia en tus ojos, rey señor mío; pues que ha hecho el rey lo que su siervo ha dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 23, 'Levantóse luego Joab, y fué á Gessur, y volvió á Absalom á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 24, 'Mas el rey dijo: Váyase á su casa, y no vea mi rostro. Y volvióse Absalom á su casa, y no vió el rostro del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 25, 'Y no había en todo Israel hombre tan hermoso como Absalom, de alabar en gran manera: desde la planta de su pie hasta la mollera no había en él defecto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 26, 'Y cuando se cortaba el cabello, (lo cual hacía al fin de cada año, pues le causaba molestia, y por eso se lo cortaba,) pesaba el cabello de su cabeza doscientos siclos de peso real.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 27, 'Y Naciéronle á Absalom tres hijos, y una hija que se llamó Thamar, la cual era hermosa de ver.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 28, 'Y estuvo Absalom por espacio de dos años en Jerusalem, y no vió la cara del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 29, 'Y mandó Absalom por Joab, para enviarlo al rey; mas no quiso venir á él; ni aunque envió por segunda vez, quiso él venir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 30, 'Entonces dijo á sus siervos: Bien sabéis las tierras de Joab junto á mi lugar, donde tiene sus cebadas; id, y pegadles fuego; y los siervos de Absalom pegaron fuego á las tierras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 31, 'Levantóse por tanto Joab, y vino á Absalom á su casa, y díjole: ¿Por qué han puesto fuego tus siervos á mis tierras?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 32, 'Y Absalom respondió á Joab: He aquí, yo he enviado por ti, diciendo que vinieses acá, á fin de enviarte yo al rey á que le dijeses: ¿Para qué vine de Gessur? mejor me fuera estar aún allá. Vea yo ahora la cara del rey; y si hay en mí pecado, máteme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 14, 33, 'Vino pues Joab al rey, é hízoselo saber. Entonces llamó á Absalom, el cual vino al rey, é inclinó su rostro á tierra delante del rey: y el rey besó á Absalom.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 1, 'ACONTECIO después de esto, que Absalom se hizo de carros y caballos, y cincuenta que corriesen delante de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 2, 'Y levantábase Absalom de mañana, y poníase á un lado del camino de la puerta; y á cualquiera que tenía pleito y venía al rey á juicio, Absalom le llamaba á sí, y decíale: ¿De qué ciudad eres? Y él respondía: Tu siervo es de una de las tribus de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 3, 'Entonces Absalom le decía: Mira, tus palabras son buenas y justas: mas no tienes quien te oiga por el rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 4, 'Y decía Absalom: ¡Quién me pusiera por juez en la tierra, para que viniesen á mí todos los que tienen pleito ó negocio, que yo les haría justicia!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 5, 'Y acontecía que, cuando alguno se llegaba para inclinarse á él, él extendía su mano, y lo tomaba, y lo besaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 6, 'Y de esta manera hacía con todo Israel que venía al rey á juicio: y así robaba Absalom el corazón de los de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 7, 'Y al cabo de cuarenta años aconteció que Absalom dijo al rey: Yo te ruego me permitas que vaya á Hebrón, á pagar mi voto que he prometido á Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 8, 'Porque tu siervo hizo voto cuando estaba en Gessur en Siria, diciendo: Si Jehová me volviere á Jerusalem, yo serviré á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 9, 'Y el rey dijo: Ve en paz. Y él se levantó, y se fué á Hebrón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 10, 'Empero envió Absalom espías por todas las tribus de Israel, diciendo: Cuando oyereis el sonido de la trompeta, diréis: Absalom reina en Hebrón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 11, 'Y fueron con Absalom doscientos hombres de Jerusalem por él convidados, los cuales iban en su sencillez, sin saber nada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 12, 'También envió Absalom por Achitophel Gilonita, del consejo de David, á Gilo su ciudad, mientras hacía sus sacrificios. Y la conjuración vino á ser grande, pues se iba aumentando el pueblo con Absalom.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 13, 'Y vino el aviso á David, diciendo: El corazón de todo Israel va tras Absalom.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 14, 'Entonces David dijo á todos sus siervos que estaban con él en Jerusalem: Levantaos, y huyamos, porque no podremos escapar delante de Absalom; daos priesa á partir, no sea que apresurándose él nos alcance, y arroje el mal sobre nosotros, y hiera la ciudad á filo de espada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 15, 'Y los siervos del rey dijeron al rey: He aquí, tus siervos están prestos á todo lo que nuestro señor el rey eligiere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 16, 'El rey entonces salió, con toda su familia en pos de él. Y dejó el rey diez mujeres concubinas para que guardasen la casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 17, 'Salió pues el rey con todo el pueblo que le seguía, y paráronse en un lugar distante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 18, 'Y todos sus siervos pasaban á su lado, con todos los Ceretheos y Peletheos; y todos los Getheos, seiscientos hombres que habían venido á pie desde Gath, iban delante del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 19, 'Y dijo el rey á Ittai Getheo: ¿Para qué vienes tú también con nosotros? vuélvete y quédate con el rey; porque tú eres extranjero, y desterrado también de tu lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 20, '¿Ayer viniste, y téngote de hacer hoy que mudes lugar para ir con nosotros? Yo voy como voy: tú vuélvete, y haz volver á tus hermanos: en ti haya misericordia y verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 21, 'Y respondió Ittai al rey, diciendo: Vive Dios, y vive mi señor el rey, que, ó para muerte ó para vida, donde mi señor el rey estuviere, allí estará también tu siervo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 22, 'Entonces David dijo á Ittai: Ven pues, y pasa. Y pasó Ittai Getheo, y todos sus hombres, y toda su familia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 23, 'Y todo el país lloró en alta voz; pasó luego toda la gente el torrente de Cedrón; asimismo pasó el rey, y todo el pueblo pasó, al camino que va al desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 24, 'Y he aquí, también iba Sadoc, y con él todos los Levitas que llevaban el arca del pacto de Dios; y asentaron el arca del pacto de Dios. Y subió Abiathar después que hubo acabado de salir de la ciudad todo el pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 25, 'Pero dijo el rey á Sadoc: Vuelve el arca de Dios á la ciudad; que si yo hallare gracia en los ojos de Jehová, él me volverá, y me hará ver á ella y á su tabernáculo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 26, 'Y si dijere: No me agradas: aquí estoy, haga de mí lo que bien le pareciere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 27, 'Dijo aún el rey á Sadoc sacerdote: ¿No eres tú el vidente? Vuélvete en paz á la ciudad; y con vosotros vuestros dos hijos, tu hijo Ahimaas, y Jonathán hijo de Abiathar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 28, 'Mirad, yo me detendré en los campos del desierto, hasta que venga respuesta de vosotros que me dé aviso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 29, 'Entonces Sadoc y Abiathar volvieron el arca de Dios á Jerusalem; y estuviéronse allá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 30, 'Y David subió la cuesta de las olivas; y subió la llorando, llevando la cabeza cubierta, y los pies descalzos. También todo el pueblo que tenía consigo cubrió cada uno su cabeza, y subieron llorando así como subían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 31, 'Y dieron aviso á David, diciendo: Achitophel está entre los que conspiraron con Absalom. Entonces dijo David: Entontece ahora, oh Jehová, el consejo de Achitophel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 32, 'Y como David llegó á la cumbre del monte para adorar allí á Dios, he aquí Husai Arachîta que le salió al encuentro, trayendo rota su ropa, y tierra sobre su cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 33, 'Y díjole David: Si pasares conmigo, serme has de carga;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 34, 'Mas si volvieres á la ciudad, y dijeres á Absalom: Rey, yo seré tu siervo; como hasta aquí he sido siervo de tu padre, así seré ahora siervo tuyo, entonces tú me disiparás el consejo de Achitophel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 35, '¿No estarán allí contigo Sadoc y Abiathar sacerdotes? Por tanto, todo lo que oyeres en la casa del rey, darás aviso de ello á Sadoc y á Abiathar sacerdotes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 36, 'Y he aquí que están con ellos sus dos hijos, Ahimaas el de Sadoc, y Jonathán el de Abiathar: por mano de ellos me enviaréis aviso de todo lo que oyereis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 15, 37, 'Así se vino Husai amigo de David á la ciudad; y Absalom entró en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 16, 1, 'Y como David pasó un poco de la cumbre del monte, he aquí Siba, el criado de Mephi-boseth, que lo salía á recibir con un par de asnos enalbardados, y sobre ellos doscientos panes, y cien hilos de pasas, y cien panes de higos secos, y un cuero de vino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 16, 2, 'Y dijo el rey á Siba: ¿Qué es esto? Y Siba respondió: Los asnos son para la familia del rey, en que suban; los panes y la pasa para los criados, que coman; y el vino, para que beban los que se cansaren en el desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 16, 3, 'Y dijo el rey: ¿Dónde está el hijo de tu señor? Y Siba respondió al rey: He aquí él se ha quedado en Jerusalem, porque ha dicho: Hoy me devolverá la casa de Israel el reino de mi padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 16, 4, 'Entonces el rey dijo á Siba: He aquí, sea tuyo todo lo que tiene Mephi-boseth. Y respondió Siba inclinándose: Rey señor mío, halle yo gracia delante de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 16, 5, 'Y vino el rey David hasta Bahurim: y he aquí, salía uno de la familia de la casa de Saúl, el cual se llamaba Semei, hijo de Gera; y salía maldiciendo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 16, 6, 'Y echando piedras contra David, y contra todos los siervos del rey David: y todo el pueblo, y todos los hombres valientes estaban á su diestra y á su siniestra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 16, 7, 'Y decía Semei, maldiciéndole: Sal, sal, varón de sangres, y hombre de Belial;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 16, 8, 'Jehová te ha dado el pago de toda la sangre de la casa de Saúl, en lugar del cual tú has reinado: mas Jehová ha entregado el reino en mano de tu hijo Absalom; y hete aquí sorprendido en tu maldad, porque eres varón de sangres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 16, 9, 'Entonces Abisai hijo de Sarvia, dijo al rey: ¿Por qué maldice este perro muerto á mi señor el rey? Yo te ruego que me dejes pasar, y quitaréle la cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 16, 10, 'Y el rey respondió: ¿Qué tengo yo con vosotros, hijos de Sarvia? El maldice así, porque Jehová le ha dicho que maldiga á David; ¿quién pues le dirá: Por qué lo haces así?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 16, 11, 'Y dijo David á Abisai y á todos sus siervos: He aquí, mi hijo que ha salido de mis entrañas, acecha á mi vida: ¿cuánto más ahora un hijo de Benjamín? Dejadle que maldiga, que Jehová se lo ha dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 16, 12, 'Quizá mirará Jehová á mi aflicción, y me dará Jehová bien por sus maldiciones de hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 16, 13, 'Y como David y los suyos iban por el camino, Semei iba por el lado del monte delante de él, andando y maldiciendo, y arrojando piedras delante de él, y esparciendo polvo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 16, 14, 'Y el rey y todo el pueblo que con él estaba, llegaron fatigados, y descansaron allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 16, 15, 'Y Absalom y todo el pueblo, los varones de Israel, entraron en Jerusalem, y con él Achitophel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 16, 16, 'Y acaeció luego, que como Husai Arachîta amigo de David hubo llegado á Absalom, díjole Husai: Viva el rey, viva el rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 16, 17, 'Y Absalom dijo á Husai: ¿Este es tu agradecimiento para con tu amigo? ¿por qué no fuiste con tu amigo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 16, 18, 'Y Husai respondió á Absalom: No: antes al que eligiere Jehová y este pueblo y todos los varones de Israel, de aquél seré yo, y con aquél quedaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 16, 19, '¿Y á quién había yo de servir? ¿no es á su hijo? Como he servido delante de tu padre, así seré delante de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 16, 20, 'Entonces dijo Absalom á Achitophel: Consultad qué haremos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 16, 21, 'Y Achitophel dijo á Absalom: Entra á las concubinas de tu padre, que él dejó para guardar la casa; y todo el pueblo de Israel oirá que te has hecho aborrecible á tu padre, y así se esforzarán las manos de todos los que están contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 16, 22, 'Entonces pusieron una tienda á Absalom sobre el terrado, y entró Absalom á las concubinas de su padre, en ojos de todo Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 16, 23, 'Y el consejo que daba Achitophel en aquellos días, era como si consultaran la palabra de Dios. Tal era el consejo de Achitophel, así con David como con Absalom.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 17, 1, 'ENTONCES Achitophel dijo á Absalom: Yo escogeré ahora doce mil hombres, y me levantaré, y seguiré á David esta noche;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 17, 2, 'Y daré sobre él cuando él estará cansado y flaco de manos: lo atemorizaré, y todo el pueblo que está con él huirá, y heriré al rey solo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 17, 3, 'Así tornaré á todo el pueblo á ti: y cuando ellos hubieren vuelto, (pues aquel hombre es el que tú quieres) todo el pueblo estará en paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 17, 4, 'Esta razón pareció bien á Absalom y á todos los ancianos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 17, 5, 'Y dijo Absalom: Llama también ahora á Husai Arachîta, para que asimismo oigamos lo que él dirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 17, 6, 'Y como Husai vino á Absalom, hablóle Absalom, diciendo: Así ha dicho Achitophel; ¿seguiremos su consejo, ó no? Di tú.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 17, 7, 'Entonces Husai dijo á Absalom: El consejo que ha dado esta vez Achitophel no es bueno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 17, 8, 'Y añadió Husai: Tú sabes que tu padre y los suyos son hombres valientes, y que están con amargura de ánimo, como la osa en el campo cuando le han quitado los hijos. Además, tu padre es hombre de guerra, y no tendrá la noche con el pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 17, 9, 'He aquí él estará ahora escondido en alguna cueva, ó en otro lugar: y si al principio cayeren algunos de los tuyos, oirálo quien lo oyere, y dirá: El pueblo que sigue á Absalom ha sido derrotado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 17, 10, 'Así aun el hombre valiente, cuyo corazón sea como corazón de león, sin duda desmayará: porque todo Israel sabe que tu padre es hombre valiente, y que los que están con él son esforzados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 17, 11, 'Aconsejo pues que todo Israel se junte á ti, desde Dan hasta Beerseba, en multitud como la arena que está á la orilla de la mar, y que tú en persona vayas á la batalla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 17, 12, 'Entonces le acometeremos en cualquier lugar que pudiere hallarse, y daremos sobre él como cuando el rocío cae sobre la tierra, y ni uno dejaremos de él, y de todos los que con él están.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 17, 13, 'Y si se recogiere en alguna ciudad, todos los de Israel traerán sogas á aquella ciudad, y la arrastraremos hasta el arroyo, que nunca más parezca piedra de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 17, 14, 'Entonces Absalom y todos los de Israel dijeron: El consejo de Husai Arachîta es mejor que el consejo de Achitophel. Porque había Jehová ordenado que el acertado consejo de Achitophel se frustara, para que Jehová hiciese venir el mal sobre Absalom.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 17, 15, 'Dijo luego Husai á Sadoc y á Abiathar sacerdotes: Así y así aconsejó Achitophel á Absalom y á los ancianos de Israel: y de esta manera aconsejé yo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 17, 16, 'Por tanto enviad inmediatemente, y dad aviso á David, diciendo: No quedes esta noche en los campos del desierto, sino pasa luego el Jordán, porque el rey no sea consumido, y todo el pueblo que con él está.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 17, 17, 'Y Jonathán y Ahimaas estaban junto á la fuente de Rogel, porque no podían ellos mostrarse viniendo á la ciudad; fué por tanto una criada, y dióles el aviso: y ellos fueron, y noticiáronlo al rey David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 17, 18, 'Empero fueron vistos por un mozo, el cual dió cuenta á Absalom: sin embargo los dos se dieron priesa á caminar, y llegaron á casa de un hombre en Bahurim, que tenía un pozo en su patio, dentro del cual se metieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 17, 19, 'Y tomando la mujer de la casa una manta, extendióla sobre la boca del pozo, y tendió sobre ella el grano trillado; y no se penetró el negocio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 17, 20, 'Llegando luego los criados de Absalom á la casa á la mujer, dijéronle: ¿Dónde están Ahimaas y Jonathán? Y la mujer les respondió: Ya han pasado el vado de las aguas. Y como ellos los buscaron y no los hallaron volviéronse á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 17, 21, 'Y después que ellos se hubieron ido, estotros salieron del pozo, y fuéronse, y dieron aviso al rey David; y dijéronle: Levantaos y daos priesa á pasar las aguas, porque Achitophel ha dado tal consejo contra vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 17, 22, 'Entonces David se levantó, y todo el pueblo que con él estaba, y pasaron el Jordán antes que amaneciese; ni siquiera faltó uno que no pasase el Jordán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 17, 23, 'Y Achitophel, viendo que no se había puesto por obra su consejo, enalbardó su asno, y levantóse, y fuése á su casa en su ciudad; y después de disponer acerca de su casa, ahorcóse y murió, y fué sepultado en el sepulcro de su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 17, 24, 'Y David llegó á Mahanaim, y Absalom pasó el Jordán con toda la gente de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 17, 25, 'Y Absalom constituyó á Amasa, sobre el ejército en lugar de Joab, el cual Amasa fué hijo de un varón de Israel llamado Itra, el cual había entrado á Abigail hija de Naas, hermana de Sarvia, madre de Joab.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 17, 26, 'Y asentó campo Israel con Absalom en tierra de Galaad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 17, 27, 'Y luego que David llegó á Mahanaim, Sobi hijo de Naas de Rabba de los hijos de Ammon, y Machîr hijo de Ammiel de Lodebar, y Barzillai Galaadita de Rogelim,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 17, 28, 'Trajeron á David y al pueblo que estaba con él, camas, y tazas, y vasijas de barro, y trigo, y cebada, y harina, y grano tostado, habas, lentejas, y garbanzos tostados,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 17, 29, 'Miel, manteca, ovejas, y quesos de vacas, para que comiesen; porque dijeron: Aquel pueblo está hambriento, y cansado, y tendrá sed en el desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 1, 'DAVID pues revistó el pueblo que tenía consigo, y puso sobre ellos tribunos y centuriones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 2, 'Y consignó la tercera parte del pueblo al mando de Joab, y otra tercera al mando de Abisai, hijo de Sarvia, hermano de Joab, y la otra tercera parte al mando de Ittai Getheo. Y dijo el rey al pueblo: Yo también saldré con vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 3, 'Mas el pueblo dijo: No saldrás; porque si nosotros huyéremos, no harán caso de nosotros; y aunque la mitad de nosotros muera, no harán caso de nosotros: mas tú ahora vales tanto como diez mil de nosotros. Será pues mejor que tú nos des ayuda desde la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 4, 'Entonces el rey les dijo: Yo haré lo que bien os pareciere. Y púsose el rey á la entrada de la puerta, mientras salía todo el pueblo de ciento en ciento y de mil en mil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 5, 'Y el rey mandó á Joab y á Abisai y á Ittai, diciendo: Tratad benignamente por amor de mí al mozo Absalom. Y todo el pueblo oyó cuando dió el rey orden acerca de Absalom á todos los capitanes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 6, 'Salió pues el pueblo al campo contra Israel, y dióse la batalla en el bosque de Ephraim;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 7, 'Y allí cayó el pueblo de Israel delante de los siervos de David, é hízose una gran matanza de veinte mil hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 8, 'Y derramándose allí el ejército por la haz de toda la tierra, fueron más los que consumió el bosque de los del pueblo, que los que consumió el cuchillo aquel día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 9, 'Y encontróse Absalom con los siervos de David: é iba Absalom sobre un mulo, y el mulo se entró debajo de un espeso y grande alcornoque, y asiósele la cabeza al alcornoque, y quedó entre el cielo y la tierra; pues el mulo en que iba pasó delante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 10, 'Y viéndolo uno, avisó á Joab, diciendo: He aquí que he visto á Absalom colgado de un alcornoque.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 11, 'Y Joab respondió al hombre que le daba la nueva: Y viéndolo tú, ¿por qué no le heriste luego allí echándole á tierra? y sobre mí, que te hubiera dado diez siclos de plata, y un talabarte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 12, 'Y el hombre dijo á Joab: Aunque me importara en mis manos mil siclos de plata, no extendiera yo mi mano contra el hijo del rey; porque nosotros lo oímos cuando el rey te mandó á ti y á Abisai y á Ittai, diciendo: Mirad que ninguno toque en el joven Absalom.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 13, 'Por otra parte, habría yo hecho traición contra mi vida (pues que al rey nada se le esconde), y tú mismo estarías en contra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 14, 'Y respondió Joab: No es razón que yo te ruegue. Y tomando tres dardos en sus manos, hincólos en el corazón de Absalom, que aun estaba vivo en medio del alcornoque.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 15, 'Cercándolo luego diez mancebos escuderos de Joab, hirieron á Absalom, y acabáronle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 16, 'Entonces Joab tocó la corneta, y el pueblo se volvió de seguir á Israel, porque Joab detuvo al pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 17, 'Tomando después á Absalom, echáronle en un gran hoyo en el bosque, y levantaron sobre él un muy grande montón de piedras; y todo Israel huyó, cada uno á sus estancias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 18, 'Y había Absalom en su vida tomado y levantádose una columna, la cual está en el valle del rey; porque había dicho: Yo no tengo hijo que conserve la memoria de mi nombre. Y llamó aquella columna de su nombre: y así se llamó el Lugar de Absalom, hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 19, 'Entonces Ahimaas hijo de Sadoc dijo: ¿Correré ahora, y daré las nuevas al rey de cómo Jehová ha defendido su causa de la mano de sus enemigos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 20, 'Y respondió Joab: Hoy no llevarás las nuevas: las llevarás otro día: no darás hoy la nueva, porque el hijo del rey es muerto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 21, 'Y Joab dijo á Cusi: Ve tú, y di al rey lo que has visto. Y Cusi hizo reverencia á Joab, y corrió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 22, 'Entonces Ahimaas hijo de Sadoc tornó á decir á Joab: Sea lo que fuere, yo correré ahora tras Cusi. Y Joab dijo: Hijo mío, ¿para qué has tú de correr, pues que no hallarás premio por las nuevas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 23, 'Mas él respondió: Sea lo que fuere, yo correré. Entonces le dijo: Corre. Corrió pues Ahimaas por el camino de la llanura, y pasó delante de Cusi.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 24, 'Estaba David á la sazón sentado entre las dos puertas; y el atalaya había ido al terrado de sobre la puerta en el muro, y alzando sus ojos, miró, y vió á uno que corría solo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 25, 'El atalaya dió luego voces, é hízolo saber al rey. Y el rey dijo: Si es solo, buenas nuevas trae. En tanto que él venía acercándose,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 26, 'Vió el atalaya otro que corría; y dió voces el atalaya al portero, diciendo: He aquí otro hombre que corre solo. Y el rey dijo: Este también es mensajero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 27, 'Y el atalaya volvió á decir: Paréceme el correr del primero como el correr de Ahimaas hijo de Sadoc. Y respondió el rey: Ese es hombre de bien, y viene con buena nueva.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 28, 'Entonces Ahimaas dijo en alta voz al rey: Paz. E inclinóse á tierra delante del rey, y dijo: Bendito sea Jehová Dios tuyo, que ha entregado á los hombres que habían levantado sus manos contra mi señor el rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 29, 'Y el rey dijo: ¿El mozo Absalom tiene paz? Y Ahimaas respondió: Vi yo un grande alboroto cuando envió Joab al siervo del rey y á mí tu siervo; mas no sé qué era.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 30, 'Y el rey dijo: Pasa, y ponte allí. Y él pasó, y paróse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 31, 'Y luego vino Cusi, y dijo: Reciba nueva mi señor el rey, que hoy Jehová ha defendido tu causa de la mano de todos los que se habían levantado contra ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 32, 'El rey entonces dijo á Cusi: ¿El mozo Absalom tiene paz? Y Cusi respondió: Como aquel mozo sean los enemigos de mi señor el rey, y todos los que se levantan contra ti para mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 18, 33, 'Entonces el rey se turbó, y subióse á la sala de la puerta, y lloró; y yendo, decía así: ¡Hijo mío Absalom, hijo mío, hijo mío Absalom! ¡Quién me diera que muriera yo en lugar de ti, Absalom, hijo mío, hijo mío!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 1, 'Y DIERON aviso á Joab: He aquí el rey llora, y hace duelo por Absalom.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 2, 'Y volvióse aquel día la victoria en luto para todo el pueblo; porque oyó decir el pueblo aquel día que el rey tenía dolor por su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 3, 'Entróse el pueblo aquel día en la ciudad escondidamente, como suele entrar á escondidas el pueblo avergonzado que ha huído de la batalla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 4, 'Mas el rey, cubierto el rostro, clamaba en alta voz: ¡Hijo mío Absalom, Absalom, hijo mío, hijo mío!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 5, 'Y entrando Joab en casa al rey, díjole: Hoy has avergonzado el rostro de todos tus siervos, que han hoy librado tu vida, y la vida de tus hijos y de tus hijas, y la vida de tus mujeres, y la vida de tus concubinas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 6, 'Amando á los que te aborrecen, y aborreciendo á los que te aman: porque hoy has declarado que nada te importan tus príncipes y siervos; pues hoy echo de ver que si Absalom viviera, bien que nosotros todos estuviéramos hoy muertos, entonces te contentaras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 7, 'Levántate pues ahora, y sal fuera, y halaga á tus siervos: porque juro por Jehová, que si no sales, ni aun uno quede contigo esta noche; y de esto te pesará más que de todos los males que te han sobrevenido desde tu mocedad hasta ahora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 8, 'Entonces se levantó el rey, y sentóse á la puerta; y fué declarado á todo el pueblo, diciendo: He aquí el rey está sentado á la puerta. Y vino todo el pueblo delante del rey; mas Israel había huído, cada uno á sus estancias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 9, 'Y todo el pueblo porfiaba en todas las tribus de Israel, diciendo: El rey nos ha librado de mano de nuestros enemigos, y él nos ha salvado de mano de los Filisteos; y ahora había huído, de la tierra por miedo de Abaslom.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 10, 'Y Absalom, á quien habíamos ungido sobre nosotros, es muerto en la batalla. ¿Por qué pues os estáis ahora quedos en orden á hacer volver al rey?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 11, 'Y el rey David envió á Sadoc y á Abiathar sacerdotes, diciendo: Hablad á los ancianos de Judá y decidles: ¿Por qué seréis vosotros los postreros en volver el rey á su casa, ya que la palabra de todo Israel ha venido al rey de volverle á su casa?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 12, 'Vosotros sois mis hermanos; mis huesos y mi carne sois: ¿por qué pues seréis vosotros los postreros en volver al rey?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 13, 'Asimismo diréis á Amasa: ¿No eres tú también hueso mío y carne mía? Así me haga Dios, y así me añada, si no fueres general del ejército delante de mí para siempre, en lugar de Joab.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 14, 'Así inclinó el corazón de todos los varones de Judá, como el de un solo hombre, para que enviasen á decir al rey: Vuelve tú, y todos tus siervos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 15, 'Volvió pues el rey, y vino hasta el Jordán. Y Judá vino á Gilgal, á recibir al rey y pasarlo el Jordán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 16, 'Y Semei hijo de Gera, hijo de Benjamín, que era de Bahurim, dióse priesa á venir con los hombres de Judá á recibir al rey David;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 17, 'Y con él venían mil hombres de Benjamín; asimismo Siba criado de la casa de Saúl, con sus quince hijos y sus veinte siervos, los cuales pasaron el Jordán delante del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 18, 'Atravesó después la barca para pasar la familia del rey, y para hacer lo que le pluguiera. Entonces Semei hijo de Gera se postró delante del rey cuando él había pasado el Jordán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 19, 'Y dijo al rey: No me impute mi señor iniquidad, ni tengas memoria de los males que tu siervo hizo el día que mi señor el rey salió de Jerusalem, para guardarlos el rey en su corazón;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 20, 'Porque yo tu siervo conozco haber pecado, y he venido hoy el primero de toda la casa de José, para descender á recibir á mi señor el rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 21, 'Y Abisai hijo de Sarvia responidió y dijo: ¿No ha de morir por esto Semei, que maldijo al ungido de Jehová?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 22, 'David entonces dijo: ¿Qué tenéis vosotros conmigo, hijos de Sarvia, que me habéis de ser hoy adversarios? ¿ha de morir hoy alguno en Israel? ¿no conozco yo que hoy soy rey sobre Israel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 23, 'Y dijo el rey á Semei: No morirás. Y el rey se lo juró.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 24, 'También Mephi-boseth hijo de Saúl descendió á recibir al rey: no había lavado sus pies, ni había cortado su barba, ni tampoco había lavado sus vestidos, desde el día que el rey salió hasta el día que vino en paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 25, 'Y luego que vino él á Jerusalem á recibir al rey, el rey le dijo: Mephi-boseth, ¿Por qué no fuiste conmigo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 26, 'Y él dijo: Rey señor mío, mi siervo me ha engañado; pues había tu siervo dicho: Enalbardaré un asno, y subiré en él, é iré al rey; porque tu siervo es cojo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 27, 'Empero él revolvió á tu siervo delante de mi señor el rey; mas mi señor el rey es como un ángel de Dios: haz pues lo que bien te pareciere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 28, 'Porque toda la casa de mi padre era digna de muerte delante de mi señor el rey, y tú pusiste á tu siervo entre los convidados de tu mesa. ¿Qué derecho pues tengo aún para quejarme más contra el rey?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 29, 'Y el rey le dijo: ¿Para qué hablas más palabras? Yo he determinado que tú y Siba partáis las tierras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 30, 'Y Mephi-boseth dijo al rey: Y aun tómelas él todas, pues que mi señor el rey ha vuelto en paz á su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 31, 'También Barzillai Galaadita descendió de Rogelim, y pasó el Jordán con el rey, para acompañarle de la otra parte del Jordán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 32, 'Y era Barzillai muy viejo, de ochenta años, el cual había dado provisión al rey cuando estaba en Mahanaim, porque era hombre muy rico.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 33, 'Y el rey dijo á Barzillai: Pasa conmigo, y yo te daré de comer conmigo en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 34, 'Mas Barzillai dijo al rey: ¿Cuántos son los días del tiempo de mi vida, para que yo suba con el rey á Jerusalem?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 35, 'Yo soy hoy día de edad de ochenta años, que ya no haré diferencia entre lo bueno y lo malo: ¿tomará gusto ahora tu siervo en lo que comiere ó bebiere? ¿oiré más la voz de los cantores y de las cantoras? ¿para qué, pues, sería aún tu siervo molesto á mi señor el rey?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 36, 'Pasará tu siervo un poco el Jordán con el rey: ¿por qué me ha de dar el rey tan grande recompensa?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 37, 'Yo te ruego que dejes volver á tu siervo, y que muera en mi ciudad, junto al sepulcro de mi padre y de mi madre. He aquí tu siervo Chimham; que pase él con mi señor el rey, y hazle lo que bien te pareciere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 38, 'Y el rey dijo: Pues pase conmigo Chimham, y yo haré con él como bien te parezca: y todo lo que tú pidieres de mí, yo lo haré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 39, 'Y todo el pueblo pasó el Jordán: y luego que el rey hubo también pasado, el rey besó á Barzillai, y bendíjolo; y él se volvió á su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 40, 'El rey entonces pasó á Gilgal, y con él pasó Chimham; y todo el pueblo de Judá, con la mitad del pueblo de Israel, pasaron al rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 41, 'Y he aquí todos los varones de Israel vinieron al rey, y le dijeron: ¿Por qué los hombres de Judá, nuestros hermanos, te han llevado, y han hecho pasar el Jordán al rey y á su familia, y á todos los varones de David con él?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 42, 'Y todos los varones de Judá respondieron á todos los de Israel: Porque el rey es nuestro pariente. Mas ¿por qué os enojáis vosotros de eso? ¿hemos nosotros comido algo del rey? ¿hemos recibido de él algún don?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 19, 43, 'Entonces respondieron los varones de Israel, y dijeron á los de Judá: Nosotros tenemos en el rey diez partes, y en el mismo David más que vosotros: ¿por qué pues nos habéis tenido en poco? ¿no hablamos nosotros primero en volver á nuestro rey? Y el razonamiento de los varones de Judá fué más fuerte que el de los varones de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 20, 1, 'Y ACAECIO estar allí un hombre perverso que se llamaba Seba, hijo de Bichri, hombre de Benjamín, el cual tocó la corneta, y dijo: No tenemos nosotros parte en David, ni heredad en el hijo de Isaí: Israel, ¡cada uno á sus estancias!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 20, 2, 'Así se fueron de en pos de David todos los hombres de Israel, y seguían á Seba hijo de Bichri: mas los de Judá fueron adheridos á su rey, desde el Jordán hasta Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 20, 3, 'Y luego que llegó David á su casa en Jerusalem, tomó el rey las diez mujeres concubinas que había dejado para guardar la casa, y púsolas en una casa en guarda, y dióles de comer: pero nunca más entró á ellas, sino que quedaron encerradas hasta que murieron en viudez de por vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 20, 4, 'Después dijo el rey á Amasa: Júntame los varones de Judá para dentro de tres días, y hállate tú aquí presente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 20, 5, 'Fué pues Amasa á juntar á Judá; pero detúvose más del tiempo que le había sido señalado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 20, 6, 'Y dijo David á Abisai: Seba hijo de Bichri nos hará ahora más mal que Absalom: toma pues tú los siervos de tu señor, y ve tras él, no sea que halle las ciudades fortificadas, y se nos vaya de delante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 20, 7, 'Entonces salieron en pos de él los hombres de Joab, y los Ceretheos y Peletheos, y todos los valientes: salieron de Jerusalem para ir tras Seba hijo de Bichri.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 20, 8, 'Y estando ellos cerca de la grande peña que está en Gabaón, salióles Amasa al encuentro. Ahora bien, la vestidura que Joab tenía sobrepuesta estábale ceñida, y sobre ella el cinto de una daga pegada á sus lomos en su vaina, de la que así como él avanzó, cayóse aquélla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 20, 9, 'Entonces Joab dijo á Amasa: ¿Tienes paz, hermano mío? Y tomó Joab con la diestra la barba de Amasa, para besarlo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 20, 10, 'Y como Amasa no se cuidó de la daga que Joab en la mano tenía, hirióle éste con ella en la quinta costilla, y derramó sus entrañas por tierra, y cayó muerto sin darle segundo golpe. Después Joab y su hermano Abisai fueron en seguimiento de Seba hijo de Bichri.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 20, 11, 'Y uno de los criados de Joab se paró junto á él, diciendo: Cualquiera que amare á Joab y á David vaya en pos de Joab.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 20, 12, 'Y Amasa se había revolcado en la sangre en mitad del camino: y viendo aquel hombre que todo el pueblo se paraba, apartó á Amasa del camino al campo, y echó sobre él una vestidura, porque veía que todos los que venían se paraban junto á él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 20, 13, 'Luego, pues, que fué apartado del camino, pasaron todos los que seguían á Joab, para ir tras Seba hijo de Bichri.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 20, 14, 'Y él pasó por todas las tribus de Israel hasta Abel y Beth-maachâ y todo Barim: y juntáronse, y siguiéronlo también.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 20, 15, 'Y vinieron y cercáronlo en Abel de Beth-maachâ, y pusieron baluarte contra la ciudad; y puesto que fué al muro, todo el pueblo que estaba con Joab trabajaba por derribar la muralla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 20, 16, 'Entonces una mujer sabia dió voces en la ciudad, diciendo: Oid, oid; ruégoos que digáis á Joab se llegue á acá, para que yo hable con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 20, 17, 'Y como él se acercó á ella, dijo la mujer: ¿Eres tú Joab? Y él respondió: Yo soy. Y ella le dijo: Oye las palabras de tu sierva. Y él respondió: Oigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 20, 18, 'Entonces tornó ella á hablar, diciendo: Antiguamente solían hablar, diciendo: Quien preguntare, pregunte en Abel: y así concluían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 20, 19, 'Yo soy de las pacíficas y fieles de Israel: y tú procuras destruir una ciudad que es madre de Israel: ¿por qué destruyes la heredad de Jehová?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 20, 20, 'Y Joab respondió, diciendo: Nunca tal, nunca tal me acontezca, que yo destruya ni deshaga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 20, 21, 'La cosa no es así: mas un hombre del monte de Ephraim, que se llama Seba hijo de Bichri, ha levantado su mano contra el rey David: entregad á ése solamente, y me iré de la ciudad. Y la mujer dijo á Joab: He aquí su cabeza te será echada desde el muro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 20, 22, 'La mujer fué luego á todo el pueblo con su sabiduría; y ellos cortaron la cabeza á Seba hijo de Bichri, y echáronla á Joab. Y él tocó la corneta, y esparciéronse de la ciudad, cada uno á su estancia. Y Joab se volvió al rey á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 20, 23, 'Así quedó Joab sobre todo el ejército de Israel; y Benaía hijo de Joiada sobre los Ceretheos y Peletheos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 20, 24, 'Y Adoram sobre los tributos; y Josaphat hijo de Ahillud, el canciller;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 20, 25, 'Y Seba, escriba; y Sadoc y Abiathar, sacerdotes;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 20, 26, '(20-25) é Ira Jaireo fué un jefe principal cerca de David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 21, 1, 'Y EN los días de David hubo hambre por tres años consecutivos. Y David consultó á Jehová, y Jehová le dijo: Es por Saúl, y por aquella casa de sangre; porque mató á los Gabaonitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 21, 2, 'Entonces el rey llamó á los Gabaonitas, y hablóles. (Los Gabaonitas no eran de los hijos de Israel, sino del residuo de los Amorrheos, á los cuales los hijos de Israel habían hecho juramento: mas Saúl había procurado matarlos con motivo de celo por los hijos de Israel y de Judá.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 21, 3, 'Dijo pues David á los Gabaonitas: ¿Qué os haré, y con qué expiaré para que bendigáis á la heredad de Jehová?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 21, 4, 'Y los Gabaonitas le respondieron: No tenemos nosotros querella sobre plata ni sobre oro con Saúl, y con su casa: ni queremos que muera hombre de Israel. Y él les dijo: Lo que vosotros dijereis os haré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 21, 5, 'Y ellos respondieron al rey: De aquel hombre que nos destruyó, y que maquinó contra nosotros, para extirparnos sin dejar nada de nosotros en todo el término de Israel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 21, 6, 'Dénsenos siete varones de sus hijos, para que los ahorquemos á Jehová en Gabaa de Saúl, el escogido de Jehová. Y el rey dijo: Yo los daré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 21, 7, 'Y perdonó el rey á Mephi-boseth, hijo de Jonathán, hijo de Saúl, por el juramento de Jehová que hubo entre ellos, entre David y Jonathán hijo de Saúl.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 21, 8, 'Mas tomó el rey dos hijos de Rispa hija de Aja, los cuales ella había parido á Saúl, á saber, á Armoni y á Mephi-boseth; y cinco hijos de Michâl hija de Saúl, los cuales ella había parido á Adriel, hijo de Barzillai Molathita;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 21, 9, 'Y entrególos en manos de los Gabaonitas, y ellos los ahorcaron en el monte delante de Jehová: y murieron juntos aquellos siete, lo cuales fueron muertos en el tiempo de la siega, en los primeros días, en el principio de la siega de las cebadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 21, 10, 'Tomando luego Rispa hija de Aja un saco, tendióselo sobre un peñasco, desde el principio de la siega hasta que llovió sobre ellos agua del cielo; y no dejó á ninguna ave del cielo asentarse sobre ellos de día, ni bestias del campo de noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 21, 11, 'Y fué dicho á David lo que hacía Rispa hija de Aja, concubina de Saúl.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 21, 12, 'Entonces David fué, y tomó los huesos de Saúl y los huesos de Jonathán su hijo, de los hombres de Jabes de Galaad, que los habían hurtado de la plaza de Beth-san, donde los habían colgado los Filisteos, cuando deshicieron los Filisteos á Saúl en Gilboa:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 21, 13, 'E hizo llevar de allí los huesos de Saúl y los huesos de Jonathán su hijo; y juntaron también los huesos de los ahorcados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 21, 14, 'Y sepultaron los huesos de Saúl y los de su hijo Jonathán en tierra de Benjamín, en Sela, en el sepulcro de Cis su padre; é hicieron todo lo que el rey había mandado. Después se aplacó Dios con la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 21, 15, 'Y como los Filisteos tornaron á hacer guerra á Israel, descendió David y sus siervos con él, y pelearon con los Filisteos: y David se cansó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 21, 16, 'En esto Isbi-benob, el cual era de los hijos del gigante, y el peso de cuya lanza era de trescientos siclos de metal, y tenía él ceñida una nueva espada, trató de herir á David:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 21, 17, 'Mas Abisai hijo de Sarvia le socorrió, é hirió al Filisteo, y matólo. Entonces los hombres de David le juraron, diciendo: Nunca más de aquí adelante saldrás con nosotros á batalla, porque no apagues la lámpara de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 21, 18, 'Otra segunda guerra hubo después en Gob contra los Filisteos: entonces Sibechâi Husathita hirió á Saph, que era de los hijos del gigante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 21, 19, 'Otra guerra hubo en Gob contra los Filisteos, en la cual Elhanan, hijo de Jaare-oregim de Beth-lehem, hirió á Goliath Getheo, el asta de cuya lanza era como un enjullo de telar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 21, 20, 'Después hubo otra guerra en Gath, donde hubo un hombre de grande altura, el cual tenía doce dedos en las manos, y otros doce en los pies, veinticuatro en todos: y también era de lo hijos del gigante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 21, 21, 'Este desafió á Israel, y matólo Jonathán, hijo de Sima hermano de David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 21, 22, 'Estos cuatro le habían nacido al gigante en Gath, los cuales cayeron por la mano de David, y por la mano de sus siervos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 1, 'Y HABLO David á Jehová las palabras de este cántico, el día que Jehová le había librado de la mano de todos sus enemigos, y de la mano de Saúl.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 2, 'Y dijo: Jehová es mi roca, y mi fortaleza, y mi libertador;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 3, 'Dios de mi roca, en él confiaré: Mi escudo, y el cuerno de mi salud, mi fortaleza, y mi refugio; Mi salvador, que me librarás de violencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 4, 'Invocaré á Jehová, digno de ser loado. Y seré salvo de mis enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 5, 'Cuando me cercaron ondas de muerte, Y arroyos de iniquidad me asombraron,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 6, 'Me rodearon los dolores del infierno, Y me tomaron descuidado lazos de muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 7, 'Tuve angustia, invoqué á Jehová, Y clamé á mi Dios: Y él oyó mi voz desde su templo; Llegó mi clamor á sus oídos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 8, 'La tierra se removió, y tembló; Los fundamentos de los cielos fueron movidos, Y se estremecieron, porque él se airó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 9, 'Subió humo de sus narices, Y de su boca fuego consumidor, Por el cual se encendieron carbones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 10, 'Y abajo los cielos, y descendió: Una oscuridad debajo de sus pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 11, 'Subió sobre el querubín, y voló: Aparecióse sobre las alas del viento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 12, 'Puso tinieblas alrededor de sí á modo de pabellones; Aguas negras y espesas nubes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 13, 'Del resplandor de su presencia Se encendieron ascuas ardientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 14, 'Jehová tronó desde los cielos, Y el Altísimo dió su voz;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 15, 'Arrojó saetas, y desbaratólos; Relampagueó, y consumiólos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 16, 'Entonces aparecieron los manantiales de la mar, Y los fundamentos del mundo fueron descubiertos, A la reprensión de Jehová, Al resoplido del aliento de su nariz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 17, 'Extendió su mano de lo alto, y arrebatóme, Y sacóme de copiosas aguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 18, 'Libróme de fuertes enemigos, De aquellos que me aborrecían, los cuales eran más fuertes que yo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 19, 'Asaltáronme en el día de mi calamidad; Mas Jehová fué mi sostén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 20, 'Sacóme á anchura; Libróme, porque puso su voluntad en mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 21, 'Remuneróme Jehová conforme á mi justicia: Y conforme á la limpieza de mis manos, me dió la paga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 22, 'Porque yo guardé los caminos de Jehová; Y no me aparté impíamente de mi Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 23, 'Porque delante de mí tengo todas sus ordenanzas; Y atento á sus fueros, no me retiraré de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 24, 'Y fuí íntegro para con él, Y guardéme de mi iniquidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 25, 'Remuneróme por tanto Jehová conforme á mi justicia, Y conforme á mi limpieza delante de sus ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 26, 'Con el bueno eres benigno, Y con el íntegro te muestras íntegro;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 27, 'Limpio eres para con el limpio, Mas con el perverso eres rígido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 28, 'Y tú salvas al pueblo humilde; Mas tus ojos sobre los altivos, para abatirlos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 29, 'Porque tú eres mi lámpara, oh Jehová: Jehová da luz á mis tinieblas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 30, 'Porque en ti romperé ejércitos, Y con mi Dios saltaré las murallas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 31, 'Dios, perfecto su camino: La palabra de Jehová purificada, Escudo es de todos los que en él esperan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 32, 'Porque ¿qué Dios hay sino Jehová? ¿O quién es fuerte sino nuestro Dios?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 33, 'Dios es el que con virtud me corrobora, y el que despeja mi camino;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 34, 'El que hace mis pies como de ciervas, Y el que me asienta en mis alturas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 35, 'El que enseña mis manos para la pelea, y da que con mis brazos quiebre el arco de acero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 36, 'Tú me diste asimismo el escudo de tu salud, Y tu benignidad me ha acrecentado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 37, 'Tú ensanchaste mis pasos debajo de mí, Para que no titubeasen mis rodillas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 38, 'Perseguiré á mis enemigos, y quebrantarélos; Y no me volveré hasta que los acabe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 39, 'Los consumiré, y los heriré, y no se levantarán; Y caerán debajo de mis pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 40, 'Ceñísteme de fortaleza para la batalla, Y postraste debajo de mí los que contra mí se levantaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 41, 'Tú me diste la cerviz de mis enemigos, De mis aborrecedores, y que yo los destruyese.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 42, 'Miraron, y no hubo quien los librase; A Jehová, mas no les respondió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 43, 'Yo los desmenuzaré como polvo de la tierra; Hollarélos como á lodo de las plazas, y los disiparé.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 44, 'Tú me libraste de contiendas de pueblos: Tú me guardaste para que fuese cabeza de gentes: Pueblos que no conocía, me sirvieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 45, 'Los extraños titubeaban á mí: En oyendo, me obedecían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 46, 'Los extraños desfallecían, Y temblaban en sus escondrijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 47, 'Viva Jehová, y sea bendita mi roca; Sea ensalzado el Dios, la roca de mi salvamento:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 48, 'El Dios que me ha vengado, Y sujeta los pueblos debajo de mí:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 49, 'Y que me saca de entre mis enemigos: Tu me sacaste en alto de entre los que se levantaron contra mi: Librásteme del varón de iniquidades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 50, 'Por tanto yo te confesaré entre las gentes, oh Jehová, Y cantaré á tu nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 22, 51, 'El que engrandece las saludes de su rey, Y hace misericordia á su ungido, A David, y á su simiente, para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 1, 'ESTAS son las postreras palabras de David. Dijo David hijo de Isaí, Dijo aquel varón que fué levantado alto, El ungido del Dios de Jacob, El suave en cánticos de Israel:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 2, 'El espíritu de Jehová ha hablado por mí, Y su palabra ha sido en mi lengua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 3, 'El Dios de Israel ha dicho, Hablóme el Fuerte de Israel: El señoreador de los hombres será justo. Señoreador en temor de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 4, 'Será como la luz de la mañana cuando sale el sol, De la mañana sin nubes; Cuando la hierba de la tierra brota Por medio del resplandor después de la lluvia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 5, 'No así mi casa para con Dios: Sin embargo él ha hecho conmigo pacto perpetuo, Ordenado en todas las cosas, y será guardado; Bien que toda esta mi salud, y todo mi deseo No lo haga él florecer todavía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 6, 'Mas los de Belial serán todos ellos como espinas arrancadas, Las cuales nadie toma con la mano;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 7, 'Sino que el que quiere tocar en ellas, Armase de hierro y de asta de lanza, Y son quemadas en su lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 8, 'Estos son los nombres de los valientes que tuvo David: El Tachmonita, que se sentaba en cátedra, principal de los capitanes: era éste Adino el Eznita, que mató en una ocasión sobre ochocientos hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 9, 'Después de éste, Eleazar, hijo de Dodo de Ahohi, fué de los tres valientes que estaban con David, cuando desafiaron á los Filisteos que se habían juntado allí á la batalla, y subieron los de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 10, 'Este, levantándose, hirió á los Filisteos, hasta que su mano se cansó, y quedósele contraída á la espada. Aquel día Jehová hizo gran salud: y volvióse el pueblo en pos de él solamente á tomar el despojo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 11, 'Después de éste fué Samma, hijo de Age Araita: que habiéndose juntado los Filisteos en una aldea, había allí una suerte de tierra llena de lentejas, y el pueblo había huído delante de los Filisteos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 12, 'El entonces se paró en medio de la suerte de tierra, y defendióla, é hirió á los Filisteos; y Jehová hizo una gran salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 13, 'Y tres de los treinta principales descendieron y vinieron en tiempo de la siega á David á la cueva de Adullam: y el campo de los Filisteos estaba en el valle de Raphaim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 14, 'David entonces estaba en la fortaleza, y la guarnición de los Filisteos estaba en Beth-lehem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 15, 'Y David tuvo deseo, y dijo: ¡Quién me diera á beber del agua de la cisterna de Beth-lehem, que está á la puerta!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 16, 'Entonces los tres valientes rompieron por el campo de los Filisteos, y sacaron agua de la cisterna de Beth-lehem, que estaba á la puerta; y tomaron, y trajéronla á David: mas él no la quiso beber, sino derramóla á Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 17, 'Lejos sea de mí, oh Jehová, que yo haga esto. ¿He de beber yo la sangre de los varones que fueron con peligro de su vida? Y no quiso beberla. Los tres valientes hicieron esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 18, 'Y Abisai hermano de Joab, hijo de Sarvia, fué el principal de los tres; el cual alzó su lanza contra trescientos, que mató; y tuvo nombre entre los tres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 19, 'El era el más aventajado de los tres, y el primero de ellos; mas no llegó á los tres primeros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 20, 'Despues, Benaía hijo de Joiada, hijo de un varón esforzado, grande en hechos, de Cabseel. Este hirió dos leones de Moab: y él mismo descendió, é hirió un león en medio de un foso en el tiempo de la nieve:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 21, 'También hirió él á un Egipcio, hombre de grande estatura: y tenía el Egipcio una lanza en su mano; mas descendió á él con un palo, y arrebató al Egipcio la lanza de la mano, y matólo con su propia lanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 22, 'Esto hizo Benaía hijo de Joiada, y tuvo nombre entre los tres valientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 23, 'De los treinta fué el más aventajado; pero no llegó á los tres primeros. Y púsolo David en su consejo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 24, 'Asael hermano de Joab fué de los treinta; Elhaanan hijo de Dodo de Beth-lehem;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 25, 'Samma de Harodi, Elica de Harodi;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 26, 'Heles de Palti, Hira, hijo de Jecces, de Tecoa;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 27, 'Abiezer de Anathoth, Mebunnai de Husa;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 28, 'Selmo de Hahoh, Maharai de Netophath;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 29, 'Helec hijo de Baana de Netophath, Ittai hijo de Ribai de Gabaa de los hijos de Benjamín;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 30, 'Benaía Pirathonita, Hiddai del arroyo de Gaas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 31, 'Abi-albon de Arbath, Asmaveth de Barhum;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 32, 'Elihaba de Saalbón, Jonathán de los hijo de Jassén;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 33, 'Samma de Arar, Ahiam hijo de Sarar de Arar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 34, 'Elipheleth hijo de Asbai hijo de Maachâti; Eliam hijo de Achîtophel de Gelón;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 35, 'Hesrai del Carmelo, Pharai de Arbi;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 36, 'Igheal hijo de Nathán de Soba, Bani de Gadi;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 37, 'Selec de Ammón, Naharai de Beeroth, escudero de Joab hijo de Sarvia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 38, 'Ira de Ithri, Gareb de Ithri;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 23, 39, 'Uría Hetheo. Entre todos treinta y siete.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 24, 1, 'Y VOLVIO el furor de Jehová á encenderse contra Israel, é incitó á David contra ellos á que dijese: Ve, cuenta á Israel y á Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 24, 2, 'Y dijo el rey á Joab, general del ejército que tenía consigo: Rodea todas las tribus de Israel, desde Dan hasta Beer-seba, y contad el pueblo, para que yo sepa el número de la gente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 24, 3, 'Y Joab respondió al rey: Añada Jehová tu Dios al pueblo cien veces tanto como son, y que lo vea mi señor al rey; mas ¿para qué quiere esto mi señor el rey?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 24, 4, 'Empero la palabra del rey pudo más que Joab, y que los capitanes del ejército. Salió pues Joab, con los capitanes del ejército, de delante del rey, para contar el pueblo de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 24, 5, 'Y pasando el Jordán asentaron en Aroer, á la mano derecha de la ciudad que está en medio de la arroyada de Gad y junto á Jazer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 24, 6, 'Después vinieron á Galaad, y á la tierra baja de Absi: y de allí vinieron á Dan-jaán y alrededor de Sidón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 24, 7, 'Y vinieron luego á la fortaleza de Tiro, y á todas las ciudades de los Heveos y de los Cananeos; y salieron al mediodía de Judá, á Beer-seba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 24, 8, 'Y después que hubieron andado toda la tierra, volvieron á Jerusalem al cabo de nueve meses y veinte días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 24, 9, 'Y Joab dió la cuenta del número del pueblo al rey; y fueron los de Israel ochocientos mil hombres fuertes que sacaban espada; y de los de Judá quinientos mil hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 24, 10, 'Y después que David hubo contado el pueblo, punzóle su corazón; y dijo David á Jehová: Yo he pecado gravemente por haber hecho esto; mas ahora, oh Jehová, ruégote que quites el pecado de tu siervo, porque yo he obrado muy neciamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 24, 11, 'Y por la mañana, cuando David se hubo levantado, fué palabra de Jehová á Gad profeta, vidente de David, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 24, 12, 'Ve, y di á David: Así ha dicho Jehová: Tres cosas te ofrezco: tú te escogerás una de ellas, la cual yo haga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 24, 13, 'Vino pues Gad á David, é intimóle, y díjole: ¿Quieres que te vengan siete años de hambre en tu tierra? ¿ó que huyas tres meses delante de tus enemigos, y que ellos te persigan? ¿o que tres días haya pestilencia en tu tierra? Piensa ahora, y mira qué responderé al que me ha enviado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 24, 14, 'Entonces David dijo á Gad: En grande angustia estoy: ruego que caiga en la mano de Jehová, porque sus miseraciones son muchas, y que no caiga yo en manos de hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 24, 15, 'Y envió Jehová pestilencia á Israel desde la mañana hasta el tiempo señalado: y murieron del pueblo, desde Dan hasta Beer-seba, setenta mil hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 24, 16, 'Y como el ángel extendió su mano sobre Jerusalem para destruirla, Jehová se arrepintió de aquel mal, y dijo al ángel que destruía el pueblo: Basta ahora; detén tu mano. Entonces el ángel de Jehová estaba junto á la era de Arauna Jebuseo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 24, 17, 'Y David dijo á Jehová, cuando vió al ángel que hería al pueblo: Yo pequé, yo hice la maldad: ¿qué hicieron estas ovejas? Ruégote que tu mano se torne contra mí, y contra la casa de mi padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 24, 18, 'Y Gad vino á David aquel día, y díjole: Sube, y haz un altar á Jehová en la era de Arauna Jebuseo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 24, 19, 'Y subió David, conforme al dicho de Gad, que Jehová le había mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 24, 20, 'Y mirando Arauna, vió al rey y á sus siervos que pasaban á él. Saliendo entonces Arauna, inclinóse delante del rey hacia tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 24, 21, 'Y Arauna dijo: ¿Por qué viene mi señor el rey á su siervo? Y David respondió: Para comprar de ti la era, para edificar altar á Jehová, á fin de que la mortandad cese del pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 24, 22, 'Y Arauna dijo á David: Tome y sacrifique mi señor el rey lo que bien le pareciere; he aquí bueyes para el holocausto; y trillos y otros pertrechos de bueyes para leña:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 24, 23, 'Todo lo da como un rey Arauna al rey. Luego dijo Arauna al rey: Jehová tu Dios te sea propicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 24, 24, 'Y el rey dijo á Arauna: No, sino por precio te lo compraré; porque no ofreceré á Jehová mi Dios holocaustos por nada. Entonces David compró la era y los bueyes por cincuenta siclos de plata.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2SA', '2 Samuel', 24, 25, 'Y edificó allí David un altar á Jehová, y sacrificó holocaustos y pacíficos; y Jehová se aplacó con la tierra, y cesó la plaga de Israel.');
